let MAP_GAME = 'FR';
let MAP_SELECTED_LOC = null;
let MAP_REGION = 'kanto';

function getPageHashId() {
  var raw = (window.location.hash || '').replace(/^#/, '').trim();
  if (!raw) return '';
  raw = raw.split('?')[0];
  if (raw.indexOf('page=') === 0) raw = raw.slice(5);
  return raw.toLowerCase();
}

function getHashRoute() {
  var raw = (window.location.hash || '').replace(/^#/, '').trim();
  if (!raw) return { page: 'home', params: new URLSearchParams() };
  var parts = raw.split('?');
  var page = (parts[0] || 'home').trim().toLowerCase();
  if (page.indexOf('page=') === 0) page = page.slice(5);
  return {
    page: page || 'home',
    params: new URLSearchParams(parts[1] || '')
  };
}

var _hashSyncMuted = false;

function setPageHash(id, params) {
  var page = id && id !== 'home' ? id : 'home';
  var query = '';
  if (params) {
    var qp = new URLSearchParams();
    Object.keys(params).forEach(function(key) {
      var value = params[key];
      if (value !== undefined && value !== null && value !== '') qp.set(key, String(value));
    });
    query = qp.toString();
  }
  var target = '#' + page + (query ? '?' + query : '');
  if (window.location.hash !== target) {
    _hashSyncMuted = true;
    window.location.hash = target;
    setTimeout(function(){ _hashSyncMuted = false; }, 0);
  }
}

function applyHashRoute(route) {
  route = route || getHashRoute();
  var page = route.page || 'home';
  var params = route.params || new URLSearchParams();

  if (page === 'distributionchecklist') page = 'distributions';

  if (page === 'home') { resetHome(); return; }
  if (!document.getElementById('page-' + page)) return;

  if (page === 'dex') {
    var num = parseInt(params.get('pokemon') || params.get('num') || '', 10);
    var q = params.get('q') || params.get('name') || '';
    if (num) {
      var p = POKE.find(function(mon) { return mon.num === num; });
      _openDexSearch(p ? p.name : q, num);
      return;
    }
    window.showPage('dex', null);
    return;
  }

  if (page === 'moves') {
    _openMoveDex(params.get('move') || params.get('name') || '', parseInt(params.get('id') || '', 10) || null);
    return;
  }

  if (page === 'items') {
    var itemId = parseInt(params.get('id') || '', 10);
    if (itemId) {
      var item = (typeof ALL_ITEMS !== 'undefined' ? ALL_ITEMS : []).find(function(it) { return Array.isArray(it) && it[0] === itemId; });
      _openItemDex(item || [itemId]);
      return;
    }
    window.showPage('items', null);
    return;
  }

  if (page === 'tmhm') { _openTmhm(params.get('move') || params.get('name') || '', params.get('code') || ''); return; }
  if (page === 'tutors') { _openTutors(params.get('move') || params.get('name') || ''); return; }
  if (page === 'abilities') { _openAbilities(params.get('ability') || params.get('name') || ''); return; }
  if (page === 'learnsets') { _openLearnsets(parseInt(params.get('pokemon') || params.get('num') || '', 10) || null); return; }
  if (page === 'encounters') { _openEncounters(params.get('route') || params.get('location') || '', params.get('game') || ''); return; }
  if (page === 'itemlocs') { _openItemLocs(params.get('item') || params.get('name') || '', params.get('game') || ''); return; }
  if (page === 'bulba') {
    var guideKey = params.get('guide') || '';
    var partNum = parseInt(params.get('part') || '', 10);
    var extraKey = params.get('extra') || '';
    var sectionId = params.get('section') || params.get('id') || '';
    const bulbaBtn = document.getElementById('navBulba');
    showPage('bulba', bulbaBtn);
    if (!window._bulbaBuilt) { buildBulbaGuide(); window._bulbaBuilt = true; }
    if (guideKey && BULBA_BASES && BULBA_BASES[guideKey] && guideKey !== BULBA_GAME) {
      bulbaSwitchGame(guideKey, null);
    }
    if (partNum) { bulbaLoadPart(partNum); return; }
    if (extraKey) { bulbaLoadExtra(extraKey, extraKey); return; }
    if (sectionId) { _openGuideSection(sectionId); return; }
    if (guideKey) { bulbaLoadIndex(); return; }
    return;
  }

  if (typeof window.openTopLevelPage === 'function') {
    window.openTopLevelPage(page);
  }
}

function pageTitleLabel(id) {
  var custom = {
    home: 'Home',
    dex: 'Pokedex',
    bulba: 'Bulba Guide',
    tracker: 'Tracker',
    moves: 'Moves Dex',
    items: 'Items Dex',
    held: 'Held Items',
    tmhm: 'TM/HM Locator',
    excl: 'Exclusives',
    tradeevo: 'Trade Evos',
    npctrades: 'NPC Trades',
    team: 'Team Builder',
    calc: 'Damage Calculator',
    compare: 'Pokemon Comparison',
    opt: 'Optimizer',
    ivev: 'IV / EV Calculator',
    natures: 'Nature Chart',
    expcalc: 'EXP Calculator',
    breed: 'Breeding Calculator',
    catchcalc: 'Catch Rate Calc',
    happiness: 'Happiness Tracker',
    dexdash: 'Dex Dashboard',
    ribbons: 'Ribbon Tracker',
    kantomapview: 'Kanto Map',
    emeraldmapview: 'Emerald Map',
    easydex: 'Easy Dex',
    typechart: 'Type Chart',
    speedtiers: 'Speed Tiers',
    safarizone: 'Safari Zone Calculator',
    statcalc: 'Stat Calculator',
    e4ref: 'Elite Four & Champion',
    routebrowser: 'Route Browser',
    distributions: 'Distributions',
    distributionchecklist: 'Distributions'
  };
  if (custom[id]) return custom[id];
  var nav = document.getElementById('nav' + id.charAt(0).toUpperCase() + id.slice(1));
  if (nav && nav.textContent) return nav.textContent.trim().replace(/\s+/g, ' ');
  var page = document.getElementById('page-' + id);
  if (page) {
    var heading = page.querySelector('h1, h2, .page-title, .dexdash-title, .section-title');
    if (heading && heading.textContent) return heading.textContent.trim().replace(/\s+/g, ' ');
  }
  return id ? id.charAt(0).toUpperCase() + id.slice(1) : 'Home';
}

function setBrowserPageTitle(id) {
  var label = pageTitleLabel(id || 'home');
  document.title = 'Gen3 eGuide - ' + label;
}

function showPage(id, btn) {
  if (id === 'distributionchecklist') {
    id = 'distributions';
    btn = document.getElementById('navDistributions');
  }
  if (id === 'notes' && typeof window.enterNotesFullPage === 'function') {
    window.enterNotesFullPage();
  } else if (typeof window.exitNotesFullPage === 'function') {
    window.exitNotesFullPage(false);
  }
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.page-nav-btn').forEach(b => b.classList.remove('active'));
  var targetPage = document.getElementById('page-' + id);
  if (targetPage) {
    // Trigger CSS fade-in via toggling 'active' after a micro-tick so animation re-fires
    void targetPage.offsetWidth; // force reflow
    targetPage.classList.add('active');
  }
  try { localStorage.setItem('gen3-last-page', id); } catch(e) {}
  var currentRoute = getHashRoute();
  if (currentRoute.page !== id || !window.location.hash) setPageHash(id);
  if (btn) btn.classList.add('active');
  else {
    const navBtn = document.getElementById('nav' + id.charAt(0).toUpperCase() + id.slice(1));
    if (navBtn) navBtn.classList.add('active');
  }
  setBrowserPageTitle(id);
  if (id === 'dex' && typeof buildTable === 'function') {
    try { buildTable(); } catch (e) {}
  }
  if (id === 'bulba' && !window._bulbaBuilt && typeof buildBulbaGuide === 'function') {
    buildBulbaGuide();
    window._bulbaBuilt = true;
  }
  // Keep iOS tab bar in sync
  if (typeof iosUpdateForPage === 'function') iosUpdateForPage(id);
}

function setMapGame(g, btn) {
  MAP_GAME = g;
  document.querySelectorAll('.map-game-btns button').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  if (MAP_SELECTED_LOC) showMapLocation(MAP_SELECTED_LOC);
}

function switchMapRegion(region, btn) {
  MAP_REGION = region;
  document.querySelectorAll('.map-tab').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  MAP_SELECTED_LOC = null;
  document.getElementById('mapLocTitle').textContent = 'SELECT A LOCATION';
  document.getElementById('mapResults').innerHTML = '<div class="map-empty">Click any town or location on the map to see Pokémon and items available there.</div>';
  renderMapRegion(region);
}

function renderMapRegion(region) {
  const img = MAP_IMAGES[region];
  const zoneList = MAP_ZONES[region] || [];
  const scroll = document.getElementById('mapScroll');
  if (!img) return;

  let zonesSvg = '';
  for (const z of zoneList) {
    const isSel = MAP_SELECTED_LOC === z.id;
    const fillCol = isSel ? 'rgba(255,215,0,0.35)' : 'rgba(255,215,0,0)';
    const strokeCol = isSel ? 'rgba(255,215,0,1)' : 'rgba(255,215,0,0)';
    const eid = z.id.replace(/"/g, '&quot;').replace(/'/g, '&#39;');
    zonesSvg += '<g class="map-zone-hit" onclick="selectMapZone(this)" data-id="' + eid + '">'
      + '<rect class="map-zone-rect" x="' + z.x + '" y="' + z.y + '" width="' + z.w + '" height="' + z.h + '" rx="4"'
      + ' fill="' + fillCol + '" stroke="' + strokeCol + '" stroke-width="2"/>'
      + '</g>';
  }

  scroll.innerHTML = '<div style="position:relative;display:inline-block;line-height:0">'
    + '<img src="' + img.b64 + '" width="' + img.w + '" height="' + img.h + '"'
    + ' style="display:block;image-rendering:pixelated;image-rendering:crisp-edges" draggable="false"/>'
    + '<svg xmlns="http://www.w3.org/2000/svg"'
    + ' style="position:absolute;top:0;left:0;cursor:crosshair"'
    + ' width="' + img.w + '" height="' + img.h + '" id="mapSvgOverlay">'
    + zonesSvg + '</svg></div>';
}

function selectMapZone(el) {
  const locId = el.dataset.id;
  // Update visuals
  const overlay = document.getElementById('mapSvgOverlay');
  if (overlay) {
    overlay.querySelectorAll('.map-zone-rect').forEach(r => {
      r.setAttribute('fill', 'rgba(255,215,0,0)');
      r.setAttribute('stroke', 'rgba(255,215,0,0)');
    });
    const rect = el.querySelector('.map-zone-rect');
    if (rect) {
      rect.setAttribute('fill', 'rgba(255,215,0,0.35)');
      rect.setAttribute('stroke', 'rgba(255,215,0,1)');
    }
  }
  showMapLocation(locId);
}

function showMapLocation(locId) {
  MAP_SELECTED_LOC = locId;
  document.getElementById('mapLocTitle').textContent = locId.toUpperCase();

  const game = MAP_GAME;
  const zoneList = MAP_ZONES[MAP_REGION] || [];
  const zone = zoneList.find(z => z.id === locId);
  const searchTerms = zone ? zone.terms : [locId];

  // ── Pokémon search ──
  const results = [];
  for (const p of POKE) {
    const gameData = p.games[game] || '';
    if (!gameData) continue;
    const lines = gameData.split('\n');
    const matchLines = lines.filter(l =>
      searchTerms.some(term => l.toLowerCase().includes(term.toLowerCase()))
    );
    if (matchLines.length > 0) {
      results.push({ p, method: matchLines[0].split('(')[0].trim() });
    }
  }

  // ── Item search ──
  const itemResults = [];
  if (typeof ALL_ITEMS !== 'undefined') {
    for (const it of ALL_ITEMS) {
      const locs = it[4] || {};
      const locStr = locs[game] || '';
      if (!locStr) continue;
      const locLower = locStr.toLowerCase();
      if (searchTerms.some(term => locLower.includes(term.toLowerCase()))) {
        itemResults.push({ id: it[0], name: it[1], locStr: locStr });
      }
    }
  }

  const container = document.getElementById('mapResults');
  const TC = {normal:'#9E9E9E',fire:'#E8501A',water:'#1B8FE8',grass:'#3DA83D',electric:'#D4A800',ice:'#60C8C8',fighting:'#B83020',poison:'#8B3099',ground:'#8B6840',flying:'#6850C0',psychic:'#D01868',bug:'#78A810',rock:'#807840',ghost:'#4030A0',dragon:'#5038E8',dark:'#403030',steel:'#9898A8'};

  const gameNames = {FR:'FireRed',LG:'LeafGreen',R:'Ruby',S:'Sapphire',E:'Emerald'};
  const gameName = gameNames[game] || game;

  if (results.length === 0 && itemResults.length === 0) {
    const altGame = game === 'FR' ? 'LeafGreen' : game === 'LG' ? 'FireRed' : game === 'R' ? 'Sapphire' : game === 'S' ? 'Ruby' : '';
    container.innerHTML = '<div class="map-empty">Nothing found for <strong>' + locId + '</strong> in ' + gameName + '.' + (altGame ? '<br><br>Try switching to ' + altGame + '?' : '') + '</div>';
    return;
  }

  container.innerHTML = '';

  // ── Pokémon section ──
  if (results.length > 0) {
    const hdr = document.createElement('div');
    hdr.style.cssText = 'font-size:9px;font-weight:800;color:var(--muted);margin-bottom:8px';
    hdr.textContent = results.length + ' POKÉMON';
    container.appendChild(hdr);
    for (const {p, method} of results) {
      const card = document.createElement('div');
      card.className = 'map-poke-card';
      const img = document.createElement('img');
      img.src = 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + p.num + '.png';
      img.width = 30; img.height = 30;
      img.onerror = function() { this.style.display = 'none'; };
      const info = document.createElement('div');
      info.style.cssText = 'flex:1;min-width:0';
      const nameEl = document.createElement('div');
      nameEl.className = 'map-poke-name';
      nameEl.textContent = p.name;
      const typesEl = document.createElement('div');
      typesEl.className = 'map-poke-types';
      p.types.forEach(function(t) {
        const sp = document.createElement('span');
        sp.className = 'map-poke-type';
        sp.style.background = TC[t] || '#666';
        sp.style.color = ['electric','ice','steel'].includes(t) ? '#000' : '#fff';
        sp.textContent = t;
        typesEl.appendChild(sp);
      });
      const methodEl = document.createElement('div');
      methodEl.className = 'map-poke-method';
      methodEl.textContent = method;
      info.appendChild(nameEl);
      info.appendChild(typesEl);
      info.appendChild(methodEl);
      card.appendChild(img);
      card.appendChild(info);
      card.addEventListener('click', (function(name) { return function() { jumpToDex(name); }; })(p.name));
      container.appendChild(card);
    }
  }

  // ── Items section ──
  if (itemResults.length > 0) {
    const itemHdr = document.createElement('div');
    itemHdr.style.cssText = 'font-size:9px;font-weight:800;color:var(--muted);margin-top:' + (results.length > 0 ? '14px' : '0') + ';margin-bottom:8px';
    itemHdr.textContent = itemResults.length + ' ITEM' + (itemResults.length > 1 ? 'S' : '');
    container.appendChild(itemHdr);
    var itemHtml = '';
    for (const {id, name, locStr} of itemResults) {
      const iconUrl = (typeof ITEM_ICONS !== 'undefined' && ITEM_ICONS[id]) ? ITEM_ICONS[id] : '';
      const iconHtml = iconUrl
        ? '<img src="' + iconUrl + '" width="24" height="24" style="image-rendering:pixelated;flex-shrink:0" onerror="this.style.display=\'none\'">'
        : '<span style="width:24px;height:24px;flex-shrink:0;display:inline-block"></span>';
      const safeName = name.replace(/\\/g,'\\\\').replace(/'/g,"\\'");
      const dispName = name.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
      const dispLoc  = locStr.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
      itemHtml += '<div style="display:flex;align-items:center;gap:8px;padding:5px 8px;background:var(--card);border-radius:5px;border:1px solid var(--border);margin-bottom:4px;cursor:pointer;transition:border-color 0.15s" onmouseover="this.style.borderColor=\'var(--game-color,var(--gold))\'" onmouseout="this.style.borderColor=\'var(--border)\'" onclick="openItemByName(\'' + safeName + '\')">'
        + iconHtml
        + '<div style="flex:1;min-width:0">'
        + '<div style="font-weight:800;font-size:11px;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + dispName + '</div>'
        + '<div style="font-size:9px;color:var(--muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;margin-top:1px">' + dispLoc + '</div>'
        + '</div></div>';
    }
    const itemWrap = document.createElement('div');
    itemWrap.innerHTML = itemHtml;
    container.appendChild(itemWrap);
  }
}

function jumpToDex(name) {
  closeExtMap();
  var p = POKE.find(function(pk) { return pk.name === name; });
  var hadOpenDetail = openEvoNum !== null;
  document.getElementById('searchInput').value = name;
  SEARCH = name;
  if (hadOpenDetail && p) openEvoNum = p.num;
  buildTable();
  if (p) {
    setTimeout(function() {
      var row = document.getElementById('poke-row-' + p.num);
      if (row) row.scrollIntoView({ behavior:'smooth', block:'start' });
    }, 80);
  }
}
buildTable();


