// ═══════════════════════════════════════════════════════════════
//  ITEM DEX
// ═══════════════════════════════════════════════════════════════
const ITEM_CAT_COLORS = {"Ball":"#E8501A","Medicine":"#E91E63","Battle":"#B83020","Vitamin":"#9C27B0","Hold":"#1B8FE8","Evolution":"#78C850","Key":"#D4A800","TM/HM":"#60C8C8","Berry":"#4CAF50","Other":"#607D8B"};
let itSortKey='id', itSortDir=1, itCatFilter='All', itOpenId=null;

function getItemLocation(it) {
  // it[4] is {FR,LG,R,S,E}
  const locs = it[4];
  if (!locs) return '';
  if (GAME === 'all') {
    // Show a compact multi-game view: only unique location strings
    const seen = new Set();
    const lines = [];
    [['🔥 FR','FR'],['🌿 LG','LG'],['🔴 R','R'],['🔷 S','S'],['💚 E','E']].forEach(([label,g])=>{
      const v = locs[g]||'';
      if(!v) return;
      if(!seen.has(v)) { seen.add(v); lines.push(`<span style="color:var(--muted);font-size:10px">${label}</span> ${v}`); }
      else { lines.push(`<span style="color:var(--muted);font-size:10px">${label}</span> ↑ same`); }
    });
    return lines.join('<br>');
  }
  return locs[GAME] || '<span style="color:var(--muted);font-style:italic">Not available in this game.</span>';
}

function getItemLocationShort(it) {
  const locs = it[4];
  if (!locs) return '';
  if (GAME === 'all') {
    // find first non-empty
    const v = locs.FR || locs.LG || locs.R || locs.S || locs.E || '';
    return v.length > 65 ? v.slice(0,65)+'…' : v;
  }
  const v = locs[GAME]||'';
  return v.length > 65 ? v.slice(0,65)+'…' : v;
}

function setItemCat(cat, btn) {
  itCatFilter = cat;
  document.querySelectorAll('.item-cat-btn').forEach(b => {
    b.classList.remove('active');
    const c = ITEM_CAT_COLORS[b.textContent.trim()];
    if (c) { b.style.background = c; b.style.color = '#fff'; }
    else { b.style.background = 'var(--card)'; b.style.color = 'var(--text)'; }
  });
  btn.classList.add('active');
  itOpenId = null;
  renderItemDex();
}

function filterItemDex() { itOpenId=null; renderItemDex(); }

function itSort(key) {
  if(itSortKey===key) itSortDir*=-1;
  else { itSortKey=key; itSortDir=1; }
  document.querySelectorAll('.item-table th').forEach(th=>th.classList.remove('sort-asc','sort-desc'));
  const th = document.getElementById('itth-'+key);
  if(th) th.classList.add(itSortDir===1?'sort-asc':'sort-desc');
  renderItemDex();
}

function getItemsFiltered() {
  const q = (document.getElementById('itSearch')||{}).value?.toLowerCase().trim()||'';
  return ALL_ITEMS.filter(it=>{
    if(itCatFilter!=='All' && it[2]!==itCatFilter) return false;
    // For search: match name, effect, or location for current game
    if(q) {
      const locStr = GAME==='all'
        ? Object.values(it[4]||{}).join(' ')
        : (it[4]||{})[GAME]||'';
      if(!it[1].toLowerCase().includes(q) && !it[3].toLowerCase().includes(q) && !locStr.toLowerCase().includes(q)) return false;
    }
    // Hide items explicitly marked empty for the selected game (e.g. HM08 Dive for FR/LG)
    if (GAME !== 'all' && it[4] && it[4].hasOwnProperty(GAME) && it[4][GAME] === '') return false;
    return true;
  }).sort((a,b)=>{
    const ki={id:0,name:1,cat:2};
    const i=ki[itSortKey]??0;
    let av=a[i],bv=b[i];
    if(typeof av==='string') av=av.toLowerCase();
    if(typeof bv==='string') bv=bv.toLowerCase();
    return av<bv?-itSortDir:av>bv?itSortDir:0;
  });
}

function buildItemDex() { renderItemDex(); }

function renderItemDex() {
  const items = getItemsFiltered();
  const gameName = {all:'All Games',FR:'FireRed',LG:'LeafGreen',R:'Ruby',S:'Sapphire',E:'Emerald'}[GAME]||'';
  document.getElementById('itCountLabel').textContent = items.length+' items';
  // Update column header to show current game
  const locHeader = document.getElementById('itth-loc');
  if(locHeader) locHeader.textContent = GAME==='all' ? 'Location (All Games)' : 'Location — '+gameName;
  const tbody = document.getElementById('itTbody');
  let rows = '';
  items.forEach(it=>{
    const [id,name,cat,effect] = it;
    const catColor = ITEM_CAT_COLORS[cat]||'#888';
    const effShort = effect.length>55 ? effect.slice(0,55)+'…' : effect;
    const locShort = getItemLocationShort(it);
    const locVal = it[4] ? (GAME==='all' ? '' : (it[4][GAME]||'')) : '';
    const unavail = GAME!=='all' && !locVal;
    const rowStyle = unavail ? 'opacity:0.5' : '';
    rows += `<tr class="it-row" id="itr-${id}" onclick="toggleItDet(${id})" style="${rowStyle}">
      <td><div style="display:flex;align-items:center;gap:7px"><img src="${ITEM_ICONS[id]||''}" width="24" height="24" style="image-rendering:pixelated;flex-shrink:0" onerror="this.style.display='none'"><span class="item-name">${name}</span></div></td>
      <td><span class="item-cat-badge" style="background:${catColor};color:#fff">${cat}</span></td>
      <td style="font-size:11px;color:var(--muted);max-width:220px">${effShort}</td>
      <td style="font-size:11px;color:${unavail?'var(--muted)':'var(--text)'};max-width:260px;font-style:${unavail?'italic':'normal'}">${unavail?'Not available in this game.':locShort}</td>
    </tr>
    <tr class="it-det-row" id="itd-${id}"><td colspan="4"><div class="it-det-panel" id="itdp-${id}"></div></td></tr>`;
  });
  tbody.innerHTML = rows;
  if(itOpenId!==null) {
    const dr=document.getElementById('itd-'+itOpenId);
    const rr=document.getElementById('itr-'+itOpenId);
    if(dr) { dr.classList.add('open'); rr?.classList.add('it-exp-open'); renderItDetPanel(itOpenId); }
    else itOpenId=null;
  }
}

function toggleItDet(id) {
  if(itOpenId===id) {
    document.getElementById('itd-'+id)?.classList.remove('open');
    document.getElementById('itr-'+id)?.classList.remove('it-exp-open');
    itOpenId=null;
    setPageHash('items', null);
    return;
  }
  if(itOpenId!==null) {
    document.getElementById('itd-'+itOpenId)?.classList.remove('open');
    document.getElementById('itr-'+itOpenId)?.classList.remove('it-exp-open');
  }
  itOpenId=id;
  document.getElementById('itd-'+id)?.classList.add('open');
  document.getElementById('itr-'+id)?.classList.add('it-exp-open');
  setPageHash('items', { id: id });
  renderItDetPanel(id);
}

function renderItDetPanel(id) {
  const panel = document.getElementById('itdp-'+id);
  if(!panel) return;
  // Re-render on every open so game-switch updates it
  const it = ALL_ITEMS.find(x=>x[0]===id);
  if(!it) return;
  const [,name,cat,effect] = it;
  const fullLoc = getItemLocation(it);
  const iconUrl = ITEM_ICONS[id] || '';
  panel.innerHTML = `<div class="it-det-inner">
    <div class="it-det-effect"><strong>Effect</strong>${iconUrl ? `<img src="${iconUrl}" width="20" height="20" style="image-rendering:pixelated;vertical-align:middle;margin-right:6px" onerror="this.style.display='none'">` : ''}${effect}</div>
    <div class="it-det-location"><strong>How to obtain</strong>${fullLoc}</div>
  </div>`;
  panel.dataset.rendered='1';
}


