const TYPE_COLORS_MD = {
  Normal:'#A8A878',Fire:'#F08030',Water:'#6890F0',Grass:'#78C850',
  Electric:'#F8D030',Ice:'#98D8D8',Fighting:'#C03028',Poison:'#A040A0',
  Ground:'#E0C068',Flying:'#A890F0',Psychic:'#F85888',Bug:'#A8B820',
  Rock:'#B8A038',Ghost:'#705898',Dragon:'#7038F8',Dark:'#705848',
  Steel:'#B8B8D0'
};
let MD_SORT_KEY='id', MD_SORT_DIR=1, MD_TYPE_FILTER=null, MD_CAT_FILTER=null, MD_CONTEST_FILTER=null, MD_TUTOR_FILTER=false, MD_TMHM_FILTER=false, MD_SEARCH='', MD_OPEN_ID=null;

function buildMoveDex() {
  const page = document.getElementById('page-moves');
  const allTypes = ['Normal','Fire','Water','Grass','Electric','Ice','Fighting','Poison','Ground','Flying','Psychic','Bug','Rock','Ghost','Dragon','Dark','Steel'];
  let typeBtns = allTypes.map(t => {
    return `<button class="mdex-type-btn" data-type="${t}" onclick="mdexSetType('${t}')">${typeSprite(t.toLowerCase())}</button>`;
  }).join('');
  page.innerHTML = `
    <div class="movedex-toolbar" style="top:0">
      <div style="position:relative;display:flex;align-items:center;flex:1;min-width:180px;"><input class="movedex-search" id="mdex-search" placeholder="Search moves…" oninput="mdexSearch(this.value);updateMdexClear(this)" style="flex:1;min-width:0;padding-right:28px"><button class="search-bar-clear" id="mdexClear" onclick="clearMdexSearch()" title="Clear search">✕</button></div>
      <div class="movedex-cat-filter">
        <button class="mdex-cat-btn" onclick="mdexSetCat('Physical')">⚔ Physical</button>
        <button class="mdex-cat-btn" onclick="mdexSetCat('Special')">✨ Special</button>
        <button class="mdex-cat-btn" onclick="mdexSetCat('Status')">● Status</button>
        <span style="width:1px;background:var(--border);margin:0 2px;align-self:stretch;display:inline-block;opacity:0.5"></span>
        <button class="mdex-cat-btn" style="font-size:9px" onclick="mdexSetContest('Cool',this)" id="mc-Cool">Cool</button>
        <button class="mdex-cat-btn" style="font-size:9px" onclick="mdexSetContest('Beautiful',this)" id="mc-Beautiful">Beauty</button>
        <button class="mdex-cat-btn" style="font-size:9px" onclick="mdexSetContest('Cute',this)" id="mc-Cute">Cute</button>
        <button class="mdex-cat-btn" style="font-size:9px" onclick="mdexSetContest('Clever',this)" id="mc-Clever">Clever</button>
        <button class="mdex-cat-btn" style="font-size:9px" onclick="mdexSetContest('Tough',this)" id="mc-Tough">Tough</button>
        <span style="width:1px;background:var(--border);margin:0 2px;align-self:stretch;display:inline-block;opacity:0.5"></span>
        <button class="mdex-cat-btn" style="font-size:9px" onclick="mdexToggleTutor(this)" id="mc-tutor">🎓 Tutor</button>
        <button class="mdex-cat-btn" style="font-size:9px" onclick="mdexToggleTmhm(this)" id="mc-tmhm">💿 TM/HM</button>
      </div>
      <span class="movedex-count" id="mdex-count"></span>
    </div>
    <div class="movedex-toolbar" style="position:static;padding-top:6px;padding-bottom:8px;gap:5px;">
      <div class="movedex-type-filter" id="mdex-type-btns">${typeBtns}</div>
    </div>
    <div class="movedex-table-wrap">
      <table class="movedex-table" id="mdex-table">
        <thead><tr>
          <th onclick="mdexSort('id')">#</th>
          <th onclick="mdexSort('name')">Name</th>
          <th onclick="mdexSort('type')">Type</th>
          <th onclick="mdexSort('cat')">Cat</th>
          <th onclick="mdexSort('power')" style="text-align:right">Power</th>
          <th onclick="mdexSort('acc')" style="text-align:right">Acc</th>
          <th onclick="mdexSort('pp')" style="text-align:right">PP</th>
          <th onclick="mdexSort('learners')">Learners</th>
          <th style="white-space:nowrap">Contest</th>
        </tr></thead>
        <tbody id="mdex-tbody"></tbody>
      </table>
    </div>`;
  mdexRender();
  // Show/hide contest appeal filters based on game (RSE only)
  const isRSE = ['R','S','E'].includes(GAME);
  ['mc-Cool','mc-Beautiful','mc-Cute','mc-Clever','mc-Tough','mdex-contest-sep'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.style.display = isRSE || GAME==='all' ? '' : 'none';
  });
  if (!isRSE && GAME!=='all' && MD_CONTEST_FILTER) {
    MD_CONTEST_FILTER = null;
    document.querySelectorAll('.mdex-cat-btn').forEach(b => b.classList.remove('active'));
  }
  // Restore input value and active states after DOM rebuild
  const inp = document.getElementById('mdex-search');
  if (inp && MD_SEARCH) {
    inp.value = MD_SEARCH;
    const clr = document.getElementById('mdexClear');
    if (clr) clr.classList.add('visible');
  }
  if (MD_CAT_FILTER) {
    document.querySelectorAll('.mdex-cat-btn').forEach(function(b){
      if (b.textContent.trim().replace(/^[\u2694\u2728\u25cf]\s*/,'') === MD_CAT_FILTER) b.classList.add('active');
    });
  }
  if (MD_TYPE_FILTER) {
    const tb = document.querySelector('[data-type="'+MD_TYPE_FILTER+'"]');
    if (tb) tb.classList.add('active');
  }
  if (MD_TUTOR_FILTER) {
    const tutorBtn = document.getElementById('mc-tutor');
    if (tutorBtn) tutorBtn.classList.add('active');
  }
  if (MD_TMHM_FILTER) {
    const tmhmBtn = document.getElementById('mc-tmhm');
    if (tmhmBtn) tmhmBtn.classList.add('active');
  }
}

function mdexGetFiltered() {
  const q = MD_SEARCH.toLowerCase();
  return Object.entries(MOVES_DATA).filter(([id,m]) => {
    if (q && !m[0].toLowerCase().includes(q) && !m[1].toLowerCase().includes(q) && !m[6].toLowerCase().includes(q)) return false;
    if (MD_TYPE_FILTER && m[1]!==MD_TYPE_FILTER) return false;
    if (MD_CAT_FILTER && m[2]!==MD_CAT_FILTER) return false;
    if (MD_CONTEST_FILTER && CONTEST_CATS[m[0]]!==MD_CONTEST_FILTER) return false;
    if (MD_TUTOR_FILTER) {
      const td = TUTOR_NPC_DATA[m[0]];
      if (!td) return false;
      if (GAME !== 'all' && !td.games.includes(GAME)) return false;
    }
    if (MD_TMHM_FILTER) {
      const hasTmhm = ALL_ITEMS.some(function(it) {
        if (it[2] !== 'TM/HM') return false;
        var moveName = it[1].replace(/^(TM|HM)\d+\s*/, '');
        if (moveName !== m[0]) return false;
        if (GAME === 'all') return true;
        return !!(it[4] && it[4][GAME]);
      });
      if (!hasTmhm) return false;
    }
    return true;
  });
}

function mdexRender() {
  // Show/hide contest filters based on game
  const isRSE = ['R','S','E','all'].includes(GAME);
  const isFRLG = ['FR','LG'].includes(GAME);
  ['mc-Cool','mc-Beautiful','mc-Cute','mc-Clever','mc-Tough'].forEach(function(id){
    const el = document.getElementById(id);
    if(el) el.style.display = isFRLG ? 'none' : '';
  });
  // Reset contest filter if switching to FR/LG
  if(isFRLG && MD_CONTEST_FILTER) { MD_CONTEST_FILTER=null; document.querySelectorAll('[id^="mc-"]').forEach(function(b){b.classList.remove('active');}); }
  // Hide/show contest column
  const mdexTbl = document.getElementById('mdex-table');
  if (mdexTbl) mdexTbl.classList.toggle('mdex-no-contest', isFRLG);
  const rows = mdexGetFiltered();
  rows.sort((a,b) => {
    const [aid,am]=a,[bid,bm]=b; let av,bv;
    if (MD_SORT_KEY==='id')       {av=+aid;bv=+bid;}
    else if (MD_SORT_KEY==='name') {av=am[0];bv=bm[0];}
    else if (MD_SORT_KEY==='type') {av=am[1];bv=bm[1];}
    else if (MD_SORT_KEY==='cat')  {av=am[2];bv=bm[2];}
    else if (MD_SORT_KEY==='power'){av=am[3]||0;bv=bm[3]||0;}
    else if (MD_SORT_KEY==='acc')  {av=am[4]||0;bv=bm[4]||0;}
    else if (MD_SORT_KEY==='pp')   {av=am[5]||0;bv=bm[5]||0;}
    else if (MD_SORT_KEY==='learners'){av=Object.keys(MOVE_LEARNERS[am[0]]||{}).length;bv=Object.keys(MOVE_LEARNERS[bm[0]]||{}).length;}
    if (av<bv) return -1*MD_SORT_DIR; if (av>bv) return 1*MD_SORT_DIR; return 0;
  });
  document.querySelectorAll('.movedex-table th').forEach((th,i)=>{th.classList.remove('sort-asc','sort-desc');});
  const colMap={id:0,name:1,type:2,cat:3,power:4,acc:5,pp:6,learners:7};
  const ths = document.querySelectorAll('#mdex-table thead th');
  if (ths[colMap[MD_SORT_KEY]]) ths[colMap[MD_SORT_KEY]].classList.add(MD_SORT_DIR===1?'sort-asc':'sort-desc');
  const tbody = document.getElementById('mdex-tbody');
  if (!tbody) return;
  tbody.innerHTML='';
  rows.forEach(([id,m]) => {
    const [name,type,cat,power,acc,pp,desc]=m;
    const tc=TYPE_COLORS_MD[type]||'#888';
    const catIcon=cat==='Physical'?'⚔':cat==='Special'?'✨':'●';
    const catColor=cat==='Physical'?'var(--fire)':cat==='Special'?'#6890F0':'var(--muted)';
    const lcount=Object.keys(MOVE_LEARNERS[name]||{}).length;
    const pwrColor=power>=100?'#F08030':power>=60?'var(--text)':'var(--muted)';
    const isOpen=MD_OPEN_ID==id;
    const tr=document.createElement('tr');
    tr.className='mrow'+(isOpen?' mopen':'');
    tr.setAttribute('data-mid',id);
    tr.onclick=()=>mdexToggle(id);
    tr.innerHTML=`
      <td style="color:var(--muted);font-size:10px;font-family:monospace">${id}</td>
      <td style="font-weight:800">${name}</td>
      <td>${typeSprite(type.toLowerCase())}</td>
      <td style="color:${catColor};font-weight:800">${catIcon} ${cat}</td>
      <td style="text-align:right;font-family:monospace;font-weight:800;color:${pwrColor}">${power||'<span style=\"color:var(--muted);font-style:italic\">—</span>'}</td>
      <td style="text-align:right;font-family:monospace;color:var(--muted)">${acc?acc+'%':'<span style=\"font-style:italic\">—</span>'}</td>
      <td style="text-align:right;font-family:monospace;color:var(--muted)">${pp}</td>
      <td style="color:var(--muted);font-size:11px">${lcount||'—'}</td>
      <td style="font-size:10px;font-weight:700">${(()=>{if(['FR','LG'].includes(GAME))return'<span style=\'color:var(--muted);font-size:9px\'>RSE only</span>';const cc=CONTEST_CATS[name];if(!cc)return'<span style=\"color:var(--muted)\">—</span>';const cols={Cool:'#E8501A',Beautiful:'#1B8FE8',Cute:'#D070D0',Clever:'#3DA83D',Tough:'#9E9E9E'};const col=cols[cc]||'#888';return'<span style=\"background:'+col+'22;color:'+col+';border:1px solid '+col+'44;padding:1px 6px;border-radius:3px\">'+cc+'</span>';})()}</td>`;
    const dtr=document.createElement('tr');
    dtr.className='mdet-row'+(isOpen?' mopen':'');
    dtr.setAttribute('data-did',id);
    const dtd=document.createElement('td');
    dtd.colSpan=9;
    const dp=document.createElement('div');
    dp.className='mdet-panel';
    if (isOpen){dp.innerHTML=mdexBuildDetail(id,m);requestAnimationFrame(()=>dp.style.maxHeight=dp.scrollHeight+'px');}
    dtd.appendChild(dp);dtr.appendChild(dtd);
    tbody.appendChild(tr);tbody.appendChild(dtr);
  });
  const ce=document.getElementById('mdex-count');
  if (ce) ce.textContent=rows.length+' moves';
}

function mdexBuildDetail(id,m) {
  const [name,type,cat,power,acc,pp,desc]=m;
  const learners=MOVE_LEARNERS[name]||{};
  const entries=Object.entries(learners).sort((a,b)=>+a[0]-+b[0]);
  const tc=TYPE_COLORS_MD[type]||'#888';
  const pwrColor=power>=100?'#F08030':power>=60?'var(--text)':'var(--muted)';
  let chips='';
  if (!entries.length) {
    chips='<div style="font-size:11px;color:var(--muted);font-style:italic">No learners in this dex.</div>';
  } else {
    entries.forEach(([num,methods])=>{
      const p=POKE.find(x=>x.num===+num);
      const pname=p?p.name:'#'+num;
      const tags=methods.map(mt=>{
        const cls=mt.startsWith('Lv')||mt==='Base'?'lv':mt.startsWith('TM')?'tm':mt.startsWith('HM')?'hm':'egg';
        return `<span class="mmethod ${cls}">${mt}</span>`;
      }).join('');
      chips+=`<span class="mchip" onclick="event.stopPropagation();mdexGoTo(${num})"><img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/${num}.png" onerror="this.style.display='none'">${pname}${tags}</span>`;
    });
  }
  return `<div class="mdet-inner">
    <div class="mdet-desc">${desc}</div>
    <div>
      <div style="font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:0.5px;color:var(--muted);margin-bottom:8px">Move Stats</div>
      <div class="mdet-stat-row"><span class="mdet-stat-label">Type</span><span style="color:${tc};font-weight:800">${type}</span></div>
      <div class="mdet-stat-row"><span class="mdet-stat-label">Category</span><span style="font-weight:800">${cat}</span></div>
      <div class="mdet-stat-row"><span class="mdet-stat-label">Power</span><span style="color:${pwrColor};font-weight:800">${power||'—'}</span></div>
      <div class="mdet-stat-row"><span class="mdet-stat-label">Accuracy</span><span style="font-weight:800">${acc?acc+'%':'—'}</span></div>
      <div class="mdet-stat-row"><span class="mdet-stat-label">PP</span><span style="font-weight:800">${pp}</span></div>
    </div>
    <div>
      <div style="font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:0.5px;color:var(--muted);margin-bottom:8px">Learners (${entries.length})</div>
      <div class="mdet-learners-grid">${chips}</div>
    </div>
    ${(()=>{const td=TUTOR_NPC_DATA[name];if(!td)return'';const gl=td.games.map(g=>`<span style="font-family:'Press Start 2P',monospace;font-size:6px;padding:2px 6px;border-radius:2px;background:rgba(255,215,0,0.15);color:var(--gold);border:1px solid rgba(255,215,0,0.4)">${g}</span>`).join(' ');return`<div style="margin-top:12px;padding:10px 12px;background:rgba(100,180,255,0.06);border:1px solid rgba(100,180,255,0.25);border-radius:6px"><div style="font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:0.5px;color:#64b4ff;margin-bottom:6px">🎓 MOVE TUTOR ${gl}</div><div style="font-size:11px;color:var(--text);line-height:1.7">${td.npc}</div>${td.note?`<div style="font-size:10px;color:var(--muted);margin-top:3px">${td.note}</div>`:''}</div>`;})()}
    ${(()=>{
      const tmItem = ALL_ITEMS.find(function(it){ return it[2]==='TM/HM' && it[1].replace(/^(TM|HM)\d+\s*/,'')===name; });
      if (!tmItem) return '';
      const tmCode = tmItem[1].match(/^(TM|HM)\d+/)[0];
      const locs = tmItem[4] || {};
      const GAME_LABELS = {FR:'🔥 FireRed',LG:'🌿 LeafGreen',R:'🔴 Ruby',S:'🔷 Sapphire',E:'🟢 Emerald'};
      const GAME_COLORS = {FR:'var(--fire)',LG:'var(--leaf)',R:'#FF5555',S:'#5599FF',E:'var(--emerald)'};
      let rows = '';
      // If a specific game is selected, show only that game; otherwise show all
      const gamesToShow = (GAME && GAME !== 'all') ? [GAME] : ['FR','LG','R','S','E'];
      gamesToShow.forEach(function(g){
        const loc = locs[g];
        rows += `<div style="display:flex;gap:8px;align-items:baseline;font-size:11px;margin-bottom:4px;">
          <span style="font-family:'Press Start 2P',monospace;font-size:6px;color:${GAME_COLORS[g]};flex-shrink:0;width:60px">${GAME_LABELS[g].replace(/^\S+\s/,'')}</span>
          <span style="color:${loc ? 'var(--text)' : 'var(--muted)'};">${loc || 'Not available'}</span>
        </div>`;
      });
      return `<div style="margin-top:12px;padding:10px 12px;background:rgba(255,215,0,0.05);border:1px solid rgba(255,215,0,0.25);border-radius:6px">
        <div style="font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:0.5px;color:var(--gold);margin-bottom:8px">💿 ${tmCode} LOCATION</div>
        ${rows}
      </div>`;
    })()}
  </div>`;
}

function mdexToggle(id) {
  const tbody=document.getElementById('mdex-tbody');if(!tbody)return;
  const prev=MD_OPEN_ID;
  if (prev!==null) {
    const pr=tbody.querySelector(`tr.mrow[data-mid="${prev}"]`);
    const pd=tbody.querySelector(`tr.mdet-row[data-did="${prev}"]`);
    if(pr)pr.classList.remove('mopen');
    if(pd){pd.classList.remove('mopen');const pp=pd.querySelector('.mdet-panel');if(pp)pp.style.maxHeight='0';}
  }
  if (prev==id){MD_OPEN_ID=null;setPageHash('moves', null);return;}
  MD_OPEN_ID=id;
  const mv = MOVES_DATA[id];
  setPageHash('moves', { move: mv ? mv[1] : '', id: id });
  const r=tbody.querySelector(`tr.mrow[data-mid="${id}"]`);
  const d=tbody.querySelector(`tr.mdet-row[data-did="${id}"]`);
  if(r)r.classList.add('mopen');
  if(d){
    d.classList.add('mopen');
    const dp=d.querySelector('.mdet-panel');
    if(dp){
      if(!dp.dataset.rendered){const mv=MOVES_DATA[id];if(mv)dp.innerHTML=mdexBuildDetail(id,mv);dp.dataset.rendered='1';}
      requestAnimationFrame(()=>dp.style.maxHeight=dp.scrollHeight+'px');
    }
  }
}

function mdexGoTo(num) {
  SEARCH = '';
  var inp = document.getElementById('searchInput');
  if (inp) inp.value = '';
  openEvoNum = num;
  showPage('dex', document.getElementById('navDex'));
  setTimeout(function() {
    var r = document.getElementById('poke-row-' + num);
    var container = document.getElementById('tablePanel');
    if (!r || !container) return;
    if (openEvoNum !== num) toggleEvoRow(num);
    flashDexRow(num);
    var thead = container.querySelector('thead');
    var theadH = thead ? thead.getBoundingClientRect().height : 0;
    var rowTop = r.getBoundingClientRect().top;
    var containerTop = container.getBoundingClientRect().top;
    container.scrollTo({ top: container.scrollTop + (rowTop - containerTop) - theadH - 14, behavior: 'smooth' });
  }, 80);
}
function mdexSort(key) {if(MD_SORT_KEY===key)MD_SORT_DIR*=-1;else{MD_SORT_KEY=key;MD_SORT_DIR=1;}MD_OPEN_ID=null;mdexRender();}
function mdexSetType(type) {MD_TYPE_FILTER=MD_TYPE_FILTER===type?null:type;MD_OPEN_ID=null;document.querySelectorAll('.mdex-type-btn').forEach(b=>b.classList.toggle('active',b.dataset.type===MD_TYPE_FILTER));mdexRender();}
function mdexSetCat(cat) {MD_CAT_FILTER=MD_CAT_FILTER===cat?null:cat;MD_OPEN_ID=null;document.querySelectorAll('.mdex-cat-btn').forEach(b=>b.classList.toggle('active',MD_CAT_FILTER!==null&&b.textContent.includes(MD_CAT_FILTER)));mdexRender();}
function updateMdexClear(inp) {
  var btn = document.getElementById('mdexClear');
  if (btn) btn.classList.toggle('visible', inp.value.length > 0);
}
function clearMdexSearch() {
  var inp = document.getElementById('mdex-search');
  if (!inp) return;
  inp.value = '';
  MD_SEARCH = ''; MD_OPEN_ID = null; mdexRender();
  inp.focus();
  document.getElementById('mdexClear').classList.remove('visible');
}
function updateItClear(inp) {
  var btn = document.getElementById('itClear');
  if (btn) btn.classList.toggle('visible', inp.value.length > 0);
}
function clearItSearch() {
  var inp = document.getElementById('itSearch');
  if (!inp) return;
  inp.value = '';
  inp.dispatchEvent(new Event('input'));
  inp.focus();
  document.getElementById('itClear').classList.remove('visible');
}

function updateSearchClear(inp) {
  var btn = document.getElementById('searchClear');
  if (btn) btn.classList.toggle('visible', inp.value.length > 0);
}
function clearSearch() {
  var inp = document.getElementById('searchInput');
  if (!inp) return;
  inp.value = '';
  inp.dispatchEvent(new Event('input'));
  inp.focus();
}

// Generic clear-button helpers used by all search bars
function updateClearBtn(inp, btnId) {
  var btn = document.getElementById(btnId);
  if (btn) btn.classList.toggle('visible', inp.value.length > 0);
}
function clearInp(inpId, btnId, fn) {
  var inp = document.getElementById(inpId);
  if (!inp) return;
  inp.value = '';
  var btn = document.getElementById(btnId);
  if (btn) btn.classList.remove('visible');
  if (fn) fn();
  inp.focus();
}

function mdexSearch(val) {MD_SEARCH=val;MD_OPEN_ID=null;mdexRender();}
function mdexToggleTutor(btn) {
  MD_TUTOR_FILTER = !MD_TUTOR_FILTER;
  MD_OPEN_ID = null;
  btn.classList.toggle('active', MD_TUTOR_FILTER);
  mdexRender();
}
function mdexToggleTmhm(btn) {
  MD_TMHM_FILTER = !MD_TMHM_FILTER;
  MD_OPEN_ID = null;
  btn.classList.toggle('active', MD_TMHM_FILTER);
  mdexRender();
}
function mdexSetContest(cat, btn) {
  MD_CONTEST_FILTER = MD_CONTEST_FILTER===cat ? null : cat;
  MD_OPEN_ID=null;
  document.querySelectorAll('[id^="mc-"]').forEach(function(b){b.classList.remove('active');});
  if(MD_CONTEST_FILTER && btn) btn.classList.add('active');
  mdexRender();
}
function goToMoveInDex(moveName) {
  const btn = document.getElementById('navMoves');
  showPage('moves', btn);
  if (!window._movesBuilt) { buildMoveDex(); window._movesBuilt = true; }
  // Find the exact move ID by name
  const exactEntry = Object.entries(MOVES_DATA).find(([id, m]) => m[0].toLowerCase() === moveName.toLowerCase());
  const exactId = exactEntry ? exactEntry[0] : null;
  MD_SEARCH = moveName; MD_OPEN_ID = exactId ? Number(exactId) : null;
  const inp = document.getElementById('mdex-search');
  if (inp) { inp.value = moveName; updateMdexClear(inp); }
  mdexRender();
  // Scroll the already-open row into view
  if (exactId) {
    setTimeout(function() {
      var row = document.querySelector('#mdex-tbody tr.mrow[data-mid="' + exactId + '"]');
      if (row) row.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }, 80);
  }
}



