const EGG_GROUP_COLORS = {
  Monster:'#78A850',Grass:'#78C850',Bug:'#A8B820',Flying:'#6890F0',
  Water1:'#6890F0',Water2:'#6890F0',Water3:'#6890F0',Field:'#E0C068',
  Fairy:'#EE99AC',Humanshape:'#C03028',Amorphous:'#705898',Dragon:'#7038F8',
  Mineral:'#B8A038',Ditto:'#6890F0',Undiscovered:'#68A090',Unknown:'#888'
};

function renderEggPanel(num) {
  const groups = EGG_GROUPS_DATA[num] || ['Unknown'];
  const isUndiscovered = groups.includes('Undiscovered');
  const isDitto = groups.includes('Ditto');

  let html = '<div class="egg-panel"><div class="egg-panel-title">Breeding</div>';

  // Egg group badges
  html += '<div class="egg-group-row">';
  groups.forEach(g => {
    const cls = g === 'Undiscovered' ? 'undiscovered' : g === 'Ditto' ? 'ditto' : '';
    html += `<span class="egg-group-badge ${cls}">🥚 ${g}</span>`;
  });
  html += '</div>';

  if (isUndiscovered) {
    html += '<div style="font-size:11px;color:var(--muted);font-style:italic">Cannot breed — no egg can be obtained.</div>';
    html += '</div>';
    return html;
  }

  // Compatible partners
  // Ditto can breed with everything except Undiscovered
  let compat = [];
  if (isDitto) {
    compat = POKE.filter(p => {
      const pg = EGG_GROUPS_DATA[p.num] || ['Unknown'];
      return !pg.includes('Undiscovered') && !pg.includes('Ditto');
    });
  } else {
    compat = POKE.filter(p => {
      if (p.num === num) return false;
      const pg = EGG_GROUPS_DATA[p.num] || ['Unknown'];
      if (pg.includes('Undiscovered')) return false;
      if (pg.includes('Ditto')) return true; // Ditto always compatible
      // Share at least one egg group
      return groups.some(g => pg.includes(g));
    });
  }

  // Deduplicate to base forms only (show lowest num in each evo chain)
  const seen = new Set();
  const baseCompat = compat.filter(p => {
    const chain = getEvoChain(p.num);
    const base = Math.min(...chain);
    if (seen.has(base)) return false;
    seen.add(base);
    return true;
  });

  html += `<div class="egg-compat-title">Compatible partners (${baseCompat.length})</div>`;
  html += '<div class="egg-compat-grid">';
  baseCompat.forEach(p => {
    html += `<span class="egg-compat-chip" onclick="filterByPoke(${p.num})" title="${p.name}">
      <img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/${p.num}.png" onerror="this.style.display='none'">
      ${p.name}
    </span>`;
  });
  html += '</div>';
  html += '</div>';
  return html;
}


