const STAT_LABELS = ['HP','Atk','Def','SpAtk','SpDef','Speed'];
const STAT_COLORS = [
  '#4CAF50',  // HP     - green
  '#FF6B35',  // Atk    - fire orange
  '#7986CB',  // Def    - blue-grey
  '#AB47BC',  // SpAtk  - purple
  '#26C6DA',  // SpDef  - cyan
  '#FFD700',  // Speed  - gold
];

function statBarColor(val) {
  if (val >= 150) return '#e040fb';
  if (val >= 110) return '#4CAF50';
  if (val >= 80)  return '#8BC34A';
  if (val >= 60)  return '#FFC107';
  if (val >= 40)  return '#FF9800';
  return '#F44336';
}

function renderStatsPanel(num) {
  const stats = BASE_STATS[num];
  if (!stats) return '';
  const total = stats.reduce((a, b) => a + b, 0);
  const maxStat = 255; // HP cap

  function _statTier(v) {
    if (v >= 140) return ['GODLIKE','st-godlike'];
    if (v >= 100) return ['GREAT','st-great'];
    if (v >= 60)  return ['AVERAGE','st-average'];
    if (v >= 35)  return ['BAD','st-bad'];
    return ['WEAK','st-weak'];
  }
  let html = '<div class="stats-panel"><div class="stats-title">BASE STATS</div>';
  stats.forEach((val, i) => {
    const pct = Math.round((val / maxStat) * 100);
    const col = STAT_COLORS[i];
    const barCol = statBarColor(val);
    const valCol = val >= 110 ? '#4CAF50' : val <= 40 ? '#F44336' : 'var(--text)';
    const [tierLabel, tierClass] = _statTier(val);
    html += `<div class="stat-row">
      <div class="stat-label" style="color:${col}">${STAT_LABELS[i]}</div>
      <div class="stat-bar-wrap">
        <div class="stat-bar" style="--bar-w:${pct}%;--bar-delay:${i * 0.08}s;background:${barCol}"></div>
      </div>
      <div class="stat-val" style="color:${valCol}">${val}</div>
      <div class="stat-tier ${tierClass}">${tierLabel}</div>
    </div>`;
  });
  html += `<div class="stat-total-row">
    <div class="stat-total-label">TOTAL</div>
    <div class="stat-total-val">${total}</div>
  </div>`;
  html += '</div>';
  return html;
}




// ═══════════════════════════════════════════════════════════════
//  META PANEL (catch rate, friendship, gender, height, weight, held items, trades)
// ═══════════════════════════════════════════════════════════════
function renderMetaPanel(num) {
  const m = POKE_META[num];
  if (!m) return '';

  // Catch rate visual: colour based on difficulty
  const crColour = m.cr >= 200 ? '#4CAF50' : m.cr >= 100 ? '#FFC107' : m.cr >= 30 ? '#FF9800' : '#F44336';
  const crLabel = m.cr >= 200 ? 'Common' : m.cr >= 100 ? 'Uncommon' : m.cr >= 30 ? 'Rare' : 'Very Rare';

  let html = '<div class="meta-panel">';
  html += '<div class="meta-panel-title">DETAILS</div>';
  html += '<div class="meta-grid">';

  // Catch Rate
  html += `<div class="meta-item">
    <div class="meta-label">Catch Rate</div>
    <div class="meta-value"><span style="color:${crColour};font-weight:700">${m.cr}</span>
      <span style="font-size:10px;color:var(--muted);margin-left:4px">(${crLabel})</span></div>
  </div>`;

  // Base Friendship
  html += `<div class="meta-item">
    <div class="meta-label">Base Friendship</div>
    <div class="meta-value">${m.fr}</div>
  </div>`;

  // Gender
  html += `<div class="meta-item">
    <div class="meta-label">Gender</div>
    <div class="meta-value">${m.gr}</div>
  </div>`;

  // Height & Weight
  html += `<div class="meta-item">
    <div class="meta-label">Height</div>
    <div class="meta-value">${m.ht}</div>
  </div>`;
  html += `<div class="meta-item">
    <div class="meta-label">Weight</div>
    <div class="meta-value">${m.wt}</div>
  </div>`;

  html += '</div>'; // meta-grid

  // Held Items
  if (m.held && m.held.length > 0) {
    html += '<div class="meta-section-title">Wild Held Items</div>';
    html += '<div class="meta-held-list">';
    m.held.forEach((item, i) => {
      const chance = i === 0 ? '50%' : '5%';
      html += `<span class="meta-held-chip">${itemSprite(item,16)}<span class="meta-held-chance">${chance}</span> ${item}</span>`;
    });
    html += '</div>';
  }

  // In-Game Trades
  const tradeGames = Object.keys(m.trades || {});
  if (tradeGames.length > 0) {
    html += '<div class="meta-section-title">In-Game Trades</div>';
    html += '<div class="meta-trade-list">';
    tradeGames.forEach(game => {
      const badgeClass = {FR:'active-fr',LG:'active-lg',R:'active-r',S:'active-s',E:'active-e'}[game] || '';
      html += `<div class="meta-trade-row">
        <span class="gbadge ${badgeClass}" style="font-size:8px;padding:2px 5px">${game}</span>
        <span style="font-size:11px">${m.trades[game]}</span>
      </div>`;
    });
    html += '</div>';
  }

  html += '</div>'; // meta-panel
  return html;
}

