function getEvoMethod(fromNum, toNum) {
  return EVO_METHODS[fromNum + ':' + toNum] || EVO_METHODS[toNum + ':' + fromNum] || '?';
}

// Build a structured evolution tree for a pokemon number
// Returns array of stages: [{num, branches:[{num, branches:[...]}]}]
// Simple linear/branching structure
function buildEvoTree(rootNum) {
  // For branched evolutions (Eevee, Slowpoke, etc.) we need special handling
  // EVO_CHAIN gives us the flat list — we figure out structure from EVO_METHODS keys

  const chainNums = getEvoChain(rootNum);
  if (chainNums.length <= 1) return null; // no evolution

  // Find the base (first in chain by dex number, but respect actual chain order)
  // Detect branching: if multiple chain members share the same predecessor
  const children = {}; // parent -> [children]
  chainNums.forEach(n => {
    chainNums.forEach(m => {
      if (n !== m && (EVO_METHODS[n+':'+m] || EVO_METHODS[m+':'+n])) {
        // Check direction: lower dex is typically the base EXCEPT for baby pokemon
        const key = n + ':' + m;
        if (EVO_METHODS[key]) {
          if (!children[n]) children[n] = [];
          if (!children[n].includes(m)) children[n].push(m);
        }
      }
    });
  });

  // Find root (node with no parent in chain)
  const allChildren = Object.values(children).flat();
  const roots = chainNums.filter(n => !allChildren.includes(n));
  const root = roots.length ? roots[0] : chainNums[0];

  function buildNode(num) {
    return {
      num: num,
      children: (children[num] || []).map(c => ({ num: c, method: getEvoMethod(num, c), children: (children[c]||[]).map(gc => ({num:gc, method:getEvoMethod(c,gc), children:[]})) }))
    };
  }

  return buildNode(root);
}

function renderEvoChain(p) {
  const tree = buildEvoTree(p.num);
  if (!tree) return '<div style="color:var(--muted);font-size:11px;padding:8px">No evolution</div>';

  function nodeHTML(nodeNum, currentNum) {
    const isCurrent = nodeNum === currentNum;
    const pData = POKE.find(x => x.num === nodeNum);
    const name = pData ? pData.name : '#' + nodeNum;
    const safeName = name.replace(/'/g, "\\'");
    const evoSpriteBase = 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + (window._shinyMode ? 'shiny/' : '');
    return `<div class="evo-node${isCurrent?' current':''}" onclick="event.stopPropagation();guideDex('${safeName}')">
      <img src="${evoSpriteBase}${nodeNum}.png" alt="${name}" onerror="this.style.opacity=0.2">
      <div class="evo-node-name">${name}</div>
      <div class="evo-node-num">#${String(nodeNum).padStart(3,'0')}</div>
    </div>`;
  }

  function arrowHTML(method) {
    return `<div class="evo-arrow"><div class="evo-arrow-line">→</div><div class="evo-arrow-method">${method}</div></div>`;
  }

  function renderNode(node, currentNum) {
    let html = nodeHTML(node.num, currentNum);
    if (node.children.length === 1) {
      // Linear
      html += arrowHTML(node.children[0].method);
      html += renderNode(node.children[0], currentNum);
    } else if (node.children.length > 1) {
      // Branching — show arrow then a vertical stack of options
      html += arrowHTML('');
      html += '<div class="evo-branch">';
      node.children.forEach(child => {
        html += '<div style="display:flex;align-items:center">';
        html += `<div class="evo-arrow-method" style="min-width:64px;text-align:center;font-size:8px;color:var(--gold)">${child.method}</div>`;
        html += renderNode(child, currentNum);
        html += '</div>';
      });
      html += '</div>';
    }
    return html;
  }

  return `<div class="evo-panel-inner">${renderNode(tree, p.num)}</div>`;
}

function filterByPoke(num) {
  const p = POKE.find(x => x.num === num);
  if (!p) return;
  document.getElementById('searchInput').value = p.name;
  SEARCH = p.name;
  buildTable();
}

// Track currently open evo row
var openEvoNum = null;

// Navigate to Pokédex, find Pokémon by name, scroll to it and open its detail panel
function guideDex(name) {
  var p = POKE.find(function(pk) { return pk.name === name; });
  if (!p) return;
  var num = p.num;

  // Clear search and pre-set openEvoNum BEFORE buildTable() runs so it
  // reopens the correct Pokémon rather than whatever was previously open.
  SEARCH = '';
  var inp = document.getElementById('searchInput');
  if (inp) inp.value = '';
  openEvoNum = num;

  // If the Pokémon has no data in the current game, switch to All Games
  var gameData = p.games[GAME];
  if (GAME !== 'all' && (!gameData || gameData === 'nan')) {
    GAME = 'all';
    SORT_KEY = null; SORT_DIR = 1;
    syncHeaderBadges('all');
    var allTab = document.querySelector('.game-tab.active-all, .game-tab[onclick*="\'all\'"]');
    if (allTab) { document.querySelectorAll('.game-tab').forEach(function(b){ b.className='game-tab'; }); allTab.className='game-tab active-all'; }
  }

  // Switch to Pokédex page — showPage calls buildTable() internally
  showPage('dex', document.getElementById('navDex'));

  setTimeout(function() {
    var pokeRow = document.getElementById('poke-row-' + num);
    if (pokeRow) {
      if (openEvoNum !== num) toggleEvoRow(num);
      flashDexRow(num);
      // Scroll the tablePanel so the poke-row sits at the very top
      var panel = document.getElementById('tablePanel');
      if (panel) {
        var stickyHeader = panel.querySelector('.section-header');
        var stickyH = stickyHeader ? stickyHeader.offsetHeight : 0;
        var panelTop = panel.getBoundingClientRect().top;
        var rowTop = pokeRow.getBoundingClientRect().top;
        panel.scrollTop = panel.scrollTop + (rowTop - panelTop) - stickyH;
      } else {
        pokeRow.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }
    }
  }, 80);
}

function toggleEvoRow(num) {
  const chainRow = document.getElementById('evo-row-' + num);
  const pokeRow = document.getElementById('poke-row-' + num);
  if (!chainRow || !pokeRow) return;
  const reduceMotion = !!(window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches);

  function stopPanelAnimation(panel) {
    if (!panel) return;
    if (panel._evoTimer) {
      clearTimeout(panel._evoTimer);
      panel._evoTimer = null;
    }
    if (panel._evoDone) {
      panel.removeEventListener('transitionend', panel._evoDone);
      panel._evoDone = null;
    }
  }

  function closePanel(row, panel) {
    if (!row || !panel) return;
    stopPanelAnimation(panel);
    if (reduceMotion) {
      row.classList.remove('open');
      panel.style.height = '0px';
      return;
    }
    var current = panel.scrollHeight;
    panel.style.height = current + 'px';
    panel.offsetHeight;
    row.classList.remove('open');
    requestAnimationFrame(function() {
      panel.style.height = '0px';
    });
  }

  function openPanel(row, panel) {
    if (!row || !panel) return;
    stopPanelAnimation(panel);
    if (reduceMotion) {
      row.classList.add('open');
      panel.style.height = 'auto';
      return;
    }
    row.classList.add('open');
    panel.style.height = '0px';
    panel.offsetHeight;
    var target = panel.scrollHeight;
    panel.style.height = target + 'px';
    panel._evoDone = function(ev) {
      if (ev.propertyName !== 'height') return;
      panel.style.height = 'auto';
      panel.removeEventListener('transitionend', panel._evoDone);
      panel._evoDone = null;
    };
    panel.addEventListener('transitionend', panel._evoDone);
    panel._evoTimer = setTimeout(function() {
      if (panel._evoDone) {
        panel.style.height = 'auto';
        panel.removeEventListener('transitionend', panel._evoDone);
        panel._evoDone = null;
      }
      panel._evoTimer = null;
    }, 420);
  }

  if (openEvoNum === num) {
    // Close
    closePanel(chainRow, chainRow.querySelector('.evo-panel'));
    pokeRow.classList.remove('evo-open');
    openEvoNum = null;
    setPageHash('dex', SEARCH ? { q: SEARCH } : null);
  } else {
    // Close previous
    if (openEvoNum !== null) {
      const prevChain = document.getElementById('evo-row-' + openEvoNum);
      const prevPoke = document.getElementById('poke-row-' + openEvoNum);
      if (prevChain) closePanel(prevChain, prevChain.querySelector('.evo-panel'));
      if (prevPoke) prevPoke.classList.remove('evo-open');
    }
    // Open this one — lazy render content
    const panel = chainRow.querySelector('.evo-panel');
    if (panel && !panel.dataset.rendered) {
      const p = POKE.find(x => x.num === num);
      if (p) {
        const evoHTML = getEvoChain(num).length > 1 ? renderEvoChain(p) : '';
        panel.innerHTML = evoHTML + renderStatsPanel(num) + renderMetaPanel(num) + renderAbilitiesPanel(num) + renderMovesPanel(num) + renderEggPanel(num) + renderContestPanel(num);
      }
      panel.dataset.rendered = '1';
    }
    openPanel(chainRow, panel);
    // Reset stat-bar scan animations so they play every time the panel opens
    var statBars = panel ? panel.querySelectorAll('.stat-bar') : [];
    statBars.forEach(function(bar) {
      bar.style.animation = 'none';
      bar.getBoundingClientRect(); // force reflow
      bar.style.animation = '';
    });
    pokeRow.classList.add('evo-open');
    openEvoNum = num;
    setPageHash('dex', { pokemon: num });
  }
}


