let selectedAttackType = null;
let selectedDefendTypes = [];
let typePanelOpen = false;

function buildTypePanel() {
  const body = document.getElementById('typePanelBody');

  // Mode tabs
  let html = '<div style="display:flex;gap:0;margin-bottom:16px;border-bottom:2px solid var(--border)">'
    + '<button class="type-mode-btn active" id="tmb-full" onclick="setTypeMode(\'full\',this)" style="font-size:10px;font-weight:800;padding:8px 14px;background:transparent;border:none;color:var(--fire);cursor:pointer;border-bottom:2px solid var(--fire);margin-bottom:-2px;letter-spacing:0.5px">FULL CHART</button>'
    + '<button class="type-mode-btn" id="tmb-lookup" onclick="setTypeMode(\'lookup\',this)" style="font-size:10px;font-weight:800;padding:8px 14px;background:transparent;border:none;color:var(--muted);cursor:pointer;border-bottom:2px solid transparent;margin-bottom:-2px;letter-spacing:0.5px">LOOKUP</button>'
    + '</div>';

  // Full chart view
  html += '<div id="tc-full">';
  html += '<p style="font-size:11px;color:var(--muted);margin-bottom:10px">Rows = Attacking type · Columns = Defending type</p>';
  html += buildFullChart();
  html += '</div>';

  // Lookup view (hidden by default)
  html += '<div id="tc-lookup" style="display:none">';
  html += buildLookupView();
  html += '</div>';

  body.innerHTML = html;
}

function setTypeMode(mode, btn) {
  document.querySelectorAll('.type-mode-btn').forEach(b => {
    b.style.color = 'var(--muted)';
    b.style.borderBottomColor = 'transparent';
  });
  btn.style.color = 'var(--fire)';
  btn.style.borderBottomColor = 'var(--fire)';
  document.getElementById('tc-full').style.display = mode === 'full' ? 'block' : 'none';
  document.getElementById('tc-lookup').style.display = mode === 'lookup' ? 'block' : 'none';
}

function buildFullChart() {
  const abbr = {normal:'NOR',fire:'FIR',water:'WAT',electric:'ELE',grass:'GRS',ice:'ICE',fighting:'FGT',poison:'PSN',ground:'GRD',flying:'FLY',psychic:'PSY',bug:'BUG',rock:'ROC',ghost:'GHO',dragon:'DRG',dark:'DRK',steel:'STL'};

  let t = '<div style="overflow-x:auto"><table class="tc-table"><thead><tr>'
    + '<th class="row-head" style="font-size:9px;color:var(--game-color,var(--gold))">ATK ↓ / DEF →</th>';

  TYPES.forEach(dt => {
    const id = TYPE_ICON_IDS[dt];
    let colContent;
    if (id) {
      colContent = `<div style="position:relative;width:32px;height:88px;overflow:visible;margin:0 auto">`
        + `<img src="${TYPE_ICON_BASE}${id}.png" alt="${dt}" title="${dt.charAt(0).toUpperCase()+dt.slice(1)}" height="22"`
        + ` style="position:absolute;top:50%;left:50%;transform:translate(-50%,-50%) rotate(-90deg);image-rendering:pixelated;"`
        + ` onerror="_typeFB(this,'${dt}')"></div>`;
    } else {
      const c = TYPE_COLORS[dt]; const txtc = ['electric','ice','normal','ground'].includes(dt)?'#222':'#fff';
      colContent = `<span style="writing-mode:vertical-rl;font-size:8px;background:${c};color:${txtc};padding:2px 4px">${abbr[dt]}</span>`;
    }
    t += `<th class="col-head" style="height:92px;vertical-align:middle">${colContent}</th>`;
  });
  t += '</tr></thead><tbody>';

  TYPES.forEach(atk => {
    t += `<tr><th class="row-head" style="position:sticky;left:0">${typeSprite(atk)}</th>`;
    TYPES.forEach(def => {
      const mult = TYPE_CHART[atk][def];
      let cls = 'tc-cell-1', label = '1';
      if (mult === 2)   { cls = 'tc-cell-2';  label = '2'; }
      if (mult === 0.5) { cls = 'tc-cell-05'; label = '½'; }
      if (mult === 0)   { cls = 'tc-cell-0';  label = '0'; }
      t += `<td class="${cls}" title="${atk} → ${def}: ×${mult}">${label}</td>`;
    });
    t += '</tr>';
  });

  t += '</tbody></table></div>';
  t += '<div style="display:flex;gap:16px;margin-top:10px;font-size:10px">'
    + '<span><span style="background:#4a9e40;color:#fff;padding:1px 6px;border-radius:3px">2</span> Super effective</span>'
    + '<span><span style="background:#9e3a3a;color:#fff;padding:1px 6px;border-radius:3px">½</span> Not very effective</span>'
    + '<span><span style="background:#222;color:#666;padding:1px 6px;border-radius:3px">0</span> No effect</span>'
    + '</div>';
  return t;
}

function buildLookupView() {
  let html = '<p style="font-size:11px;color:var(--muted);margin-bottom:12px">Select one or two defending types to see full matchup breakdown:</p>';

  // Defending type selector (pick 1 or 2)
  html += '<div style="margin-bottom:6px;font-size:10px;font-weight:800;color:var(--muted)">DEFENDING TYPE(S):</div>';
  html += '<div class="type-selector" id="defTypeSelector">';
  TYPES.forEach(t => {
    html += `<button class="type-sel-btn" data-type="${t}" onclick="toggleDefType('${t}',this)">${typeSprite(t)}</button>`;
  });
  html += '</div>';

  html += '<div id="tcLookupResult" style="margin-top:16px"><div style="color:var(--muted);font-size:12px;font-style:italic">Select a type above to see its weaknesses and resistances.</div></div>';
  return html;
}

function toggleDefType(type, btn) {
  const idx = selectedDefendTypes.indexOf(type);
  if (idx >= 0) {
    selectedDefendTypes.splice(idx, 1);
    btn.classList.remove('active');
  } else {
    if (selectedDefendTypes.length >= 2) {
      // Deselect the oldest
      const old = selectedDefendTypes.shift();
      const oldBtn = document.querySelector(`.type-sel-btn[data-type="${old}"]`);
      if (oldBtn) oldBtn.classList.remove('active');
    }
    selectedDefendTypes.push(type);
    btn.classList.add('active');
  }
  renderLookupResult();
}

function renderLookupResult() {
  const el = document.getElementById('tcLookupResult');
  if (!el) return;
  if (selectedDefendTypes.length === 0) {
    el.innerHTML = '<div style="color:var(--muted);font-size:12px;font-style:italic">Select a type above to see its weaknesses and resistances.</div>';
    return;
  }

  const types = selectedDefendTypes;
  const label = types.map(t => typeSprite(t)).join(' + ');

  // Calculate combined effectiveness for each attacking type
  const results = {4:[], 2:[], 1:[], 0.5:[], 0.25:[], 0:[]};
  TYPES.forEach(atk => {
    let mult = 1;
    types.forEach(def => { mult *= TYPE_CHART[atk][def]; });
    const key = mult === 4 ? 4 : mult === 2 ? 2 : mult === 1 ? 1 : mult === 0.5 ? 0.5 : mult === 0.25 ? 0.25 : 0;
    results[key].push(atk);
  });

  function typeBadges(arr) {
    return arr.map(t => typeSprite(t)).join('');
  }

  let html = `<div class="tc-lookup"><div style="display:flex;align-items:center;gap:8px;margin-bottom:14px">`
    + '<span style="font-family:monospace;font-size:9px;font-weight:800;color:var(--muted)">DEFENDING:</span>'
    + `<span>${label}</span>`
    + `</div>`;

  const groups = [
    {key:4,   label:'4× Weak',           color:'#c00'},
    {key:2,   label:'2× Weak',           color:'#e84040'},
    {key:0.5, label:'½× Resists',        color:'#3a9e60'},
    {key:0.25,label:'¼× Strongly resists',color:'#2a7a50'},
    {key:0,   label:'0× Immune',         color:'#666'},
  ];

  groups.forEach(g => {
    if (results[g.key] && results[g.key].length > 0) {
      html += `<div class="tc-group"><div class="tc-group-label" style="color:${g.color}">${g.label}</div>`
        + `<div class="tc-badges">${typeBadges(results[g.key])}</div></div>`;
    }
  });

  if (results[1].length > 0) {
    html += `<div class="tc-group"><div class="tc-group-label">1× Normal</div>`
      + `<div class="tc-badges">${typeBadges(results[1])}</div></div>`;
  }

  html += '</div>';
  el.innerHTML = html;
}

