function closeExtMap(){} // stub — slide-out removed; called by jumpToDex

// ── VERSION EXCLUSIVES ──
var EXCL_MODE = 'RS';

function setExclMode(mode, btn) {
  EXCL_MODE = mode;
  document.querySelectorAll('.excl-mode-btn').forEach(function(b) { b.classList.remove('active'); });
  btn.classList.add('active');
  buildExcl();
}

function buildExcl() {
  var body = document.getElementById('exclBody');
  var leftPoke, rightPoke, leftTitle, rightTitle, lCol, rCol;

  if (EXCL_MODE === 'RS') {
    leftPoke  = POKE.filter(function(p){ return p.games.R && !p.games.S; });
    rightPoke = POKE.filter(function(p){ return p.games.S && !p.games.R; });
    leftTitle = '&#x1F534; RUBY ONLY'; rightTitle = '&#x1F535; SAPPHIRE ONLY';
    lCol = '#FF5555'; rCol = '#5599FF';
  } else if (EXCL_MODE === 'RE') {
    leftPoke  = POKE.filter(function(p){ return p.games.R && !p.games.E; });
    rightPoke = POKE.filter(function(p){ return p.games.E && !p.games.R; });
    leftTitle = '&#x1F534; RUBY ONLY'; rightTitle = '&#x1F7E2; EMERALD ONLY';
    lCol = '#FF5555'; rCol = '#44DD88';
  } else if (EXCL_MODE === 'SE') {
    leftPoke  = POKE.filter(function(p){ return p.games.S && !p.games.E; });
    rightPoke = POKE.filter(function(p){ return p.games.E && !p.games.S; });
    leftTitle = '&#x1F535; SAPPHIRE ONLY'; rightTitle = '&#x1F7E2; EMERALD ONLY';
    lCol = '#5599FF'; rCol = '#44DD88';
  } else if (EXCL_MODE === 'FR_LG') {
    leftPoke  = POKE.filter(function(p){ return p.games.FR && !p.games.LG; });
    rightPoke = POKE.filter(function(p){ return p.games.LG && !p.games.FR; });
    leftTitle = '&#x1F525; FIRERED ONLY'; rightTitle = '&#x1F343; LEAFGREEN ONLY';
    lCol = '#FF6B35'; rCol = '#4CAF50';
  } else {
    leftPoke  = POKE.filter(function(p){ return p.games.E && !p.games.R && !p.games.S; });
    body.style.gridTemplateColumns = '1fr';
    body.innerHTML = '<div class="excl-col">'
      + '<div class="excl-col-header"><h3 style="color:#44DD88">&#x1F7E2; EMERALD EXCLUSIVE (' + leftPoke.length + ')</h3><div class="excl-cnt">Not in Ruby or Sapphire</div></div>'
      + '<div class="excl-list">' + leftPoke.map(function(p){ return exclCard(p,'E'); }).join('') + '</div>'
      + '</div>';
    return;
  }

  body.style.gridTemplateColumns = '1fr 1fr';
  var leftGame = (EXCL_MODE === 'FR_LG') ? 'FR' : EXCL_MODE[0];
  var rightGame = (EXCL_MODE === 'FR_LG') ? 'LG' : EXCL_MODE[1];
  body.innerHTML =
    '<div class="excl-col">'
    + '<div class="excl-col-header"><h3 style="color:' + lCol + '">' + leftTitle + '</h3><div class="excl-cnt">' + leftPoke.length + ' Pokemon</div></div>'
    + '<div class="excl-list">' + leftPoke.map(function(p){ return exclCard(p, leftGame); }).join('') + '</div>'
    + '</div>'
    + '<div class="excl-col">'
    + '<div class="excl-col-header"><h3 style="color:' + rCol + '">' + rightTitle + '</h3><div class="excl-cnt">' + rightPoke.length + ' Pokemon</div></div>'
    + '<div class="excl-list">' + rightPoke.map(function(p){ return exclCard(p, rightGame); }).join('') + '</div>'
    + '</div>';
}

function exclCard(p, game) {
  var raw = p.games[game] || '';
  var line = raw.split('\n')[0] || '\u2014';
  var typeHtml = typeBadges(p.types);
  var nameEsc = p.name.replace(/'/g, "\\'");
  return '<div class="excl-card">'
    + '<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + p.num + '.png" loading="lazy" width="32" height="32" style="image-rendering:pixelated;cursor:pointer;" onclick="guideDex(\'' + nameEsc + '\')">'
    + '<div>'
    + '<div class="excl-pnum">#' + String(p.num).padStart(3,'0') + ' ' + typeHtml + '</div>'
    + '<div class="excl-pname guide-poke-link" onclick="guideDex(\'' + nameEsc + '\')" style="cursor:pointer;">' + p.name + '</div>'
    + '<div class="excl-method">' + line + '</div>'
    + '</div>'
    + '</div>';
}

// ══ TEAM BUILDER ══════════════════════════════════════════════
var TB_TEAM = [];
var TB_GAME = 'all';
var TB_GAME_COLORS = {all:'var(--gold)',FR:'var(--fire)',LG:'var(--leaf)',R:'#FF5555',S:'#5599FF',E:'#44DD88'};
function tbUpdateTitleColor(g) {
  var t = document.getElementById('tb-page-title');
  if (t) t.style.setProperty('color', TB_GAME_COLORS[g] || 'var(--gold)');
}

function tbPersist() {
  try { localStorage.setItem('gen3-tb-team', JSON.stringify(TB_TEAM)); } catch(e) {}
  try { localStorage.setItem('gen3-tb-game', TB_GAME); } catch(e) {}
}
function tbRestore() {
  try {
    var t = localStorage.getItem('gen3-tb-team');
    if (t) TB_TEAM = JSON.parse(t).filter(function(n){ return typeof n === 'number'; });
  } catch(e) {}
  try {
    var g = localStorage.getItem('gen3-tb-game');
    if (g) TB_GAME = g;
  } catch(e) {}
}
tbRestore();
var TB_TYPES = ['normal','fire','water','electric','grass','ice','fighting','poison','ground','flying','psychic','bug','rock','ghost','dragon','dark','steel'];
var TB_COLORS = {
  normal:'#9E9E9E',fire:'#E8501A',water:'#1B8FE8',grass:'#3DA83D',electric:'#D4A800',
  ice:'#60C8C8',fighting:'#B83020',poison:'#8B3099',ground:'#8B6840',flying:'#6850C0',
  psychic:'#D01868',bug:'#78A810',rock:'#807840',ghost:'#4030A0',dragon:'#5038E8',
  dark:'#403030',steel:'#9898A8'
};
var TB_LIGHT_TEXT = {electric:1, ice:1, steel:0};

function tbTypeColor(t) { return TB_COLORS[t] || '#666'; }
function tbTypeText(t) { return TB_LIGHT_TEXT[t] ? '#000' : '#fff'; }

function tbTypePill(t) {
  return typeSprite(t.toLowerCase());
}

// ── game filter ──────────────────────────────────────────────
function tbSetGame(g, btn) {
  TB_GAME = g;
  document.querySelectorAll('.tb-game-btn').forEach(function(b){ b.className='tb-game-btn'; });
  btn.className = 'tb-game-btn active-' + g.toLowerCase();
  tbUpdateTitleColor(g);
  tbPersist();
  tbRenderSlots();
  tbRenderAnalysis();
}

function tbClear() {
  TB_TEAM = [];
  tbPersist();
  tbRenderSlots();
  tbRenderAnalysis();
}

// ── availability ─────────────────────────────────────────────
function tbAvail(num) {
  if (TB_GAME === 'all') return 'ok';
  var p = POKE.find(function(x){ return x.num===num; });
  if (!p) return 'na';
  var loc = (p.games[TB_GAME] || '').trim().toLowerCase();
  if (!loc) return 'na';
  // pure trade: only method is trade
  if (/^trade\b/.test(loc)) return 'trade';
  return 'ok';
}

// ── search / add ─────────────────────────────────────────────
function tbSearch(val) {
  var dd = document.getElementById('tb-dropdown');
  if (!val) { dd.style.display='none'; return; }
  var q = val.toLowerCase();
  var hits = POKE.filter(function(p){
    return p.name.toLowerCase().indexOf(q)!== -1 || String(p.num).indexOf(q)!== -1;
  }).slice(0,14);
  if (!hits.length) { dd.style.display='none'; return; }
  dd.innerHTML = hits.map(function(p){
    var on = TB_TEAM.indexOf(p.num)!==-1;
    var full = TB_TEAM.length>=6 && !on;
    var av = tbAvail(p.num);
    var pill = av==='na' ? '<span class="tb-avail-pill tb-avail-na">N/A</span>'
             : av==='trade' ? '<span class="tb-avail-pill tb-avail-trade">TRADE</span>' : '';
    return '<div class="tb-dropdown-item'+(on||full?' disabled':'')+'" onclick="tbAdd('+p.num+')">'
      +'<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/'+p.num+'.png" width="26" height="26" style="image-rendering:pixelated">'
      +'<span style="flex:1;font-size:12px;font-weight:700">'+p.name+'</span>'
      +(on?'<span style="font-size:9px;color:var(--muted)">on team</span>':pill)
      +'</div>';
  }).join('');
  dd.style.display = 'block';
}

function tbAdd(num) {
  if (TB_TEAM.indexOf(num)!==-1 || TB_TEAM.length>=6) return;
  TB_TEAM.push(num);
  tbPersist();
  document.getElementById('tb-search').value='';
  document.getElementById('tb-dropdown').style.display='none';
  tbRenderSlots();
  tbRenderAnalysis();
}

function tbRemove(num) {
  TB_TEAM = TB_TEAM.filter(function(n){ return n!==num; });
  tbPersist();
  tbRenderSlots();
  tbRenderAnalysis();
}

// ── slots ─────────────────────────────────────────────────────
function tbRenderSlots() {
  var hint = document.getElementById('tb-hint');
  var el = document.getElementById('tb-slots');
  if (!TB_TEAM.length) { el.innerHTML=''; hint.style.display='block'; return; }
  hint.style.display='none';
  el.innerHTML = TB_TEAM.map(function(num){
    var p = POKE.find(function(x){ return x.num===num; });
    if (!p) return '';
    var av = tbAvail(num);
    var bs = BASE_STATS[num]||[0,0,0,0,0,0];
    var ab = ABILITIES_DATA[num];
    var abStr = ab ? ab.a1+(ab.a2?' / '+ab.a2:'') : '';
    var cls = av==='na'?'tb-slot-card unavail':av==='trade'?'tb-slot-card trade':'tb-slot-card';
    var badge = av==='na'
      ? '<div><span class="tb-avail-pill tb-avail-na">⚠ Not in '+TB_GAME+'</span></div>'
      : av==='trade'
      ? '<div><span class="tb-avail-pill tb-avail-trade">🔄 Trade required</span></div>' : '';
    return '<div class="'+cls+'">'
      +'<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/'+num+'.png" width="38" height="38" style="image-rendering:pixelated;flex-shrink:0">'
      +'<div style="flex:1;min-width:0">'
      +'<div style="font-size:12px;font-weight:800;margin-bottom:3px">'+p.name+'</div>'
      +'<div style="display:flex;gap:3px;flex-wrap:wrap;margin-bottom:3px">'+p.types.map(tbTypePill).join('')+'</div>'
      +'<div style="font-size:9px;color:var(--muted)">Spd <b style="color:var(--text)">'+bs[5]+'</b>'+(abStr?' · '+abStr:'')+'</div>'
      +badge
      +'</div>'
      +'<button class="tb-slot-remove" onclick="tbRemove('+num+')">✕</button>'
      +'</div>';
  }).join('');

  var rem = 6 - TB_TEAM.length;
  if (rem>0) el.innerHTML += '<div style="font-size:10px;color:var(--muted);text-align:center;padding:6px 0;opacity:0.6">'+rem+' slot'+(rem>1?'s':'')+' remaining</div>';
}

// ── defense multiplier ────────────────────────────────────────
function tbDefMult(defTypes, atkType) {
  var m = 1;
  defTypes.forEach(function(dt){
    var row = TYPE_CHART[atkType];
    if (row && row[dt]!==undefined) m *= row[dt];
  });
  return m;
}

// ── analysis ──────────────────────────────────────────────────
function tbRenderAnalysis() {
  var inner = document.getElementById('tb-analysis-inner');
  if (!TB_TEAM.length) {
    inner.innerHTML='<div class="tb-empty"><div class="tb-empty-icon">⚔</div><div class="tb-empty-text">BUILD YOUR TEAM</div><div style="font-size:11px;margin-top:12px;line-height:1.8;">Add Pokémon to see type coverage,<br>weaknesses, speed tiers and more.</div></div>';
    return;
  }
  inner.innerHTML = tbSectionCoverage() + tbSectionWeakness() + tbSectionResist() + tbSectionSpeed() + tbSectionStats() + tbSectionWarnings();
}

// ── COVERAGE ─────────────────────────────────────────────────
function tbSectionCoverage() {
  // Count team members that have STAB super-effective vs each defending type
  var counts = {};
  TB_TYPES.forEach(function(t){ counts[t]=0; });
  TB_TEAM.forEach(function(num){
    var p = POKE.find(function(x){ return x.num===num; });
    if (!p) return;
    TB_TYPES.forEach(function(def){
      var hitsSE = p.types.some(function(atk){
        var row = TYPE_CHART[atk];
        return row && (row[def]||0) >= 2;
      });
      if (hitsSE) counts[def]++;
    });
  });

  var uncovered = TB_TYPES.filter(function(t){ return counts[t]===0; });

  var tiles = TB_TYPES.map(function(t){
    var n = counts[t];
    var bg = n===0 ? 'rgba(60,60,80,0.35)' : n===1 ? 'rgba(255,215,0,0.12)' : 'rgba(76,175,80,0.18)';
    var bc = n===0 ? 'rgba(80,80,100,0.5)' : n===1 ? 'rgba(255,215,0,0.45)' : 'rgba(76,175,80,0.5)';
    var tc = n===0 ? 'var(--muted)' : n===1 ? 'var(--gold)' : '#81C784';
    return '<div class="tb-type-tile" style="background:'+bg+';border-color:'+bc+'">'
      +typeSprite(t.toLowerCase())
      +'<div class="tb-type-count" style="color:'+tc+'">'+(n===0?'✗':n===1?'1×':n+'×')+'</div>'
      +'</div>';
  }).join('');

  var missingNote = uncovered.length
    ? '<div style="margin-top:10px;padding:8px 12px;background:rgba(60,60,80,0.3);border-radius:5px;border:1px solid var(--border);font-size:11px;color:var(--muted)">No STAB super-effective coverage vs: '
      + uncovered.map(tbTypePill).join(' ') + '</div>'
    : '<div style="margin-top:10px;padding:8px 12px;background:rgba(76,175,80,0.07);border-radius:5px;border:1px solid rgba(76,175,80,0.3);font-size:11px;color:#81C784">✓ Full type coverage — your team has STAB moves that hit every type SE.</div>';

  return '<div class="tb-section"><div class="tb-section-title" style="color:var(--gold)">OFFENSIVE COVERAGE</div>'
    +'<div style="font-size:10px;color:var(--muted);margin-bottom:10px">Types hit super-effectively by at least one team member (STAB only)</div>'
    +'<div style="display:flex;flex-wrap:wrap;gap:5px">'+tiles+'</div>'
    +missingNote+'</div>';
}

// ── WEAKNESSES ───────────────────────────────────────────────
function tbSectionWeakness() {
  var wkMap = {}, imMap = {};
  TB_TYPES.forEach(function(t){ wkMap[t]=0; imMap[t]=0; });
  TB_TEAM.forEach(function(num){
    var p = POKE.find(function(x){ return x.num===num; });
    if (!p) return;
    TB_TYPES.forEach(function(atk){
      var m = tbDefMult(p.types, atk);
      if (m===0) imMap[atk]++;
      else if (m>=2) wkMap[atk]++;
    });
  });

  var relevant = TB_TYPES.filter(function(t){ return wkMap[t]>0||imMap[t]>0; });
  if (!relevant.length) return '<div class="tb-section"><div class="tb-section-title" style="color:#ef5350">TEAM WEAKNESSES</div><div style="font-size:11px;color:#81C784;padding:8px 0">No shared weaknesses — great type synergy!</div></div>';

  var tiles = relevant.map(function(t){
    var w = wkMap[t], im = imMap[t];
    var bg = w>=4?'rgba(183,28,28,0.3)':w>=3?'rgba(198,40,40,0.22)':w>=2?'rgba(255,107,53,0.16)':'rgba(255,215,0,0.1)';
    var bc = w>=3?'rgba(183,28,28,0.55)':w>=2?'rgba(255,107,53,0.45)':'rgba(255,215,0,0.4)';
    var wc = w>=3?'#ef5350':w>=2?'var(--fire)':'var(--gold)';
    return '<div class="tb-type-tile" style="background:'+bg+';border-color:'+bc+'">'
      +typeSprite(t.toLowerCase())
      +(w?'<div class="tb-type-count" style="color:'+wc+'">'+w+' weak</div>':'')
      +(im?'<div style="font-size:9px;color:#81C784">'+im+' immune</div>':'')
      +'</div>';
  }).join('');

  return '<div class="tb-section"><div class="tb-section-title" style="color:#ef5350">TEAM WEAKNESSES</div>'
    +'<div style="font-size:10px;color:var(--muted);margin-bottom:10px">Attack types that hit your team members for 2× or more</div>'
    +'<div style="display:flex;flex-wrap:wrap;gap:5px">'+tiles+'</div></div>';
}

// ── RESISTANCES ──────────────────────────────────────────────
function tbSectionResist() {
  var rMap = {}, iMap = {};
  TB_TYPES.forEach(function(t){ rMap[t]=0; iMap[t]=0; });
  TB_TEAM.forEach(function(num){
    var p = POKE.find(function(x){ return x.num===num; });
    if (!p) return;
    TB_TYPES.forEach(function(atk){
      var m = tbDefMult(p.types, atk);
      if (m===0) iMap[atk]++;
      else if (m<1) rMap[atk]++;
    });
  });

  var covered = TB_TYPES.filter(function(t){ return rMap[t]>0||iMap[t]>0; });
  if (!covered.length) return '';

  var tiles = covered.map(function(t){
    return '<div class="tb-type-tile" style="background:rgba(76,175,80,0.1);border-color:rgba(76,175,80,0.35)">'
      +typeSprite(t.toLowerCase())
      +(iMap[t]?'<div class="tb-type-count" style="color:#81C784">'+iMap[t]+'✦ imm</div>':'')
      +(rMap[t]?'<div style="font-size:9px;color:#a5d6a7">'+rMap[t]+' res</div>':'')
      +'</div>';
  }).join('');

  return '<div class="tb-section"><div class="tb-section-title" style="color:#81C784">RESISTANCES & IMMUNITIES</div>'
    +'<div style="font-size:10px;color:var(--muted);margin-bottom:10px">Attack types resisted or nullified by at least one member</div>'
    +'<div style="display:flex;flex-wrap:wrap;gap:5px">'+tiles+'</div></div>';
}

// ── SPEED TIERS ───────────────────────────────────────────────
function tbSectionSpeed() {
  var sorted = TB_TEAM.map(function(num){
    var p = POKE.find(function(x){ return x.num===num; });
    return {num:num, name:p?p.name:'?', spd:(BASE_STATS[num]||[0,0,0,0,0,0])[5]};
  }).sort(function(a,b){ return b.spd-a.spd; });

  var rows = sorted.map(function(s){
    var pct = Math.min(Math.round((s.spd/180)*100), 100);
    var col = s.spd>=110?'#81C784':s.spd>=80?'var(--gold)':s.spd>=55?'#90a4ae':'#ef5350';
    var tier = s.spd>=110?'Fast':s.spd>=80?'Mid':s.spd>=55?'Slow':'V.Slow';
    return '<div class="tb-bar-row">'
      +'<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/'+s.num+'.png" width="22" height="22" style="image-rendering:pixelated;flex-shrink:0">'
      +'<div style="width:96px;font-size:11px;font-weight:700;flex-shrink:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+s.name+'</div>'
      +'<div class="tb-bar-track"><div class="tb-bar-fill" style="width:'+pct+'%;background:'+col+'"></div></div>'
      +'<div style="width:34px;text-align:right;font-size:12px;font-weight:800;color:'+col+'">'+s.spd+'</div>'
      +'<div style="width:44px;text-align:right;font-size:9px;color:'+col+';flex-shrink:0">'+tier+'</div>'
      +'</div>';
  }).join('');

  return '<div class="tb-section"><div class="tb-section-title" style="color:#64b4ff">SPEED TIERS</div>'
    +'<div style="margin-bottom:10px">'+rows+'</div>'
    +'<div style="font-size:10px;color:var(--muted)">🟢 110+ Fast &nbsp; 🟡 80–109 Mid &nbsp; ⚫ 55–79 Slow &nbsp; 🔴 &lt;55 Very Slow</div>'
    +'</div>';
}

// ── STATS TABLE ──────────────────────────────────────────────
function tbSectionStats() {
  var labels = ['HP','Atk','Def','SpA','SpD','Spe'];
  var statColor = function(v){ return v>=120?'#81C784':v>=90?'var(--gold)':v>=60?'var(--text)':'var(--muted)'; };

  var rows = TB_TEAM.map(function(num){
    var p = POKE.find(function(x){ return x.num===num; });
    var bs = BASE_STATS[num]||[0,0,0,0,0,0];
    var bst = bs.reduce(function(a,b){return a+b;},0);
    return '<tr>'
      +'<td style="display:flex;align-items:center;gap:6px"><img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/'+num+'.png" width="20" height="20" style="image-rendering:pixelated">'+(p?p.name:'?')+'</td>'
      +bs.map(function(v){ return '<td style="color:'+statColor(v)+'">'+v+'</td>'; }).join('')
      +'<td style="color:var(--gold)">'+bst+'</td>'
      +'</tr>';
  }).join('');

  var avgRow = '';
  if (TB_TEAM.length>1) {
    var totals=[0,0,0,0,0,0];
    TB_TEAM.forEach(function(num){ var bs=BASE_STATS[num]||[0,0,0,0,0,0]; bs.forEach(function(v,i){totals[i]+=v;}); });
    var n=TB_TEAM.length;
    var avgBst=totals.reduce(function(a,b){return a+b;},0)/n;
    avgRow='<tr style="opacity:0.65"><td style="font-weight:700;font-size:10px;color:var(--muted)">AVG</td>'
      +totals.map(function(v){ return '<td style="font-size:10px;color:var(--muted)">'+Math.round(v/n)+'</td>'; }).join('')
      +'<td style="font-size:10px;color:var(--muted)">'+Math.round(avgBst)+'</td></tr>';
  }

  return '<div class="tb-section"><div class="tb-section-title" style="color:var(--muted)">BASE STAT OVERVIEW</div>'
    +'<div style="overflow-x:auto"><table class="tb-stat-table"><thead><tr>'
    +'<th style="text-align:left">Pokémon</th>'
    +labels.map(function(l){return '<th>'+l+'</th>';}).join('')
    +'<th>BST</th></tr></thead><tbody>'+rows+avgRow+'</tbody></table></div>'
    +'<div style="font-size:10px;color:var(--muted);margin-top:8px">🟢 120+ elite &nbsp; 🟡 90+ great &nbsp; ⚫ 60+ average &nbsp; dim = below average</div>'
    +'</div>';
}

// ── WARNINGS ─────────────────────────────────────────────────
function tbSectionWarnings() {
  var warns = [];

  // Per-type weakness count
  var wkMap = {};
  TB_TYPES.forEach(function(t){ wkMap[t]=0; });
  TB_TEAM.forEach(function(num){
    var p=POKE.find(function(x){return x.num===num;});
    if(!p)return;
    TB_TYPES.forEach(function(atk){
      if(tbDefMult(p.types,atk)>=2) wkMap[atk]++;
    });
  });
  TB_TYPES.forEach(function(t){
    var w=wkMap[t];
    if(w>=4) warns.push(tbTypePill(t)+' <strong>threatens '+w+'/'+TB_TEAM.length+' of your team</strong> — strongly consider a resist or immunity.');
    else if(w>=3) warns.push(tbTypePill(t)+' hits <strong>'+w+' members</strong> for super-effective damage.');
  });

  // Type duplication
  var typeCounts={};
  TB_TEAM.forEach(function(num){
    var p=POKE.find(function(x){return x.num===num;});
    if(!p)return;
    p.types.forEach(function(t){typeCounts[t]=(typeCounts[t]||0)+1;});
  });
  Object.keys(typeCounts).forEach(function(t){
    if(typeCounts[t]>=4) warns.push('Heavy '+tbTypePill(t)+' stacking ('+typeCounts[t]+' members share this type) — shared weaknesses may cripple your team.');
  });

  // No Water-type (HM/utility concern)
  if(TB_TEAM.length>=4){
    var hasWater=TB_TEAM.some(function(num){var p=POKE.find(function(x){return x.num===num;});return p&&p.types.indexOf('water')!==-1;});
    if(!hasWater) warns.push('No Water-type — you may lack a Surfer for HM05 Surf, which is required for progression in both Kanto and Hoenn.');
  }

  // All slow
  if(TB_TEAM.length>=4){
    var allSlow=TB_TEAM.every(function(num){return (BASE_STATS[num]||[0,0,0,0,0,0])[5]<60;});
    if(allSlow) warns.push('Every Pokémon on your team has base Speed below 60 — you will almost always move last in battle.');
  }

  // Game unavailability
  if(TB_GAME!=='all'){
    var naList=TB_TEAM.filter(function(num){return tbAvail(num)==='na';});
    var tradeList=TB_TEAM.filter(function(num){return tbAvail(num)==='trade';});
    if(naList.length){
      var names=naList.map(function(num){var p=POKE.find(function(x){return x.num===num;});return p?'<strong>'+p.name+'</strong>':'#'+num;});
      warns.push(names.join(', ')+' cannot be obtained in <strong>'+TB_GAME+'</strong> without trading from another game.');
    }
    if(tradeList.length){
      var names2=tradeList.map(function(num){var p=POKE.find(function(x){return x.num===num;});return p?'<strong>'+p.name+'</strong>':'#'+num;});
      warns.push(names2.join(', ')+' can only be obtained via trade in <strong>'+TB_GAME+'</strong>.');
    }
  }

  if(!warns.length) return '<div class="tb-section"><div class="tb-section-title" style="color:var(--fire)">TEAM NOTES</div><div style="font-size:11px;color:#81C784;padding:8px 0">✓ No major issues detected — solid team composition!</div></div>';

  return '<div class="tb-section"><div class="tb-section-title" style="color:var(--fire)">⚠ TEAM NOTES</div>'
    +warns.map(function(w){return '<div class="tb-warning">'+w+'</div>';}).join('')
    +'</div>';
}

// ── Apply restored state to UI ────────────────────────────────
function tbApplyRestore() {
  document.querySelectorAll('.tb-game-btn').forEach(function(b){ b.className='tb-game-btn'; });
  var tbBtn = document.querySelector('.tb-game-btn[onclick*="\'' + TB_GAME + '\'"]');
  if (tbBtn) tbBtn.className = 'tb-game-btn active-' + TB_GAME.toLowerCase();
  tbRenderSlots();
  tbRenderAnalysis();
}

// ── public hook: add from dex ────────────────────────────────
function tbAddFromDex(num) {
  var navBtn = document.getElementById('navTeam');
  showPage('team', navBtn);
  if (!window._teamBuilt) { window._teamBuilt = true; tbApplyRestore(); }
  tbAdd(num);
}

// ══ POKÉDEX TRACKER ═══════════════════════════════════════════
var TRK_SAVE = 'FR';
var _TRK_TAB_CLASSES = ['active-fr','active-lg','active-r','active-s','active-e'];
function trkUpdateTabAccent(save, skipPulse) {
  var tabs = document.querySelectorAll('.trk-save-tab');
  tabs.forEach(function(b) {
    b.classList.remove('active');
    _TRK_TAB_CLASSES.forEach(function(c){ b.classList.remove(c); });
  });
  var activeKey = 'active-' + save.toLowerCase();
  tabs.forEach(function(b) {
    var onc = b.getAttribute('onclick') || '';
    if (onc.indexOf("trkSetSave('" + save + "'") !== -1) {
      b.classList.add(activeKey);
      if (!skipPulse) pulseElement(b, 'game-tab-pulse', 560);
    }
  });
}
var TRK_FILTER = 'all';
var TRK_MODE = 'game'; // 'game' or 'national'
var TRK_SEARCH = '';
var TRK_MARK_MODE = 'caught';

var TRK_GAME_LABELS = { FR:'FireRed', LG:'LeafGreen', R:'Ruby', S:'Sapphire', E:'Emerald' };
var TRK_GAME_COLORS = { FR:'var(--fire)', LG:'var(--leaf)', R:'#FF5555', S:'#5599FF', E:'var(--emerald)' };
var TRK_GAMES = ['FR','LG','R','S','E'];
var TRK_STATE_VERSION = 1;
var GEN3_DRIVE_FILE_NAME = 'gen3-site-backup.json';
var GEN3_DRIVE_CLIENT_ID = '';
var GEN3_SITE_STATE_KEYS = ['gen3-game', 'gen3-theme', 'gen3-drive-client-id', 'FRLG_StorageKey', 'Emerald_StorageKey', 'g3notes_v2'];
var GEN3_SITE_STATE_PREFIXES = ['pokedex_tracker_', 'trk_shiny_', 'trk_seen_', 'trk_evolved_', 'trk_bred_', 'trk_traded_', 'trk_held_', 'trk_legendary_', 'trk_tm_', 'nuzlocke_fainted_', 'nuzlocke_enc_', 'bulba-progress-', 'bulba-progress-guide-'];

var TRK_COLORS = {
  normal:'#9E9E9E',fire:'#E8501A',water:'#1B8FE8',grass:'#3DA83D',electric:'#D4A800',
  ice:'#60C8C8',fighting:'#B83020',poison:'#8B3099',ground:'#8B6840',flying:'#6850C0',
  psychic:'#D01868',bug:'#78A810',rock:'#807840',ghost:'#4030A0',dragon:'#5038E8',
  dark:'#403030',steel:'#9898A8'
};
var TRK_COMPLETION_META = {
  seen:{ key:'trk_seen_', autoCaught:false, autoSeen:false, label:'Seen' },
  evolved:{ key:'trk_evolved_', autoCaught:true, autoSeen:true, label:'Evolved' },
  bred:{ key:'trk_bred_', autoCaught:true, autoSeen:true, label:'Bred' },
  traded:{ key:'trk_traded_', autoCaught:true, autoSeen:true, label:'Traded' },
  held:{ key:'trk_held_', autoCaught:false, autoSeen:false, label:'Held Farmed' },
  legendary:{ key:'trk_legendary_', autoCaught:true, autoSeen:true, label:'Legendary' }
};

function trkCompletionKey(kind, save) {
  var meta = TRK_COMPLETION_META[kind];
  return meta ? meta.key + save : '';
}

function trkLoadCompletion(kind, save) {
  try {
    var raw = localStorage.getItem(trkCompletionKey(kind, save));
    return raw ? JSON.parse(raw) : [];
  } catch(e) { return []; }
}

function trkSaveCompletion(kind, save, arr) {
  try { localStorage.setItem(trkCompletionKey(kind, save), JSON.stringify(trkNormalizeNumberList(arr))); } catch(e) {}
}

function trkHasCompletion(kind, num, save) {
  return trkLoadCompletion(kind, save || TRK_SAVE).indexOf(num) !== -1;
}

function trkToggleCompletion(kind, num, save) {
  save = save || TRK_SAVE;
  var arr = trkLoadCompletion(kind, save);
  var idx = arr.indexOf(num);
  var turningOn = idx === -1;
  if (turningOn) arr.push(num);
  else arr.splice(idx, 1);
  trkSaveCompletion(kind, save, arr);
  if (turningOn) {
    var meta = TRK_COMPLETION_META[kind];
    if (meta && meta.autoSeen) {
      var seen = trkLoadCompletion('seen', save);
      if (seen.indexOf(num) === -1) { seen.push(num); trkSaveCompletion('seen', save, seen); }
    }
    if (meta && meta.autoCaught) {
      var caught = trkLoad(save);
      if (caught.indexOf(num) === -1) { caught.push(num); trkSave(save, caught); }
    }
  }
}

function trkSeen(num, save) {
  return trkHasCompletion('seen', num, save) || trkLoad(save || TRK_SAVE).indexOf(num) !== -1;
}

function trkFindMarkButton(mode) {
  return Array.from(document.querySelectorAll('.trk-mark-btn')).find(function(btn) {
    return (btn.getAttribute('onclick') || '').indexOf("'" + mode + "'") !== -1;
  }) || null;
}

function trkFindFilterButton(mode) {
  return Array.from(document.querySelectorAll('.trk-filter-btn')).find(function(btn) {
    return (btn.getAttribute('onclick') || '').indexOf("'" + mode + "'") !== -1;
  }) || null;
}

function trkSetMarkMode(mode, btn) {
  TRK_MARK_MODE = mode;
  prefSet('gen3-tracker-mark-mode', mode);
  document.querySelectorAll('.trk-mark-btn').forEach(function(b){ b.classList.remove('active'); });
  if (btn) btn.classList.add('active');
  var hint = document.getElementById('trk-mode-hint');
  if (hint) {
    hint.textContent = 'Left-click = ' + ({
      caught:'caught',
      seen:'seen',
      evolved:'mark evolved',
      bred:'mark bred',
      traded:'mark traded',
      held:'mark held-item farmed'
    })[mode] + ' · Right-click = shiny · Data saved locally per save file';
  }
}

function trkToggleSidebarDropdown(id) {
  var el = document.getElementById(id);
  if (!el) return;
  el.classList.toggle('open');
}

function trkTmKey(save) { return 'trk_tm_' + save; }
function trkLoadTm(save) {
  try {
    var raw = localStorage.getItem(trkTmKey(save));
    return raw ? JSON.parse(raw) : [];
  } catch(e) { return []; }
}
function trkSaveTm(save, arr) {
  try { localStorage.setItem(trkTmKey(save), JSON.stringify(arr.map(function(v){ return parseInt(v,10); }).filter(Boolean).sort(function(a,b){ return a-b; }))); } catch(e) {}
}
function trkTmListForSave(save) {
  var game = save || TRK_SAVE;
  return ALL_ITEMS.filter(function(it) {
    if (it[2] !== 'TM/HM') return false;
    var loc = (it[4] || {})[game];
    return !!loc && loc !== 'Not available';
  });
}
function trkToggleTm(id) {
  var arr = trkLoadTm(TRK_SAVE);
  var idx = arr.indexOf(id);
  if (idx === -1) arr.push(id); else arr.splice(idx, 1);
  trkSaveTm(TRK_SAVE, arr);
  renderTmChecklist();
  trkRenderSidebar();
}

function openTmChecklist() {
  var overlay = document.getElementById('tmChecklistOverlay');
  var trkColor = getComputedStyle(document.getElementById('page-tracker') || document.documentElement).getPropertyValue('--trk-color').trim();
  if (trkColor) overlay.style.setProperty('--trk-color', trkColor);
  overlay.classList.add('open');
  renderTmChecklist();
}

function closeTmChecklist() {
  document.getElementById('tmChecklistOverlay').classList.remove('open');
}

function renderTmChecklist() {
  var list = trkTmListForSave(TRK_SAVE);
  var collected = trkLoadTm(TRK_SAVE);
  var set = {};
  collected.forEach(function(id){ set[id] = true; });
  var sub = document.getElementById('tmChecklistSub');
  if (sub) sub.textContent = 'Track collected discs for the ' + TRK_GAME_LABELS[TRK_SAVE] + ' save.';
  var count = document.getElementById('tmChecklistCount');
  if (count) count.textContent = collected.length + ' / ' + list.length + ' collected';
  var grid = document.getElementById('tmChecklistGrid');
  if (!grid) return;
  grid.innerHTML = list.map(function(it) {
    return '<label class="tmcheck-item">'
      + '<input type="checkbox" ' + (set[it[0]] ? 'checked' : '') + ' onchange="trkToggleTm(' + it[0] + ')">'
      + '<div>'
      + '<div class="tmcheck-item-code">' + it[1].split(' ')[0] + '</div>'
      + '<div class="tmcheck-item-name">' + it[1].replace(/^(TM|HM)\d+\s*/, '') + '</div>'
      + '<div class="tmcheck-item-loc">' + ((it[4] || {})[TRK_SAVE] || '') + '</div>'
      + '</div>'
      + '</label>';
  }).join('');
}

function trkLegendarySet() {
  var names = ['Articuno','Zapdos','Moltres','Mewtwo','Mew','Raikou','Entei','Suicune','Lugia','Ho-Oh','Deoxys','Kyogre','Groudon','Rayquaza','Latias','Latios','Regirock','Regice','Registeel','Jirachi'];
  var out = {};
  POKE.forEach(function(p) { if (names.indexOf(p.name) !== -1) out[p.num] = true; });
  return out;
}
var TRK_LEGENDARIES = trkLegendarySet();

// ── Storage ──────────────────────────────────────────────────
// ── Shiny helpers ────────────────────────────────────────────
function trkShinyKey(save) { return 'trk_shiny_' + save; }

function trkLoadShiny(save) {
  try {
    var raw = localStorage.getItem(trkShinyKey(save));
    return raw ? JSON.parse(raw) : [];
  } catch(e) { return []; }
}

function trkSaveShiny(save, arr) {
  try { localStorage.setItem(trkShinyKey(save), JSON.stringify(arr)); } catch(e) {}
}

function trkIsShiny(num) {
  return trkLoadShiny(TRK_SAVE).indexOf(num) !== -1;
}

function trkToggleShiny(num) {
  var shinies = trkLoadShiny(TRK_SAVE);
  var idx = shinies.indexOf(num);
  if (idx === -1) {
    shinies.push(num);
    // Also mark as caught if not already
    var caught = trkLoad(TRK_SAVE);
    if (caught.indexOf(num) === -1) { caught.push(num); trkSave(TRK_SAVE, caught); }
  } else {
    shinies.splice(idx, 1);
  }
  trkSaveShiny(TRK_SAVE, shinies);
  trkRenderGrid();
  trkRenderSidebar();
  if (window._easyDexBuilt && GAME === TRK_SAVE) renderEasyDexPage();
  settingsMaybeDriveReminder();
}

function trkKey(save) { return 'pokedex_tracker_' + save; }

function trkLoad(save) {
  try {
    var raw = localStorage.getItem(trkKey(save));
    return raw ? JSON.parse(raw) : [];
  } catch(e) { return []; }
}

function trkSave(save, caught) {
  try { localStorage.setItem(trkKey(save), JSON.stringify(caught)); } catch(e) {}
}

function trkStatus(msg, kind) {
  var el = document.getElementById('settings-status') || document.getElementById('trk-status');
  if (!el) return;
  el.textContent = msg;
  el.className = 'trk-status' + (kind ? ' ' + kind : '');
}

function trkNormalizeNumberList(arr) {
  if (!Array.isArray(arr)) return [];
  var seen = {};
  return arr.map(function(v) { return parseInt(v, 10); })
    .filter(function(v) {
      if (!isFinite(v) || v < 1 || v > 386 || seen[v]) return false;
      seen[v] = true;
      return true;
    })
    .sort(function(a, b) { return a - b; });
}

function gen3ShouldExportLocalStorageKey(key) {
  if (GEN3_SITE_STATE_KEYS.indexOf(key) !== -1) return true;
  return GEN3_SITE_STATE_PREFIXES.some(function(prefix) { return key.indexOf(prefix) === 0; });
}

function gen3CollectSiteState() {
  var storage = {};
  try {
    for (var i = 0; i < localStorage.length; i++) {
      var key = localStorage.key(i);
      if (!key || !gen3ShouldExportLocalStorageKey(key)) continue;
      storage[key] = localStorage.getItem(key);
    }
  } catch(e) {}
  return {
    version: TRK_STATE_VERSION,
    exportedAt: new Date().toISOString(),
    trackerMode: 'gen3-site-backup',
    activeSave: TRK_SAVE,
    localStorage: storage
  };
}

function gen3ApplySiteState(data) {
  if (!data || typeof data !== 'object' || !data.localStorage || typeof data.localStorage !== 'object') {
    throw new Error('That file does not look like a site backup export.');
  }
  Object.keys(data.localStorage).forEach(function(key) {
    if (!gen3ShouldExportLocalStorageKey(key)) return;
    var value = data.localStorage[key];
    if (typeof value !== 'string') return;
    try { localStorage.setItem(key, value); } catch(e) {}
  });
  if (data.activeSave && TRK_GAMES.indexOf(data.activeSave) !== -1) {
    TRK_SAVE = data.activeSave;
  } else {
    var storedGame = localStorage.getItem('gen3-game');
    if (storedGame && TRK_GAMES.indexOf(storedGame) !== -1) TRK_SAVE = storedGame;
  }
}

function gen3RefreshImportedState() {
  trkUpdateTabAccent(TRK_SAVE, true);
  var theme = localStorage.getItem('gen3-theme');
  document.body.classList.toggle('light-theme', theme === 'light');
  var themeBtn = document.getElementById('themeToggle');
  if (themeBtn) themeBtn.textContent = theme === 'light' ? '☀️' : '🌙';
  if (typeof setGameFromHeader === 'function') {
    var savedGame = localStorage.getItem('gen3-game') || 'all';
    try { setGameFromHeader(savedGame, null); } catch(e) {}
  }
  trkRenderSidebar();
  trkRenderGrid();
}

function gen3ExportSiteState() {
  var payload = gen3CollectSiteState();
  var json = JSON.stringify(payload, null, 2);
  var stamp = (payload.exportedAt || '').slice(0, 10) || 'export';
  var blob = new Blob([json], { type:'application/json' });
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a');
  a.href = url;
  a.download = 'gen3-site-backup-' + stamp + '.json';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(function() { URL.revokeObjectURL(url); }, 1000);
  try { localStorage.setItem('gen3-last-export-at', payload.exportedAt || new Date().toISOString()); } catch(e) {}
  trkStatus('Site backup exported. You can share it or restore it on another device.', 'ok');
  settingsRefreshDataSummary();
}

function gen3PromptImportSiteState() {
  var choice = prompt('Paste exported site backup JSON here, or type FILE to choose a .json file.');
  if (choice === null) return;
  if (choice.trim().toUpperCase() === 'FILE') {
    var fileInput = document.getElementById('trk-import-file');
    if (fileInput) {
      fileInput.value = '';
      fileInput.click();
    }
    return;
  }
  gen3ImportSiteStateText(choice);
}

function gen3HandleImportFile(event) {
  var file = event && event.target && event.target.files ? event.target.files[0] : null;
  if (!file) return;
  var mode = event && event.target && event.target.dataset ? event.target.dataset.importMode : '';
  if (event && event.target && event.target.dataset) event.target.dataset.importMode = '';
  var reader = new FileReader();
  reader.onload = function() {
    var text = String(reader.result || '');
    if (mode === 'tracker') settingsImportTrackerText(text);
    else gen3ImportSiteStateText(text);
  };
  reader.onerror = function() {
    trkStatus('Could not read that file. Try exporting again.', 'err');
  };
  reader.readAsText(file);
}

function gen3ImportSiteStateText(text) {
  var parsed;
  try {
    parsed = JSON.parse(text);
  } catch(e) {
    trkStatus('Import failed: invalid JSON.', 'err');
    return;
  }
  if (settingsShouldConfirm('import') && !confirm('Importing will replace saved site data in this browser, including tracker progress and guide progress. Continue?')) return;
  try {
    settingsCaptureRestorePoint('Before site import');
    gen3ApplySiteState(parsed);
    gen3RefreshImportedState();
    try { localStorage.setItem('gen3-last-import-at', new Date().toISOString()); } catch(e) {}
    trkStatus('Site backup imported successfully.', 'ok');
    settingsRefreshDataSummary();
  } catch(err) {
    trkStatus('Import failed: ' + (err && err.message ? err.message : 'invalid site backup.'), 'err');
  }
}

function gen3GetDriveClientId() {
  return GEN3_DRIVE_CLIENT_ID || localStorage.getItem('gen3-drive-client-id') || '';
}

function gen3EnsureDriveClientId() {
  var clientId = gen3GetDriveClientId();
  if (clientId) return clientId;
  clientId = prompt('Enter your Google OAuth Client ID for this site.');
  if (!clientId) return '';
  try { localStorage.setItem('gen3-drive-client-id', clientId.trim()); } catch(e) {}
  settingsSyncDriveField();
  return clientId.trim();
}

function gen3LoadScript(src) {
  return new Promise(function(resolve, reject) {
    if (document.querySelector('script[src="' + src + '"]')) {
      var existing = document.querySelector('script[src="' + src + '"]');
      if (existing.getAttribute('data-loaded') === 'true') return resolve();
      existing.addEventListener('load', function() { resolve(); }, { once:true });
      existing.addEventListener('error', function() { reject(new Error('Script load failed.')); }, { once:true });
      return;
    }
    var s = document.createElement('script');
    s.src = src;
    s.async = true;
    s.defer = true;
    s.onload = function() { s.setAttribute('data-loaded', 'true'); resolve(); };
    s.onerror = function() { reject(new Error('Script load failed.')); };
    document.head.appendChild(s);
  });
}

function gen3EnsureGoogleIdentity() {
  if (location.protocol === 'file:') {
    return Promise.reject(new Error('Google Drive sync needs the site served from localhost or https, not file://.'));
  }
  if (window.google && window.google.accounts && window.google.accounts.oauth2) return Promise.resolve();
  return gen3LoadScript('https://accounts.google.com/gsi/client');
}

function gen3RequestDriveToken() {
  return gen3EnsureGoogleIdentity().then(function() {
    var clientId = gen3EnsureDriveClientId();
    if (!clientId) throw new Error('Google Drive sync needs an OAuth Client ID.');
    return new Promise(function(resolve, reject) {
      var tokenClient = google.accounts.oauth2.initTokenClient({
        client_id: clientId,
        scope: 'https://www.googleapis.com/auth/drive.appdata',
        callback: function(resp) {
          if (resp && resp.access_token) resolve(resp.access_token);
          else reject(new Error('Google sign-in did not return an access token.'));
        }
      });
      tokenClient.requestAccessToken({ prompt:'consent' });
    });
  });
}

function gen3DriveFetch(path, token, opts) {
  opts = opts || {};
  opts.headers = opts.headers || {};
  opts.headers.Authorization = 'Bearer ' + token;
  return fetch(path, opts).then(function(resp) {
    if (!resp.ok) {
      return resp.text().then(function(text) {
        throw new Error('Google Drive request failed (' + resp.status + '). ' + text);
      });
    }
    return resp;
  });
}

function gen3FindDriveBackup(token) {
  var q = encodeURIComponent("name='" + GEN3_DRIVE_FILE_NAME + "' and 'appDataFolder' in parents and trashed=false");
  var url = 'https://www.googleapis.com/drive/v3/files?q=' + q + '&spaces=appDataFolder&fields=files(id,name,modifiedTime)&orderBy=modifiedTime desc&pageSize=1';
  return gen3DriveFetch(url, token).then(function(resp) { return resp.json(); })
    .then(function(data) { return data.files && data.files[0] ? data.files[0] : null; });
}

function gen3UploadDriveBackup(token, payload) {
  return gen3FindDriveBackup(token).then(function(existing) {
    var boundary = 'gen3-boundary-' + Date.now();
    var metadata = { name: GEN3_DRIVE_FILE_NAME, parents:['appDataFolder'], mimeType:'application/json' };
    var body = '--' + boundary + '\r\n'
      + 'Content-Type: application/json; charset=UTF-8\r\n\r\n'
      + JSON.stringify(existing ? { name: GEN3_DRIVE_FILE_NAME } : metadata) + '\r\n'
      + '--' + boundary + '\r\n'
      + 'Content-Type: application/json\r\n\r\n'
      + JSON.stringify(payload, null, 2) + '\r\n'
      + '--' + boundary + '--';
    var base = existing
      ? 'https://www.googleapis.com/upload/drive/v3/files/' + existing.id + '?uploadType=multipart'
      : 'https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart';
    return gen3DriveFetch(base, token, {
      method: existing ? 'PATCH' : 'POST',
      headers: { 'Content-Type': 'multipart/related; boundary=' + boundary },
      body: body
    });
  });
}

function gen3DownloadDriveBackup(token) {
  return gen3FindDriveBackup(token).then(function(file) {
    if (!file) throw new Error('No Google Drive backup found yet.');
    var url = 'https://www.googleapis.com/drive/v3/files/' + file.id + '?alt=media';
    return gen3DriveFetch(url, token).then(function(resp) { return resp.text(); });
  });
}

function gen3SaveToDrive() {
  var payload = gen3CollectSiteState();
  trkStatus('Connecting to Google Drive…', '');
  gen3RequestDriveToken()
    .then(function(token) { return gen3UploadDriveBackup(token, payload); })
    .then(function() { trkStatus('Google Drive backup saved to app data.', 'ok'); })
    .catch(function(err) { trkStatus(err && err.message ? err.message : 'Google Drive save failed.', 'err'); });
}

function gen3LoadFromDrive() {
  trkStatus('Connecting to Google Drive…', '');
  gen3RequestDriveToken()
    .then(function(token) { return gen3DownloadDriveBackup(token); })
    .then(function(text) {
      if (settingsShouldConfirm('import') && !confirm('Loading from Google Drive will replace saved site data in this browser. Continue?')) return null;
      gen3ImportSiteStateText(text);
      return true;
    })
    .catch(function(err) { trkStatus(err && err.message ? err.message : 'Google Drive load failed.', 'err'); });
}

function trkGetCaught() { return trkLoad(TRK_SAVE); }

function trkIsCaught(num) {
  return trkGetCaught().indexOf(num) !== -1;
}

function _spawnConfetti(sourceEl) {
  var colors = ['#ffd700','#ff6b35','#44dd88','#64a0ff','#ff69b4','#fff'];
  var rect = sourceEl ? sourceEl.getBoundingClientRect() : {left: window.innerWidth/2, top: window.innerHeight/2, width:0, height:0};
  var cx = rect.left + rect.width/2;
  var cy = rect.top + rect.height/2;
  for (var i = 0; i < 18; i++) {
    var p = document.createElement('div');
    p.className = 'confetti-particle';
    var col = colors[Math.floor(Math.random()*colors.length)];
    var size = 5 + Math.random()*6;
    var angle = (Math.random()*360);
    var dist = 40 + Math.random()*80;
    var tx = Math.cos(angle * Math.PI/180) * dist;
    var ty = Math.sin(angle * Math.PI/180) * dist - 30;
    var dur = 0.5 + Math.random()*0.4;
    p.style.cssText = 'left:'+cx+'px;top:'+cy+'px;width:'+size+'px;height:'+size+'px;background:'+col+';border-radius:'+(Math.random()>0.5?'50%':'2px')+';--tx:'+tx+'px;--ty:'+ty+'px;--cd:'+dur+'s;';
    document.body.appendChild(p);
    setTimeout(function(el){ el.remove(); }, (dur+0.1)*1000, p);
  }
}

function trkToggle(num) {
  var card = document.getElementById('trk-card-' + num);
  if (TRK_MARK_MODE === 'caught') {
    var caught = trkLoad(TRK_SAVE);
    var idx = caught.indexOf(num);
    if (idx === -1) {
      caught.push(num);
      // Confetti burst + bounce on the card
      if (card) {
        card.classList.add('just-caught');
        card.addEventListener('animationend', function(){ card.classList.remove('just-caught'); }, {once:true});
        _spawnConfetti(card);
      }
      // Auto-mark legendary status for legendary Pokémon
      if (TRK_LEGENDARIES[num]) {
        var leg = trkLoadCompletion('legendary', TRK_SAVE);
        if (leg.indexOf(num) === -1) { leg.push(num); trkSaveCompletion('legendary', TRK_SAVE, leg); }
      }
    } else {
      caught.splice(idx, 1);
      if (card && !motionReduced()) pulseElement(card, 'trk-mark-pop', 420);
      // Remove auto-legendary on uncatch
      if (TRK_LEGENDARIES[num]) {
        var leg2 = trkLoadCompletion('legendary', TRK_SAVE);
        var li = leg2.indexOf(num);
        if (li !== -1) { leg2.splice(li, 1); trkSaveCompletion('legendary', TRK_SAVE, leg2); }
      }
    }
    trkSave(TRK_SAVE, caught);
  } else if (TRK_MARK_MODE === 'seen') {
    trkToggleCompletion('seen', num, TRK_SAVE);
    if (card && !motionReduced()) pulseElement(card, 'trk-stamp-seen', 520);
  } else {
    trkToggleCompletion(TRK_MARK_MODE, num, TRK_SAVE);
    if (card && !motionReduced()) pulseElement(card, 'trk-stamp-gold', 520);
  }
  trkRenderGrid();
  trkRenderSidebar();
  if (window._easyDexBuilt && GAME === TRK_SAVE) renderEasyDexPage();
  settingsMaybeDriveReminder();
}

// ── Availability ─────────────────────────────────────────────
// Returns 'native', 'trade', or 'unavail' for a pokemon in current save's game
function trkAvail(p) {
  var loc = (p.games[TRK_SAVE] || '').trim().toLowerCase();
  if (!loc) {
    // Check if it's in any gen3 game at all
    var anySrc = TRK_GAMES.some(function(g) { return !!p.games[g]; });
    return anySrc ? 'trade' : 'unavail';
  }
  if (/^trade\b/.test(loc)) return 'trade';
  return 'native';
}

function trkSources(p) {
  return TRK_GAMES.filter(function(g) { return !!p.games[g]; });
}

// ── Save / filter switching ──────────────────────────────────
function trkSetSave(save, btn) {
  TRK_SAVE = save;
  trkUpdateTabAccent(save);
  trkRenderSidebar();
  trkRenderGrid();
  renderTmChecklist();
  if (window._easyDexBuilt && GAME === TRK_SAVE) renderEasyDexPage();
}

function trkSetFilter(f, btn) {
  TRK_FILTER = f;
  prefSet('gen3-tracker-filter', f);
  document.querySelectorAll('.trk-filter-btn').forEach(function(b) { b.classList.remove('active'); });
  document.querySelectorAll('.trk-stat-box').forEach(function(b) { b.classList.remove('active'); });
  if (btn) btn.classList.add('active');
  trkRenderGrid();
  settingsMaybeDriveReminder();
}

function trkSetMode(mode, btn) {
  TRK_MODE = mode;
  document.querySelectorAll('.trk-mode-btn').forEach(function(b) { b.classList.remove('active'); });
  btn.classList.add('active');
  trkRenderGrid();
}

// ── Sidebar ──────────────────────────────────────────────────
function trkRenderSidebar() {
  var caught = trkGetCaught();
  var shinies = trkLoadShiny(TRK_SAVE);
  var seenList = trkLoadCompletion('seen', TRK_SAVE);
  var evolvedList = trkLoadCompletion('evolved', TRK_SAVE);
  var bredList = trkLoadCompletion('bred', TRK_SAVE);
  var tradedList = trkLoadCompletion('traded', TRK_SAVE);
  var heldList = trkLoadCompletion('held', TRK_SAVE);
  var legendaryList = trkLoadCompletion('legendary', TRK_SAVE);
  var tmList = trkLoadTm(TRK_SAVE);
  var caughtSet = {};
  caught.forEach(function(n) { caughtSet[n] = true; });

  // Count native vs trade pokemon in this game
  var native = POKE.filter(function(p) { return trkAvail(p) === 'native'; });
  var tradeNeeded = POKE.filter(function(p) { return trkAvail(p) === 'trade'; });
  var total = POKE.length; // 386 for national dex
  var caughtCount = caught.length;
  var shinyCount = shinies.length;
  var remaining = total - caughtCount;

  // Progress ring: national dex %
  var pct = Math.round((caughtCount / total) * 100);
  var circumference = 289;
  var offset = circumference - (circumference * caughtCount / total);
  var gameCol = TRK_GAME_COLORS[TRK_SAVE] || 'var(--emerald)';
  var trkPage = document.getElementById('page-tracker');
  if (trkPage) trkPage.style.setProperty('--trk-color', gameCol);
  var ring = document.getElementById('trk-ring');
  if (ring) {
    ring.style.strokeDashoffset = offset;
    ring.style.stroke = gameCol;
  }
  var pctEl = document.getElementById('trk-pct');
  if (pctEl) { pctEl.textContent = pct + '%'; pctEl.style.setProperty('color', gameCol); }
  var fracEl = document.getElementById('trk-fraction');
  if (fracEl) fracEl.textContent = caughtCount + ' / ' + total;
  var labelEl = document.getElementById('trk-save-label');
  if (labelEl) { labelEl.textContent = TRK_GAME_LABELS[TRK_SAVE] + ' Save'; labelEl.style.setProperty('color', gameCol); }

  // Stat boxes
  var el = function(id, v) { var e = document.getElementById(id); if (e) e.textContent = v; };
  el('trk-s-caught', caughtCount);
  el('trk-s-seen', remaining);
  el('trk-s-native', native.length);
  el('trk-s-trade', tradeNeeded.length);
  el('trk-s-shiny', shinyCount);
  el('trk-s-seen2', trkNormalizeNumberList(seenList.concat(caught)).length);
  el('trk-s-evolved', evolvedList.length);
  el('trk-s-bred', bredList.length);
  el('trk-s-traded2', tradedList.length);
  el('trk-s-held', heldList.length);
  el('trk-s-legendary', legendaryList.length);
  el('trk-s-tm', tmList.length + ' / ' + trkTmListForSave(TRK_SAVE).length);


  var remainingBody = document.getElementById('trk-remaining-body');
  if (remainingBody) {
    function remainingGroups() {
      var groups = {
        direct:[],
        special:[],
        evolve:[],
        npcTrade:[],
        linkTrade:[]
      };
      POKE.forEach(function(p) {
        if (caughtSet[p.num]) return;
        var lines = parseLines((p.games[TRK_SAVE] || ''));
        var direct = lines.some(function(e){ return optEncounterableMethod(e.method); });
        var npcTrade = lines.some(function(e){ return e.method === 'trade'; });
        var special = lines.some(function(e){ return ['special','breed','fossil','event'].indexOf(e.method) !== -1; });
        var evolve = lines.some(function(e){ return e.method === 'evolve'; });
        var linkTrade = !String((p.games[TRK_SAVE] || '')).trim() ? trkSources(p).length > 0 : false;
        if (direct) groups.direct.push(p.name);
        else if (special) groups.special.push(p.name);
        else if (evolve) groups.evolve.push(p.name);
        else if (npcTrade) groups.npcTrade.push(p.name);
        else if (linkTrade) groups.linkTrade.push(p.name);
      });
      return groups;
    }
    var gr = remainingGroups();
    var defs = [
      ['Direct catches', gr.direct],
      ['Special / gift', gr.special],
      ['Evolution cleanup', gr.evolve],
      ['In-game trades', gr.npcTrade],
      ['Link trades', gr.linkTrade]
    ];
    remainingBody.innerHTML = defs.map(function(def, idx) {
      var names = def[1];
      var preview = names.slice(0, 4).join(', ');
      var rest = names.slice(4);
      var expandId = 'trk-rem-expand-' + idx;
      var btnId = 'trk-rem-btn-' + idx;
      var extraHtml = rest.length
        ? '<span id="' + expandId + '" style="display:none;">, ' + rest.join(', ') + '</span>'
          + '<button id="' + btnId + '" class="trk-rem-more-btn" onclick="trkToggleRemaining(' + idx + ',' + rest.length + ')">+' + rest.length + ' more</button>'
        : '';
      return '<div class="trk-remaining-row">'
        + '<div class="trk-remaining-head"><span>' + def[0] + '</span><span>' + names.length + '</span></div>'
        + '<div class="trk-remaining-sub">' + (names.length ? preview + extraHtml : 'Nothing left in this bucket.') + '</div>'
        + '</div>';
    }).join('');
  }
}

// ── Long-press for shiny/nuzlocke (mobile) ───────────────────
var _trkLongPressTimer = null;
var _trkLongPressStartX = 0;
var _trkLongPressStartY = 0;
var _trkLongPressFired = false;

function trkSetupLongPress(grid) {
  if (grid._longPressSetup) return;
  grid._longPressSetup = true;

  // passive:false so we can call preventDefault() — blocks browser long-press menu
  grid.addEventListener('touchstart', function(e) {
    var card = e.target.closest('[data-trk-num]');
    if (!card) return;
    e.preventDefault(); // blocks browser context menu AND synthesised click — we handle tap via touchend
    _trkLongPressFired = false;
    _trkLongPressStartX = e.touches[0].clientX;
    _trkLongPressStartY = e.touches[0].clientY;
    _trkLongPressTimer = setTimeout(function() {
      _trkLongPressTimer = null;
      _trkLongPressFired = true;
      var num = parseInt(card.dataset.trkNum, 10);
      if (NUZLOCKE_MODE) { nuzlockeMarkFainted(num); } else { trkToggleShiny(num); }
      // Brief pulse so user knows it fired
      card.style.transition = 'transform 0.12s';
      card.style.transform = 'scale(0.88)';
      setTimeout(function() { card.style.transform = ''; }, 180);
    }, 550);
  }, { passive: false });

  // Since preventDefault on touchstart blocks click, handle tap here
  grid.addEventListener('touchend', function(e) {
    if (_trkLongPressTimer) {
      clearTimeout(_trkLongPressTimer);
      _trkLongPressTimer = null;
    }
    if (_trkLongPressFired) return; // long press already handled
    var card = e.target.closest('[data-trk-num]');
    if (!card) return;
    var num = parseInt(card.dataset.trkNum, 10);
    trkToggle(num);
  }, { passive: true });

  grid.addEventListener('touchmove', function(e) {
    if (!_trkLongPressTimer) return;
    var dx = e.touches[0].clientX - _trkLongPressStartX;
    var dy = e.touches[0].clientY - _trkLongPressStartY;
    if (Math.sqrt(dx*dx + dy*dy) > 8) {
      clearTimeout(_trkLongPressTimer);
      _trkLongPressTimer = null;
    }
  }, { passive: true });

  // Block right-click context menu on desktop too (already on each card inline, belt-and-braces)
  grid.addEventListener('contextmenu', function(e) {
    if (e.target.closest('[data-trk-num]')) e.preventDefault();
  });
}

// ── Grid ─────────────────────────────────────────────────────
function trkRenderGrid() {
  var caught = trkGetCaught();
  var caughtSet = {};
  caught.forEach(function(n) { caughtSet[n] = true; });

  var q = (document.getElementById('trk-search') || {}).value || '';
  q = q.toLowerCase();

  var _filterSets = {};
  if (['seen','evolved','bred','traded','held','legendary'].indexOf(TRK_FILTER) !== -1) {
    var _kind = TRK_FILTER === 'seen' ? 'seen' : TRK_FILTER;
    trkLoadCompletion(_kind, TRK_SAVE).forEach(function(n){ _filterSets[n] = true; });
    if (TRK_FILTER === 'seen') caught.forEach(function(n){ _filterSets[n] = true; });
  }

  var filtered = POKE.filter(function(p) {
    // search
    if (q && p.name.toLowerCase().indexOf(q) === -1 && String(p.num).indexOf(q) === -1) return false;

    var av = trkAvail(p);
    var isCaught = !!caughtSet[p.num];

    var isFaintedFilter = NUZLOCKE_MODE && nuzlockeIsFainted(TRK_SAVE, p.num);
    var isShinyFilter = trkIsShiny(p.num);
    switch (TRK_FILTER) {
      case 'caught':    return isCaught && !isFaintedFilter;
      case 'uncaught':  return !isCaught && !isFaintedFilter;
      case 'shiny':     return isShinyFilter;
      case 'native':    return av === 'native';
      case 'trade':     return av === 'trade';
      case 'national':  return true;
      case 'fainted':   return isFaintedFilter;
      case 'alive':     return isCaught && !isFaintedFilter;
      case 'seen':
      case 'evolved':
      case 'bred':
      case 'traded':
      case 'held':
      case 'legendary': return !!_filterSets[p.num];
      default: return true;
    }
  });

  // Sort: game dex mode = by dex number, national = national number
  // Sort by mode: 'game' = regional dex order, 'national' = national number
  filtered.sort(function(a, b) {
    if (TRK_MODE === 'game') {
      var isRSE = ['R','S','E'].indexOf(TRK_SAVE) !== -1;
      var dexKey = isRSE ? 'rse' : 'frlg';
      var da = (DEX_MAP[String(a.num)] || {})[dexKey] || a.num;
      var db = (DEX_MAP[String(b.num)] || {})[dexKey] || b.num;
      return da - db;
    }
    return a.num - b.num;
  });

  var countEl = document.getElementById('trk-count');
  if (countEl) countEl.textContent = filtered.length + ' shown';

  var grid = document.getElementById('trk-grid');
  if (!grid) return;

  var shinySet = {};
  trkLoadShiny(TRK_SAVE).forEach(function(n) { shinySet[n] = true; });
  var seenSet = {}, evolvedSet = {}, bredSet = {}, tradedSet = {}, heldSet = {}, legendarySet = {};
  trkLoadCompletion('seen', TRK_SAVE).forEach(function(n){ seenSet[n] = true; });
  trkLoadCompletion('evolved', TRK_SAVE).forEach(function(n){ evolvedSet[n] = true; });
  trkLoadCompletion('bred', TRK_SAVE).forEach(function(n){ bredSet[n] = true; });
  trkLoadCompletion('traded', TRK_SAVE).forEach(function(n){ tradedSet[n] = true; });
  trkLoadCompletion('held', TRK_SAVE).forEach(function(n){ heldSet[n] = true; });
  trkLoadCompletion('legendary', TRK_SAVE).forEach(function(n){ legendarySet[n] = true; });

  grid.innerHTML = filtered.map(function(p) {
    var av = trkAvail(p);

    var isCaught = !!caughtSet[p.num];
    var isShiny  = !!shinySet[p.num];
    var isFainted = NUZLOCKE_MODE && nuzlockeIsFainted(TRK_SAVE, p.num);
    var cls = 'trk-card';
    if (isFainted) cls += ' nuzlocke-fainted';
    else if (isCaught) cls += ' caught';
    else cls += ' uncaught';
    if (isShiny) cls += ' shiny';
    if (av === 'trade' && !isCaught && !isFainted) cls += ' need-trade';

    var typeDots = p.types.map(function(t) {
      return '<div class="trk-type-dot" style="background:' + (TRK_COLORS[t]||'#666') + '"></div>';
    }).join('');

    var sources = trkSources(p);
    var srcStr = sources.filter(function(g){ return g !== TRK_SAVE; }).map(function(g){ return TRK_GAME_LABELS[g]; }).join(', ');
    var baseTooltip = isCaught ? (isShiny ? '✨ Caught (Shiny!)' : '✅ Caught')
      : av === 'native' ? '🏠 In Regional Dex: ' + TRK_GAME_LABELS[TRK_SAVE]
      : av === 'trade' ? '🔄 Trade from: ' + (srcStr || 'other games')
      : '❌ Not in Gen 3';
    var tooltipText = isFainted ? '💀 Fainted — right-click / long-press to restore'
      : NUZLOCKE_MODE ? baseTooltip + ' · Right-click / long-press = mark fainted'
      : baseTooltip + ' · Right-click / long-press = toggle shiny';

    var spriteUrl = isShiny
      ? 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/shiny/' + p.num + '.png'
      : 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + p.num + '.png';

    var contextHandler = NUZLOCKE_MODE
      ? 'if(NUZLOCKE_MODE){event.preventDefault();nuzlockeMarkFainted(' + p.num + ');return false;}'
      : 'event.preventDefault();trkToggleShiny(' + p.num + ');return false;';

    var safeTitle = tooltipText.replace(/"/g, '&quot;').replace(/'/g, '&#39;');
    var fallbackSrc = 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + p.num + '.png';
    return '<div class="' + cls + '" id="trk-card-' + p.num + '" data-trk-num="' + p.num + '" onclick="trkToggle(' + p.num + ')" oncontextmenu="' + contextHandler + '" title="' + safeTitle + '">'
      + '<div class="trk-card-check">' + (isShiny ? '✨' : '✓') + '</div>'
      + '<span class="trk-shiny-badge">✨</span>'
      + '<img class="trk-card-img" src="' + spriteUrl + '" loading="lazy" onerror="this.src=&quot;' + fallbackSrc + '&quot;">'
      + '<div class="trk-card-num">#' + String(p.num).padStart(3,'0') + '</div>'
      + '<div class="trk-card-name">' + p.name + '</div>'
      + '<div class="trk-type-dots">' + typeDots + '</div>'
      + '<span class="trk-trade-badge">TRADE</span>'
      + '<div class="trk-status-badges">'
      + '<span class="trk-status-chip seen ' + ((seenSet[p.num] || isCaught) ? 'on' : '') + '">SEEN</span>'
      + '<span class="trk-status-chip evolved ' + (evolvedSet[p.num] ? 'on' : '') + '">EVO</span>'
      + '<span class="trk-status-chip bred ' + (bredSet[p.num] ? 'on' : '') + '">BRD</span>'
      + '<span class="trk-status-chip traded ' + (tradedSet[p.num] ? 'on' : '') + '">TRD</span>'
      + '<span class="trk-status-chip held ' + (heldSet[p.num] ? 'on' : '') + '">HLD</span>'
      + (TRK_LEGENDARIES[p.num] ? '<span class="trk-status-chip legendary ' + (legendarySet[p.num] ? 'on' : '') + '">LEG</span>' : '')
      + '</div>'
      + '<div class="trk-tooltip">' + tooltipText + '</div>'
      + '</div>';
  }).join('');

  // Long-press = shiny/nuzlocke (mobile alternative to right-click)
  trkSetupLongPress(grid);
}

// ── Bulk actions ─────────────────────────────────────────────
function trkMarkAll() {
  var all = POKE.map(function(p) { return p.num; });
  trkSave(TRK_SAVE, all);
  // Auto-mark all legendaries
  var legNums = POKE.filter(function(p) { return !!TRK_LEGENDARIES[p.num]; }).map(function(p) { return p.num; });
  trkSaveCompletion('legendary', TRK_SAVE, legNums);
  trkRenderGrid();
  trkRenderSidebar();
  renderTmChecklist();
  if (window._easyDexBuilt && GAME === TRK_SAVE) renderEasyDexPage();
  settingsMaybeDriveReminder();
}

function trkClearSave() {
  if (settingsShouldConfirm('reset') && !confirm('Reset all caught data for ' + TRK_GAME_LABELS[TRK_SAVE] + '? This cannot be undone.')) return;
  settingsCaptureRestorePoint('Before tracker reset (' + TRK_SAVE + ')');
  trkSave(TRK_SAVE, []);
  trkSaveShiny(TRK_SAVE, []);
  nuzlockeSaveFainted(TRK_SAVE, []);
  Object.keys(TRK_COMPLETION_META).forEach(function(kind){ trkSaveCompletion(kind, TRK_SAVE, []); });
  trkSaveTm(TRK_SAVE, []);
  trkRenderGrid();
  trkRenderSidebar();
  renderTmChecklist();
  trkStatus(TRK_GAME_LABELS[TRK_SAVE] + ' save reset.', '');
  if (window._easyDexBuilt && GAME === TRK_SAVE) renderEasyDexPage();
  settingsMaybeDriveReminder();
}

// ── Remaining obtainable expand ──────────────────────────────
function trkToggleRemaining(idx, count) {
  var expand = document.getElementById('trk-rem-expand-' + idx);
  var btn    = document.getElementById('trk-rem-btn-'    + idx);
  if (!expand || !btn) return;
  var open = expand.style.display !== 'none';
  expand.style.display = open ? 'none' : 'inline';
  btn.textContent = open ? '+' + count + ' more' : 'Show less';
}

// ── Legend ────────────────────────────────────────────────────
function trkShowLegend() {
  var el = document.getElementById('trkLegendOverlay');
  if (el) el.classList.add('open');
}
function trkHideLegend() {
  var el = document.getElementById('trkLegendOverlay');
  if (el) el.classList.remove('open');
}

// ── Init ──────────────────────────────────────────────────────
function buildTracker() {
  var completion = document.getElementById('trk-completion-panel');
  if (completion) completion.classList.add('open');
  TRK_FILTER = prefGet('gen3-tracker-filter', 'all');
  TRK_MARK_MODE = prefGet('gen3-tracker-mark-mode', 'caught');
  trkSetMarkMode(TRK_MARK_MODE, trkFindMarkButton(TRK_MARK_MODE));
  var filterBtn = trkFindFilterButton(TRK_FILTER);
  if (filterBtn) trkSetFilter(TRK_FILTER, filterBtn);
  trkRenderSidebar();
  trkRenderGrid();
  renderTmChecklist();
}

// Auto-init: if the tracker page is already active on load, build it.
(function() {
  function initTrackerIfActive() {
    var page = document.getElementById('page-tracker');
    var count = document.getElementById('trk-count');
    var grid = document.getElementById('trk-grid');
    var looksEmpty = (!count || !count.textContent.trim()) && (!grid || !grid.innerHTML.trim());
    if (page && page.classList.contains('active') && looksEmpty) {
      buildTracker();
      window._trackerBuilt = true;
    }
  }
  function scheduleTrackerRecovery() {
    initTrackerIfActive();
    setTimeout(initTrackerIfActive, 60);
    setTimeout(initTrackerIfActive, 180);
    setTimeout(initTrackerIfActive, 420);
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', scheduleTrackerRecovery, { once:true });
  } else {
    scheduleTrackerRecovery();
  }
})();

// ══ TM/HM LOCATOR ═════════════════════════════════════════════
var TMHM_REGION = 'frlg'; // 'frlg' or 'rse'
var TMHM_GAME = 'FR';
var TMHM_TYPE = 'all'; // 'all', 'TM', 'HM'

var TMHM_REGION_GAMES = {
  frlg: ['FR','LG'],
  rse:  ['R','S','E']
};

var TMHM_GAME_LABELS = {FR:'FireRed',LG:'LeafGreen',R:'Ruby',S:'Sapphire',E:'Emerald'};
var TMHM_GROUP_LABELS = {FR:'FireRed / LeafGreen', R:'Ruby / Sapphire', E:'Emerald'};
var TMHM_GAME_COLORS = {FR:'var(--fire)',LG:'var(--leaf)',R:'#e05555',S:'#5599FF',E:'#44DD88'};





function tmhmSetType(type, btn) {
  TMHM_TYPE = type;
  document.querySelectorAll('.tmhm-type-btn').forEach(function(b){ b.classList.remove('active'); });
  btn.classList.add('active');
  tmhmRender();
}



function tmhmSyncFromGame(g) {
  if (g === 'all') return;
  TMHM_GAME = g;
  TMHM_REGION = (g === 'FR' || g === 'LG') ? 'frlg' : 'rse';
  document.querySelectorAll('.tmhm-game-btn').forEach(function(b){ b.classList.remove('active'); });
  var gb = document.querySelector('.tmhm-game-btn[onclick*="' + g + '"]');
  if (gb) gb.classList.add('active');
  tmhmRender();
}

function buildTmhmLocator() {
  tmhmRender();
}

function tmhmRender() {
  var q = ((document.getElementById('tmhm-search') || {}).value || '').toLowerCase();
  var games = TMHM_REGION_GAMES[TMHM_REGION];

  // Get TM/HM items filtered to current region
  var items = ALL_ITEMS.filter(function(it) {
    if (it[2] !== 'TM/HM') return false;
    var name = it[1]; // e.g. "TM01 Focus Punch" or "HM03 Surf"
    var isTM = /^TM/.test(name);
    var isHM = /^HM/.test(name);
    if (TMHM_TYPE === 'TM' && !isTM) return false;
    if (TMHM_TYPE === 'HM' && !isHM) return false;
    // Region filter: item must be available in at least one game of the region
    var locs = it[4] || {};
    var inRegion = games.some(function(g) { return !!locs[g]; });
    if (!inRegion && !isHM) return false; // HMs show even if FR/LG only location
    // HMs: filter by region - RSE HM08 shouldn't show in FR/LG region
    if (isHM) {
      if (TMHM_REGION === 'frlg' && name === 'HM08 Dive') return false;
    }
    if (q) {
      var loc = locs[TMHM_GAME] || '';
      var moveEntry = Object.entries(MOVES_DATA).find(function(e){ return e[1][0] === name.replace(/^(TM|HM)\d+\s*/,''); });
      var moveName = name.replace(/^(TM|HM)\d+\s*/,'');
      if (moveName.toLowerCase().indexOf(q) === -1 && loc.toLowerCase().indexOf(q) === -1) return false;
    }
    return true;
  });

  // Sort TMs numerically, HMs after
  items.sort(function(a, b) {
    var an = parseInt(a[1].match(/\d+/)[0]);
    var bn = parseInt(b[1].match(/\d+/)[0]);
    var aIsHM = /^HM/.test(a[1]) ? 1 : 0;
    var bIsHM = /^HM/.test(b[1]) ? 1 : 0;
    if (aIsHM !== bIsHM) return aIsHM - bIsHM;
    return an - bn;
  });

  var countEl = document.getElementById('tmhm-count');
  if (countEl) countEl.textContent = items.length + ' moves';

  var inner = document.getElementById('tmhm-inner');
  if (!inner) return;

  if (!items.length) {
    inner.innerHTML = '<div style="text-align:center;padding:40px;color:var(--muted);font-family:\'Press Start 2P\',monospace;font-size:8px;">NO RESULTS</div>';
    return;
  }

  // Separate TMs and HMs
  var tms = items.filter(function(it){ return /^TM/.test(it[1]); });
  var hms = items.filter(function(it){ return /^HM/.test(it[1]); });

  function renderSection(list, title) {
    if (!list.length) return '';
    var rows = list.map(function(it) {
      var name = it[1];
      var num = name.match(/^(TM|HM)(\d+)/);
      var prefix = num ? num[1] : '';
      var numStr = num ? num[2] : '';
      var moveName = name.replace(/^(TM|HM)\d+\s*/, '');
      var locs = it[4] || {};
      var loc = locs[TMHM_GAME] || '';
      var effect = it[3] || '';

      var moveEntry = null;
      Object.entries(MOVES_DATA).forEach(function(e){
        if (e[1][0] === moveName) moveEntry = e[1];
      });
      var moveType = moveEntry ? moveEntry[1] : '';
      var moveCat = moveEntry ? moveEntry[2] : '';
      var movePow = moveEntry ? moveEntry[3] : null;

      var catIcon = moveCat === 'Physical' ? '⚔' : moveCat === 'Special' ? '✨' : moveCat === 'Status' ? '●' : '';
      var powStr = movePow ? movePow : '—';
      var powColor = movePow >= 100 ? '#F08030' : movePow >= 60 ? 'var(--text)' : 'var(--muted)';

      var tmKey = (prefix + numStr).toUpperCase();
      var tmEntry = ALL_ITEMS.find(function(it){ return it[1].toUpperCase().indexOf(tmKey) === 0; });
      var tmIconUrl = (tmEntry && ITEM_ICONS[tmEntry[0]]) ? ITEM_ICONS[tmEntry[0]] : ITEM_SPRITE_BASE + prefix.toLowerCase() + numStr + '.png';
      var tmSprite = '<img src="' + tmIconUrl + '" width="20" height="20" style="image-rendering:pixelated;flex-shrink:0;vertical-align:middle" onerror="this.style.display=\'none\'">';

      var locText = loc
        ? '<span style="color:var(--text)">' + loc + '</span>'
        : '<span style="color:var(--muted);font-style:italic">Not available</span>';

      return '<tr>'
        + '<td style="white-space:nowrap"><div style="display:flex;align-items:center;gap:6px">' + tmSprite + '<span class="tmhm-num-badge">' + prefix + numStr + '</span></div></td>'
        + '<td style="white-space:nowrap"><span class="tmhm-move-link" onclick="goToMoveInDex(\'' + moveName.replace(/'/g,"\\'") + '\')">' + moveName + '</span></td>'
        + '<td>' + (moveType ? typeSprite(moveType.toLowerCase()) : '') + '</td>'
        + '<td style="font-size:11px;color:var(--muted);white-space:nowrap">' + catIcon + ' ' + moveCat + ' <span style="font-family:monospace;font-weight:800;font-size:12px;color:' + powColor + '">' + powStr + '</span></td>'
        + '<td style="font-size:11px;color:var(--muted);max-width:260px">' + effect.slice(0,55) + (effect.length>55?'…':'') + '</td>'
        + '<td style="min-width:200px">' + locText + '</td>'
        + '</tr>';
    }).join('');

    return '<div class="tmhm-section">'
      + '<div class="panel" style="padding:0;overflow-x:auto;">'
      + '<div class="tmhm-section-title">' + title + '</div>'
      + '<table class="tmhm-table">'
      + '<thead><tr>'
      + '<th>#</th>'
      + '<th>Move</th>'
      + '<th>Type</th>'
      + '<th>Cat / Pwr</th>'
      + '<th>Effect</th>'
      + '<th>Location — ' + TMHM_GAME_LABELS[TMHM_GAME] + '</th>'
      + '</tr></thead>'
      + '<tbody>' + rows + '</tbody>'
      + '</table></div></div>';
  }

  var html = '';
  if (TMHM_TYPE !== 'HM') html += renderSection(tms, 'TECHNICAL MACHINES (TM01–TM50)');
  if (TMHM_TYPE !== 'TM') html += renderSection(hms, 'HIDDEN MACHINES (HM01–HM0' + (TMHM_REGION === 'rse' ? '8' : '7') + ')');
  inner.innerHTML = html;
}

// ══ DAMAGE CALCULATOR ══════════════════════════════════════════

// Gen 3: Physical/Special split is by TYPE, not move
var CALC_PHYSICAL_TYPES = {normal:1,fighting:1,flying:1,poison:1,ground:1,rock:1,bug:1,ghost:1,steel:1};
// Special types: fire,water,grass,electric,ice,psychic,dragon,dark

var CALC_TYPE_COLORS = {
  normal:'#9E9E9E',fire:'#E8501A',water:'#1B8FE8',grass:'#3DA83D',electric:'#D4A800',
  ice:'#60C8C8',fighting:'#B83020',poison:'#8B3099',ground:'#8B6840',flying:'#6850C0',
  psychic:'#D01868',bug:'#78A810',rock:'#807840',ghost:'#4030A0',dragon:'#5038E8',
  dark:'#403030',steel:'#9898A8'
};

var calcState = {
  atk: null,  // { num, name, types, bs }
  def: null,
  move: null, // { id, name, type, cat, power, acc }
  weather: 'none'
};

// ── Pokémon search ──────────────────────────────────────────
function calcPokeSearch(side, val) {
  var ddId = side + '-dd';
  var dd = document.getElementById(ddId);
  if (!val || val.length < 1) { dd.style.display = 'none'; return; }
  var q = val.toLowerCase();
  var hits = POKE.filter(function(p) {
    return p.name.toLowerCase().indexOf(q) !== -1 || String(p.num).indexOf(q) !== -1;
  }).slice(0, 12);
  if (!hits.length) { dd.style.display = 'none'; return; }
  dd.innerHTML = hits.map(function(p) {
    var tc = (p.types||[]).map(function(t){
      return typeSprite(t.toLowerCase());
    }).join(' ');
    return '<div class="calc-poke-dd-item" onmousedown="calcSelectPoke(\'' + side + '\',' + p.num + ')">'
      + '<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + p.num + '.png" width="24" height="24" style="image-rendering:pixelated">'
      + '<span style="flex:1">' + p.name + '</span>'
      + '<span>' + tc + '</span>'
      + '</div>';
  }).join('');
  dd.style.display = 'block';
}

function calcSelectPoke(side, num) {
  var p = POKE.find(function(x){ return x.num === num; });
  if (!p) return;
  var bs = BASE_STATS[num] || [80,80,80,80,80,80];
  calcState[side] = { num: num, name: p.name, types: p.types, bs: bs };

  document.getElementById(side + '-search').value = p.name;
  document.getElementById(side + '-dd').style.display = 'none';

  // Fill base stats
  var isPhys = calcIsPhysical();
  if (side === 'atk') {
    document.getElementById('atk-base').value = isPhys ? bs[1] : bs[3];
  } else {
    document.getElementById('def-base').value = isPhys ? bs[2] : bs[4];
    var hp = calcStatValue(bs[0], parseInt(document.getElementById('def-level').value) || 50,
      31, 0, 1, true);
    document.getElementById('def-hp-display').textContent = 'HP: ' + hp;
  }

  calcRenderSelected(side, p, bs);
  calcUpdate();
}

function calcRenderSelected(side, p, bs) {
  var el = document.getElementById(side + '-selected');
  el.style.display = 'flex';
  var typeHtml = (p.types||[]).map(function(t){
    return typeSprite(t.toLowerCase());
  }).join('');
  var statNames = ['HP','Atk','Def','SpA','SpD','Spe'];
  var statCols = ['#ef5350','#FF6B35','#9E9E9E','#64b4ff','#81C784','#FFD700'];
  var statsHtml = bs.map(function(v,i){
    var pct = Math.min(Math.round(v/255*100),100);
    return '<div style="display:flex;align-items:center;gap:5px;font-size:9px">'
      + '<span style="width:26px;color:var(--muted);font-weight:800;flex-shrink:0">' + statNames[i] + '</span>'
      + '<div style="flex:1;height:5px;background:var(--darker);border-radius:3px"><div style="width:' + pct + '%;height:100%;background:' + statCols[i] + ';border-radius:3px"></div></div>'
      + '<span style="width:26px;text-align:right;font-weight:800;color:' + statCols[i] + '">' + v + '</span>'
      + '</div>';
  }).join('');
  el.innerHTML = '<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + p.num + '.png" width="40" height="40" style="image-rendering:pixelated;flex-shrink:0">'
    + '<div style="flex:1;min-width:0">'
    + '<div style="font-size:12px;font-weight:800;margin-bottom:3px">' + p.name + ' <span style="font-family:\'Press Start 2P\',monospace;font-size:7px;color:var(--muted)">#' + String(p.num).padStart(3,'0') + '</span></div>'
    + '<div style="display:flex;gap:3px;margin-bottom:6px">' + typeHtml + '</div>'
    + '<div style="display:flex;flex-direction:column;gap:2px">' + statsHtml + '</div>'
    + '</div>'
    + '<button class="calc-poke-clear" onmousedown="calcClearPoke(\'' + side + '\')">✕</button>';
}

function calcClearPoke(side) {
  calcState[side] = null;
  document.getElementById(side + '-search').value = '';
  document.getElementById(side + '-selected').style.display = 'none';
  if (side === 'def') document.getElementById('def-hp-display').textContent = '';
  calcUpdate();
}

// ── Move search ─────────────────────────────────────────────
function calcMoveSearch(val) {
  var dd = document.getElementById('move-dd');
  if (!val || val.length < 1) { dd.style.display = 'none'; return; }
  var q = val.toLowerCase();
  var hits = ALL_MOVES_DATA.filter(function(m) {
    return m[1].toLowerCase().indexOf(q) !== -1;
  }).filter(function(m) { return m[4] > 0; }) // only damaging moves
    .slice(0, 16);
  if (!hits.length) { dd.style.display = 'none'; return; }
  dd.innerHTML = hits.map(function(m) {
    var col = CALC_TYPE_COLORS[m[2].toLowerCase()] || '#666';
    var isPhysType = CALC_PHYSICAL_TYPES[m[2].toLowerCase()] ? 'Phys' : 'Spec';
    return '<div class="calc-move-dd-item" onmousedown="calcSelectMove(' + m[0] + ')">'
      + '<span style="font-weight:700">' + m[1] + '</span>'
      + '<span style="display:flex;gap:5px;align-items:center;flex-shrink:0">'
      + typeSprite(m[2].toLowerCase())
      + '<span style="font-size:9px;color:var(--muted)">' + isPhysType + ' · Pwr ' + (m[4]||'—') + '</span>'
      + '</span></div>';
  }).join('');
  dd.style.display = 'block';
}

function calcSelectMove(id) {
  var m = ALL_MOVES_DATA.find(function(x){ return x[0] === id; });
  if (!m) return;
  // m = [id, name, type, cat_char, power, acc, pp, desc]
  calcState.move = { id: id, name: m[1], type: m[2].toLowerCase(), power: m[4], acc: m[5] };

  document.getElementById('move-search').value = m[1];
  document.getElementById('move-dd').style.display = 'none';

  // Update type selector
  document.getElementById('move-type').value = m[2].toLowerCase();

  // Update power field
  document.getElementById('move-power').value = m[4] || '';

  // Show move info
  var isPhys = CALC_PHYSICAL_TYPES[m[2].toLowerCase()];
  document.getElementById('move-sel-name').textContent = m[1];
  document.getElementById('move-sel-type').innerHTML = typeSprite(m[2].toLowerCase());
  document.getElementById('move-sel-type').style.background = '';
  document.getElementById('move-sel-type').style.color = '';
  document.getElementById('move-sel-type').style.border = '';
  document.getElementById('move-sel-cat').textContent = (isPhys ? '⚔ Physical' : '✨ Special') + ' (Gen 3)';
  document.getElementById('move-sel-info').textContent = 'Pwr: ' + (m[4]||'—') + ' · Acc: ' + (m[5]||'—') + '%';
  document.getElementById('move-gen3-note').textContent = 'Gen 3: ' + m[2] + '-type moves use ' + (isPhys ? 'Atk vs Def' : 'SpAtk vs SpDef') + ' regardless of the move\'s Gen 4+ category.';
  document.getElementById('move-selected-display').style.display = 'block';

  // Auto-fill stat bases from selected pokemon
  if (calcState.atk) {
    var bs = calcState.atk.bs;
    document.getElementById('atk-base').value = isPhys ? bs[1] : bs[3];
  }
  if (calcState.def) {
    var bsd = calcState.def.bs;
    document.getElementById('def-base').value = isPhys ? bsd[2] : bsd[4];
  }

  calcUpdate();
}

// ── Weather ─────────────────────────────────────────────────
var CALC_WEATHER = 'none';
var WEATHER_NOTES = {
  none: '',
  sun: 'Harsh Sun: Fire moves ×1.5, Water moves ×0.5. Solar Beam fires without charging.',
  rain: 'Rain: Water moves ×1.5, Fire moves ×0.5. Thunder never misses.',
  sand: 'Sandstorm: Rock-types gain ×1.5 SpDef. Non-Rock/Ground/Steel take 1/16 HP damage per turn.',
  hail: 'Hail: Ice-types immune to hail damage. Non-Ice types take 1/16 HP damage per turn. Blizzard never misses.'
};

function calcSetWeather(wx, btn) {
  CALC_WEATHER = wx;
  document.querySelectorAll('.calc-weather-btn').forEach(function(b){ b.classList.remove('active'); });
  btn.classList.add('active');
  document.getElementById('wx-note').textContent = WEATHER_NOTES[wx] || '';
  calcUpdate();
}

// ── Toggle buttons ──────────────────────────────────────────
function calcToggle(id, activeClass) {
  var btn = document.getElementById(id);
  if (btn.classList.contains(activeClass)) btn.classList.remove(activeClass);
  else btn.classList.add(activeClass);
  calcUpdate();
}

function calcIsActive(id) {
  var btn = document.getElementById(id);
  // Check if any active class is applied
  return btn.className.indexOf('active') !== -1;
}

// ── Stat calculation ────────────────────────────────────────
// Gen 3 stat formula: ((2*Base + IV + floor(EV/4)) * Level / 100 + 5) * nature
// HP: ((2*Base + IV + floor(EV/4)) * Level / 100 + Level + 10)
function calcStatValue(base, level, iv, ev, nature, isHP) {
  base = parseInt(base) || 1;
  level = parseInt(level) || 50;
  iv = Math.max(0, Math.min(31, parseInt(iv) || 31));
  ev = Math.max(0, Math.min(252, parseInt(ev) || 0));
  nature = parseFloat(nature) || 1.0;
  if (isHP) {
    return Math.floor((2 * base + iv + Math.floor(ev / 4)) * level / 100) + level + 10;
  }
  return Math.floor((Math.floor((2 * base + iv + Math.floor(ev / 4)) * level / 100) + 5) * nature);
}

function calcIsPhysical() {
  var moveType = document.getElementById('move-type').value;
  return moveType ? !!CALC_PHYSICAL_TYPES[moveType] : true;
}

// ── Main update ─────────────────────────────────────────────
function calcUpdate() {
  var moveType = document.getElementById('move-type').value;
  var isPhys = moveType ? !!CALC_PHYSICAL_TYPES[moveType] : null;

  // Update stat type labels
  if (isPhys !== null) {
    document.getElementById('atk-stat-type').textContent = isPhys ? '(Attack)' : '(Special Attack)';
    document.getElementById('def-stat-type').textContent = isPhys ? '(Defense)' : '(Special Defense)';
    // Sandstorm SpDef note
    document.getElementById('def-sand-boost').textContent = isPhys ? '🏜 Sand (no effect)' : '🏜 Sand SpDef ×1.5';
  }

  // Calculate and display attacker stat
  var atkBase = parseInt(document.getElementById('atk-base').value) || 0;
  var atkLevel = parseInt(document.getElementById('atk-level').value) || 50;
  var atkIV = parseInt(document.getElementById('atk-iv').value) || 31;
  var atkEV = parseInt(document.getElementById('atk-ev').value) || 0;
  var atkNature = parseFloat(document.getElementById('atk-nature').value) || 1.0;
  var atkStat = calcStatValue(atkBase, atkLevel, atkIV, atkEV, atkNature, false);
  document.getElementById('atk-calc-stat').textContent = atkStat;

  // Calculate and display defender stat
  var defBase = parseInt(document.getElementById('def-base').value) || 0;
  var defLevel = parseInt(document.getElementById('def-level').value) || 50;
  var defIV = parseInt(document.getElementById('def-iv').value) || 31;
  var defEV = parseInt(document.getElementById('def-ev').value) || 0;
  var defNature = parseFloat(document.getElementById('def-nature').value) || 1.0;
  var defStat = calcStatValue(defBase, defLevel, defIV, defEV, defNature, false);
  document.getElementById('def-calc-stat').textContent = defStat;

  // Update def HP display
  if (calcState.def) {
    var hpBase = calcState.def.bs[0];
    var hp = calcStatValue(hpBase, defLevel, 31, 0, 1, true);
    document.getElementById('def-hp-display').textContent = 'HP: ' + hp;
  }

  // Require move power and type to calculate
  var movePowerRaw = parseInt(document.getElementById('move-power').value);
  if (!movePowerRaw || !moveType || movePowerRaw <= 0) {
    document.getElementById('calc-result-card').classList.remove('has-result');
    document.getElementById('calc-result-body').innerHTML = '<div class="calc-empty-state"><div class="calc-empty-icon">⚡</div><div style="font-family:\'Press Start 2P\',monospace;font-size:8px;letter-spacing:1px">SELECT MOVE + POKÉMON</div><div style="font-size:11px;margin-top:10px;line-height:1.7">Pick an attacker, defender, and move<br>to calculate damage.</div></div>';
    return;
  }

  // ── Gen 3 Damage Formula ──
  // Damage = floor( floor( floor(2*Level/5 + 2) * Power * A / D / 50 ) * Modifier ) + 2
  // Modifier = STAB * Type * Weather * Crit * Burn * Badge * Reflect/Screen * Random

  var movePower = movePowerRaw;

  // STAB: does attacker's type match move type?
  var stabActive = calcIsActive('cond-stab');
  var hasStab = stabActive;
  if (!hasStab && calcState.atk) {
    hasStab = calcState.atk.types.some(function(t){ return t === moveType; });
  }
  var stab = hasStab ? 1.5 : 1.0;

  // Type effectiveness
  var typeMultiplier = 1.0;
  var typeBreakdown = [];
  if (calcState.def) {
    calcState.def.types.forEach(function(defType) {
      var row = TYPE_CHART[moveType];
      var mult = row ? (row[defType] !== undefined ? row[defType] : 1) : 1;
      typeMultiplier *= mult;
      typeBreakdown.push({ type: defType, mult: mult });
    });
  }

  // Weather modifier
  var weatherMod = 1.0;
  var weatherNote = '';
  if (CALC_WEATHER === 'sun') {
    if (moveType === 'fire') { weatherMod = 1.5; weatherNote = '☀ Sun: Fire ×1.5'; }
    else if (moveType === 'water') { weatherMod = 0.5; weatherNote = '☀ Sun: Water ×0.5'; }
  } else if (CALC_WEATHER === 'rain') {
    if (moveType === 'water') { weatherMod = 1.5; weatherNote = '🌧 Rain: Water ×1.5'; }
    else if (moveType === 'fire') { weatherMod = 0.5; weatherNote = '🌧 Rain: Fire ×0.5'; }
  }

  // Sandstorm: Rock-type SpDef boost (only if move is special and def is Rock-type)
  var sandBoostActive = calcIsActive('def-sand-boost');
  var sandBoost = 1.0;
  if (CALC_WEATHER === 'sand' && !isPhys && sandBoostActive) {
    sandBoost = 1.5;
    weatherNote = (weatherNote ? weatherNote + ' · ' : '') + '🏜 Sand: Rock SpDef ×1.5';
  }

  // Flash Fire: fire immunity becomes fire boost
  var ffActive = calcIsActive('cond-ff');
  var ffMod = (ffActive && moveType === 'fire') ? 1.5 : 1.0;

  // Charge: doubles Electric power
  var chargeMod = (calcIsActive('cond-charge') && moveType === 'electric') ? 2.0 : 1.0;
  if (chargeMod === 2.0) movePower = movePower * 2;

  // Critical hit: ×2 in Gen 3 (does NOT ignore stat drops in Gen 3, unlike later gens)
  var crit = calcIsActive('atk-crit') ? 2.0 : 1.0;

  // Burn: halves physical damage
  var burn = (calcIsActive('atk-burn') && isPhys) ? 0.5 : 1.0;

  // Badge boost: Gen 3 gives slight boost (ignore for clean calculation — note it)
  var badge = calcIsActive('atk-badge') ? 1.1 : 1.0;

  // Reflect / Light Screen: halves damage from that category
  var screen = 1.0;
  if (isPhys && calcIsActive('def-reflect')) screen = 0.5;
  if (!isPhys && calcIsActive('def-lightscreen')) screen = 0.5;

  // Apply effective defense stat with sandstorm
  var effDefStat = Math.floor(defStat / sandBoost);

  // Apply effective attack stat with burn
  var effAtkStat = Math.floor(atkStat * burn);

  // Core damage (before random and badge)
  var baseDmg = Math.floor(Math.floor(Math.floor(2 * atkLevel / 5 + 2) * movePower * effAtkStat / effDefStat) / 50);

  // Apply modifiers in Gen 3 order
  baseDmg = Math.floor(baseDmg * stab);
  baseDmg = Math.floor(baseDmg * typeMultiplier);
  baseDmg = Math.floor(baseDmg * weatherMod);
  baseDmg = Math.floor(baseDmg * ffMod);
  baseDmg = Math.floor(baseDmg * crit);
  baseDmg = baseDmg + 2;  // Gen 3 adds 2 at the end before random
  baseDmg = Math.floor(baseDmg * badge);
  baseDmg = Math.floor(baseDmg * screen);

  // Random roll: 0.85–1.00 (Gen 3 uses 217–255/255)
  var dmgMin = Math.floor(baseDmg * 217 / 255);
  var dmgMax = baseDmg; // 255/255 = 1.0

  // HP of defender
  var defHP = calcState.def
    ? calcStatValue(calcState.def.bs[0], defLevel, 31, 0, 1, true)
    : null;

  var pctMin = defHP ? (dmgMin / defHP * 100).toFixed(1) : null;
  var pctMax = defHP ? (dmgMax / defHP * 100).toFixed(1) : null;

  // OHKO check
  var ohkoHtml = '';
  if (defHP) {
    if (dmgMin >= defHP) ohkoHtml = '<div class="calc-ohko-badge calc-ohko-1">⚡ GUARANTEED OHKO</div>';
    else if (dmgMax >= defHP) ohkoHtml = '<div class="calc-ohko-badge calc-ohko-2">⚡ POSSIBLE OHKO</div>';
    else if (dmgMax * 2 >= defHP) ohkoHtml = '<div class="calc-ohko-badge calc-ohko-3">2HKO POSSIBLE</div>';
  }

  // Type effectiveness label
  var typeEffLabel = typeMultiplier === 0 ? '<span style="color:#81C784;font-weight:800">Immune (0×)</span>'
    : typeMultiplier >= 4 ? '<span style="color:#ef5350;font-weight:800">Super ×4</span>'
    : typeMultiplier >= 2 ? '<span style="color:var(--fire);font-weight:800">Super ×' + typeMultiplier + '</span>'
    : typeMultiplier >= 1 ? '<span style="color:var(--text)">Neutral ×1</span>'
    : typeMultiplier > 0 ? '<span style="color:#64b4ff;font-weight:800">Resisted ×' + typeMultiplier + '</span>'
    : '<span style="color:#81C784;font-weight:800">Immune ×0</span>';

  var atkName = calcState.atk ? calcState.atk.name : 'Attacker';
  var defName = calcState.def ? calcState.def.name : 'Defender';
  var moveName = calcState.move ? calcState.move.name : (document.getElementById('move-search').value || 'Move');

  document.getElementById('calc-result-card').classList.add('has-result');
  document.getElementById('calc-result-body').innerHTML =
    '<div style="font-size:11px;color:var(--muted);margin-bottom:12px;text-align:center">'
    + atkName + ' → ' + moveName + ' → ' + defName
    + '</div>'
    + '<div class="calc-dmg-display">'
    + '<div class="calc-dmg-range">' + dmgMin + ' – ' + dmgMax + '</div>'
    + '<div class="calc-dmg-pct">' + (pctMin !== null ? pctMin + '% – ' + pctMax + '% of ' + defName + '\'s HP' : 'Damage range (min–max roll)') + '</div>'
    + ohkoHtml
    + '</div>'
    + '<div class="calc-breakdown">'
    + '<div class="calc-breakdown-row"><span class="calc-breakdown-label">Base power</span><span class="calc-breakdown-val">' + movePowerRaw + (chargeMod===2?' (×2 Charge → '+movePower+')':'') + '</span></div>'
    + '<div class="calc-breakdown-row"><span class="calc-breakdown-label">Gen 3 category</span><span class="calc-breakdown-val">' + (isPhys ? '⚔ Physical (Atk vs Def)' : '✨ Special (SpAtk vs SpDef)') + '</span></div>'
    + '<div class="calc-breakdown-row"><span class="calc-breakdown-label">Attacker stat (' + (isPhys?'Atk':'SpAtk') + ')</span><span class="calc-breakdown-val">' + atkStat + (burn<1?' <span style="color:var(--fire);font-size:10px">× 0.5 burned</span>':'') + '</span></div>'
    + '<div class="calc-breakdown-row"><span class="calc-breakdown-label">Defender stat (' + (isPhys?'Def':'SpDef') + ')</span><span class="calc-breakdown-val">' + defStat + (sandBoost>1?' <span style="color:#B8A038;font-size:10px">× 1.5 sand</span>':'') + '</span></div>'
    + '<div class="calc-breakdown-row"><span class="calc-breakdown-label">STAB</span><span class="calc-breakdown-val">' + (stab===1.5?'×1.5 ✦':'×1.0') + '</span></div>'
    + '<div class="calc-breakdown-row"><span class="calc-breakdown-label">Type effectiveness</span><span class="calc-breakdown-val">' + typeEffLabel + '</span></div>'
    + (weatherMod!==1.0?'<div class="calc-breakdown-row"><span class="calc-breakdown-label">Weather</span><span class="calc-breakdown-val">' + weatherNote + '</span></div>':'')
    + (ffMod!==1.0?'<div class="calc-breakdown-row"><span class="calc-breakdown-label">Flash Fire</span><span class="calc-breakdown-val">×1.5</span></div>':'')
    + (crit!==1.0?'<div class="calc-breakdown-row"><span class="calc-breakdown-label">Critical hit</span><span class="calc-breakdown-val">×2 💥</span></div>':'')
    + (screen!==1.0?'<div class="calc-breakdown-row"><span class="calc-breakdown-label">Screen</span><span class="calc-breakdown-val">×0.5 🛡</span></div>':'')
    + '</div>';
}

// ══ IV/EV CALCULATOR ═══════════════════════════════════════════

var IVEV_STAT_NAMES = ['HP','Atk','Def','SpA','SpD','Spe'];
var IVEV_STAT_COLS  = ['#ef5350','#FF6B35','#9E9E9E','#64b4ff','#81C784','#FFD700'];

// Nature table: [stat boosted (0=none/all), stat lowered]
// Index: 0=Atk,1=Def,2=SpA,3=SpD,4=Spe  (-1 = HP, not affected)
var NATURE_TABLE = {
  neutral:{b:-1,l:-1}, hardy:{b:0,l:0}, lonely:{b:0,l:1}, brave:{b:0,l:4},
  adamant:{b:0,l:2}, naughty:{b:0,l:3}, bold:{b:1,l:0}, docile:{b:1,l:1},
  relaxed:{b:1,l:4}, impish:{b:1,l:2}, lax:{b:1,l:3}, modest:{b:2,l:0},
  mild:{b:2,l:1}, quiet:{b:2,l:4}, bashful:{b:2,l:2}, rash:{b:2,l:3},
  calm:{b:3,l:0}, gentle:{b:3,l:1}, sassy:{b:3,l:4}, careful:{b:3,l:2},
  quirky:{b:3,l:3}, timid:{b:4,l:0}, hasty:{b:4,l:1}, jolly:{b:4,l:2},
  naive:{b:4,l:3}, serious:{b:4,l:4}
};

var IVEV_POKE = null;
var IVEV_POKERUS = false;
var IVEV_IVS  = [31,31,31,31,31,31];
var IVEV_EVS  = [0,0,0,0,0,0];

// ── Pokémon search ──────────────────────────────────────────
function ivevPokeSearch(val) {
  var dd = document.getElementById('ivev-dd');
  if (!val) { dd.style.display='none'; return; }
  var q = val.toLowerCase();
  var hits = POKE.filter(function(p){ return p.name.toLowerCase().indexOf(q)!==-1 || String(p.num).indexOf(q)!==-1; }).slice(0,12);
  if (!hits.length) { dd.style.display='none'; return; }
  dd.innerHTML = hits.map(function(p){
    return '<div class="ivev-poke-dd-item" onmousedown="ivevSelectPoke('+p.num+')">'
      +'<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/'+p.num+'.png" width="24" height="24" style="image-rendering:pixelated">'
      +'<span>'+p.name+'</span>'
      +'<span style="margin-left:auto;font-family:\'Press Start 2P\',monospace;font-size:7px;color:var(--muted)">#'+String(p.num).padStart(3,'0')+'</span>'
      +'</div>';
  }).join('');
  dd.style.display='block';
}

function ivevSelectPoke(num) {
  var p = POKE.find(function(x){ return x.num===num; });
  if (!p) return;
  IVEV_POKE = { num:num, name:p.name, types:p.types, bs: BASE_STATS[num]||[80,80,80,80,80,80] };
  document.getElementById('ivev-search').value = p.name;
  document.getElementById('ivev-dd').style.display='none';

  // Show sprite + types
  var tc = (p.types||[]).map(function(t){
    return typeSprite(t);
  }).join('');
  document.getElementById('ivev-poke-info').style.display='flex';
  document.getElementById('ivev-poke-info').innerHTML =
    '<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/'+num+'.png" width="40" height="40" style="image-rendering:pixelated">'
    +'<div><div style="font-weight:800;font-size:13px">'+p.name+'</div><div style="display:flex;gap:3px;margin-top:2px">'+tc+'</div></div>'
    +'<button onclick="ivevClearPoke()" title="Remove Pokémon" style="background:none;border:1px solid var(--border);color:var(--muted);border-radius:4px;font-size:11px;padding:2px 7px;cursor:pointer;margin-left:4px;transition:all 0.12s;" onmouseover="this.style.borderColor=\'var(--game-color,var(--gold))\';this.style.color=\'var(--game-color,var(--gold))\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.color=\'var(--muted)\'">✕</button>';

  // Reset EVs, keep IVs at 31
  IVEV_EVS = [0,0,0,0,0,0];
  ivevRebuildGrid();
  ivevUpdate();
}

function ivevClearPoke() {
  IVEV_POKE = null;
  document.getElementById('ivev-search').value = '';
  document.getElementById('ivev-poke-info').style.display = 'none';
  document.getElementById('ivev-poke-info').innerHTML = '';
  IVEV_EVS = [0,0,0,0,0,0];
  document.getElementById('ivev-stat-grid').innerHTML = '';
  document.getElementById('ivev-ev-total').style.display = 'none';
  var out = document.getElementById('ivev-output');
  if (out) out.innerHTML = '';
}

// ── Grid ────────────────────────────────────────────────────
function ivevRebuildGrid() {
  var grid = document.getElementById('ivev-stat-grid');
  // Keep header row (first 7 cells), replace the rest
  var headers = grid.innerHTML.match(/<!-- Headers -->([\s\S]*?)<!-- Stat rows/);
  // Just regenerate stat rows
  var statRowsHtml = IVEV_STAT_NAMES.map(function(name, i) {
    var base = IVEV_POKE ? IVEV_POKE.bs[i] : 0;
    var isHP = (i===0);
    return '<div class="ivev-cell" style="display:flex;align-items:center;justify-content:center">'
      +'<span class="ivev-cell-label" style="color:'+IVEV_STAT_COLS[i]+'">'+name+'</span>'
      +'</div>'
      +'<div class="ivev-cell ivev-cell-base">'+base+'</div>'
      +'<div class="ivev-cell"><input class="ivev-inp" id="ivev-iv-'+i+'" type="number" min="0" max="31" value="'+IVEV_IVS[i]+'" oninput="ivevIVChange('+i+',this)"></div>'
      +'<div class="ivev-cell"><input class="ivev-inp" id="ivev-ev-'+i+'" type="number" min="0" max="'+(isHP?252:252)+'" value="'+IVEV_EVS[i]+'" oninput="ivevEVChange('+i+',this)"></div>'
      +'<div class="ivev-cell" id="ivev-nat-'+i+'" style="font-size:11px;font-weight:800;color:var(--muted)">×1.0</div>'
      +'<div class="ivev-cell ivev-result-cell" id="ivev-res-'+i+'" style="color:'+IVEV_STAT_COLS[i]+'">—</div>'
      +'<div class="ivev-bar-cell" id="ivev-bar-cell-'+i+'"><div class="ivev-stat-bar-wrap"><div class="ivev-stat-bar" id="ivev-bar-'+i+'" style="width:0%;background:'+IVEV_STAT_COLS[i]+'"></div></div></div>';
  }).join('');

  // Rebuild full grid
  grid.innerHTML =
    '<div class="ivev-col-header stat-h">STAT</div>'
    +'<div class="ivev-col-header">BASE</div>'
    +'<div class="ivev-col-header">IV <span style="font-weight:400;opacity:0.6">(0–31)</span></div>'
    +'<div class="ivev-col-header">EV <span style="font-weight:400;opacity:0.6">(0–252)</span></div>'
    +'<div class="ivev-col-header">NATURE</div>'
    +'<div class="ivev-col-header stat-h">RESULT</div>'
    +'<div class="ivev-col-header">BAR</div>'
    + statRowsHtml;
}

function ivevIVChange(i, inp) {
  var v = Math.max(0, Math.min(31, parseInt(inp.value)||0));
  IVEV_IVS[i] = v;
  ivevUpdate();
}

function ivevEVChange(i, inp) {
  var v = Math.max(0, Math.min(255, parseInt(inp.value)||0));
  IVEV_EVS[i] = v;
  inp.classList.toggle('over-cap', v > 252);
  ivevUpdate();
}

function ivevTogglePokerus(btn) {
  IVEV_POKERUS = !IVEV_POKERUS;
  btn.textContent = IVEV_POKERUS ? 'ON ×2' : 'OFF';
  btn.classList.toggle('on', IVEV_POKERUS);
}

function ivevClearEVs() {
  IVEV_EVS = [0,0,0,0,0,0];
  for (var i=0;i<6;i++){
    var inp=document.getElementById('ivev-ev-'+i);
    if(inp){inp.value=0;inp.classList.remove('over-cap');}
  }
  ivevUpdate();
}

function ivevOptimalEVs() {
  // Set first boosted stat and speed to 252, leftover 6 to HP
  var natureKey = document.getElementById('ivev-nature-sel').value;
  var nat = NATURE_TABLE[natureKey]||{b:-1,l:-1};
  IVEV_EVS = [0,0,0,0,0,0];
  // 252 in boosted stat, 252 in Speed, 6 in HP
  var boostIdx = nat.b >= 0 ? nat.b : 0; // Atk by default
  IVEV_EVS[boostIdx] = 252;
  IVEV_EVS[5] = 252; // Speed
  if (IVEV_EVS[0] === 0) IVEV_EVS[0] = 6; // HP remainder
  for (var i=0;i<6;i++){
    var inp=document.getElementById('ivev-ev-'+i);
    if(inp) inp.value=IVEV_EVS[i];
  }
  ivevUpdate();
}

// ── Stat calculation ────────────────────────────────────────
function ivevCalcStat(base, level, iv, ev, natureMult, isHP) {
  base = parseInt(base)||0;
  level = parseInt(level)||50;
  iv = Math.max(0,Math.min(31,parseInt(iv)||0));
  ev = Math.max(0,Math.min(255,parseInt(ev)||0));
  natureMult = parseFloat(natureMult)||1.0;
  if (isHP) {
    return Math.floor((2*base + iv + Math.floor(ev/4)) * level/100) + level + 10;
  }
  return Math.floor((Math.floor((2*base + iv + Math.floor(ev/4)) * level/100) + 5) * natureMult);
}

function ivevGetNatureMults() {
  var key = document.getElementById('ivev-nature-sel').value;
  var nat = NATURE_TABLE[key]||{b:-1,l:-1};
  var mults = [1,1,1,1,1,1];
  // stat indices: HP=0,Atk=1,Def=2,SpA=3,SpD=4,Spe=5
  // nature indices: 0=Atk,1=Def,2=SpA,3=SpD,4=Spe
  var nToS = [1,2,3,4,5]; // nature index → stat index
  if (nat.b >= 0 && nat.b !== nat.l) mults[nToS[nat.b]] = 1.1;
  if (nat.l >= 0 && nat.b !== nat.l) mults[nToS[nat.l]] = 0.9;
  return mults;
}

function ivevGetNatureLabel(statIdx, mults) {
  var m = mults[statIdx];
  if (statIdx===0 || m===1.0) return '<span style="color:var(--muted)">×1.0</span>';
  if (m===1.1) return '<span style="color:#ef5350;font-weight:800">+×1.1</span>';
  if (m===0.9) return '<span style="color:#64b4ff;font-weight:800">−×0.9</span>';
  return '×1.0';
}

function ivevUpdate() {
  if (!IVEV_POKE) return;
  var level = parseInt(document.getElementById('ivev-level').value)||50;
  var mults = ivevGetNatureMults();
  var totalEV = 0;
  var results = [];

  for (var i=0;i<6;i++) {
    var iv = parseInt(document.getElementById('ivev-iv-'+i)&&document.getElementById('ivev-iv-'+i).value)||IVEV_IVS[i];
    var ev = IVEV_EVS[i];
    totalEV += ev;
    var isHP = (i===0);
    var stat = ivevCalcStat(IVEV_POKE.bs[i], level, iv, ev, mults[i], isHP);
    results.push(stat);

    // Update nature label
    var natEl = document.getElementById('ivev-nat-'+i);
    if (natEl) natEl.innerHTML = ivevGetNatureLabel(i, mults);

    // Update result
    var resEl = document.getElementById('ivev-res-'+i);
    if (resEl) resEl.textContent = stat;

    // Update bar (max ~400 for display)
    var maxForDisplay = isHP ? 500 : 400;
    var pct = Math.min(Math.round(stat/maxForDisplay*100),100);
    var barEl = document.getElementById('ivev-bar-'+i);
    if (barEl) barEl.style.width = pct+'%';
  }

  // EV total bar
  var totalCapped = Math.min(totalEV, 510);
  var pctTotal = Math.round(totalCapped/510*100);
  var barColor = totalEV > 510 ? '#ef5350' : totalEV === 510 ? 'var(--gold)' : '#44DD88';
  var evBar = document.getElementById('ivev-ev-bar');
  var evCount = document.getElementById('ivev-ev-count');
  if (evBar) { evBar.style.width = pctTotal+'%'; evBar.style.background = barColor; }
  if (evCount) {
    evCount.textContent = totalEV+' / 510';
    evCount.style.color = totalEV > 510 ? '#ef5350' : totalEV===510 ? 'var(--gold)' : '#44DD88';
  }

  // Pokérus note
  if (IVEV_POKERUS) {
    // Show effective EV gain rate note
  }
}

// ── IV Finder ───────────────────────────────────────────────
function ivefFind() {
  var level = parseInt(document.getElementById('ivf-level').value)||50;
  var ev = parseInt(document.getElementById('ivf-ev').value)||0;
  var statIds = ['hp','atk','def','spa','spd','spe'];
  var statNames2 = ['HP','Atk','Def','SpA','SpD','Spe'];
  var html = '<div style="display:flex;flex-direction:column;gap:4px">';
  var anyFilled = false;

  statIds.forEach(function(sid, i) {
    var inp = document.getElementById('ivf-'+sid);
    var observed = parseInt(inp ? inp.value : '');
    if (isNaN(observed)) return;
    anyFilled = true;
    var isHP = (i===0);
    var base = IVEV_POKE ? IVEV_POKE.bs[i] : 80;
    // Find matching IVs
    var matches = [];
    for (var iv=0;iv<=31;iv++) {
      var stat = ivefCalcStat(base, level, iv, ev, 1.0, isHP);
      if (stat === observed) matches.push(iv);
    }
    // Check with nature boost/penalty too
    var matchesBoost=[], matchesPen=[];
    if (!isHP) {
      for (var iv2=0;iv2<=31;iv2++) {
        if (ivefCalcStat(base,level,iv2,ev,1.1,false)===observed) matchesBoost.push(iv2);
        if (ivefCalcStat(base,level,iv2,ev,0.9,false)===observed) matchesPen.push(iv2);
      }
    }
    var rangeStr = matches.length===0 ? '<span style="color:#ef5350">No match</span>'
      : matches.length===32 ? '<span style="color:var(--muted)">Any IV</span>'
      : matches[0]===matches[matches.length-1] ? '<span style="color:var(--gold);font-weight:800">IV = '+matches[0]+'</span>'
      : '<span style="color:var(--gold);font-weight:800">IV '+matches[0]+'–'+matches[matches.length-1]+'</span>';

    html += '<div class="ivev-range-row">'
      +'<span class="ivev-range-lbl" style="color:'+IVEV_STAT_COLS[i]+'">'+statNames2[i]+'</span>'
      +'<span style="color:var(--muted);margin-right:8px">'+observed+' →</span>'
      +rangeStr
      +(matchesBoost.length&&!isHP?' <span style="font-size:9px;color:#ef5350;margin-left:8px">+nature: '+matchesBoost[0]+(matchesBoost.length>1?'–'+matchesBoost[matchesBoost.length-1]:'')+' IV</span>':'')
      +(matchesPen.length&&!isHP?' <span style="font-size:9px;color:#64b4ff;margin-left:8px">−nature: '+matchesPen[0]+(matchesPen.length>1?'–'+matchesPen[matchesPen.length-1]:'')+' IV</span>':'')
      +'</div>';
  });

  html += '</div>';
  if (!anyFilled) html = '<div style="color:var(--muted);font-size:11px;font-style:italic">Enter observed stat values above to find possible IVs.</div>';

  document.getElementById('ivf-results').innerHTML = html;
}

function ivefCalcStat(base, level, iv, ev, nat, isHP) {
  base=parseInt(base)||0; level=parseInt(level)||50;
  iv=Math.max(0,Math.min(31,iv)); ev=Math.max(0,Math.min(255,parseInt(ev)||0));
  if (isHP) return Math.floor((2*base+iv+Math.floor(ev/4))*level/100)+level+10;
  return Math.floor((Math.floor((2*base+iv+Math.floor(ev/4))*level/100)+5)*nat);
}


// ── Hidden Power Calculator ────────────────────────────────
var HP_TYPES = ['Fighting','Flying','Poison','Ground','Rock','Bug','Ghost','Steel','Fire','Water','Grass','Electric','Psychic','Ice','Dragon','Dark'];

function calcHP() {
  var ivs = [];
  for (var i=0;i<6;i++) {
    var v = parseInt(document.getElementById('hp-iv-'+i).value);
    if (isNaN(v)||v<0||v>31) v = 31;
    ivs.push(v);
  }
  // Type formula: floor(((b0 + 2*b1 + 4*b2 + 8*b3 + 16*b4 + 32*b5) * 15) / 63)
  // where bN = IV mod 2 (LSB of each IV), order: HP,Atk,Def,Spe,SpA,SpD
  var bits = [ivs[0]%2, ivs[1]%2, ivs[2]%2, ivs[5]%2, ivs[3]%2, ivs[4]%2];
  var typeIdx = Math.floor((bits[0]+2*bits[1]+4*bits[2]+8*bits[3]+16*bits[4]+32*bits[5])*15/63);

  // Power formula: floor(((c0 + 2*c1 + 4*c2 + 8*c3 + 16*c4 + 32*c5) * 40) / 63) + 30
  // where cN = floor(IV/2) mod 2 (bit 1 of each IV), order: HP,Atk,Def,Spe,SpA,SpD
  var pbits = [Math.floor(ivs[0]/2)%2, Math.floor(ivs[1]/2)%2, Math.floor(ivs[2]/2)%2, Math.floor(ivs[5]/2)%2, Math.floor(ivs[3]/2)%2, Math.floor(ivs[4]/2)%2];
  var power = Math.floor((pbits[0]+2*pbits[1]+4*pbits[2]+8*pbits[3]+16*pbits[4]+32*pbits[5])*40/63)+30;

  var typeName = HP_TYPES[typeIdx];
  var typeColors = {Fighting:'#B83020',Flying:'#6850C0',Poison:'#8B3099',Ground:'#8B6840',Rock:'#807840',Bug:'#78A810',Ghost:'#4030A0',Steel:'#9898A8',Fire:'#E8501A',Water:'#1B8FE8',Grass:'#3DA83D',Electric:'#D4A800',Psychic:'#D01868',Ice:'#60C8C8',Dragon:'#5038E8',Dark:'#403030'};
  var col = typeColors[typeName] || '#666';
  var powerClass = power >= 65 ? '#81C784' : power >= 55 ? 'var(--gold)' : 'var(--muted)';

  var res = document.getElementById('hp-result');
  res.innerHTML =
    '<div style="display:flex;align-items:center;gap:10px">'
    + '<span style="font-size:10px;color:var(--muted);font-weight:700">TYPE</span>'
    + '<span style="font-size:15px;font-weight:800;padding:4px 12px;border-radius:5px;text-transform:uppercase;background:'+col+'22;color:'+col+';border:2px solid '+col+'55">'+typeName+'</span>'
    + '</div>'
    + '<div style="display:flex;align-items:center;gap:10px">'
    + '<span style="font-size:10px;color:var(--muted);font-weight:700">POWER</span>'
    + '<span style="font-size:20px;font-weight:800;color:'+powerClass+'">'+power+'</span>'
    + '<span style="font-size:10px;color:var(--muted)">'+(power===70?'✓ Maximum power!':power>=60?'Good power':'Low power — aim for IVs where bit1=1')+'</span>'
    + '</div>';
}

function hpCopyFromCalc() {
  for (var i=0;i<6;i++) {
    var src = document.getElementById('ivev-iv-'+i);
    var dst = document.getElementById('hp-iv-'+i);
    if (src && dst) dst.value = src.value || 31;
  }
  calcHP();
}

function hpSetIVs(hp,atk,def,spa,spd,spe) {
  var vals=[hp,atk,def,spa,spd,spe];
  for(var i=0;i<6;i++){
    var inp=document.getElementById('hp-iv-'+i);
    if(inp) inp.value=vals[i];
  }
  calcHP();
}

// Run on page init
(function(){ calcHP(); })();

// Init grid on page load
(function() {
  // Build empty grid
  var grid = document.getElementById('ivev-stat-grid');
  if (!grid) return;
  var statRowsHtml = IVEV_STAT_NAMES.map(function(name, i) {
    return '<div class="ivev-cell" style="display:flex;align-items:center;justify-content:center">'
      +'<span class="ivev-cell-label" style="color:'+IVEV_STAT_COLS[i]+'">'+name+'</span>'
      +'</div>'
      +'<div class="ivev-cell ivev-cell-base" id="ivev-base-'+i+'">—</div>'
      +'<div class="ivev-cell"><input class="ivev-inp" id="ivev-iv-'+i+'" type="number" min="0" max="31" value="31" oninput="ivevIVChange('+i+',this)"></div>'
      +'<div class="ivev-cell"><input class="ivev-inp" id="ivev-ev-'+i+'" type="number" min="0" max="252" value="0" oninput="ivevEVChange('+i+',this)"></div>'
      +'<div class="ivev-cell" id="ivev-nat-'+i+'" style="font-size:11px;font-weight:800;color:var(--muted)">×1.0</div>'
      +'<div class="ivev-cell ivev-result-cell" id="ivev-res-'+i+'" style="color:'+IVEV_STAT_COLS[i]+'">—</div>'
      +'<div class="ivev-bar-cell" id="ivev-bar-cell-'+i+'"><div class="ivev-stat-bar-wrap"><div class="ivev-stat-bar" id="ivev-bar-'+i+'" style="width:0%;background:'+IVEV_STAT_COLS[i]+'"></div></div></div>';
  }).join('');
  grid.innerHTML = grid.innerHTML + statRowsHtml;
})();

// ══ COMPARISON TOOL ═══════════════════════════════════════════
var CMP_A = null, CMP_B = null, CMP_TAB = 'stats';

var CMP_TYPE_COLORS = {normal:'#9E9E9E',fire:'#E8501A',water:'#1B8FE8',grass:'#3DA83D',electric:'#D4A800',ice:'#60C8C8',fighting:'#B83020',poison:'#8B3099',ground:'#8B6840',flying:'#6850C0',psychic:'#D01868',bug:'#78A810',rock:'#807840',ghost:'#4030A0',dragon:'#5038E8',dark:'#403030',steel:'#9898A8'};
var CMP_STAT_NAMES = ['HP','Atk','Def','SpA','SpD','Spe'];
var CMP_STAT_COLS  = ['#ef5350','#FF6B35','#9E9E9E','#64b4ff','#81C784','#FFD700'];

function cmpTypePill(t) {
  return typeSprite(t);
}

// ── Search ──────────────────────────────────────────────────
function cmpSearch(side, val) {
  var dd = document.getElementById('cmp-' + side + '-dd');
  if (!val) { dd.style.display = 'none'; return; }
  var q = val.toLowerCase();
  var hits = POKE.filter(function(p) {
    return p.name.toLowerCase().indexOf(q) !== -1 || String(p.num).indexOf(q) !== -1;
  }).slice(0, 12);
  if (!hits.length) { dd.style.display = 'none'; return; }
  dd.innerHTML = hits.map(function(p) {
    return '<div class="cmp-dd-item" onmousedown="cmpSelect(\'' + side + '\',' + p.num + ')">'
      + '<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + p.num + '.png" width="24" height="24" style="image-rendering:pixelated">'
      + '<span style="flex:1">' + p.name + '</span>'
      + '<span style="font-family:\'Press Start 2P\',monospace;font-size:6px;color:var(--muted)">#' + String(p.num).padStart(3,'0') + '</span>'
      + '</div>';
  }).join('');
  dd.style.display = 'block';
}

function cmpSelect(side, num) {
  var p = POKE.find(function(x) { return x.num === num; });
  if (!p) return;
  var data = { num: num, name: p.name, types: p.types, bs: BASE_STATS[num] || [80,80,80,80,80,80] };
  if (side === 'a') CMP_A = data; else CMP_B = data;
  document.getElementById('cmp-' + side + '-search').value = p.name;
  document.getElementById('cmp-' + side + '-dd').style.display = 'none';
  cmpRenderCard(side, data);
  cmpRenderPanel();
}

function cmpRenderCard(side, data) {
  var card = document.getElementById('cmp-' + side + '-card');
  var typeHtml = data.types.map(cmpTypePill).join('');
  card.style.display = 'flex';
  card.innerHTML = '<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + data.num + '.png">'
    + '<div style="flex:1">'
    + '<div class="cmp-poke-card-name">' + data.name + '</div>'
    + '<div class="cmp-poke-card-num">#' + String(data.num).padStart(3,'0') + '</div>'
    + '<div style="margin-top:4px">' + typeHtml + '</div>'
    + '</div>'
    + '<button class="cmp-clear-btn" onmousedown="cmpClear(\'' + side + '\')">✕</button>';
}

function cmpClear(side) {
  if (side === 'a') CMP_A = null; else CMP_B = null;
  document.getElementById('cmp-' + side + '-search').value = '';
  document.getElementById('cmp-' + side + '-card').style.display = 'none';
  cmpRenderPanel();
}

function cmpSetTab(tab, btn) {
  CMP_TAB = tab;
  document.querySelectorAll('.cmp-tab').forEach(function(b) { b.classList.remove('active'); });
  btn.classList.add('active');
  cmpRenderPanel();
}

// ── Main panel render ───────────────────────────────────────
function cmpRenderPanel() {
  var panel = document.getElementById('cmp-panel');
  if (!CMP_A && !CMP_B) {
    panel.innerHTML = '<div class="cmp-empty">Select two Pokémon above to compare.</div>';
    return;
  }
  // Show/hide contest tab based on game
  var isRSECtx = ['R','S','E'].includes(GAME);
  var contestTab = document.querySelector('.cmp-tab[onclick*="contest"]');
  if (contestTab) {
    contestTab.style.display = isRSECtx || GAME==='all' ? '' : 'none';
    if (!isRSECtx && GAME!=='all' && CMP_TAB==='contest') CMP_TAB='stats';
  }
  if (CMP_TAB === 'stats')         panel.innerHTML = cmpPanelStats();
  else if (CMP_TAB === 'moves')    panel.innerHTML = cmpPanelMoves();
  else if (CMP_TAB === 'abilities') panel.innerHTML = cmpPanelAbilities();
  else if (CMP_TAB === 'contest')  panel.innerHTML = cmpPanelContest();
  else if (CMP_TAB === 'breeding') panel.innerHTML = cmpPanelBreeding();
}

// ── STATS PANEL ─────────────────────────────────────────────
function cmpPanelStats() {
  var a = CMP_A, b = CMP_B;
  var placeholder = function(side) {
    return '<div style="text-align:center;padding:30px;color:var(--muted);font-style:italic">Select Pokémon ' + side.toUpperCase() + '</div>';
  };
  if (!a && !b) return placeholder('A') + placeholder('B');

  var bsA = a ? a.bs : null;
  var bsB = b ? b.bs : null;
  var bstA = bsA ? bsA.reduce(function(s,v){return s+v;},0) : 0;
  var bstB = bsB ? bsB.reduce(function(s,v){return s+v;},0) : 0;
  var maxStat = 255;

  var rows = CMP_STAT_NAMES.map(function(name, i) {
    var vA = bsA ? bsA[i] : null;
    var vB = bsB ? bsB[i] : null;
    var winA = vA !== null && vB !== null && vA > vB;
    var winB = vB !== null && vA !== null && vB > vA;
    var pctA = vA !== null ? Math.round(vA / maxStat * 100) : 0;
    var pctB = vB !== null ? Math.round(vB / maxStat * 100) : 0;
    var diffStr = (vA !== null && vB !== null) ? (vA - vB > 0 ? '<span style="color:#ef5350">+' + (vA-vB) + '</span>' : vA-vB < 0 ? '<span style="color:#64b4ff">' + (vA-vB) + '</span>' : '<span style="color:var(--muted)">0</span>') : '';
    return '<div class="cmp-stat-row">'
      + '<div class="cmp-stat-a" style="' + (winA?'color:#ef5350':'') + '">' + (vA !== null ? vA : '—') + '</div>'
      + '<div class="cmp-bar-a-wrap"><div class="cmp-bar-fill-a' + (winA?' winner':'') + '" style="width:' + pctA + '%"></div></div>'
      + '<div class="cmp-stat-name" style="color:' + CMP_STAT_COLS[i] + '">' + name + '</div>'
      + '<div style="font-size:9px;text-align:center">' + diffStr + '</div>'
      + '<div class="cmp-bar-b-wrap"><div class="cmp-bar-fill-b' + (winB?' winner':'') + '" style="width:' + pctB + '%"></div></div>'
      + '<div class="cmp-stat-b" style="' + (winB?'color:#64b4ff':'') + '">' + (vB !== null ? vB : '—') + '</div>'
      + '</div>';
  }).join('');

  var typeRowA = a ? a.types.map(cmpTypePill).join('') : '—';
  var typeRowB = b ? b.types.map(cmpTypePill).join('') : '—';

  var abA = a ? ABILITIES_DATA[a.num] : null;
  var abB = b ? ABILITIES_DATA[b.num] : null;
  var abStrA = abA ? abA.a1 + (abA.a2 ? ' / ' + abA.a2 : '') : '—';
  var abStrB = abB ? abB.a1 + (abB.a2 ? ' / ' + abB.a2 : '') : '—';

  var _sp = 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/';
  var vsHeader = '<div class="cmp-vs-header">'
    + '<div class="cmp-vs-slot">'
    + (a ? '<img class="cmp-vs-sprite" src="' + _sp + a.num + '.png" alt="' + a.name + '">' : '<div style="width:72px;height:72px"></div>')
    + '<div class="cmp-vs-name" style="color:#ef5350">' + (a ? a.name : '—') + '</div>'
    + '<div style="text-align:center">' + typeRowA + '</div>'
    + (bsA ? '<div class="cmp-vs-bst" style="background:rgba(239,83,80,0.12);color:#ef5350;border:1px solid rgba(239,83,80,0.3)">BST ' + bstA + '</div>' : '')
    + '</div>'
    + '<div class="cmp-vs-mid">VS</div>'
    + '<div class="cmp-vs-slot">'
    + (b ? '<img class="cmp-vs-sprite cmp-vs-sprite-b" src="' + _sp + b.num + '.png" alt="' + b.name + '">' : '<div style="width:72px;height:72px"></div>')
    + '<div class="cmp-vs-name" style="color:#64b4ff">' + (b ? b.name : '—') + '</div>'
    + '<div style="text-align:center">' + typeRowB + '</div>'
    + (bsB ? '<div class="cmp-vs-bst" style="background:rgba(100,180,255,0.12);color:#64b4ff;border:1px solid rgba(100,180,255,0.3)">BST ' + bstB + '</div>' : '')
    + '</div>'
    + '</div>';

  return '<div style="background:var(--card);border:1px solid var(--border);border-radius:10px;padding:16px;min-width:0;width:100%;box-sizing:border-box;">'
    + vsHeader
    + rows
    // BST row
    + '<div class="cmp-bst-row">'
    + '<div><span class="cmp-bst-val" style="color:var(--fire)">' + (bsA ? bstA : '—') + '</span> <span style="font-size:9px;color:var(--muted)">BST</span></div>'
    + '<div style="font-size:10px;color:var(--muted)">' + (bsA && bsB ? (bstA > bstB ? '<span style="color:#ef5350">A wins by ' + (bstA-bstB) + '</span>' : bstB > bstA ? '<span style="color:#64b4ff">B wins by ' + (bstB-bstA) + '</span>' : '<span style="color:var(--gold)">Equal</span>') : '') + '</div>'
    + '<div style="text-align:right"><span class="cmp-bst-val" style="color:#64b4ff">' + (bsB ? bstB : '—') + '</span> <span style="font-size:9px;color:var(--muted)">BST</span></div>'
    + '</div>'
    // Ability row
    + '<div style="display:grid;grid-template-columns:1fr auto 1fr;gap:8px;margin-top:10px;padding-top:10px;border-top:1px solid var(--border);font-size:11px">'
    + '<div style="color:var(--fire)">' + abStrA + '</div>'
    + '<div class="cmp-stat-name">ABILITY</div>'
    + '<div style="color:#64b4ff;text-align:right">' + abStrB + '</div>'
    + '</div>'
    + '</div>';
}

// ── MOVES PANEL ─────────────────────────────────────────────
function cmpPanelMoves() {
  if (!CMP_A && !CMP_B) return '<div class="cmp-empty">Select Pokémon to compare moves.</div>';

  var lsA = CMP_A ? LEARNSETS[CMP_A.num] : null;
  var lsB = CMP_B ? LEARNSETS[CMP_B.num] : null;

  function getMoveSet(ls) {
    var moves = new Set();
    if (!ls) return moves;
    (ls.level||[]).forEach(function(m){ moves.add(m[1]); });
    (ls.egg||[]).forEach(function(m){ moves.add(m); });
    (ls.tm||[]).forEach(function(n){ var name = TM_NAMES[n]; if(name) moves.add(name); });
    (ls.hm||[]).forEach(function(n){ var name = HM_NAMES[n]; if(name) moves.add(name); });
    return moves;
  }

  var setA = getMoveSet(lsA);
  var setB = getMoveSet(lsB);

  var shared = [], onlyA = [], onlyB = [];
  setA.forEach(function(m){ if(setB.has(m)) shared.push(m); else onlyA.push(m); });
  setB.forEach(function(m){ if(!setA.has(m)) onlyB.push(m); });
  shared.sort(); onlyA.sort(); onlyB.sort();

  function moveTag(name, cls) {
    return '<span class="cmp-move-tag ' + cls + '" onclick="goToMoveInDex(\'' + name + '\')" title="View in Move Dex">' + name + '</span>';
  }

  var html = '<div class="cmp-move-cols">'
    // Column A
    + '<div><div class="cmp-move-col-title" style="color:var(--fire)">' + (CMP_A ? CMP_A.name : 'Pokémon A') + ' (' + setA.size + ' moves)</div>'
    + (shared.length ? '<div class="cmp-move-section"><div class="cmp-move-section-label" style="color:var(--gold)">Shared (' + shared.length + ')</div>'
      + shared.map(function(m){return moveTag(m,'cmp-move-shared');}).join('')+'</div>' : '')
    + (onlyA.length ? '<div class="cmp-move-section"><div class="cmp-move-section-label">Unique to ' + (CMP_A?CMP_A.name:'A') + ' (' + onlyA.length + ')</div>'
      + onlyA.map(function(m){return moveTag(m,'cmp-move-unique');}).join('')+'</div>' : '')
    + (setA.size===0 ? '<div class="cmp-empty">No learnset data.</div>' : '')
    + '</div>'
    // Column B
    + '<div><div class="cmp-move-col-title" style="color:#64b4ff">' + (CMP_B ? CMP_B.name : 'Pokémon B') + ' (' + setB.size + ' moves)</div>'
    + (shared.length ? '<div class="cmp-move-section"><div class="cmp-move-section-label" style="color:var(--gold)">Shared (' + shared.length + ')</div>'
      + shared.map(function(m){return moveTag(m,'cmp-move-shared');}).join('')+'</div>' : '')
    + (onlyB.length ? '<div class="cmp-move-section"><div class="cmp-move-section-label">Unique to ' + (CMP_B?CMP_B.name:'B') + ' (' + onlyB.length + ')</div>'
      + onlyB.map(function(m){return moveTag(m,'cmp-move-unique');}).join('')+'</div>' : '')
    + (setB.size===0 ? '<div class="cmp-empty">No learnset data.</div>' : '')
    + '</div>'
    + '</div>';

  return '<div style="background:var(--card);border:1px solid var(--border);border-radius:10px;padding:16px;min-width:0;width:100%;box-sizing:border-box;">'
    + '<div style="font-size:10px;color:var(--muted);margin-bottom:12px">🟡 Shared moves click through to Move Dex. Learnset includes level-up, TM, HM, and egg moves.</div>'
    + html + '</div>';
}

// ── ABILITIES PANEL ─────────────────────────────────────────
function cmpPanelAbilities() {
  function abilityCard(num, name, side) {
    var ab = ABILITIES_DATA[num];
    var col = side === 'a' ? 'var(--fire)' : '#64b4ff';
    if (!ab) return '<div style="color:var(--muted);font-style:italic;padding:8px">No ability data.</div>';
    var html = '<div style="margin-bottom:8px">'
      + '<div class="cmp-ability-name" style="color:' + col + '">' + ab.a1 + '</div>'
      + '<div class="cmp-ability-slot">Ability slot 1</div>'
      + '</div>';
    if (ab.a2) {
      html += '<div style="border-top:1px solid var(--border);padding-top:8px;margin-top:8px">'
        + '<div class="cmp-ability-name" style="color:' + col + '">' + ab.a2 + '</div>'
        + '<div class="cmp-ability-slot">Ability slot 2</div>'
        + '</div>';
    }
    return html;
  }

  var html = '<div class="cmp-two-col">'
    + '<div class="cmp-ability-card" style="border-left:3px solid var(--fire)">'
    + '<div style="font-family:\'Press Start 2P\',monospace;font-size:6px;color:var(--fire);margin-bottom:10px">' + (CMP_A?CMP_A.name:'Pokémon A') + '</div>'
    + (CMP_A ? abilityCard(CMP_A.num, CMP_A.name, 'a') : '<div class="cmp-empty">Select Pokémon A</div>')
    + '</div>'
    + '<div class="cmp-ability-card" style="border-left:3px solid #64b4ff">'
    + '<div style="font-family:\'Press Start 2P\',monospace;font-size:6px;color:#64b4ff;margin-bottom:10px">' + (CMP_B?CMP_B.name:'Pokémon B') + '</div>'
    + (CMP_B ? abilityCard(CMP_B.num, CMP_B.name, 'b') : '<div class="cmp-empty">Select Pokémon B</div>')
    + '</div>'
    + '</div>';

  // Shared ability check
  if (CMP_A && CMP_B) {
    var abA = ABILITIES_DATA[CMP_A.num];
    var abB = ABILITIES_DATA[CMP_B.num];
    if (abA && abB) {
      var sharedAbs = [];
      [abA.a1, abA.a2].forEach(function(ab) {
        if (ab && (ab === abB.a1 || ab === abB.a2)) sharedAbs.push(ab);
      });
      if (sharedAbs.length) {
        html += '<div style="margin-top:12px;padding:10px 14px;background:rgba(255,215,0,0.06);border-left:3px solid var(--gold);border-radius:0 6px 6px 0;font-size:11px">'
          + '✦ Shared: <strong>' + sharedAbs.join(', ') + '</strong></div>';
      }
    }
  }

  return '<div style="background:var(--card);border:1px solid var(--border);border-radius:10px;padding:16px;min-width:0;width:100%;box-sizing:border-box;">' + html + '</div>';
}

// ── CONTEST PANEL ────────────────────────────────────────────
function cmpPanelContest() {
  if (!CMP_A && !CMP_B) return '<div class="cmp-empty">Select Pokémon to compare contest affinity.</div>';

  var CONTEST_CATS = ['Cool','Beauty','Cute','Smart','Tough'];
  var CONTEST_COLS = ['#E8501A','#1B8FE8','#D070D0','#3DA83D','#9898A8'];
  // Derive from base stats (same logic as renderContestPanel)
  function getContestVals(bs) {
    if (!bs) return null;
    return {
      Cool: bs[1], Beauty: bs[3], Cute: bs[5], Smart: bs[4], Tough: Math.round((bs[2]+bs[0])/2)
    };
  }

  var vA = CMP_A ? getContestVals(CMP_A.bs) : null;
  var vB = CMP_B ? getContestVals(CMP_B.bs) : null;

  var rows = CONTEST_CATS.map(function(cat, i) {
    var a = vA ? vA[cat] : null;
    var b = vB ? vB[cat] : null;
    var winA = a!==null && b!==null && a > b;
    var winB = b!==null && a!==null && b > a;
    var pctA = a !== null ? Math.round(a/255*100) : 0;
    var pctB = b !== null ? Math.round(b/255*100) : 0;
    var diff = (a!==null&&b!==null) ? (a-b>0?'<span style="color:#ef5350">+'+(a-b)+'</span>':a-b<0?'<span style="color:#64b4ff">'+(a-b)+'</span>':'<span style="color:var(--muted)">0</span>') : '';
    return '<div class="cmp-contest-row">'
      + '<div style="text-align:right;font-size:13px;font-weight:800;color:' + (winA?CONTEST_COLS[i]:'var(--muted)') + '">' + (a!==null?a:'—') + '</div>'
      + '<div class="cmp-bar-a-wrap"><div class="cmp-bar-fill-a' + (winA?' winner':'') + '" style="width:'+pctA+'%;background:'+CONTEST_COLS[i]+'88"></div></div>'
      + '<div style="font-size:9px;font-weight:800;text-align:center;color:'+CONTEST_COLS[i]+'">'+cat+'</div>'
      + '<div style="font-size:9px;text-align:center">' + diff + '</div>'
      + '<div class="cmp-bar-b-wrap"><div class="cmp-bar-fill-b' + (winB?' winner':'') + '" style="width:'+pctB+'%;background:'+CONTEST_COLS[i]+'88"></div></div>'
      + '<div style="font-size:13px;font-weight:800;color:' + (winB?CONTEST_COLS[i]:'var(--muted)') + '">' + (b!==null?b:'—') + '</div>'
      + '</div>';
  }).join('');

  return '<div style="background:var(--card);border:1px solid var(--border);border-radius:10px;padding:16px;min-width:0;width:100%;box-sizing:border-box;">'
    + '<div style="display:grid;grid-template-columns:60px 1fr 44px 44px 1fr 60px;gap:6px;margin-bottom:12px;padding-bottom:10px;border-bottom:1px solid var(--border)">'
    + '<div style="text-align:right;font-size:12px;font-weight:800;color:var(--fire)">' + (CMP_A?CMP_A.name:'—') + '</div>'
    + '<div></div><div></div><div></div><div></div>'
    + '<div style="font-size:12px;font-weight:800;color:#64b4ff">' + (CMP_B?CMP_B.name:'—') + '</div>'
    + '</div>'
    + rows
    + '<div style="font-size:10px;color:var(--muted);margin-top:12px;font-style:italic">Contest affinity derived from base stats. Cool=Atk, Beauty=SpAtk, Cute=Speed, Smart=SpDef, Tough=avg(Def+HP).</div>'
    + '</div>';
}

// ── BREEDING PANEL ───────────────────────────────────────────
function cmpPanelBreeding() {
  function breedCard(data, side) {
    if (!data) return '<div class="cmp-empty">Select Pokémon ' + side + '.</div>';
    var col = side === 'A' ? 'var(--fire)' : '#64b4ff';
    var groups = EGG_GROUPS_DATA[data.num] || ['Unknown'];
    var groupHtml = groups.map(function(g) {
      return '<span style="background:rgba(255,215,0,0.1);border:1px solid rgba(255,215,0,0.3);color:var(--gold);font-size:9px;font-weight:800;padding:2px 7px;border-radius:3px;margin-right:4px">🥚 ' + g + '</span>';
    }).join('');
    var ls = LEARNSETS[data.num];
    var eggMoves = ls && ls.egg ? ls.egg : [];
    var eggHtml = eggMoves.length
      ? eggMoves.map(function(m){ return '<span class="cmp-move-tag cmp-move-unique" onclick="goToMoveInDex(\''+m+'\')" title="View in Move Dex">'+m+'</span>'; }).join('')
      : '<span style="font-size:10px;color:var(--muted);font-style:italic">None on record</span>';
    return '<div style="border-left:3px solid ' + col + ';padding-left:12px">'
      + '<div style="font-family:\'Press Start 2P\',monospace;font-size:6px;color:' + col + ';margin-bottom:10px">' + data.name + '</div>'
      + '<div style="margin-bottom:10px"><div style="font-size:9px;font-weight:800;color:var(--muted);text-transform:uppercase;margin-bottom:6px">Egg Groups</div>' + groupHtml + '</div>'
      + '<div><div style="font-size:9px;font-weight:800;color:var(--muted);text-transform:uppercase;margin-bottom:6px">Egg Moves</div>' + eggHtml + '</div>'
      + '</div>';
  }

  // Shared egg group check
  var sharedGroups = [];
  if (CMP_A && CMP_B) {
    var gA = EGG_GROUPS_DATA[CMP_A.num] || [];
    var gB = EGG_GROUPS_DATA[CMP_B.num] || [];
    gA.forEach(function(g) { if (gB.indexOf(g) !== -1 && g !== 'Undiscovered') sharedGroups.push(g); });
  }

  var compatNote = CMP_A && CMP_B
    ? (sharedGroups.length
        ? '<div style="padding:10px 14px;background:rgba(76,175,80,0.08);border-left:3px solid #81C784;border-radius:0 6px 6px 0;font-size:11px;margin-bottom:14px">✓ <strong>' + CMP_A.name + '</strong> and <strong>' + CMP_B.name + '</strong> share egg group(s): <strong>' + sharedGroups.join(', ') + '</strong> — they can breed together.</div>'
        : '<div style="padding:10px 14px;background:rgba(255,107,53,0.07);border-left:3px solid var(--fire);border-radius:0 6px 6px 0;font-size:11px;margin-bottom:14px">✗ <strong>' + CMP_A.name + '</strong> and <strong>' + CMP_B.name + '</strong> have no shared egg groups — they cannot breed together.</div>')
    : '';

  return '<div style="background:var(--card);border:1px solid var(--border);border-radius:10px;padding:16px;min-width:0;width:100%;box-sizing:border-box;">'
    + compatNote
    + '<div class="cmp-two-col">'
    + '<div>' + breedCard(CMP_A, 'A') + '</div>'
    + '<div>' + breedCard(CMP_B, 'B') + '</div>'
    + '</div></div>';
}


// ═══════════════════════════════════════════════════════════
// QoL: Theme, Universal Search, Game persistence, Print
// ═══════════════════════════════════════════════════════════

// ── THEME ─────────────────────────────────────────────────
function toggleTheme() {
  const isLight = document.body.classList.toggle('light-theme');
  document.getElementById('themeToggle').textContent = isLight ? '☀️' : '🌙';
  localStorage.setItem('gen3-theme', isLight ? 'light' : 'dark');
  var sel = document.getElementById('settingsTheme');
  if (sel) sel.value = isLight ? 'light' : 'dark';
}
(function initTheme() {
  const saved = localStorage.getItem('gen3-theme');
  if (saved === 'light') {
    document.body.classList.add('light-theme');
    const btn = document.getElementById('themeToggle');
    if (btn) btn.textContent = '☀️';
  }
})();

(function initAppearancePrefs() {
  const savedDensity = localStorage.getItem('gen3-density');
  if (savedDensity) {
    setDensity(savedDensity, document.querySelector('.density-btn[onclick*="' + savedDensity + '"]'));
  }
  const savedFont = localStorage.getItem('gen3-font-size');
  if (savedFont) {
    const mainSlider = document.getElementById('fontSizeSlider');
    if (mainSlider) mainSlider.value = savedFont;
    setFontSize(savedFont);
  }
  SHOW_EVO_CHAIN = prefBool('gen3-default-evo-chain', false);
  USE_NATIVE_DEX = prefGet('gen3-dex-numbering', 'national') === 'game';
  BEST_RATE_MODE = prefGet('gen3-best-rate-mode', 'off');
  EASYDEX_TAB = prefGet('gen3-easydex-tab', 'catch');
  EASYDEX_HIDE_CAUGHT = prefBool('gen3-easydex-hide-caught', true);
  TRK_FILTER = prefGet('gen3-tracker-filter', 'all');
  TRK_MARK_MODE = prefGet('gen3-tracker-mark-mode', 'caught');
  window._shinyMode = prefBool('gen3-shiny-sprites', false);
  settingsApplyAccessibilityPrefs();
})();

// ── GAME PERSISTENCE ──────────────────────────────────────
(function initGame() {
  const startupMode = localStorage.getItem('gen3-startup-mode') || 'default';
  const savedLast = localStorage.getItem('gen3-game');
  const savedDefault = localStorage.getItem('gen3-default-game');
  const saved = startupMode === 'default'
    ? (savedLast || savedDefault || 'all')
    : (savedLast || savedDefault || 'all');
  if (saved) {
    // Find the game button and click it after DOM is ready
    const trySet = () => {
      if (typeof setGameFromHeader === 'function') {
        setGameFromHeader(saved, null);
        return;
      }
      const btns = document.querySelectorAll('.game-tab');
      btns.forEach(btn => {
        if (btn.onclick && btn.onclick.toString().includes("'" + saved + "'")) btn.click();
      });
    };
    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', trySet, { once:true });
    else trySet();
  }
})();

(function initStartupPage() {
  const startupMode = localStorage.getItem('gen3-startup-mode') || 'restore';
  const hashRoute = getHashRoute();
  const hashPageId = hashRoute.page;
  const pageId = hashPageId || (startupMode === 'restore'
    ? (localStorage.getItem('gen3-last-page') || localStorage.getItem('gen3-default-page') || 'home')
    : (localStorage.getItem('gen3-default-page') || 'home'));
  const openPage = function() {
    if (hashPageId) { applyHashRoute(hashRoute); return; }
    if (pageId === 'home') { resetHome(); return; }

    // Map page id → { btn, init } where init() builds the page if not yet built
    const pageMap = {
      dex:         { btn:'navDex',          init: function(){ buildTable(); } },
      bulba:       { btn:'navBulba',         init: function(){ if(!window._bulbaBuilt){buildBulbaGuide();window._bulbaBuilt=true;} bulbaAutoSelectGame(); } },
      tracker:     { btn:'navTracker',       init: function(){ buildTracker(); window._trackerBuilt = true; } },
      moves:       { btn:'navMoves',         init: function(){ if(!window._movesBuilt){buildMoveDex();window._movesBuilt=true;} } },
      tmhm:        { btn:'navTmhm',          init: null },
      tutors:      { btn:'navTutors',        init: function(){ if(window.ensurePageReady) window.ensurePageReady('tutors'); } },
      items:       { btn:'navItems',         init: function(){ if(!window._itemsBuilt){buildItemDex();window._itemsBuilt=true;} } },
      held:        { btn:'navHeld',          init: function(){ if(!window._heldBuilt){buildHeldItems();window._heldBuilt=true;} } },
      itemlocs:    { btn:'navItemLocs',      init: function(){ if(window.ensurePageReady) window.ensurePageReady('itemlocs'); } },
      excl:        { btn:'navExcl',          init: function(){ if(!window._exclBuilt){buildExcl();window._exclBuilt=true;} } },
      easydex:     { btn:'navEasydex',       init: function(){ renderEasyDexPage();window._easyDexBuilt=true; } },
      tradeevo:    { btn:'navTradeEvo',      init: function(){ if(!window._tradevoBuilt){renderTradeEvoPage();window._tradevoBuilt=true;} } },
      npctrades:   { btn:'navNpcTrades',     init: function(){ if(!window._npcTradesBuilt){buildNpcTradesPage();window._npcTradesBuilt=true;} } },
      abilities:   { btn:'navAbilities',     init: function(){ if(window.ensurePageReady) window.ensurePageReady('abilities'); } },
      learnsets:   { btn:'navLearnsets',     init: function(){ if(window.ensurePageReady) window.ensurePageReady('learnsets'); } },
      encounters:  { btn:'navEncounters',    init: function(){ if(window.ensurePageReady) window.ensurePageReady('encounters'); } },
      kantomapview:{ btn:'navKantoMapView', init: function(){ if(!window._kantomapviewBuilt){buildKantoMapView();window._kantomapviewBuilt=true;} } },
      emeraldmapview:{ btn:'navEmeraldMapView', init: function(){ if(!window._emeraldmapviewBuilt){buildEmeraldMapView();window._emeraldmapviewBuilt=true;} } },
      team:        { btn:'navTeam',          init: function(){ if(!window._teamBuilt){window._teamBuilt=true;tbApplyRestore();} } },
      calc:        { btn:'navCalc',          init: null },
      typechart:   { btn:'navTypeChart',     init: function(){ if(!window._typeChartBuilt){buildTypePage();window._typeChartBuilt=true;} } },
      speedtiers:  { btn:'navSpeedTiers',    init: function(){ if(!window._speedtiersBuilt){buildSpeedTiersPage();window._speedtiersBuilt=true;} } },
      compare:     { btn:'navCompare',       init: null },
      opt:         { btn:'navOpt',           init: null },
      essentials:  { btn:'navEssentials',    init: function(){ if(!window._essentialsBuilt){buildEssentialsPage();window._essentialsBuilt=true;} } },
      ivev:        { btn:'navIvev',          init: null },
      natures:     { btn:'navNatures',       init: null },
      expcalc:     { btn:'navExpCalc',       init: function(){ ensureExpCalcPage(); } },
      breed:       { btn:'navBreed',         init: null },
      catchcalc:   { btn:'navCatchCalc',     init: null },
      happiness:   { btn:'navHappiness',     init: null },
      dexdash:     { btn:'navDexDash',       init: function(){ buildDexDashPage(); } },
      ribbons:     { btn:'navRibbons',       init: function(){ if(!window._ribbonsBuilt){buildRibbonPage();window._ribbonsBuilt=true;} } },
      contests:    { btn:'navContests',      init: function(){ if(!window._contestsBuilt){buildContestsPage();window._contestsBuilt=true;} } },
      frontier:    { btn:'navFrontier',      init: function(){ if(!window._frontierBuilt){buildFrontierPage();window._frontierBuilt=true;} } },
      missables:   { btn:'navMissables',     init: function(){ if(!window._missablesBuilt){buildMissablesPage();window._missablesBuilt=true;} } },
      berries:     { btn:'navBerries',       init: function(){ if(!window._berriesBuilt){buildBerriesPage();window._berriesBuilt=true;} } },
      rng:         { btn:'navRng',           init: function(){ if(!window._rngBuilt){buildRngPage();window._rngBuilt=true;} } },
      distributions:{ btn:'navDistributions', init: function(){ if(typeof window.buildDistributionsPage === 'function') window.buildDistributionsPage(); } },
      distributionchecklist:{ btn:'navDistributions', init: function(){ showPage('distributions', document.getElementById('navDistributions')); if(typeof window.buildDistributionsPage === 'function') window.buildDistributionsPage(); } },
      safarizone:  { btn:'navSafariZone',    init: function(){ if(window.ensurePageReady) window.ensurePageReady('safarizone'); } },
      statcalc:    { btn:'navStatCalc',      init: function(){ if(window.ensurePageReady) window.ensurePageReady('statcalc'); } },
      pokeblock:   { btn:'navPokeblock',     init: function(){ if(window.ensurePageReady) window.ensurePageReady('pokeblock'); } },
      e4ref:       { btn:'navE4Ref',         init: function(){ if(window.ensurePageReady) window.ensurePageReady('e4ref'); } },
      rematches:   { btn:'navRematches',     init: function(){ if(window.ensurePageReady) window.ensurePageReady('rematches'); } },
      routebrowser:{ btn:'navRouteBrowser',  init: function(){ if(window.ensurePageReady) window.ensurePageReady('routebrowser'); } },
    };

    var entry = pageMap[pageId];
    if (!entry) return;
    // Show the page directly without relying on btn.click() (hidden on mobile)
    var btn = document.getElementById(entry.btn);
    showPage(pageId, btn);
    if (entry.init) entry.init();
  };
  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', openPage, { once:true });
  else openPage();
})();

(function initStartupFallback() {
  var fallbackBuilders = {
    home: function() { resetHome(); },
    tracker: function() { if (typeof window.openTopLevelPage === 'function') window.openTopLevelPage('tracker'); },
    routebrowser: function() { if (typeof window.openTopLevelPage === 'function') window.openTopLevelPage('routebrowser'); },
    easydex: function() { showPage('easydex', document.getElementById('navEasydex')); renderEasyDexPage(); window._easyDexBuilt = true; },
    excl: function() { showPage('excl', document.getElementById('navExcl')); buildExcl(); window._exclBuilt = true; },
    dexdash: function() { showPage('dexdash', document.getElementById('navDexDash')); buildDexDashPage(); },
    ribbons: function() { showPage('ribbons', document.getElementById('navRibbons')); buildRibbonPage(); window._ribbonsBuilt = true; },
    essentials: function() { showPage('essentials', document.getElementById('navEssentials')); buildEssentialsPage(); window._essentialsBuilt = true; },
    contests: function() { showPage('contests', document.getElementById('navContests')); buildContestsPage(); window._contestsBuilt = true; },
    frontier: function() { showPage('frontier', document.getElementById('navFrontier')); buildFrontierPage(); window._frontierBuilt = true; },
    missables: function() { showPage('missables', document.getElementById('navMissables')); buildMissablesPage(); window._missablesBuilt = true; },
    berries: function() { showPage('berries', document.getElementById('navBerries')); buildBerriesPage(); window._berriesBuilt = true; },
    rng: function() { showPage('rng', document.getElementById('navRng')); buildRngPage(); window._rngBuilt = true; }
  };

  function pageLooksEmpty(pageId) {
    if (pageId === 'home') {
      var home = document.getElementById('home-content');
      return !home || !home.innerHTML.trim();
    }
    if (pageId === 'routebrowser') {
      var areaList = document.getElementById('rb-area-list');
      var detail = document.getElementById('rb-detail');
      return (!areaList || !areaList.innerHTML.trim()) && (!detail || !detail.innerHTML.trim());
    }
    if (pageId === 'tracker') {
      var count = document.getElementById('trk-count');
      var grid = document.getElementById('trk-grid');
      return (!count || !count.textContent.trim()) && (!grid || !grid.innerHTML.trim());
    }
    if (pageId === 'easydex') {
      var panel = document.getElementById('easydex-panel');
      return !panel || !panel.innerHTML.trim();
    }
    if (pageId === 'excl') {
      var exclPage = document.getElementById('page-excl');
      return !exclPage || !/VERSION EXCLUSIVES|FR vs LG|R vs S|E UNIQUE/.test(exclPage.textContent || '');
    }
    var contentMap = {
      dexdash: 'dexdash-content',
      ribbons: 'ribbons-content',
      essentials: 'essentials-content',
      easydex: 'easydex-panel',
      contests: 'contests-content',
      frontier: 'frontier-content',
      missables: 'missables-content',
      berries: 'berries-content',
      rng: 'rng-content'
    };
    var contentId = contentMap[pageId];
    if (contentId) {
      var box = document.getElementById(contentId);
      return !box || !box.innerHTML.trim();
    }
    return false;
  }

  function ensureVisiblePageReady() {
    var route = getHashRoute();
    var pageId = route.page || localStorage.getItem('gen3-last-page') || 'home';
    var active = document.querySelector('.page.active');
    if (!active) {
      if (pageId === 'home') {
        resetHome();
      } else {
        applyHashRoute(route);
      }
      return;
    }
    if (pageId === 'home') {
      if (active.id !== 'page-home' || pageLooksEmpty('home')) resetHome();
      return;
    }
    if (pageLooksEmpty(pageId) || active.id !== 'page-' + pageId) {
      if (fallbackBuilders[pageId]) {
        fallbackBuilders[pageId]();
        return;
      }
      if (typeof window.openTopLevelPage === 'function') window.openTopLevelPage(pageId);
      return;
    }
    if (window.ensurePageReady) window.ensurePageReady(pageId);
  }

  function runFallback() {
    ensureVisiblePageReady();
    setTimeout(ensureVisiblePageReady, 0);
    setTimeout(ensureVisiblePageReady, 60);
    setTimeout(ensureVisiblePageReady, 180);
    setTimeout(ensureVisiblePageReady, 420);
    setTimeout(ensureVisiblePageReady, 800);
  }

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', runFallback, { once:true });
  else runFallback();
})();

(function initDeferredPrefs() {
  var apply = function() {
    var evoBtn = document.getElementById('evoToggle');
    var dexBtn = document.getElementById('dexToggle');
    var bestBtn = document.getElementById('bestRateToggle');
    if (evoBtn) evoBtn.classList.toggle('active', SHOW_EVO_CHAIN);
    if (dexBtn) dexBtn.classList.toggle('native', USE_NATIVE_DEX);
    if (bestBtn) {
      bestBtn.classList.toggle('active', BEST_RATE_MODE !== 'off');
      bestBtn.textContent = BEST_RATE_MODE === 'off' ? '📍 All Rates' : BEST_RATE_MODE === 'best' ? '📍 Best Only' : '📍 Best + Ties';
    }
    if (prefBool('gen3-search-open-on-load', false)) openSearch();
  };
  if (document.readyState === 'complete') apply();
  else window.addEventListener('load', apply);
})();

function settingsSyncDriveField() {
  var clientId = gen3GetDriveClientId();
  var connected = document.getElementById('driveConnected');
  var setup = document.getElementById('driveSetup');
  var status = document.getElementById('settingsDriveStatus');
  var originEl = document.getElementById('driveOriginDisplay');
  if (connected) connected.style.display = clientId ? '' : 'none';
  if (setup) setup.style.display = clientId ? 'none' : '';
  if (originEl) originEl.textContent = window.location.origin;
  if (status) status.textContent = clientId ? 'Drive linked. Use the Backup & Sync buttons below to save or restore.' : '';
}

function settingsSaveDriveClientId() {
  var input = document.getElementById('settingsDriveClientId');
  var status = document.getElementById('settingsDriveStatus');
  var value = input ? String(input.value || '').trim() : '';
  if (!value) {
    if (status) { status.textContent = 'Paste your Client ID first.'; status.style.color = 'var(--fire)'; }
    return;
  }
  try { localStorage.setItem('gen3-drive-client-id', value); } catch(e) {}
  settingsSyncDriveField();
  if (status) { status.textContent = 'Google Drive linked successfully.'; status.style.color = 'var(--emerald)'; }
}

function driveCopyOrigin(btn) {
  var origin = window.location.origin;
  if (!origin) return;
  navigator.clipboard.writeText(origin).then(function() {
    var orig = btn.textContent;
    btn.textContent = 'Copied!';
    setTimeout(function() { btn.textContent = orig; }, 1500);
  }).catch(function() {
    var el = document.getElementById('driveOriginDisplay');
    if (el) { el.focus(); el.select && el.select(); }
  });
}

