function shortcutKeyHtml(keys) {
  return '<span class="shortcuts-key">' + keys.map(function(key) { return '<kbd>' + key + '</kbd>'; }).join('') + '</span>';
}

function activePageKey() {
  var active = document.querySelector('.page.active');
  if (!active || !active.id) return 'dex';
  return active.id.replace(/^page-/, '');
}

function currentPageTitle() {
  var page = activePageKey();
  return ({
    dex:'Pokedex',
    guide:'Guide',
    bulba:'Bulba Guide',
    moves:'Moves',
    items:'Items',
    excl:'Exclusives',
    tracker:'Tracker',
    tmhm:'TM / HM',
    held:'Held Items',
    opt:'Optimizer',
    easydex:'Easy Dex',
    tradeevo:'Trade Evos',
    team:'Team Builder',
    calc:'Damage Calculator',
    ivev:'IV / EV Calculator',
    compare:'Pokemon Comparison',
    breed:'Breeding Calculator'
  })[page] || 'Current Page';
}

function getShortcutSections() {
  if (_shortcutsMode === 'all') {
    var all = GLOBAL_SHORTCUT_SECTIONS.slice();
    Object.keys(PAGE_SHORTCUTS).forEach(function(key) {
      (PAGE_SHORTCUTS[key] || []).forEach(function(sec) { all.push(sec); });
    });
    return all;
  }
  return GLOBAL_SHORTCUT_SECTIONS.concat(PAGE_SHORTCUTS[activePageKey()] || []);
}

function renderShortcutsOverlay() {
  var body = document.getElementById('shortcutsBody');
  if (!body) return;
  var sections = getShortcutSections();
  var intro = _shortcutsMode === 'all'
    ? 'Showing the full site-wide shortcut list.'
    : 'Showing shortcuts for ' + currentPageTitle() + ' plus the global ones that work everywhere.';
  body.innerHTML = '<div class="shortcuts-intro">' + intro + '</div>' + sections.map(function(section) {
    return '<div class="shortcuts-section"><div class="shortcuts-section-title">' + section.title + '</div><div class="shortcuts-list">'
      + section.items.map(function(item) {
        return shortcutKeyHtml(item.keys) + '<div class="shortcuts-desc">' + item.desc + '</div>';
      }).join('')
      + '</div></div>';
  }).join('');
  var toggle = document.getElementById('shortcutsScopeToggle');
  if (toggle) {
    toggle.classList.toggle('active', _shortcutsMode === 'all');
    toggle.textContent = _shortcutsMode === 'all' ? 'Show Current Page' : 'Show All';
  }
}

function openShortcutsOverlay(mode) {
  _shortcutsMode = mode === 'master' ? 'all' : 'context';
  closeFeaturesOverlay();
  var settingsOverlay = document.getElementById('settingsOverlay');
  _reopenSettingsAfterShortcuts = !!(settingsOverlay && settingsOverlay.classList.contains('open'));
  if (_reopenSettingsAfterShortcuts) closeSettingsOverlay();
  var overlay = document.getElementById('shortcutsOverlay');
  if (!overlay) return;
  overlay.classList.add('open');
  renderShortcutsOverlay();
}

function closeShortcutsOverlay() {
  var overlay = document.getElementById('shortcutsOverlay');
  if (overlay) overlay.classList.remove('open');
  if (_reopenSettingsAfterShortcuts) {
    _reopenSettingsAfterShortcuts = false;
    openSettingsOverlay();
  }
}

function toggleShortcutsScope() {
  _shortcutsMode = _shortcutsMode === 'all' ? 'context' : 'all';
  renderShortcutsOverlay();
}

function shortcutShouldIgnore(e) {
  var tag = (document.activeElement && document.activeElement.tagName) || '';
  if (['INPUT','TEXTAREA','SELECT'].includes(tag)) return true;
  if (document.activeElement && document.activeElement.isContentEditable) return true;
  return !!(e.metaKey || e.ctrlKey || e.altKey);
}

function shortcutGoPage(navId, pageId, buildFn) {
  var btn = document.getElementById(navId);
  if (!btn) return;
  showPage(pageId, btn);
  if (typeof buildFn === 'function') buildFn();
}

function shortcutSetGame(game) {
  if (typeof setGameFromHeader === 'function') setGameFromHeader(game, null);
}

function shortcutStartPrefix(key) {
  _shortcutPrefix = key;
  if (_shortcutPrefixTimer) clearTimeout(_shortcutPrefixTimer);
  _shortcutPrefixTimer = setTimeout(function() {
    _shortcutPrefix = null;
    _shortcutPrefixTimer = null;
  }, 900);
}

function shortcutClearPrefix() {
  _shortcutPrefix = null;
  if (_shortcutPrefixTimer) clearTimeout(_shortcutPrefixTimer);
  _shortcutPrefixTimer = null;
}

function shortcutTrackerFilter(name) {
  var btn = Array.prototype.slice.call(document.querySelectorAll('.trk-filter-btn')).find(function(el) {
    return (el.getAttribute('onclick') || '').indexOf("trkSetFilter('" + name + "'") !== -1;
  });
  if (btn) trkSetFilter(name, btn);
}

function shortcutTrackerSave(save) {
  var btn = Array.prototype.slice.call(document.querySelectorAll('.trk-save-tab')).find(function(el) {
    return (el.getAttribute('onclick') || '').indexOf("trkSetSave('" + save + "'") !== -1;
  });
  if (btn) trkSetSave(save, btn);
}

function openSearch() {
  const overlay = document.getElementById('searchOverlay');
  overlay.classList.add('open');
  document.getElementById('searchResults').innerHTML = '';
  _srIdx = -1;
  // Call focus synchronously (required for iOS to open keyboard within tap handler)
  const inp = document.getElementById('uSearchInput');
  if (inp) { inp.value = ''; inp.focus(); }
  // rAF fallback for browsers that need layout to settle first
  requestAnimationFrame(() => { if (inp) inp.focus(); });
}

function closeSearch() {
  document.getElementById('searchOverlay').classList.remove('open');
  _srIdx = -1;
}

// Keyboard shortcut: / to open, Escape to close
document.addEventListener('keydown', e => {
  if (e.key === 'Escape') {
    closeSearch();
    closeFeaturesOverlay();
    closeShortcutsOverlay();
    shortcutClearPrefix();
    return;
  }
  if (shortcutShouldIgnore(e)) return;
  const key = e.key;
  const lower = key.toLowerCase();
  if (lower === '?' || (key === '/' && e.shiftKey)) {
    e.preventDefault();
    openShortcutsOverlay('context');
    return;
  }
  if (key === '/' && !e.shiftKey) {
    e.preventDefault();
    openSearch();
    shortcutClearPrefix();
    return;
  }
  if (_shortcutPrefix === 'g') {
    e.preventDefault();
    shortcutClearPrefix();
    if (lower === 'h') resetHome();
    if (lower === 'd') shortcutGoPage('navDex', 'dex', function(){ buildTable(); });
    else if (lower === 'b') shortcutGoPage('navBulba', 'bulba', function(){ if(!window._bulbaBuilt){ buildBulbaGuide(); window._bulbaBuilt = true; } bulbaAutoSelectGame(); });
    else if (lower === 'm') shortcutGoPage('navMoves', 'moves', function(){ if(!window._movesBuilt){ buildMoveDex(); window._movesBuilt = true; } });
    else if (lower === 'u') shortcutGoPage('navTmhm', 'tmhm', function(){ if(!window._tmhmBuilt){ buildTmhmLocator(); window._tmhmBuilt = true; } });
    else if (lower === 'i') shortcutGoPage('navItems', 'items', function(){ if(!window._itemsBuilt){ buildItemDex(); window._itemsBuilt = true; } });
    else if (lower === 'x') shortcutGoPage('navExcl', 'excl', function(){ if(!window._exclBuilt){ buildExcl(); window._exclBuilt = true; } });
    else if (lower === 't') shortcutGoPage('navTracker', 'tracker', function(){ if(!window._trackerBuilt){ buildTracker(); window._trackerBuilt = true; } });
    else if (lower === 'l') shortcutGoPage('navHeld', 'held', function(){ if(!window._heldBuilt){ buildHeldItems(); window._heldBuilt = true; } });
    else if (lower === 'o') shortcutGoPage('navOpt', 'opt', function(){ renderOptimizerPage(); window._optBuilt = true; });
    else if (lower === 'e') shortcutGoPage('navEasydex', 'easydex', function(){ renderEasyDexPage(); window._easyDexBuilt = true; });
    else if (lower === 'r') shortcutGoPage('navTradeEvo', 'tradeevo', function(){ if(!window._tradevoBuilt){ renderTradeEvoPage(); window._tradevoBuilt = true; } });
    return;
  }
  if (lower === 'g') {
    e.preventDefault();
    shortcutStartPrefix('g');
    return;
  }
  if ('123456'.includes(key)) {
    e.preventDefault();
    shortcutSetGame(({ '1':'all','2':'FR','3':'LG','4':'R','5':'S','6':'E' })[key]);
    return;
  }
  if (lower === 'z') { e.preventDefault(); toggleTheme(); return; }

  const page = activePageKey();
  if (page === 'dex') {
    if (lower === 'f') {
      e.preventDefault();
      const input = document.getElementById('searchInput');
      if (input) input.focus();
      return;
    }
    if (lower === 'r') { e.preventDefault(); cycleBestRateMode(document.getElementById('bestRateToggle')); return; }
    if (lower === 'e') { e.preventDefault(); toggleEvoChain(document.getElementById('evoToggle')); return; }
    if (lower === 'n') { e.preventDefault(); toggleDexMode(document.getElementById('dexToggle')); return; }
  }
  if (page === 'easydex') {
    if (lower === 'x') { e.preventDefault(); easyDexToggleCaught(document.getElementById('easyDexCaughtToggle')); return; }
    if (lower === 'c') { e.preventDefault(); EASYDEX_TAB = 'catch'; renderEasyDexPage(); return; }
    if (lower === 't') { e.preventDefault(); EASYDEX_TAB = 'trade'; renderEasyDexPage(); return; }
    if (lower === 'l') { e.preventDefault(); EASYDEX_TAB = 'linktrade'; renderEasyDexPage(); return; }
    if (lower === 'v') { e.preventDefault(); EASYDEX_TAB = 'evolve'; renderEasyDexPage(); return; }
    if (lower === 's') { e.preventDefault(); EASYDEX_TAB = 'special'; renderEasyDexPage(); return; }
  }
  if (page === 'tracker') {
    if (lower === 'a') { e.preventDefault(); shortcutTrackerFilter('all'); return; }
    if (lower === 'u') { e.preventDefault(); shortcutTrackerFilter('uncaught'); return; }
    if (lower === 'h') { e.preventDefault(); shortcutTrackerFilter('caught'); return; }
    if (lower === 't') { e.preventDefault(); shortcutTrackerFilter('trade'); return; }
    if (e.shiftKey && e.code === 'Digit2') { e.preventDefault(); shortcutTrackerSave('FR'); return; }
    if (e.shiftKey && e.code === 'Digit3') { e.preventDefault(); shortcutTrackerSave('LG'); return; }
    if (e.shiftKey && e.code === 'Digit4') { e.preventDefault(); shortcutTrackerSave('R'); return; }
    if (e.shiftKey && e.code === 'Digit5') { e.preventDefault(); shortcutTrackerSave('S'); return; }
    if (e.shiftKey && e.code === 'Digit6') { e.preventDefault(); shortcutTrackerSave('E'); return; }
  }
  if (page === 'tmhm' && lower === 'f') {
    e.preventDefault();
    const input = document.getElementById('tmhm-search');
    if (input) input.focus();
    return;
  }
  if (page === 'held' && lower === 'f') {
    e.preventDefault();
    const input = document.getElementById('held-search');
    if (input) input.focus();
    return;
  }
  if (['guide','bulba','moves','items'].indexOf(page) !== -1 && lower === 'f') {
    e.preventDefault();
    openSearch();
    return;
  }
  if (page === 'opt') {
    if (lower === 'c') { e.preventDefault(); OPT_TAB = 'items'; renderOptimizerPage(); return; }
    if (lower === 'v') { e.preventDefault(); OPT_TAB = 'ev'; renderOptimizerPage(); return; }
    if (lower === 's') { e.preventDefault(); OPT_TAB = 'safari'; renderOptimizerPage(); return; }
  }
});

function searchNav(e) {
  const items = document.querySelectorAll('.sr-item[data-action-idx]');
  if (e.key === 'ArrowDown') { e.preventDefault(); _srIdx = Math.min(_srIdx + 1, items.length - 1); }
  else if (e.key === 'ArrowUp') { e.preventDefault(); _srIdx = Math.max(_srIdx - 1, 0); }
  else if (e.key === 'Enter') {
    e.preventDefault();
    if (_srIdx >= 0 && window._srActions && window._srActions[_srIdx]) {
      window._srActions[_srIdx]();
    } else if (items[0]) {
      // If nothing focused, run first result
      items[0].click();
    }
    return;
  }
  else if (e.key === 'Escape') { closeSearch(); return; }
  items.forEach((el, i) => el.classList.toggle('sr-focused', i === _srIdx));
  if (items[_srIdx]) items[_srIdx].scrollIntoView({ block: 'nearest' });
}

function _norm(s) {
  // Normalise accented chars so "poke" matches "Poké", "e" matches "é" etc.
  return (s || '').normalize('NFD').replace(/[̀-ͯ]/g, '').toLowerCase();
}

function _sectionMetaById(id) {
  const allSections = []
    .concat(typeof GUIDE_SECTIONS !== 'undefined' ? GUIDE_SECTIONS : [])
    .concat(typeof RSE_GUIDE_SECTIONS !== 'undefined' ? RSE_GUIDE_SECTIONS : []);
  return allSections.find(function(sec) { return sec.id === id; }) || null;
}

function _sectionIsRse(id) {
  return typeof RSE_GUIDE_SECTIONS !== 'undefined' && RSE_GUIDE_SECTIONS.some(function(sec) { return sec.id === id; });
}

function _openGuideSection(id) {
  closeSearch();
  setPageHash('bulba', id ? { guide: BULBA_GAME, section: id } : { guide: BULBA_GAME });
  const bulbaBtn = document.getElementById('navBulba');
  showPage('bulba', bulbaBtn);
  if (!window._bulbaBuilt) { buildBulbaGuide(); window._bulbaBuilt = true; }
  bulbaAutoSelectGame();
}

function _openDexSearch(query, openNum) {
  closeSearch();
  setPageHash('dex', openNum ? { pokemon: openNum } : (query ? { q: query } : null));
  const dexBtn = document.getElementById('navDex');
  showPage('dex', dexBtn);
  if (!window._dexBuilt) { buildTable(); window._dexBuilt = true; }
  setTimeout(function() {
    SEARCH = query;
    const si = document.getElementById('searchInput');
    if (si) {
      si.value = query;
      si.dispatchEvent(new Event('input'));
    } else {
      buildTable();
    }
    if (openNum) setTimeout(function() {
      var row = document.getElementById('poke-row-' + openNum);
      var container = document.getElementById('tablePanel');
      if (!row) {
        SEARCH = '';
        if (si) si.value = '';
        buildTable();
        row = document.getElementById('poke-row-' + openNum);
      }
      if (row) {
        if (openEvoNum !== openNum) toggleEvoRow(openNum);
        flashDexRow(openNum);
        if (container) {
          var rowTop = row.getBoundingClientRect().top;
          var containerTop = container.getBoundingClientRect().top;
          var thead = container.querySelector('thead');
          var theadH = thead ? thead.getBoundingClientRect().height : 0;
          container.scrollTo({ top: container.scrollTop + (rowTop - containerTop) - theadH - 14, behavior:'smooth' });
        }
      }
    }, 100);
  }, 80);
}

function _openMoveDex(moveName, moveId) {
  closeSearch();
  setPageHash('moves', { move: moveName || '', id: moveId || '' });
  goToMoveInDex(moveName);
  if (moveId) {
    setTimeout(function() {
      if (typeof mdexToggle === 'function') mdexToggle(moveId);
    }, 150);
  }
}

function _openItemDex(item) {
  closeSearch();
  var itemId = Array.isArray(item) ? item[0] : null;
  setPageHash('items', itemId ? { id: itemId } : null);
  const itemBtn = document.getElementById('navItems');
  showPage('items', itemBtn);
  if (!window._itemsBuilt) { buildItemDex(); window._itemsBuilt = true; }
  setTimeout(function() {
    const itInp = document.getElementById('itSearch');
    if (itInp) itInp.value = '';
    itOpenId = null;
    renderItemDex();
    if (itemId !== null) {
      setTimeout(function() {
        toggleItDet(itemId);
        requestAnimationFrame(function() {
          const el = document.getElementById('itr-' + itemId);
          if (el) el.scrollIntoView({ behavior:'smooth', block:'center' });
        });
      }, 80);
    }
  }, 150);
}

function _openTmhm(moveName, tmhmCode) {
  closeSearch();
  setPageHash('tmhm', { move: moveName || '', code: tmhmCode || '' });
  const btn = document.getElementById('navTmhm');
  showPage('tmhm', btn);
  if (!window._tmhmBuilt) { buildTmhmLocator(); window._tmhmBuilt = true; }
  setTimeout(function() {
    const inp = document.getElementById('tmhm-search');
    if (inp) {
      inp.value = tmhmCode || moveName || '';
      tmhmRender();
      const sc = document.getElementById('tmhm-scroll');
      if (sc) sc.scrollTop = 0;
    }
  }, 120);
}

function _openTutors(moveName) {
  closeSearch();
  setPageHash('tutors', moveName ? { move: moveName } : null);
  const btn = document.getElementById('navTutors');
  closeNavDropdown('navMovesItemsDropdown');
  showPage('tutors', btn);
  if (window.ensurePageReady) window.ensurePageReady('tutors');
  // Highlight the move row after render
  if (moveName) {
    setTimeout(function() {
      var rows = document.querySelectorAll('#page-tutors .tutors-table tbody tr');
      rows.forEach(function(row) {
        var cell = row.querySelector('td');
        if (cell && _norm(cell.textContent) === _norm(moveName)) {
          row.style.background = 'rgba(255,215,0,0.12)';
          row.scrollIntoView({ block:'center' });
        }
      });
    }, 150);
  }
}

function _openHeldSearch(query, category) {
  closeSearch();
  const btn = document.getElementById('navHeld');
  showPage('held', btn);
  if (!window._heldBuilt) { buildHeldItems(); window._heldBuilt = true; }
  setTimeout(function() {
    const inp = document.getElementById('held-search');
    const sel = document.getElementById('held-cat-filter');
    if (inp) inp.value = query || '';
    if (sel) sel.value = category || '';
    heldFilter();
  }, 120);
}

function _openCompareWithPokemon(num) {
  closeSearch();
  const btn = document.getElementById('navCompare');
  showPage('compare', btn);
  const side = !CMP_A ? 'a' : !CMP_B ? 'b' : 'b';
  setTimeout(function() {
    cmpSelect(side, num);
  }, 80);
}

function _openEasyDex(tab, game, focusText) {
  closeSearch();
  if (game && ['FR','LG','R','S','E','all'].indexOf(game) !== -1 && typeof setGameFromHeader === 'function') {
    setGameFromHeader(game, null);
  }
  const btn = document.getElementById('navEasydex');
  showPage('easydex', btn);
  window._easyDexBuilt = true;
  if (tab) EASYDEX_TAB = tab;
  setTimeout(function() {
    renderEasyDexPage();
    if (focusText) {
      var nodes = Array.prototype.slice.call(document.querySelectorAll('#easydex-panel [style], #easydex-panel div'));
      var target = nodes.find(function(el) {
        return _norm((el.textContent || '')).indexOf(_norm(focusText)) !== -1;
      });
      if (target) target.scrollIntoView({ behavior:'smooth', block:'center' });
    }
  }, 90);
}

function _searchGroupsTemplate() {
  return [
    { key:'Pages', label:'Pages', items:[] },
    { key:'Pokemon', label:'Pokémon', items:[] },
    { key:'Moves', label:'Moves', items:[] },
    { key:'Items', label:'Items', items:[] },
    { key:'Routes', label:'Routes & Locations', items:[] },
    { key:'Trainers', label:'Trainers', items:[] },
    { key:'Abilities', label:'Abilities', items:[] },
    { key:'Tutors', label:'Move Tutors', items:[] },
    { key:'HeldItems', label:'Held Items', items:[] },
    { key:'Berries', label:'Berries', items:[] },
    { key:'Guide', label:'Guide Chapters', items:[] },
    { key:'Evolution', label:'Evolution Methods', items:[] }
  ];
}

function runSearch(q) {
  const results = document.getElementById('searchResults');
  q = _norm(q.trim());
  if (q.length < 2) { results.innerHTML = ''; _srIdx = -1; return; }

  const groups = _searchGroupsTemplate();
  const byKey = {};
  groups.forEach(function(group) { byKey[group.key] = group.items; });

  const pushHit = function(groupKey, hit) {
    if (!byKey[groupKey]) return;
    byKey[groupKey].push(hit);
  };

  const sectionMeta = {}
  Object.keys(GUIDE_DATA || {}).forEach(function(id) {
    sectionMeta[id] = _sectionMetaById(id) || { id:id, toc:id.replace(/_/g, ' '), chapter:id.replace(/_/g, ' ') };
  });

  // ── Pokémon ──
  POKE.filter(function(p) {
    return _norm(p.name).includes(q) || p.types.some(function(t) { return _norm(t) === q; }) || String(p.num) === q;
  }).slice(0, 8).forEach(function(p) {
    pushHit('Pokemon', {
      img:`https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/${p.num}.png`,
      label:`#${String(p.num).padStart(3,'0')} ${p.name}`,
      sub:p.types.map(function(t) { return t.charAt(0).toUpperCase() + t.slice(1); }).join(' / '),
      tag:'Pokémon',
      action:function() { _openDexSearch(p.name, p.num); },
      related:[
        { label:'Dex', action:function() { _openDexSearch(p.name, p.num); } },
        { label:'Compare', action:function() { _openCompareWithPokemon(p.num); } },
        { label:'Learnset', action:function() { _openLearnsets(p.num); } }
      ]
    });
  });

  // ── Moves ──
  ALL_MOVES_DATA.filter(function(m) {
    return _norm(m[1]).includes(q) || _norm(m[2]) === q || _norm(m[7] || '').includes(q);
  }).slice(0, 6).forEach(function(m) {
    const moveName = m[1];
    pushHit('Moves', {
      icon:'⚔',
      label:moveName,
      sub:(m[2] ? m[2].charAt(0).toUpperCase() + m[2].slice(1) : 'Unknown') + ' · ' + m[3] + ' · Power: ' + (m[4] || '—'),
      tag:'Move',
      action:function() { _openMoveDex(moveName, m[0]); },
      related:[
        { label:'Move Dex', action:function() { _openMoveDex(moveName, m[0]); } },
        (TUTOR_NPC_DATA[moveName] ? { label:'Tutor', action:function() { _openTutors(moveName); } } : null)
      ].filter(Boolean)
    });
  });

  // ── Abilities ──
  Object.keys(ABILITY_DESCS).filter(function(name) {
    return _norm(name).includes(q) || _norm(ABILITY_DESCS[name]).includes(q);
  }).slice(0, 5).forEach(function(name) {
    var desc = ABILITY_DESCS[name] || '';
    // Count Pokémon with this ability
    var count = Object.keys(ABILITIES_DATA).filter(function(n) {
      var ab = ABILITIES_DATA[n]; return ab && (ab.a1 === name || ab.a2 === name);
    }).length;
    pushHit('Abilities', {
      icon:'⚡',
      label:name,
      sub:desc + (count ? ' · ' + count + ' Pokémon' : ''),
      tag:'Ability',
      action:function() { _openAbilities(name); },
      related:[{ label:'Abilities', action:function() { _openAbilities(name); } }]
    });
  });

  // ── Move Tutors ──
  Object.keys(TUTOR_NPC_DATA).filter(function(name) {
    var td = TUTOR_NPC_DATA[name];
    return _norm(name).includes(q) || _norm(td.npc).includes(q) || _norm(td.note).includes(q);
  }).slice(0, 6).forEach(function(name) {
    var td = TUTOR_NPC_DATA[name];
    pushHit('Tutors', {
      icon:'🎓',
      label:name,
      sub:td.npc + (td.note ? ' · ' + td.note : ''),
      tag:'Tutor',
      action:function() { _openTutors(name); },
      related:[
        { label:'Tutors', action:function() { _openTutors(name); } },
        { label:'Move Dex', action:function() { _openMoveDex(name); } }
      ]
    });
  });

  // ── Items ──
  ALL_ITEMS.filter(function(it) {
    const name = Array.isArray(it) ? it[1] : it.name;
    const desc = Array.isArray(it) ? (it[3] || '') : (it.desc || it.effect || '');
    const locs = Array.isArray(it) ? JSON.stringify(it[4] || {}) : (it.location || '');
    return _norm(name).includes(q) || _norm(desc).includes(q) || _norm(locs).includes(q);
  }).slice(0, 6).forEach(function(it) {
    const name = Array.isArray(it) ? it[1] : it.name;
    const desc = Array.isArray(it) ? (it[3] || '') : (it.desc || it.effect || '');
    pushHit('Items', {
      icon:'🎒',
      label:name,
      sub:desc,
      tag:'Item',
      action:function() { _openItemDex(it); },
      related:[
        { label:'Items', action:function() { _openItemDex(it); } }
      ]
    });
  });

  // ── Routes / Locations from guide data ──
  const routeSeen = new Set();
  Object.keys(GUIDE_DATA || {}).forEach(function(sectionId) {
    const secData = GUIDE_DATA[sectionId] || {};
    const sec = sectionMeta[sectionId];
    Object.keys(secData.wild || {}).forEach(function(locName) {
      const key = sectionId + '::' + locName;
      if (routeSeen.has(key)) return;
      const locNorm = _norm(locName);
      const sample = (secData.wild[locName] || []).slice(0, 3).map(function(e) { return e.name; }).join(', ');
      if (locNorm.includes(q) || _norm(sample).includes(q)) {
        routeSeen.add(key);
        pushHit('Routes', {
          icon:'🗺',
          label:locName,
          sub:(sec ? sec.toc + ' · ' : '') + ((secData.wild[locName] || []).length + ' encounter(s)') + (sample ? ' · ' + sample : ''),
          tag:'Route',
          action:function() { _openGuideSection(sectionId); },
          related:[
            { label:'Guide', action:function() { _openGuideSection(sectionId); } },
            { label:'Dex', action:function() { _openDexSearch(locName); } }
          ]
        });
      }
    });
  });

  // ── Trainers from guide data ──
  const trainerSeen = new Set();
  Object.keys(GUIDE_DATA || {}).forEach(function(sectionId) {
    const secData = GUIDE_DATA[sectionId] || {};
    const sec = sectionMeta[sectionId];
    const trainerEntries = [];
    (secData.area_trainers || []).forEach(function(tr) { trainerEntries.push({ kind:'Trainer', tr:tr }); });
    if (secData.gym) {
      if (secData.gym.leader) trainerEntries.push({ kind:'Leader', tr:{ class:secData.gym.type + ' Gym', name:secData.gym.leader, pokes:secData.gym.leader_team || [] } });
      (secData.gym.trainers || []).forEach(function(tr) { trainerEntries.push({ kind:'Gym Trainer', tr:tr }); });
    }
    (secData.trainers || []).forEach(function(tr) { trainerEntries.push({ kind:'Boss', tr:tr }); });
    if (secData.rival) trainerEntries.push({ kind:'Champion', tr:secData.rival });
    (secData.rivals || []).forEach(function(tr) { trainerEntries.push({ kind:'Rival', tr:tr }); });
    trainerEntries.forEach(function(entry) {
      const tr = entry.tr || {};
      const teamNames = (tr.pokes || tr.team || tr.bulba_team || []).map(function(p) { return p.name; }).join(', ');
      const hay = [tr.class, tr.name, teamNames, sec ? sec.toc : ''].map(_norm).join(' ');
      const key = sectionId + '::' + (tr.class || '') + '::' + (tr.name || '');
      if (!tr.name || trainerSeen.has(key) || !hay.includes(q)) return;
      trainerSeen.add(key);
      pushHit('Trainers', {
        icon:'👤',
        label:(tr.class ? tr.class + ' ' : '') + tr.name,
        sub:(sec ? sec.toc + ' · ' : '') + (teamNames || 'Guide section'),
        tag:'Trainer',
        action:function() { _openGuideSection(sectionId); },
        related:[
          { label:'Guide', action:function() { _openGuideSection(sectionId); } }
        ]
      });
    });
  });


  // ── Berries ──
  const berrySeen = new Set();
  HELD_ITEMS_DB.filter(function(it) {
    return it.cat === 'berry' && (_norm(it.name).includes(q) || _norm(it.effect).includes(q) || _norm(it.location).includes(q));
  }).slice(0, 6).forEach(function(it) {
    if (berrySeen.has(it.name)) return;
    berrySeen.add(it.name);
    pushHit('Berries', {
      icon:'🫐',
      label:it.name,
      sub:it.location,
      tag:'Berry',
      action:function() { _openHeldSearch(it.name, 'berry'); },
      related:[
        { label:'Held Items', action:function() { _openHeldSearch(it.name, 'berry'); } },
        { label:'Guide', action:function() { _openGuideSection(_norm(it.location).includes('route 123') || _norm(it.location).includes('berry master') ? 'rse_berries' : 'rse_repel'); } }
      ]
    });
  });

  // ── Held Items (non-berry) ──
  HELD_ITEMS_DB.filter(function(it) {
    return it.cat !== 'berry' && (_norm(it.name).includes(q) || _norm(it.effect).includes(q) || _norm(it.location).includes(q));
  }).slice(0, 6).forEach(function(it) {
    pushHit('HeldItems', {
      icon:'💎',
      label:it.name,
      sub:it.effect + ' · ' + it.location,
      tag:'Held Item',
      action:function() { _openHeldSearch(it.name, it.cat); },
      related:[
        { label:'Held Items', action:function() { _openHeldSearch(it.name, it.cat); } }
      ]
    });
  });

  // ── Guide chapters ──
  []
    .concat(typeof GUIDE_SECTIONS !== 'undefined' ? GUIDE_SECTIONS : [])
    .concat(typeof RSE_GUIDE_SECTIONS !== 'undefined' ? RSE_GUIDE_SECTIONS : [])
    .filter(function(sec) {
      return _norm(sec.toc).includes(q) || _norm(sec.chapter || '').includes(q) || _norm((sec.content || '').replace(/<[^>]+>/g, ' ')).includes(q);
    })
    .slice(0, 6)
    .forEach(function(sec) {
      pushHit('Guide', {
        icon:'📖',
        label:sec.toc,
        sub:sec.chapter || '',
        tag:'Guide',
        action:function() { _openGuideSection(sec.id); },
        related:[
          { label:'Guide', action:function() { _openGuideSection(sec.id); } }
        ]
      });
    });

  // ── Evolution methods ──
  const evoHits = [];
  POKE.forEach(function(p) {
    Object.keys(p.games || {}).forEach(function(gk) {
      const lines = (p.games[gk] || '').split('\n').map(function(line) { return line.trim(); }).filter(Boolean);
      lines.forEach(function(line) {
        const normLine = _norm(line);
        if (!/^evolve|^trade /.test(normLine)) return;
        if (!_norm(p.name).includes(q) && !normLine.includes(q)) return;
        evoHits.push({
          pokemon:p,
          line:line,
          game:gk
        });
      });
    });
  });
  evoHits.slice(0, 6).forEach(function(hit) {
    pushHit('Evolution', {
      icon:'🔄',
      label:hit.pokemon.name,
      sub:hit.line + ' · ' + hit.game,
      tag:'Evolution',
      action:function() { _openDexSearch(hit.pokemon.name, hit.pokemon.num); },
      related:[
        { label:'Dex', action:function() { _openDexSearch(hit.pokemon.name, hit.pokemon.num); } },
        { label:'Trade Evos', action:function() {
          closeSearch();
          const btn = document.getElementById('navTradeEvo');
          showPage('tradeevo', btn);
          if (!window._tradevoBuilt) { renderTradeEvoPage(); window._tradevoBuilt = true; }
        } }
      ]
    });
  });

  // ── Easy Dex / Bulbapedia route planner ──
  const easyDexTabs = [
    { tab:'catch', label:'Easy Dex Route', sub:'Best direct catches in Bulbapedia route order', keywords:'easy dex best catches route planner chronological bulbapedia' },
    { tab:'trade', label:'Easy Dex - In-Game Trades', sub:'NPC trades grouped into the walkthrough order', keywords:'easy dex in game trades npc swaps trade route' },
    { tab:'linktrade', label:'Easy Dex - Link Trades', sub:'Trade evolutions and cross-version trade cleanup', keywords:'easy dex link trades trade evolutions cross version alakazam gengar golem scizor kingdra porygon2' },
    { tab:'evolve', label:'Easy Dex - Evolution-Only', sub:'Species that need evolving rather than direct catching', keywords:'easy dex evolution only evolve cleanup' },
    { tab:'special', label:'Easy Dex - Special / Gift', sub:'Starters, fossils, gifts, breeding and event one-offs', keywords:'easy dex special gift starters fossils breeding events' }
  ];
  easyDexTabs.forEach(function(tab) {
    if (_norm(tab.label).includes(q) || _norm(tab.sub).includes(q) || _norm(tab.keywords).includes(q)) {
      pushHit('Guide', {
        icon:'🗺',
        label:tab.label,
        sub:tab.sub,
        tag:'Easy Dex',
        action:function() { _openEasyDex(tab.tab, GAME === 'all' ? 'FR' : GAME); },
        related:[
          { label:'Easy Dex', action:function() { _openEasyDex(tab.tab, GAME === 'all' ? 'FR' : GAME); } }
        ]
      });
    }
  });

  const easyDexGames = GAME === 'all' ? ['FR','LG','R','S','E'] : [GAME];
  const easyDexRouteSeen = new Set();
  easyDexGames.forEach(function(game) {
    if (!['FR','LG','R','S','E'].includes(game)) return;
    easyDexBuildSections(game).forEach(function(section) {
      var hay = _norm([section.title, section.sub].concat(section.terms || []).join(' '));
      if (!hay.includes(q)) return;
      var key = game + '::' + section.title;
      if (easyDexRouteSeen.has(key)) return;
      easyDexRouteSeen.add(key);
      pushHit('Routes', {
        icon:'🧭',
        label:section.title,
        sub:easyDexGameLabel(game) + ' · Easy Dex route stop' + (section.sub ? ' · ' + section.sub : ''),
        tag:'Easy Dex',
        action:function() { _openEasyDex('catch', game, section.title); },
        related:[
          { label:'Easy Dex', action:function() { _openEasyDex('catch', game, section.title); } }
        ]
      });
    });
  });

  // ── Static guide pages (Speed Tiers, Contests, Battle Frontier, Missables, Berry Farming) ──
  var staticGuidePages = [
    {
      icon:'🧭', label:'Beginner Essentials', tag:'Guide',
      sub:'Grass, fishing, surfing, HMs, status, catching, money, and early-game flow',
      keywords:'beginner essentials basics onboarding grass fishing surfing hm status catching money lost stuck new player',
      action:function() { closeSearch(); var btn=document.getElementById('navEssentials'); closeNavDropdown('navGuidesDropdown'); showPage('essentials',btn); if(!window._essentialsBuilt){buildEssentialsPage();window._essentialsBuilt=true;} }
    },
    {
      icon:'⚡', label:'Speed Tiers', tag:'Guide',
      sub:'Gen 3 Speed stat benchmarks for all 386 Pokémon',
      keywords:'speed tiers fast slow benchmark competitive ironmon outspeeds',
      action:function() { closeSearch(); var btn=document.getElementById('navSpeedTiers'); closeNavDropdown('navBattleDropdown'); showPage('speedtiers',btn); if(!window._speedtiersBuilt){buildSpeedTiersPage();window._speedtiersBuilt=true;} }
    },
    {
      icon:'🎀', label:'Contest Guide', tag:'Guide',
      sub:'Pokémon Contests — conditions, Pokéblocks, appeal/jamming, ribbons',
      keywords:'contest normal cool cute smart tough ribbon pokéblock condition appeal jamming rank master',
      action:function() { closeSearch(); var btn=document.getElementById('navContests'); closeNavDropdown('navGuidesDropdown'); showPage('contests',btn); if(!window._contestsBuilt){buildContestsPage();window._contestsBuilt=true;} }
    },
    {
      icon:'🏆', label:'Battle Frontier Guide', tag:'Guide',
      sub:'Emerald Battle Frontier — all 7 facilities, Frontier Brains, streaks',
      keywords:'battle frontier tower dome factory pike pyramid arena palace brain streak emerald',
      action:function() { closeSearch(); var btn=document.getElementById('navFrontier'); closeNavDropdown('navGuidesDropdown'); showPage('frontier',btn); if(!window._frontierBuilt){buildFrontierPage();window._frontierBuilt=true;} }
    },
    {
      icon:'⚠', label:'Missables Checklist', tag:'Guide',
      sub:'Interactive checklist of missable Pokémon, items and one-time events',
      keywords:'missable missables one time event checklist permanent choice gift legendary',
      action:function() { closeSearch(); var btn=document.getElementById('navMissables'); closeNavDropdown('navProgressDropdown'); showPage('missables',btn); if(!window._missablesBuilt){buildMissablesPage();window._missablesBuilt=true;} }
    },
    {
      icon:'🫐', label:'Berry Farming Guide', tag:'Guide',
      sub:'Berry growth cycles, mutations, Berry Master phrases (RSE)',
      keywords:'berry farming growth cycle mutation master phrase emerald oran sitrus lum wiki',
      action:function() { closeSearch(); var btn=document.getElementById('navBerries'); closeNavDropdown('navGuidesDropdown'); showPage('berries',btn); if(!window._berriesBuilt){buildBerriesPage();window._berriesBuilt=true;} }
    }
  ];
  staticGuidePages.forEach(function(pg) {
    if (_norm(pg.label).includes(q) || _norm(pg.sub).includes(q) || _norm(pg.keywords).includes(q)) {
      pushHit('Guide', { icon:pg.icon, label:pg.label, sub:pg.sub, tag:pg.tag, action:pg.action, related:[{ label:pg.label, action:pg.action }] });
    }
  });

  // ── Auto-scan nav buttons so every page is always searchable ──
  // Regular nav buttons (excluding dropdown trigger labels like "POKÉMON ▾")
  document.querySelectorAll('.page-nav-btn:not(.page-nav-dropdown-trigger)').forEach(function(btn) {
    var label = btn.textContent.replace(/▾/g,'').trim();
    if (!label || !_norm(label).includes(q)) return;
    (function(el){ pushHit('Pages', { icon:'📄', label:label, sub:'', tag:'Page', action:function(){ closeSearch(); el.click(); } }); })(btn);
  });
  // Dropdown item buttons
  document.querySelectorAll('.page-nav-dropdown-item').forEach(function(btn) {
    var label = btn.textContent.trim();
    if (!label || !_norm(label).includes(q)) return;
    (function(el){ pushHit('Pages', { icon:'📄', label:label, sub:'', tag:'Page', action:function(){ closeSearch(); el.click(); } }); })(btn);
  });

  const populated = groups.filter(function(group) { return group.items.length; });
  if (!populated.length) {
    results.innerHTML = '<div class="sr-empty">No results found</div>';
    _srIdx = -1;
    return;
  }

  const actionList = [];
  let actionIdx = 0;
  const html = populated.map(function(group) {
    const rows = group.items.map(function(hit) {
      const currentIdx = actionIdx++;
      actionList[currentIdx] = hit.action;
      const media = hit.img
        ? '<img src="' + hit.img + '" alt="">'
        : '<div style="width:32px;height:32px;display:flex;align-items:center;justify-content:center;font-size:20px">' + (hit.icon || '•') + '</div>';
      const sub = (hit.sub || '').length > 110 ? hit.sub.slice(0, 110) + '…' : (hit.sub || '');
      const related = (hit.related || []).map(function(rel) {
        const relIdx = actionIdx++;
        actionList[relIdx] = rel.action;
        return '<button class="sr-related-btn" onclick="event.stopPropagation();window._srActions[' + relIdx + '] && window._srActions[' + relIdx + ']()">' + rel.label + '</button>';
      }).join('');
      return '<div class="sr-item" onclick="window._srActions[' + currentIdx + '] && window._srActions[' + currentIdx + ']()" data-action-idx="' + currentIdx + '">'
        + media
        + '<div style="min-width:0;flex:1">'
        + '<div class="sr-label">' + hit.label + '</div>'
        + '<div class="sr-sub">' + sub + '</div>'
        + (related ? '<div class="sr-related">' + related + '</div>' : '')
        + '</div>'
        + '<span class="sr-tag">' + hit.tag + '</span>'
        + '</div>';
    }).join('');
    return '<div class="sr-section"><div class="sr-section-head"><span>' + group.label + '</span><span class="sr-section-count">' + group.items.length + '</span></div>' + rows + '</div>';
  }).join('');

  window._srActions = actionList;
  _srIdx = -1;
  results.innerHTML = html;
  animateSearchResults();
}

