// ══════════════════════════════════════════════════════════════════
//  BREEDING CALCULATOR
// ══════════════════════════════════════════════════════════════════
var BREED_A = null, BREED_B = null;

function buildBreedCalc() { /* lazy-built on first show */ }

function breedSearch(side, val) {
  var dd = document.getElementById('breed-' + side + '-dd');
  if (!val) { dd.style.display = 'none'; return; }
  var q = val.toLowerCase();
  var hits = POKE.filter(function(p) {
    return p.name.toLowerCase().indexOf(q) !== -1 || String(p.num).indexOf(q) !== -1;
  }).slice(0, 10);
  if (!hits.length) { dd.style.display = 'none'; return; }
  dd.innerHTML = hits.map(function(p) {
    return '<div style="display:flex;align-items:center;gap:8px;padding:6px 10px;cursor:pointer;font-size:12px;border-bottom:1px solid var(--border);" '
      + 'onmousedown="breedSelect(\'' + side + '\',' + p.num + ')" '
      + 'onmouseover="this.style.background=\'var(--panel)\'" onmouseout="this.style.background=\'\'">'
      + '<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + p.num + '.png" width="24" height="24" style="image-rendering:pixelated">'
      + '<span style="flex:1">' + p.name + '</span>'
      + '<span style="font-size:10px;color:var(--muted)">#' + String(p.num).padStart(3,'0') + '</span>'
      + '</div>';
  }).join('');
  dd.style.display = 'block';
}

function breedSelect(side, num) {
  var p = POKE.find(function(x) { return x.num === num; });
  if (!p) return;
  if (side === 'a') BREED_A = num; else BREED_B = num;
  document.getElementById('breed-' + side + '-search').value = p.name;
  document.getElementById('breed-' + side + '-dd').style.display = 'none';
  // Show mini card
  var card = document.getElementById('breed-' + side + '-card');
  var groups = (EGG_GROUPS_DATA[String(num)] || ['Unknown']).join(', ');
  var meta = POKE_META[num] || {};
  var spr = '<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + num + '.png" width="40" height="40" style="image-rendering:pixelated">';
  card.innerHTML = spr + '<div style="font-size:11px;font-weight:700;margin-top:4px;">' + p.name + '</div>'
    + '<div style="font-size:10px;color:var(--muted);">Egg Groups: ' + groups + '</div>'
    + '<div style="font-size:10px;color:var(--muted);">Gender: ' + (meta.gr || '—') + '</div>';
  card.style.display = 'block';
  breedCalc();
}

function breedReset() {
  BREED_A = null; BREED_B = null;
  ['a','b'].forEach(function(s) {
    document.getElementById('breed-' + s + '-search').value = '';
    document.getElementById('breed-' + s + '-dd').style.display = 'none';
    document.getElementById('breed-' + s + '-card').style.display = 'none';
    document.getElementById('breed-everstone-' + s).checked = false;
  });
  document.getElementById('breed-hatch-info').style.display = 'none';
  document.getElementById('breed-results').innerHTML = '<div style="text-align:center;color:var(--muted);margin-top:60px;"><div style="font-size:32px;margin-bottom:12px;">🥚</div><div style="font-family:\'Press Start 2P\',monospace;font-size:9px;color:var(--game-color,var(--gold));margin-bottom:8px;">BREEDING CALCULATOR</div><div style="font-size:12px;line-height:1.8;max-width:480px;margin:0 auto;">Select two compatible parent Pokémon to see what egg moves the offspring can inherit, compatibility check, and hatch step counter.</div></div>';
}

function breedAreCompatible(numA, numB) {
  var groupsA = EGG_GROUPS_DATA[String(numA)] || [];
  var groupsB = EGG_GROUPS_DATA[String(numB)] || [];
  // Ditto breeds with anything except Undiscovered
  if (groupsA.indexOf('Ditto') !== -1 || groupsB.indexOf('Ditto') !== -1) {
    var other = groupsA.indexOf('Ditto') !== -1 ? groupsB : groupsA;
    return other.indexOf('Undiscovered') === -1;
  }
  // Undiscovered can't breed
  if (groupsA.indexOf('Undiscovered') !== -1 || groupsB.indexOf('Undiscovered') !== -1) return false;
  // Shared group required
  return groupsA.some(function(g) { return groupsB.indexOf(g) !== -1; });
}

function breedGetOffspring(numA, numB) {
  // Offspring is base form of female parent (or non-ditto if one is Ditto)
  var groupsA = EGG_GROUPS_DATA[String(numA)] || [];
  var groupsB = EGG_GROUPS_DATA[String(numB)] || [];
  var femaleNum = groupsA.indexOf('Ditto') !== -1 ? numB : numA;
  // Walk evo chain to find base form
  var chain = EVO_CHAIN[String(femaleNum)] || [femaleNum];
  var baseNum = chain[0];
  return baseNum;
}

function breedCalc() {
  var results = document.getElementById('breed-results');
  if (!BREED_A || !BREED_B) return;

  var compatible = breedAreCompatible(BREED_A, BREED_B);
  var groupsA = (EGG_GROUPS_DATA[String(BREED_A)] || ['?']).join(', ');
  var groupsB = (EGG_GROUPS_DATA[String(BREED_B)] || ['?']).join(', ');
  var sharedGroups = (EGG_GROUPS_DATA[String(BREED_A)] || []).filter(function(g) {
    return (EGG_GROUPS_DATA[String(BREED_B)] || []).indexOf(g) !== -1;
  });

  var html = '';

  // Compatibility banner
  if (!compatible) {
    html += '<div style="background:rgba(255,107,53,0.12);border:1px solid rgba(255,107,53,0.4);border-radius:8px;padding:16px 20px;margin-bottom:20px;">'
      + '<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--fire);margin-bottom:8px;">❌ INCOMPATIBLE</div>'
      + '<div style="font-size:12px;line-height:1.7;color:var(--text);">These Pokémon cannot breed together. '
      + 'Check egg groups: <strong>' + (POKE.find(function(p){return p.num===BREED_A;})||{name:'?'}).name + '</strong> ['
      + groupsA + '] vs <strong>' + (POKE.find(function(p){return p.num===BREED_B;})||{name:'?'}).name + '</strong> [' + groupsB + ']. '
      + 'They must share at least one egg group, or one must be Ditto.</div>'
      + '</div>';
    results.innerHTML = html;
    return;
  }

  var offspring = breedGetOffspring(BREED_A, BREED_B);
  var offspringPoke = POKE.find(function(p) { return p.num === offspring; }) || {name:'?',num:offspring};
  var offspringLearnset = LEARNSETS[String(offspring)] || {};
  var eggMoves = offspringLearnset.egg || [];

  // Figure out which egg moves each parent can teach
  var learnsetA = LEARNSETS[String(BREED_A)] || {};
  var learnsetB = LEARNSETS[String(BREED_B)] || {};
  var allMovesA = [].concat(
    (learnsetA.level || []).map(function(e){return e[1];}),
    (learnsetA.tm || []).map(function(n){return 'TM'+n;}),
    learnsetA.egg || [],
    learnsetA.tutor || []
  );
  var allMovesB = [].concat(
    (learnsetB.level || []).map(function(e){return e[1];}),
    (learnsetB.tm || []).map(function(n){return 'TM'+n;}),
    learnsetB.egg || [],
    learnsetB.tutor || []
  );

  // Compatibility banner (compatible)
  html += '<div style="background:rgba(0,204,85,0.08);border:1px solid rgba(0,204,85,0.3);border-radius:8px;padding:14px 20px;margin-bottom:20px;display:flex;align-items:center;gap:16px;">'
    + '<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + offspring + '.png" width="48" height="48" style="image-rendering:pixelated">'
    + '<div><div style="font-family:\'Press Start 2P\',monospace;font-size:7px;color:#44DD88;margin-bottom:6px;">✓ COMPATIBLE — OFFSPRING</div>'
    + '<div style="font-size:14px;font-weight:800;"><span class="guide-poke-link" onclick="guideDex(\'' + offspringPoke.name.replace(/'/g,"\\'") + '\')">' + offspringPoke.name + '</span> <span style="font-size:11px;color:var(--muted);">#' + String(offspring).padStart(3,'0') + '</span></div>'
    + '<div style="font-size:11px;color:var(--muted);margin-top:3px;">Shared egg group' + (sharedGroups.length>1?'s':'') + ': <strong>' + sharedGroups.join(', ') + '</strong></div>'
    + '</div></div>';

  // Hatch steps
  var hatchSteps = HATCH_STEPS_DATA[String(offspring)];
  if (hatchSteps) {
    document.getElementById('breed-hatch-steps').textContent = hatchSteps.toLocaleString() + ' steps';
    document.getElementById('breed-hatch-cycles').textContent = Math.round(hatchSteps/256) + ' egg cycles · With Flame Body/Magma Armor: ~' + Math.round(hatchSteps/512) + ' steps';
    document.getElementById('breed-hatch-info').style.display = 'block';
  }

  // Everstone info
  var estoneA = document.getElementById('breed-everstone-a').checked;
  var estoneB = document.getElementById('breed-everstone-b').checked;
  if (estoneA || estoneB) {
    var parentName = estoneA ? (POKE.find(function(p){return p.num===BREED_A;})||{name:'Parent A'}).name : (POKE.find(function(p){return p.num===BREED_B;})||{name:'Parent B'}).name;
    html += '<div style="background:rgba(255,215,0,0.07);border:1px solid rgba(255,215,0,0.3);border-radius:8px;padding:14px 20px;margin-bottom:20px;">'
      + '<div style="font-family:\'Press Start 2P\',monospace;font-size:7px;color:var(--gold);margin-bottom:8px;">⬟ EVERSTONE NATURE TRICK</div>'
      + '<div style="font-size:12px;line-height:1.7;">'
      + '<strong>' + parentName + '</strong> holds an Everstone. In Gen 3, this gives a <strong style="color:var(--gold);">50% chance</strong> the offspring inherits that parent\'s Nature. '
      + 'Unlike Gen 4+, this is NOT guaranteed — you may need multiple eggs. '
      + 'The Everstone must be held by the female parent (or Ditto) for best results.'
      + '</div></div>';
  }

  // Egg moves section
  html += '<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--text);letter-spacing:0.5px;margin-bottom:12px;">EGG MOVES FOR ' + offspringPoke.name.toUpperCase() + '</div>';

  if (!eggMoves.length) {
    html += '<div style="font-size:12px;color:var(--muted);padding:16px;background:var(--card);border-radius:6px;">No egg moves available for ' + offspringPoke.name + ' in Gen 3.</div>';
  } else {
    html += '<table style="width:100%;border-collapse:collapse;margin-bottom:24px;">'
      + '<thead><tr style="background:var(--card);">'
      + '<th style="padding:8px 12px;text-align:left;font-size:10px;font-weight:700;color:var(--game-color,var(--gold));border-bottom:2px solid var(--border);">Egg Move</th>'
      + '<th style="padding:8px 12px;text-align:left;font-size:10px;font-weight:700;color:var(--game-color,var(--gold));border-bottom:2px solid var(--border);">Parent A can teach?</th>'
      + '<th style="padding:8px 12px;text-align:left;font-size:10px;font-weight:700;color:var(--game-color,var(--gold));border-bottom:2px solid var(--border);">Parent B can teach?</th>'
      + '</tr></thead><tbody>';

    eggMoves.forEach(function(move, i) {
      var aHas = allMovesA.some(function(m){ return m.toLowerCase() === move.toLowerCase(); });
      var bHas = allMovesB.some(function(m){ return m.toLowerCase() === move.toLowerCase(); });
      var rowBg = (aHas || bHas) ? 'rgba(0,204,85,0.04)' : '';
      var aBadge = aHas ? '<span style="background:rgba(0,204,85,0.2);color:#44DD88;padding:2px 8px;border-radius:3px;font-size:10px;font-weight:700;">✓ YES</span>'
                        : '<span style="color:var(--muted);font-size:10px;">—</span>';
      var bBadge = bHas ? '<span style="background:rgba(0,204,85,0.2);color:#44DD88;padding:2px 8px;border-radius:3px;font-size:10px;font-weight:700;">✓ YES</span>'
                        : '<span style="color:var(--muted);font-size:10px;">—</span>';
      html += '<tr style="border-bottom:1px solid var(--border);background:' + rowBg + ';">'
        + '<td style="padding:8px 12px;font-size:12px;font-weight:700;"><span class="guide-move-link" onclick="_openMoveDex(\'' + move.replace(/'/g,"\\'") + '\')">' + move + '</span></td>'
        + '<td style="padding:8px 12px;">' + aBadge + '</td>'
        + '<td style="padding:8px 12px;">' + bBadge + '</td>'
        + '</tr>';
    });
    html += '</tbody></table>';

    var passable = eggMoves.filter(function(m) {
      return allMovesA.some(function(x){ return x.toLowerCase()===m.toLowerCase(); })
          || allMovesB.some(function(x){ return x.toLowerCase()===m.toLowerCase(); });
    });
    if (passable.length) {
      html += '<div style="background:rgba(0,204,85,0.07);border:1px solid rgba(0,204,85,0.25);border-radius:6px;padding:12px 16px;font-size:12px;">'
        + '<strong style="color:#44DD88;">✓ Passable moves (' + passable.length + '):</strong> ' + passable.map(function(m){ return '<span class="guide-move-link" onclick="_openMoveDex(\'' + m.replace(/'/g,"\\'") + '\')">' + m + '</span>'; }).join(', ')
        + '</div>';
    } else {
      html += '<div style="background:rgba(255,107,53,0.07);border:1px solid rgba(255,107,53,0.25);border-radius:6px;padding:12px 16px;font-size:12px;color:var(--muted);">'
        + 'Neither selected parent knows any egg moves for ' + offspringPoke.name + '. Try different parents or chain breed (use an intermediate Pokémon that knows the move).'
        + '</div>';
    }
  }

  // Level-up & TM moves reminder
  html += '<div style="margin-top:20px;font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--text);letter-spacing:0.5px;margin-bottom:12px;">INHERITED LEVEL-UP MOVES</div>';
  var lvlMoves = (offspringLearnset.level || []).filter(function(e){ return e[0] === 1; }).map(function(e){ return e[1]; });
  html += '<div style="font-size:12px;color:var(--muted);line-height:1.8;">'
    + 'Offspring knows these moves at Lv.1: <strong style="color:var(--text);">' + (lvlMoves.length ? lvlMoves.map(function(m){ return '<span class="guide-move-link" onclick="_openMoveDex(\'' + m.replace(/'/g,"\\'") + '\')">' + m + '</span>'; }).join(', ') : 'None') + '</strong>'
    + '<br>In Gen 3, both parents\' Lv.1 moves that the offspring can normally learn are also inherited.'
    + '</div>';

  results.innerHTML = html;
}

