function optResolveGames() {
  var sel = OPT_GAME === 'AUTO' ? (GAME === 'all' ? 'all' : GAME) : OPT_GAME;
  if (sel === 'all') return ['FR','LG','R','S','E'];
  return [sel];
}

function optGameLabel(game) {
  return ({FR:'FR',LG:'LG',R:'Ruby',S:'Sapphire',E:'Emerald'})[game] || game;
}

function optAvgLevel(levelText) {
  if (!levelText) return null;
  var nums = (levelText.match(/\d+/g) || []).map(function(n){ return parseInt(n, 10); }).filter(Boolean);
  if (!nums.length) return null;
  return nums.reduce(function(sum, n){ return sum + n; }, 0) / nums.length;
}

function optMethodLabel(method) {
  var info = MTH_INFO[method] || MTH_INFO.special;
  return info.lbl.replace(/^[^\s]+\s/, '');
}

function optEncounterableMethod(method) {
  return ['wild','surf','fish','dive','rocksmash','safari','swarm'].indexOf(method) !== -1;
}

function optPct(val) {
  if (val === null || val === undefined || isNaN(val)) return '—';
  return (Math.round(val * 10) / 10).toFixed(val >= 10 ? 1 : 2) + '%';
}

function optCard(html) {
  return '<div style="background:var(--card);border:1px solid var(--border);border-radius:6px;padding:14px 16px;">' + html + '</div>';
}

function optSetGame(game, btn) {
  OPT_GAME = game;
  document.querySelectorAll('#opt-game-row .filter-btn').forEach(function(b){ b.classList.remove('active'); });
  if (btn) btn.classList.add('active');
  renderOptimizerPage();
}

function optSetTab(tab, btn) {
  OPT_TAB = tab;
  document.querySelectorAll('#opt-tab-row .filter-btn').forEach(function(b){ b.classList.remove('active'); });
  if (btn) btn.classList.add('active');
  renderOptimizerPage();
}

function optGetHeldCandidates(query) {
  query = (query || '').trim().toLowerCase();
  if (!query) return [];
  var games = optResolveGames();
  var seen = {};
  var results = [];
  Object.keys(OPT_ITEM_OVERRIDES).forEach(function(key) {
    if (key.indexOf(query) === -1 && query.indexOf(key) === -1) return;
    (OPT_ITEM_OVERRIDES[key] || []).forEach(function(entry) {
      if (!entry.games.some(function(g){ return games.indexOf(g) !== -1; })) return;
      results.push({
        kind:'static',
        title:entry.title,
        item:key,
        games:entry.games.filter(function(g){ return games.indexOf(g) !== -1; }),
        species:null,
        location:entry.location,
        method:entry.method,
        encounterRate:entry.encounterRate,
        heldRate:entry.heldRate,
        combined:entry.encounterRate * (entry.heldRate / 100),
        avgLevel:null,
        note:entry.note || ''
      });
    });
  });
  Object.keys(POKE_META || {}).forEach(function(num) {
    var meta = POKE_META[num];
    var held = (meta && meta.held) || [];
    var matching = held.filter(function(item) { return item && item.toLowerCase().indexOf(query) !== -1; });
    if (!matching.length) return;
    var p = POKE.find(function(mon){ return String(mon.num) === String(num); });
    if (!p) return;
    games.forEach(function(g) {
      parseLines((p.games || {})[g] || '').forEach(function(entry) {
        if (!optEncounterableMethod(entry.method)) return;
        var heldName = matching[0];
        var heldRate = OPT_ITEM_RATE_HINTS[heldName.toLowerCase()] || 5;
        var rate = entry.rate === null ? 100 : entry.rate;
        var key = [heldName, p.name, g, entry.location, entry.method, entry.level].join('|');
        if (seen[key]) return;
        seen[key] = true;
        results.push({
          kind:'wild',
          title:heldName,
          item:heldName,
          games:[g],
          species:p.name,
          location:entry.location || 'Unknown',
          method:optMethodLabel(entry.method),
          encounterRate:rate,
          heldRate:heldRate,
          combined:rate * (heldRate / 100),
          avgLevel:optAvgLevel(entry.level),
          note:entry.level || ''
        });
      });
    });
  });
  return results.sort(function(a, b) {
    if (b.combined !== a.combined) return b.combined - a.combined;
    if ((b.heldRate || 0) !== (a.heldRate || 0)) return (b.heldRate || 0) - (a.heldRate || 0);
    return (b.encounterRate || 0) - (a.encounterRate || 0);
  });
}

function optRenderItems() {
  var hits = optGetHeldCandidates(OPT_ITEM_QUERY).slice(0, 12);
  var quick = ['Lucky Egg','Leftovers','Metal Coat','Dragon Scale','Light Ball','Thick Club'];
  var controls = '<div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:14px;">'
    + '<input id="opt-item-query" type="text" value="' + OPT_ITEM_QUERY.replace(/"/g, '&quot;') + '" placeholder="Search held item…"'
    + ' style="flex:1;min-width:220px;background:var(--panel);border:1px solid var(--border);border-radius:5px;padding:9px 12px;color:var(--text);font-size:12px;outline:none;"'
    + ' oninput="OPT_ITEM_QUERY=this.value;renderOptimizerPage()">'
    + quick.map(function(name){
      return '<button type="button" class="filter-btn' + (OPT_ITEM_QUERY.toLowerCase()===name.toLowerCase()?' active':'') + '" onclick="OPT_ITEM_QUERY=\'' + name.replace(/'/g, "\\'") + '\';renderOptimizerPage()">' + name + '</button>';
    }).join('')
    + '</div>';
  var intro = optCard('<div style="font-size:12px;color:var(--muted);line-height:1.7;">Ranks wild hunts by <strong style="color:var(--text);">encounter rate × held-item chance</strong>, then mixes in guaranteed gifts or floor items where those are simply better.</div>');
  if (!hits.length) {
    return controls + intro + '<div style="margin-top:14px;color:var(--muted);font-size:12px;">No held-item hunt matches for that query in the selected game context.</div>';
  }
  var rows = hits.map(function(hit) {
    var badge = hit.kind === 'static'
      ? '<span style="font-size:10px;font-weight:700;color:#44DD88;">Guaranteed</span>'
      : '<span style="font-size:10px;font-weight:700;color:var(--game-color,var(--gold));">' + optPct(hit.combined) + ' per encounter</span>';
    var gameLine = hit.games.map(optGameLabel).join(' / ');
    return '<div style="padding:12px 0;border-bottom:1px solid var(--border);">'
      + '<div style="display:flex;justify-content:space-between;gap:10px;align-items:flex-start;flex-wrap:wrap;">'
      + '<div>'
      + '<div style="font-size:13px;font-weight:800;color:var(--text);">' + (hit.species ? hit.species + ' · ' : '') + hit.location + '</div>'
      + '<div style="font-size:11px;color:var(--muted);margin-top:4px;line-height:1.7;">'
      + '<strong style="color:var(--game-color,var(--gold));">' + gameLine + '</strong> · ' + hit.method
      + (hit.encounterRate ? ' · Encounter ' + hit.encounterRate + '%' : '')
      + (hit.heldRate ? ' · Hold ' + hit.heldRate + '%' : '')
      + (hit.avgLevel ? ' · Avg Lv. ' + Math.round(hit.avgLevel) : '')
      + '</div>'
      + (hit.note ? '<div style="font-size:11px;color:var(--muted);margin-top:4px;line-height:1.6;">' + hit.note + '</div>' : '')
      + '</div>'
      + '<div style="text-align:right;min-width:120px;">' + badge + '</div>'
      + '</div>'
      + '<div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:9px;">'
      + (hit.species ? '<button type="button" class="filter-btn" onclick="guideDex(\'' + hit.species.replace(/'/g, "\\'") + '\')">Dex</button>' : '')
      + '<button type="button" class="filter-btn" onclick="_openHeldSearch(\'' + hit.item.replace(/'/g, "\\'") + '\', \'\')">Held Ref</button>'
      + '</div>'
      + '</div>';
  }).join('');
  return controls + intro + optCard(rows);
}

function optBandBounds() {
  if (OPT_EXP_BAND === '51+') return { min:51, max:999 };
  var bits = OPT_EXP_BAND.split('-');
  return { min:parseInt(bits[0],10), max:parseInt(bits[1],10) };
}

function optGetExpLocations() {
  var bounds = optBandBounds();
  var games = optResolveGames();
  var groups = {};
  POKE.forEach(function(p) {
    games.forEach(function(g) {
      parseLines((p.games || {})[g] || '').forEach(function(entry) {
        if (!optEncounterableMethod(entry.method)) return;
        var avgLevel = optAvgLevel(entry.level);
        if (avgLevel === null || avgLevel < bounds.min || avgLevel > bounds.max) return;
        var key = [g, entry.location || 'Unknown', entry.method].join('|');
        if (!groups[key]) groups[key] = { game:g, location:entry.location || 'Unknown', method:entry.method, species:[], totalRate:0, weightedLevel:0 };
        var rate = entry.rate === null ? 100 : entry.rate;
        groups[key].species.push({ name:p.name, rate:rate, avgLevel:avgLevel });
        groups[key].totalRate += rate;
        groups[key].weightedLevel += avgLevel * rate;
      });
    });
  });
  return Object.keys(groups).map(function(key) {
    var g = groups[key];
    var avg = g.totalRate ? (g.weightedLevel / g.totalRate) : 0;
    var tops = g.species.sort(function(a,b){ return b.rate - a.rate; }).slice(0,3);
    return {
      game:g.game,
      location:g.location,
      method:g.method,
      avgLevel:avg,
      totalRate:g.totalRate,
      topSpecies:tops,
      score:(avg * 2) + Math.min(g.totalRate, 100) * 0.6 + tops.length * 3
    };
  }).sort(function(a,b){ return b.score - a.score; }).slice(0, 12);
}

function optRenderExp() {
  var bands = ['1-10','11-20','21-30','31-40','41-50','51+'];
  var rows = optGetExpLocations();
  var controls = '<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px;">'
    + bands.map(function(b) {
      return '<button type="button" class="filter-btn' + (OPT_EXP_BAND===b?' active':'') + '" onclick="OPT_EXP_BAND=\'' + b + '\';renderOptimizerPage()">' + b + '</button>';
    }).join('')
    + '</div>';
  var intro = optCard('<div style="font-size:12px;color:var(--muted);line-height:1.7;">Heuristic ranking based on average encounter level inside the selected band plus encounter density. Great for finding practical grind routes fast.</div>');
  if (!rows.length) return controls + intro + '<div style="margin-top:14px;color:var(--muted);font-size:12px;">No good encounter pools found for that level band.</div>';
  return controls + intro + optCard(rows.map(function(row) {
    return '<div style="padding:12px 0;border-bottom:1px solid var(--border);">'
      + '<div style="display:flex;justify-content:space-between;gap:10px;flex-wrap:wrap;align-items:flex-start;">'
      + '<div>'
      + '<div style="font-size:13px;font-weight:800;color:var(--text);">' + row.location + '</div>'
      + '<div style="font-size:11px;color:var(--muted);margin-top:4px;">' + optGameLabel(row.game) + ' · ' + optMethodLabel(row.method) + ' · Avg Lv. ' + row.avgLevel.toFixed(1) + '</div>'
      + '<div style="font-size:11px;color:var(--muted);margin-top:5px;line-height:1.7;">Top targets: ' + row.topSpecies.map(function(sp) {
        return sp.name + ' (' + sp.rate + '%)';
      }).join(' · ') + '</div>'
      + '</div>'
      + '<div style="font-size:10px;font-weight:700;color:var(--game-color,var(--gold));">Density ' + Math.round(row.totalRate) + '%</div>'
      + '</div>'
      + '</div>';
  }).join(''));
}

function optRenderEv() {
  var stats = ['HP','Atk','Def','SpA','SpD','Spe'];
  var games = optResolveGames();
  var cards = (OPT_EV_SPOTS[OPT_EV_STAT] || []).filter(function(spot) {
    return spot.games.some(function(g){ return games.indexOf(g) !== -1; });
  });
  var controls = '<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px;">'
    + stats.map(function(stat) {
      return '<button type="button" class="filter-btn' + (OPT_EV_STAT===stat?' active':'') + '" onclick="OPT_EV_STAT=\'' + stat + '\';renderOptimizerPage()">' + stat + '</button>';
    }).join('')
    + '</div>';
  var intro = optCard('<div style="font-size:12px;color:var(--muted);line-height:1.7;">Curated EV routes chosen for reliability instead of brute-force generation. This avoids making up EV yields the current site data does not actually store.</div>');
  if (!cards.length) return controls + intro + '<div style="margin-top:14px;color:var(--muted);font-size:12px;">No curated EV spots for that stat in the selected game context yet.</div>';
  return controls + intro + '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:12px;">'
    + cards.map(function(spot) {
      return optCard(
        '<div style="font-size:12px;font-weight:800;color:var(--text);margin-bottom:6px;">' + spot.place + '</div>'
        + '<div style="font-size:10px;font-weight:700;color:var(--game-color,var(--gold));margin-bottom:7px;">' + spot.games.map(optGameLabel).join(' / ') + '</div>'
        + '<div style="font-size:11px;color:var(--muted);line-height:1.7;"><strong style="color:var(--text);">Targets:</strong> ' + spot.targets + '<br><strong style="color:var(--text);">Yield:</strong> ' + spot.yield + '<br><strong style="color:var(--text);">Why it works:</strong> ' + spot.why + '</div>'
      );
    }).join('')
    + '</div>';
}

function optGetSafariMatches(query) {
  var games = optResolveGames();
  query = (query || '').trim().toLowerCase();
  var results = [];
  POKE.forEach(function(p) {
    if (query && p.name.toLowerCase().indexOf(query) === -1) return;
    games.forEach(function(g) {
      parseLines((p.games || {})[g] || '').forEach(function(entry) {
        if (entry.method !== 'safari') return;
        results.push({
          name:p.name,
          game:g,
          location:entry.location || 'Safari Zone',
          level:entry.level || '—',
          rate:entry.rate || 0
        });
      });
    });
  });
  return results.sort(function(a,b) {
    if (b.rate !== a.rate) return b.rate - a.rate;
    return a.name.localeCompare(b.name);
  }).slice(0, 18);
}

function optRenderSafari() {
  var rows = optGetSafariMatches(OPT_SAFARI_QUERY);
  var controls = '<div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:14px;">'
    + '<input id="opt-safari-query" type="text" value="' + OPT_SAFARI_QUERY.replace(/"/g, '&quot;') + '" placeholder="Search Safari Pokémon…"'
    + ' style="flex:1;min-width:220px;background:var(--panel);border:1px solid var(--border);border-radius:5px;padding:9px 12px;color:var(--text);font-size:12px;outline:none;"'
    + ' oninput="OPT_SAFARI_QUERY=this.value;renderOptimizerPage()">'
    + '<button type="button" class="filter-btn" onclick="OPT_SAFARI_QUERY=\'Chansey\';renderOptimizerPage()">Chansey</button>'
    + '<button type="button" class="filter-btn" onclick="OPT_SAFARI_QUERY=\'Heracross\';renderOptimizerPage()">Heracross</button>'
    + '<button type="button" class="filter-btn" onclick="OPT_SAFARI_QUERY=\'Kangaskhan\';renderOptimizerPage()">Kangaskhan</button>'
    + '</div>';
  var intro = optCard('<div style="font-size:12px;color:var(--muted);line-height:1.7;">Best Safari odds pulled directly from the encounter tables. Great for checking whether a mon is merely present or actually farmable.</div>');
  if (!rows.length) return controls + intro + '<div style="margin-top:14px;color:var(--muted);font-size:12px;">No Safari entries match that Pokémon name.</div>';
  return controls + intro + optCard(rows.map(function(row) {
    return '<div style="padding:12px 0;border-bottom:1px solid var(--border);display:flex;justify-content:space-between;gap:10px;flex-wrap:wrap;align-items:flex-start;">'
      + '<div>'
      + '<div style="font-size:13px;font-weight:800;color:var(--text);">' + row.name + '</div>'
      + '<div style="font-size:11px;color:var(--muted);margin-top:4px;">' + optGameLabel(row.game) + ' · ' + row.location + ' · ' + row.level + '</div>'
      + '</div>'
      + '<div style="text-align:right;">'
      + '<div style="font-size:12px;font-weight:800;color:var(--game-color,var(--gold));">' + row.rate + '%</div>'
      + '<button type="button" class="filter-btn" style="margin-top:6px;" onclick="guideDex(\'' + row.name.replace(/'/g, "\\'") + '\')">Dex</button>'
      + '</div>'
      + '</div>';
  }).join(''));
}

function renderOptimizerPage() {
  var panel = document.getElementById('opt-panel');
  if (!panel) return;
  document.querySelectorAll('#opt-game-row .filter-btn').forEach(function(btn) {
    btn.classList.toggle('active', btn.getAttribute('data-opt-game') === OPT_GAME);
  });
  document.querySelectorAll('#opt-tab-row .filter-btn').forEach(function(btn) {
    btn.classList.toggle('active', btn.getAttribute('data-opt-tab') === OPT_TAB);
  });
  if (OPT_TAB === 'items') panel.innerHTML = optRenderItems();
  else if (OPT_TAB === 'exp') panel.innerHTML = optRenderExp();
  else if (OPT_TAB === 'ev') panel.innerHTML = optRenderEv();
  else if (OPT_TAB === 'safari') panel.innerHTML = optRenderSafari();
}

// ══════════════════════════════════════════════════════════════════
//  EASY DEX ROUTE
// ══════════════════════════════════════════════════════════════════
var EASYDEX_TAB = 'catch';
var EASYDEX_HIDE_CAUGHT = true;

function easyDexSetTab(tab, btn) {
  EASYDEX_TAB = tab;
  prefSet('gen3-easydex-tab', tab);
  document.querySelectorAll('#easydex-tab-row .filter-btn').forEach(function(b) {
    b.classList.toggle('active', b.getAttribute('data-easydex-tab') === tab);
  });
  renderEasyDexPage();
}

function easyDexToggleCaught(btn) {
  EASYDEX_HIDE_CAUGHT = !EASYDEX_HIDE_CAUGHT;
  prefSet('gen3-easydex-hide-caught', EASYDEX_HIDE_CAUGHT ? '1' : '0');
  if (btn) {
    btn.classList.toggle('active', EASYDEX_HIDE_CAUGHT);
    btn.textContent = EASYDEX_HIDE_CAUGHT ? '✅ Hide Caught' : '👁 Show All';
  }
  renderEasyDexPage();
}

function easyDexGameLabel(game) {
  return ({FR:'FireRed',LG:'LeafGreen',R:'Ruby',S:'Sapphire',E:'Emerald'})[game] || game;
}

function easyDexSourceGames(pokemon) {
  return TRK_GAMES.filter(function(g) {
    return !!String((pokemon.games[g] || '')).trim();
  });
}

function easyDexGameAvail(game, pokemon) {
  var loc = String((pokemon.games[game] || '')).trim().toLowerCase();
  if (!loc) {
    return easyDexSourceGames(pokemon).length ? 'trade' : 'unavail';
  }
  if (/^trade\b/.test(loc)) return 'trade';
  return 'native';
}

function easyDexGameParts(game) {
  if (game === 'FR' || game === 'LG') return BULBA_PARTS;
  if (game === 'R' || game === 'S') return BULBA_PARTS_RS;
  if (game === 'E') return BULBA_PARTS_E;
  return null;
}

function easyDexNormalize(text) {
  return String(text || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/pok[eé]mon/g, 'pokemon')
    .replace(/[()]/g, ' ')
    .replace(/\bmt\.\s*/g, 'mount ')
    .replace(/\bmt\s+/g, 'mount ')
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();
}

function easyDexUnique(list) {
  var seen = Object.create(null);
  return list.filter(function(item) {
    var key = easyDexNormalize(item);
    if (!key || seen[key]) return false;
    seen[key] = true;
    return true;
  });
}

function easyDexExpandRouteRange(label) {
  var m = String(label || '').trim().match(/^Routes?\s+(\d+)\s*-\s*(\d+)$/i);
  if (!m) return null;
  var a = parseInt(m[1], 10);
  var b = parseInt(m[2], 10);
  if (!(a >= 1) || !(b >= a) || b - a > 20) return null;
  var out = [];
  for (var n = a; n <= b; n++) out.push('Route ' + n);
  return out;
}

function easyDexTermsFromTitle(title) {
  var clean = String(title || '')
    .replace(/^Sevii Islands Part [IVX]+:\s*/i, '')
    .replace(/^The\s+/i, '')
    .trim();
  var rawParts = clean.split(/\s*,\s*/).map(function(part) { return part.trim(); }).filter(Boolean);
  var terms = [];
  rawParts.forEach(function(part) {
    if (/^One$/i.test(part)) terms.push('One Island');
    else if (/^Two$/i.test(part)) terms.push('Two Island');
    else if (/^Three Island$/i.test(part)) terms.push('Three Island');
    else if (/^Elite Four$/i.test(part)) {
      terms.push('Elite Four');
      terms.push('Indigo Plateau');
      terms.push('Pokemon League');
    } else {
      var expanded = easyDexExpandRouteRange(part);
      if (expanded) terms = terms.concat(expanded);
      else terms.push(part.replace(/\s*\([^)]*\)\s*/g, '').trim());
    }
  });
  if (/Pokemon League Round 2/i.test(clean)) {
    terms.push('Indigo Plateau');
    terms.push('Pokemon League');
  }
  if (/Power Plant/i.test(clean)) terms.push('Kanto Power Plant');
  if (/Pokemon Mansion/i.test(clean)) terms.push('Pokemon Mansion');
  if (/Mt\.?\s*Moon/i.test(clean)) terms.push('Mt. Moon');
  if (/Mt\.?\s*Chimney/i.test(clean)) terms.push('Mt. Chimney');
  if (/Mt\.?\s*Pyre/i.test(clean)) terms.push('Mt. Pyre');
  if (/Safari Zone/i.test(clean)) terms.push('Safari Zone');
  if (/Victory Road/i.test(clean)) terms.push('Victory Road');
  if (/Abandoned Ship/i.test(clean)) terms.push('Abandoned Ship');
  return easyDexUnique(terms);
}

function easyDexBuildSections(game) {
  var parts = easyDexGameParts(game);
  if (!parts) return [];
  var out = [];
  for (var i = 1; i < parts.length; i++) {
    if (!parts[i]) continue;
    out.push({
      id: 'easydex-' + game + '-' + parts[i].num,
      num: parts[i].num,
      title: parts[i].title,
      sub: parts[i].sub || '',
      terms: easyDexTermsFromTitle(parts[i].title),
      catches: [],
      trades: []
    });
  }
  return out;
}

function easyDexLocateSection(sections, location) {
  var locNorm = easyDexNormalize(location);
  if (!locNorm) return -1;
  for (var i = 0; i < sections.length; i++) {
    for (var j = 0; j < sections[i].terms.length; j++) {
      var termNorm = easyDexNormalize(sections[i].terms[j]);
      if (!termNorm) continue;
      if (locNorm.indexOf(termNorm) !== -1 || termNorm.indexOf(locNorm) !== -1) return i;
    }
  }
  return -1;
}

function easyDexSprite(num, name) {
  return '<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + num + '.png" alt="' + name + '" width="34" height="34" style="image-rendering:pixelated;flex:0 0 auto">';
}

function easyDexTypeBadges(types) {
  return typeBadges(types || []);
}

function easyDexMethodBadge(method) {
  var info = MTH_INFO[method] || MTH_INFO.special;
  return '<span class="mth ' + info.cls + '" style="font-size:8px;padding:2px 6px;">' + info.lbl + '</span>';
}

function easyDexLink(name, label) {
  var safe = String(name || '').replace(/'/g, "\\'");
  return '<button type="button" class="filter-btn" style="padding:5px 8px;font-size:9px;" onclick="guideDex(\'' + safe + '\')">' + (label || 'Dex') + '</button>';
}

function easyDexCaughtSet(game) {
  var set = {};
  if (!game || TRK_GAMES.indexOf(game) === -1) return set;
  trkLoad(game).forEach(function(num) { set[num] = true; });
  return set;
}

function easyDexApplyCaughtFilter(rows, caughtSet) {
  if (!EASYDEX_HIDE_CAUGHT) return rows;
  return rows.filter(function(row) { return !caughtSet[row.num]; });
}

function easyDexRate(entry) {
  return entry && entry.rate !== null && entry.rate !== undefined ? entry.rate : -1;
}

function easyDexChooseBestEncounter(game, pokemon, sections) {
  var entries = parseLines(pokemon.games[game] || '').filter(function(entry) {
    return optEncounterableMethod(entry.method) && entry.location;
  }).map(function(entry) {
    return {
      method: entry.method,
      location: entry.location,
      level: entry.level,
      rate: entry.rate,
      sectionIndex: easyDexLocateSection(sections, entry.location)
    };
  });
  if (!entries.length) return null;
  var bestRate = entries.reduce(function(max, entry) { return Math.max(max, easyDexRate(entry)); }, -1);
  var top = entries.filter(function(entry) { return easyDexRate(entry) === bestRate; });
  top.sort(function(a, b) {
    var ai = a.sectionIndex === -1 ? 999 : a.sectionIndex;
    var bi = b.sectionIndex === -1 ? 999 : b.sectionIndex;
    if (ai !== bi) return ai - bi;
    var al = optAvgLevel(a.level) || 999;
    var bl = optAvgLevel(b.level) || 999;
    if (al !== bl) return al - bl;
    return String(a.location).localeCompare(String(b.location));
  });
  var chosen = top[0];
  if (!chosen) return null;
  chosen.tieCount = top.length;
  return chosen;
}

function easyDexBuildCatchPlan(game) {
  var sections = easyDexBuildSections(game);
  var overflow = [];
  POKE.forEach(function(pokemon) {
    var best = easyDexChooseBestEncounter(game, pokemon, sections);
    if (!best) return;
    var row = {
      num: pokemon.num,
      name: pokemon.name,
      types: pokemon.types,
      method: best.method,
      location: best.location,
      level: best.level,
      rate: best.rate,
      tieCount: best.tieCount
    };
    if (best.sectionIndex >= 0) sections[best.sectionIndex].catches.push(row);
    else overflow.push(row);
  });
  sections.forEach(function(section) {
    section.catches.sort(function(a, b) {
      if (easyDexRate(b) !== easyDexRate(a)) return easyDexRate(b) - easyDexRate(a);
      return a.num - b.num;
    });
  });
  overflow.sort(function(a, b) {
    if (easyDexRate(b) !== easyDexRate(a)) return easyDexRate(b) - easyDexRate(a);
    return a.num - b.num;
  });
  return { sections: sections, overflow: overflow };
}

function easyDexTradeLocation(entry) {
  return String(entry.location || '')
    .replace(/^Trade\s+—\s*/i, '')
    .replace(/^Trade\s*/i, '')
    .trim();
}

function easyDexBuildTradePlan(game) {
  var sections = easyDexBuildSections(game);
  var overflow = [];
  POKE.forEach(function(pokemon) {
    var trades = parseLines(pokemon.games[game] || '').filter(function(entry) { return entry.method === 'trade'; });
    trades.forEach(function(entry) {
      var row = {
        num: pokemon.num,
        name: pokemon.name,
        types: pokemon.types,
        detail: easyDexTradeLocation(entry)
      };
      var idx = easyDexLocateSection(sections, row.detail);
      if (idx >= 0) sections[idx].trades.push(row);
      else overflow.push(row);
    });
  });
  sections.forEach(function(section) {
    section.trades.sort(function(a, b) { return a.num - b.num; });
  });
  overflow.sort(function(a, b) { return a.num - b.num; });
  return { sections: sections, overflow: overflow };
}

function easyDexBuildLinkTradePlan(game) {
  var tradeEvoTargets = {};
  TRADE_EVOS_GEN3.forEach(function(entry) {
    tradeEvoTargets[entry.toNum] = {
      from: entry.from,
      item: entry.item || '',
      games: entry.games,
      tip: entry.tip
    };
  });
  return POKE.map(function(pokemon) {
    var raw = String((pokemon.games[game] || '')).trim();
    var rows = [];
    if (/^trade\b/im.test(raw)) {
      return null;
    }
    if (tradeEvoTargets[pokemon.num]) {
      var evo = tradeEvoTargets[pokemon.num];
      rows.push({
        kind: 'Trade Evolution',
        text: evo.from + ' -> ' + pokemon.name + (evo.item ? ' with ' + evo.item : '')
      });
    }
    if (easyDexGameAvail(game, pokemon) === 'trade') {
      var sources = easyDexSourceGames(pokemon).filter(function(g) { return g !== game; }).map(function(g) { return TRK_GAME_LABELS[g]; });
      rows.push({
        kind: 'Version Trade',
        text: 'Catch in ' + (sources.join(', ') || 'another Gen 3 game') + ' and trade into ' + TRK_GAME_LABELS[game]
      });
    }
    if (!rows.length) return null;
    return {
      num: pokemon.num,
      name: pokemon.name,
      types: pokemon.types,
      details: rows
    };
  }).filter(Boolean).sort(function(a, b) { return a.num - b.num; });
}

function easyDexBuildEvolutionOnlyPlan(game) {
  return POKE.map(function(pokemon) {
    var entries = parseLines(pokemon.games[game] || '');
    var evolveEntry = entries.find(function(entry) { return entry.method === 'evolve'; });
    if (!evolveEntry) return null;
    var hasDirectEncounter = entries.some(function(entry) { return optEncounterableMethod(entry.method); });
    if (hasDirectEncounter) return null;
    return {
      num: pokemon.num,
      name: pokemon.name,
      types: pokemon.types,
      detail: evolveEntry.location || 'Evolution'
    };
  }).filter(Boolean).sort(function(a, b) { return a.num - b.num; });
}

function easyDexBuildSpecialPlan(game) {
  return POKE.map(function(pokemon) {
    var entries = parseLines(pokemon.games[game] || '');
    var specialEntries = entries.filter(function(entry) {
      return ['special','breed','fossil','event'].indexOf(entry.method) !== -1;
    });
    if (!specialEntries.length) return null;
    return {
      num: pokemon.num,
      name: pokemon.name,
      types: pokemon.types,
      details: specialEntries.map(function(entry) {
        return {
          method: entry.method,
          text: entry.location || 'Special'
        };
      })
    };
  }).filter(Boolean).sort(function(a, b) { return a.num - b.num; });
}

function easyDexSectionCard(section, rows, mode) {
  var count = rows.length;
  var header = '<div style="display:flex;justify-content:space-between;gap:12px;align-items:flex-start;margin-bottom:10px;">'
    + '<div><div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));line-height:1.7;">PART ' + section.num + '</div>'
    + '<div style="font-size:14px;font-weight:700;color:var(--text);line-height:1.5;">' + section.title + '</div>'
    + (section.sub ? '<div style="font-size:11px;color:var(--muted);margin-top:5px;line-height:1.6;">' + section.sub + '</div>' : '')
    + '</div>'
    + '<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:' + (count ? 'var(--fire)' : 'var(--muted)') + ';white-space:nowrap;">' + count + ' ' + (mode === 'trade' ? 'TRADES' : mode === 'special' ? 'SPECIAL' : 'MON') + '</div>'
    + '</div>';
  var itemsHtml = rows.map(function(row) {
    if (mode === 'trade') {
      return '<div style="display:flex;gap:12px;align-items:center;padding:10px 0;border-top:1px solid rgba(42,58,110,0.35);">'
        + easyDexSprite(row.num, row.name)
        + '<div style="flex:1;min-width:0;">'
        + '<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;">'
        + '<div style="font-size:13px;font-weight:700;color:var(--text);">' + row.name + '</div>'
        + easyDexTypeBadges(row.types)
        + '</div>'
        + '<div style="font-size:11px;color:var(--muted);margin-top:5px;line-height:1.6;">' + row.detail + '</div>'
        + '</div>'
        + easyDexLink(row.name)
        + '</div>';
    }
    if (mode === 'special') {
      return '<div style="display:flex;gap:12px;align-items:center;padding:10px 0;border-top:1px solid rgba(42,58,110,0.35);">'
        + easyDexSprite(row.num, row.name)
        + '<div style="flex:1;min-width:0;">'
        + '<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;">'
        + '<div style="font-size:13px;font-weight:700;color:var(--text);">' + row.name + '</div>'
        + easyDexTypeBadges(row.types)
        + '</div>'
        + row.details.map(function(detail) {
          return '<div style="font-size:11px;color:var(--muted);margin-top:5px;line-height:1.6;">' + easyDexMethodBadge(detail.method) + ' <span style="margin-left:6px;">' + detail.text + '</span></div>';
        }).join('')
        + '</div>'
        + easyDexLink(row.name)
        + '</div>';
    }
    return '<div style="display:flex;gap:12px;align-items:center;padding:10px 0;border-top:1px solid rgba(42,58,110,0.35);">'
      + easyDexSprite(row.num, row.name)
      + '<div style="flex:1;min-width:0;">'
      + '<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;">'
      + '<div style="font-size:13px;font-weight:700;color:var(--text);">' + row.name + '</div>'
      + easyDexTypeBadges(row.types)
      + easyDexMethodBadge(row.method)
      + (row.rate !== null && row.rate !== undefined ? '<span class="rate-badge ' + rateClass(row.rate) + '" style="font-size:8px;">' + row.rate + '%</span>' : '')
      + (row.tieCount > 1 ? '<span style="font-size:9px;color:var(--muted);border:1px solid rgba(156,172,214,0.24);border-radius:999px;padding:2px 7px;">tied best</span>' : '')
      + '</div>'
      + '<div style="font-size:11px;color:var(--muted);margin-top:5px;line-height:1.6;">' + row.location + (row.level ? ' · ' + row.level : '') + '</div>'
      + '</div>'
      + easyDexLink(row.name)
      + '</div>';
  }).join('');
  return '<div style="background:var(--card);border:1px solid var(--border);border-radius:6px;padding:14px 16px;">'
    + header
    + (rows.length ? itemsHtml : '<div style="font-size:11px;color:var(--muted);padding-top:4px;">Nothing lands here for this view.</div>')
    + '</div>';
}

function easyDexOverflowCard(title, rows, mode) {
  if (!rows.length) return '';
  return easyDexSectionCard({ num: 'EX', title: title, sub: 'These entries did not match the route order cleanly.' }, rows, mode);
}

function easyDexRenderCatch(game) {
  var plan = easyDexBuildCatchPlan(game);
  var caughtSet = easyDexCaughtSet(game);
  var cards = plan.sections.map(function(section) {
    return {
      section: section,
      rows: easyDexApplyCaughtFilter(section.catches, caughtSet)
    };
  }).filter(function(entry) { return entry.rows.length; }).map(function(entry) {
    return easyDexSectionCard(entry.section, entry.rows, 'catch');
  });
  var overflow = easyDexApplyCaughtFilter(plan.overflow, caughtSet);
  if (overflow.length) cards.push(easyDexOverflowCard('Other Locations', overflow, 'catch'));
  var total = cards.length ? plan.sections.reduce(function(sum, section) { return sum + easyDexApplyCaughtFilter(section.catches, caughtSet).length; }, 0) + overflow.length : 0;
  return '<div style="font-size:11px;color:var(--muted);margin-bottom:14px;line-height:1.7;">Showing each Pokémon at the single place where its direct encounter rate is best in ' + easyDexGameLabel(game) + '. If several spots tie for best, the earliest matching location in the run order wins.' + (EASYDEX_HIDE_CAUGHT ? ' Already-caught Pokémon for this tracker save are hidden by default.' : ' Showing both caught and uncaught Pokémon.') + '</div>'
    + '<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));margin-bottom:12px;">' + total + ' OPTIMAL DIRECT CATCHES</div>'
    + '<div style="display:grid;gap:14px;">' + (cards.join('') || '<div style="background:var(--card);border:1px solid var(--border);border-radius:6px;padding:16px;font-size:12px;color:var(--muted);">No location-based encounters found for this game.</div>') + '</div>';
}

function easyDexRenderTrades(game) {
  var plan = easyDexBuildTradePlan(game);
  var caughtSet = easyDexCaughtSet(game);
  var cards = plan.sections.map(function(section) {
    return {
      section: section,
      rows: easyDexApplyCaughtFilter(section.trades, caughtSet)
    };
  }).filter(function(entry) { return entry.rows.length; }).map(function(entry) {
    return easyDexSectionCard(entry.section, entry.rows, 'trade');
  });
  var overflow = easyDexApplyCaughtFilter(plan.overflow, caughtSet);
  if (overflow.length) cards.push(easyDexOverflowCard('Other Trade Spots', overflow, 'trade'));
  var total = plan.sections.reduce(function(sum, section) { return sum + easyDexApplyCaughtFilter(section.trades, caughtSet).length; }, 0) + overflow.length;
  return '<div style="font-size:11px;color:var(--muted);margin-bottom:14px;line-height:1.7;">Every in-game trade in ' + easyDexGameLabel(game) + ', grouped against the Bulbapedia walkthrough order wherever the trade location can be matched.</div>'
    + '<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));margin-bottom:12px;">' + total + ' TRADE TARGETS</div>'
    + '<div style="display:grid;gap:14px;">' + (cards.join('') || '<div style="background:var(--card);border:1px solid var(--border);border-radius:6px;padding:16px;font-size:12px;color:var(--muted);">No in-game trades found for this game.</div>') + '</div>';
}

function easyDexRenderEvolutions(game) {
  var rows = easyDexApplyCaughtFilter(easyDexBuildEvolutionOnlyPlan(game), easyDexCaughtSet(game));
  var list = rows.map(function(row) {
    return '<div style="display:flex;gap:12px;align-items:center;padding:10px 0;border-top:1px solid rgba(42,58,110,0.35);">'
      + easyDexSprite(row.num, row.name)
      + '<div style="flex:1;min-width:0;">'
      + '<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;">'
      + '<div style="font-size:13px;font-weight:700;color:var(--text);">' + row.name + '</div>'
      + easyDexTypeBadges(row.types)
      + '</div>'
      + '<div style="font-size:11px;color:var(--muted);margin-top:5px;line-height:1.6;">' + row.detail + '</div>'
      + '</div>'
      + easyDexLink(row.name)
      + '</div>';
  }).join('');
  return '<div style="font-size:11px;color:var(--muted);margin-bottom:14px;line-height:1.7;">These dex entries do not have a direct wild encounter in ' + easyDexGameLabel(game) + ', so evolution is the cleanest route to finishing them.</div>'
    + '<div style="background:var(--card);border:1px solid var(--border);border-radius:6px;padding:14px 16px;">'
    + '<div style="display:flex;justify-content:space-between;gap:12px;align-items:flex-start;margin-bottom:10px;">'
    + '<div><div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));line-height:1.7;">EVOLUTION CLEANUP</div>'
    + '<div style="font-size:14px;font-weight:700;color:var(--text);line-height:1.5;">Evolution-only entries</div>'
    + '<div style="font-size:11px;color:var(--muted);margin-top:5px;line-height:1.6;">Use this after the route list to mop up species that are only obtained by evolving something else.</div></div>'
    + '<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:' + (rows.length ? 'var(--fire)' : 'var(--muted)') + ';white-space:nowrap;">' + rows.length + ' MON</div>'
    + '</div>'
    + (rows.length ? list : '<div style="font-size:11px;color:var(--muted);padding-top:4px;">No evolution-only entries found for this game.</div>')
    + '</div>';
}

function easyDexRenderLinkTrades(game) {
  var rows = easyDexApplyCaughtFilter(easyDexBuildLinkTradePlan(game), easyDexCaughtSet(game));
  var list = rows.map(function(row) {
    return '<div style="display:flex;gap:12px;align-items:center;padding:10px 0;border-top:1px solid rgba(42,58,110,0.35);">'
      + easyDexSprite(row.num, row.name)
      + '<div style="flex:1;min-width:0;">'
      + '<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;">'
      + '<div style="font-size:13px;font-weight:700;color:var(--text);">' + row.name + '</div>'
      + easyDexTypeBadges(row.types)
      + '</div>'
      + row.details.map(function(detail) {
        return '<div style="font-size:11px;color:var(--muted);margin-top:5px;line-height:1.6;"><span style="color:var(--gold);font-weight:700;">' + detail.kind + ':</span> ' + detail.text + '</div>';
      }).join('')
      + '</div>'
      + easyDexLink(row.name)
      + '</div>';
  }).join('');
  return '<div style="font-size:11px;color:var(--muted);margin-bottom:14px;line-height:1.7;">Species that require a player-to-player trade link rather than a location visit in ' + easyDexGameLabel(game) + '. This includes trade evolutions and species whose practical route is to catch them in another Gen 3 game and trade them over.</div>'
    + '<div style="background:var(--card);border:1px solid var(--border);border-radius:6px;padding:14px 16px;">'
    + '<div style="display:flex;justify-content:space-between;gap:12px;align-items:flex-start;margin-bottom:10px;">'
    + '<div><div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));line-height:1.7;">LINK TRADE CLEANUP</div>'
    + '<div style="font-size:14px;font-weight:700;color:var(--text);line-height:1.5;">Link cable and cross-version requirements</div>'
    + '<div style="font-size:11px;color:var(--muted);margin-top:5px;line-height:1.6;">This is the final bucket for Pokémon that cannot be fully resolved by direct catches, NPC trades, gifts, or simple evolutions inside one save.</div></div>'
    + '<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:' + (rows.length ? 'var(--fire)' : 'var(--muted)') + ';white-space:nowrap;">' + rows.length + ' MON</div>'
    + '</div>'
    + (rows.length ? list : '<div style="font-size:11px;color:var(--muted);padding-top:4px;">No link-trade entries found for this game.</div>')
    + '</div>';
}

function easyDexRenderSpecial(game) {
  var rows = easyDexApplyCaughtFilter(easyDexBuildSpecialPlan(game), easyDexCaughtSet(game));
  return '<div style="font-size:11px;color:var(--muted);margin-bottom:14px;line-height:1.7;">Gift Pokémon, starters, fossils, event distributions, and other non-wild one-offs in ' + easyDexGameLabel(game) + '. This is the last bucket so the page covers the full Pokédex instead of only catchable species.</div>'
    + '<div style="background:var(--card);border:1px solid var(--border);border-radius:6px;padding:14px 16px;">'
    + '<div style="display:flex;justify-content:space-between;gap:12px;align-items:flex-start;margin-bottom:10px;">'
    + '<div><div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));line-height:1.7;">SPECIAL ACQUISITIONS</div>'
    + '<div style="font-size:14px;font-weight:700;color:var(--text);line-height:1.5;">Special / gift / fossil / event entries</div>'
    + '<div style="font-size:11px;color:var(--muted);margin-top:5px;line-height:1.6;">Use this alongside the direct catch route so every remaining acquisition method is still accounted for.</div></div>'
    + '<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:' + (rows.length ? 'var(--fire)' : 'var(--muted)') + ';white-space:nowrap;">' + rows.length + ' MON</div>'
    + '</div>'
    + (rows.length ? rows.map(function(row) { return easyDexSectionCard({num:'SP',title:'Special Acquisitions',sub:''}, [row], 'special'); }).join('') : '<div style="font-size:11px;color:var(--muted);padding-top:4px;">No special-only entries found for this game.</div>')
    + '</div>';
}

function renderEasyDexPage() {
  var panel = document.getElementById('easydex-panel');
  if (!panel) return;
  var intro = document.getElementById('easyDexIntro');
  if (intro && GAME !== 'all') {
    intro.textContent = 'A chronological easiest-dex route for ' + easyDexGameLabel(GAME) + ' using the Bulbapedia walkthrough order. Each stop highlights the Pokemon whose absolute best direct encounter rate lands there, with separate views for in-game trades, evolution cleanup, and non-wild special pickups.';
  }
  document.querySelectorAll('#easydex-tab-row .filter-btn').forEach(function(btn) {
    btn.classList.toggle('active', btn.getAttribute('data-easydex-tab') === EASYDEX_TAB);
  });
  var caughtBtn = document.getElementById('easyDexCaughtToggle');
  if (caughtBtn) {
    caughtBtn.classList.toggle('active', EASYDEX_HIDE_CAUGHT);
    caughtBtn.textContent = EASYDEX_HIDE_CAUGHT ? '✅ Hide Caught' : '👁 Show All';
  }
  if (GAME === 'all') {
    panel.innerHTML = '<div style="background:var(--card);border:1px solid var(--border);border-radius:6px;padding:18px 20px;font-size:12px;color:var(--muted);line-height:1.8;">Pick a single game with the top game tabs first. This page follows the active game and builds a chronological easiest-dex route specifically for that version.</div>';
    return;
  }
  if (EASYDEX_TAB === 'trade') panel.innerHTML = easyDexRenderTrades(GAME);
  else if (EASYDEX_TAB === 'linktrade') panel.innerHTML = easyDexRenderLinkTrades(GAME);
  else if (EASYDEX_TAB === 'evolve') panel.innerHTML = easyDexRenderEvolutions(GAME);
  else if (EASYDEX_TAB === 'special') panel.innerHTML = easyDexRenderSpecial(GAME);
  else panel.innerHTML = easyDexRenderCatch(GAME);
}

