// Trade Evo renders lazily on first tab click

function renderTradeEvoPage() {
  // Gen 3 trades
  var gen3el = document.getElementById('tradeevo-gen3');
  if (!gen3el) return;
  var thStyle = 'padding:9px 12px;text-align:left;font-family:\'Press Start 2P\',monospace;font-size:7px;color:var(--game-color,var(--gold));border-bottom:2px solid var(--border);';
  var html = '<table style="width:100%;border-collapse:collapse;margin-bottom:8px;">'
    + '<thead><tr style="background:var(--panel);">'
    + '<th style="' + thStyle + '">Trade</th>'
    + '<th style="' + thStyle + '">Required Item</th>'
    + '<th style="' + thStyle + '">Available In</th>'
    + '<th style="' + thStyle + '">Notes</th>'
    + '</tr></thead><tbody>';

  TRADE_EVOS_GEN3.forEach(function(e, i) {
    var itemBadge = e.item
      ? '<span onclick="openItemByName(\'' + e.item.replace(/'/g,"\\'") + '\')" style="display:inline-flex;align-items:center;gap:5px;background:color-mix(in srgb,var(--game-color,var(--gold)) 15%,transparent);border:1px solid color-mix(in srgb,var(--game-color,var(--gold)) 40%,transparent);border-radius:3px;padding:2px 8px;font-size:10px;font-weight:700;color:var(--game-color,var(--gold));cursor:pointer;" title="Open in Item Dex">' + itemSprite(e.item,18) + e.item + '</span>'
      : '<span style="font-size:11px;color:var(--muted);">No item</span>';
    html += '<tr style="border-bottom:1px solid var(--border);">'
      + '<td style="padding:10px 12px;">'
      + '<div style="display:flex;align-items:center;gap:10px;">'
      + '<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + e.fromNum + '.png" width="32" height="32" style="image-rendering:pixelated;cursor:pointer;" onclick="guideDex(\'' + e.from.replace(/'/g,"\\'") + '\')">'
      + '<span style="font-size:13px;color:var(--muted);">→</span>'
      + '<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + e.toNum + '.png" width="32" height="32" style="image-rendering:pixelated;cursor:pointer;" onclick="guideDex(\'' + e.to.replace(/'/g,"\\'") + '\')">'
      + '<div>'
      + '<div style="font-size:12px;font-weight:700;">'
      + '<span class="guide-poke-link" onclick="guideDex(\'' + e.from.replace(/'/g,"\\'") + '\')">' + e.from + '</span>'
      + ' → '
      + '<span class="guide-poke-link" onclick="guideDex(\'' + e.to.replace(/'/g,"\\'") + '\')">' + e.to + '</span>'
      + '</div>'
      + '<div style="font-size:10px;color:var(--muted);">#' + String(e.fromNum).padStart(3,'0') + ' → #' + String(e.toNum).padStart(3,'0') + '</div>'
      + '</div>'
      + '</div></td>'
      + '<td style="padding:10px 12px;">' + itemBadge + '</td>'
      + '<td style="padding:10px 12px;font-size:11px;color:var(--text);">' + e.games + '</td>'
      + '<td style="padding:10px 12px;font-size:11px;color:var(--muted);line-height:1.5;">' + e.tip + '</td>'
      + '</tr>';
  });
  html += '</tbody></table>';
  gen3el.innerHTML = '<div class="panel" style="overflow-x:auto;-webkit-overflow-scrolling:touch;padding:0;">' + html + '</div>';

  // Gen 4+ only
  var gen4el = document.getElementById('tradeevo-gen4');
  html = '<table style="width:100%;border-collapse:collapse;margin-bottom:8px;opacity:0.75;">'
    + '<thead><tr style="background:var(--panel);">'
    + '<th style="' + thStyle + '">Trade</th>'
    + '<th style="' + thStyle + '">Item</th>'
    + '<th style="' + thStyle + '">Note</th>'
    + '</tr></thead><tbody>';
  TRADE_EVOS_GEN4.forEach(function(e, i) {
    var fromEsc = e.from.replace(/'/g,"\\'");
    var toEsc = e.to.replace(/'/g,"\\'");
    html += '<tr style="border-bottom:1px solid var(--border)">'
      + '<td style="padding:9px 12px;font-size:12px;font-weight:700;color:var(--muted);">'
      + '<span class="guide-poke-link" onclick="guideDex(\'' + fromEsc + '\')">' + e.from + '</span>'
      + ' → '
      + '<span class="guide-poke-link" onclick="guideDex(\'' + toEsc + '\')" style="opacity:0.5;" title="Not available in Gen 3">' + e.to + '</span>'
      + '</td>'
      + '<td style="padding:9px 12px;font-size:11px;color:var(--muted);">' + e.item + '</td>'
      + '<td style="padding:9px 12px;font-size:11px;color:var(--muted);">' + e.note + '</td>'
      + '</tr>';
  });
  html += '</tbody></table>';
  gen4el.innerHTML = '<div class="panel" style="overflow-x:auto;-webkit-overflow-scrolling:touch;padding:0;">' + html + '</div>';

  // Item locations
  var _pokeNamesSorted = POKE.map(function(p){ return p.name; }).sort(function(a,b){ return b.length - a.length; });
  var _itemNamesSorted = ALL_ITEMS.map(function(it){ return it[1]; }).sort(function(a,b){ return b.length - a.length; });
  var _moveNamesSorted = ALL_MOVES_DATA.map(function(m){ return m[1]; }).sort(function(a,b){ return b.length - a.length; });
  function _linkNames(text, names, onclickFn, cssClass) {
    names.forEach(function(name) {
      var re = new RegExp('\\b' + name.replace(/[.*+?^${}()|[\]\\]/g,'\\$&') + '\\b', 'g');
      text = text.replace(re, '<span class="' + cssClass + '" onclick="' + onclickFn(name) + '" style="cursor:pointer;">' + name + '</span>');
    });
    return text;
  }
  function _linkPokeNames(text) {
    return _linkNames(text, _pokeNamesSorted, function(n){ return 'guideDex(\'' + n.replace(/'/g,"\\'") + '\')'; }, 'guide-poke-link');
  }
  function _linkItemNames(text) {
    return _linkNames(text, _itemNamesSorted, function(n){ return 'openItemByName(\'' + n.replace(/'/g,"\\'") + '\')'; }, 'guide-item-link');
  }
  function _linkMoveNames(text) {
    return _linkNames(text, _moveNamesSorted, function(n){ return '_openMoveDex(\'' + n.replace(/'/g,"\\'") + '\')'; }, 'guide-move-link');
  }
  function _linkAll(text) {
    text = _linkPokeNames(text);
    text = _linkItemNames(text);
    text = _linkMoveNames(text);
    return text;
  }
  var itemsEl = document.getElementById('tradeevo-items');
  html = '';
  TRADE_ITEM_LOCATIONS.forEach(function(entry) {
    html += '<div style="margin-bottom:16px;background:var(--card);border:1px solid var(--border);border-radius:8px;padding:14px 16px;">'
      + '<div onclick="openItemByName(\'' + entry.item.replace(/'/g,"\\'") + '\')" style="display:inline-flex;align-items:center;gap:6px;font-weight:700;font-size:13px;color:var(--game-color,var(--gold));margin-bottom:8px;cursor:pointer;" title="Open in Item Dex">' + itemSprite(entry.item,20) + entry.item + '</div>'
      + '<ul style="margin:0;padding-left:18px;">'
      + entry.locations.map(function(l){ return '<li style="font-size:12px;color:var(--muted);line-height:1.7;margin-bottom:3px;">' + _linkAll(l) + '</li>'; }).join('')
      + '</ul></div>';
  });
  itemsEl.innerHTML = html;
}

// ══════════════════════════════════════════════════════════════════
//  NUZLOCKE MODE (tracker enhancement)
// ══════════════════════════════════════════════════════════════════
var NUZLOCKE_MODE = false;
var NUZLOCKE_FAINTED = {}; // {save: [numArray]}
var NUZLOCKE_FIRST_ENC = {}; // {save: {routeKey: num}}

function nuzlockeKey(save) { return 'nuzlocke_fainted_' + save; }
function nuzlockeEncKey(save) { return 'nuzlocke_enc_' + save; }

function nuzlockeLoadFainted(save) {
  try { var r = localStorage.getItem(nuzlockeKey(save)); return r ? JSON.parse(r) : []; } catch(e) { return []; }
}
function nuzlockeSaveFainted(save, arr) {
  try { localStorage.setItem(nuzlockeKey(save), JSON.stringify(arr)); } catch(e) {}
}
function nuzlockeIsFainted(save, num) {
  return nuzlockeLoadFainted(save).indexOf(num) !== -1;
}
function nuzlockeToggleFainted(save, num) {
  var arr = nuzlockeLoadFainted(save);
  var idx = arr.indexOf(num);
  if (idx === -1) arr.push(num); else arr.splice(idx, 1);
  nuzlockeSaveFainted(save, arr);
}

function toggleNuzlockeMode() {
  NUZLOCKE_MODE = !NUZLOCKE_MODE;
  var btn = document.getElementById('trk-nuzlocke-btn');
  if (btn) {
    btn.style.background = NUZLOCKE_MODE ? 'rgba(255,107,53,0.25)' : '';
    btn.style.borderColor = NUZLOCKE_MODE ? 'var(--fire)' : 'var(--border)';
    btn.style.color = NUZLOCKE_MODE ? 'var(--fire)' : 'var(--muted)';
    btn.textContent = NUZLOCKE_MODE ? '💀 NUZLOCKE ON' : '💀 NUZLOCKE';
  }
  var legend = document.getElementById('trk-nuzlocke-legend');
  if (legend) legend.style.display = NUZLOCKE_MODE ? 'flex' : 'none';
  // Show/hide nuzlocke-specific filter buttons
  var faintedBtn = document.getElementById('trk-filter-fainted');
  var aliveBtn = document.getElementById('trk-filter-alive');
  if (faintedBtn) faintedBtn.style.display = NUZLOCKE_MODE ? '' : 'none';
  if (aliveBtn) aliveBtn.style.display = NUZLOCKE_MODE ? '' : 'none';
  trkRenderGrid();
}

function nuzlockeMarkFainted(num) {
  if (!NUZLOCKE_MODE) return;
  var wasFainted = nuzlockeIsFainted(TRK_SAVE, num);
  nuzlockeToggleFainted(TRK_SAVE, num);
  trkRenderGrid();
  if (!wasFainted) {
    var p = POKE && POKE.find(function(x) { return x.num === num; });
    _showInMemoriam(num, p ? p.name : '#' + num);
  }
}

function _showInMemoriam(num, name) {
  var el = document.getElementById('nuz-memoriam');
  if (!el) return;
  var img = el.querySelector('.memoriam-sprite');
  var nameEl = el.querySelector('.memoriam-name');
  if (img) img.src = 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + num + '.png';
  if (nameEl) nameEl.textContent = name.toUpperCase();
  el.classList.add('open');
  clearTimeout(el._timer);
  el._timer = setTimeout(function() { el.classList.remove('open'); }, 5000);
}

window.closeInMemoriam = function() {
  var el = document.getElementById('nuz-memoriam');
  if (el) { clearTimeout(el._timer); el.classList.remove('open'); }
};


