var BULBA_LB_CSS = "#bulba-lightbox{display:none;position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.92);align-items:center;justify-content:center;cursor:zoom-out;}#bulba-lightbox.open{display:flex;}#bulba-lightbox.scrollable{overflow:auto;align-items:flex-start;justify-content:flex-start;padding:20px;box-sizing:border-box;}#bulba-lightbox img{max-width:90vw;max-height:90vh;object-fit:contain;border-radius:6px;box-shadow:0 8px 40px rgba(0,0,0,0.6);cursor:zoom-in;display:block;transition:transform 0.1s ease;transform-origin:center center;}#bulba-lightbox-close{position:fixed;top:18px;right:24px;font-size:36px;color:#fff;cursor:pointer;line-height:1;z-index:10000;text-shadow:0 2px 8px rgba(0,0,0,0.8);}#bulba-lightbox-close:hover{opacity:0.7;}";

var BULBA_RESET_CSS = "/* Parts mode: force dark readable text, keep Bulbapedia backgrounds */#bulba-content.bulba-mode-part,#bulba-content.bulba-mode-part p,#bulba-content.bulba-mode-part li,#bulba-content.bulba-mode-part td,#bulba-content.bulba-mode-part th,#bulba-content.bulba-mode-part h1,#bulba-content.bulba-mode-part h2,#bulba-content.bulba-mode-part h3,#bulba-content.bulba-mode-part h4,#bulba-content.bulba-mode-part span:not([style*='color']){color:#202122!important;}#bulba-content.bulba-mode-part a{color:#3366cc!important;}";
function bulbaInjectCSS() {
  if (document.getElementById('bulba-scoped-style')) return;
  var s = document.createElement('style'); s.id='bulba-scoped-style';
  s.textContent = BULBA_CSS_TEXT; document.head.appendChild(s);
  var r = document.createElement('style'); r.id='bulba-reset-style';
  r.textContent = BULBA_RESET_CSS; document.head.appendChild(r);
  var lb = document.createElement('style'); lb.id='bulba-lb-style';
  lb.textContent = BULBA_LB_CSS; document.head.appendChild(lb);
  if (!document.getElementById('bulba-lightbox')) {
    var ov = document.createElement('div'); ov.id='bulba-lightbox';
    ov.innerHTML = '<span id="bulba-lightbox-close">&times;</span><img id="bulba-lightbox-img" src="">';
    ov.addEventListener('click', function(e){
      if (e.target===ov||e.target.id==='bulba-lightbox-close') ov.classList.remove('open');
    });
    document.body.appendChild(ov);
    ov.addEventListener('wheel', bulbaLightboxWheel, {passive:false});
    document.addEventListener('keydown',function(e){if(e.key==='Escape')ov.classList.remove('open');});
  }
}

function bulbaOpenLightbox(src) {
  var lb=document.getElementById('bulba-lightbox');
  var img=document.getElementById('bulba-lightbox-img');
  if(!lb||!img) return;
  img.src=src;
  img.classList.remove('zoomed');
  img.style.transform = 'scale(1)';
  img.style.cursor = 'zoom-in';
  _bulbaZoom = 1;
  lb.classList.add('open');
}
function bulbaToggleLightboxZoom(e) {}
var _bulbaZoom = 1;
function bulbaLightboxWheel(e) {
  e.preventDefault();
  var img = document.getElementById('bulba-lightbox-img');
  if (!img) return;
  var delta = e.deltaY < 0 ? 0.15 : -0.15;
  _bulbaZoom = Math.min(5, Math.max(0.5, _bulbaZoom + delta));
  img.style.transform = 'scale(' + _bulbaZoom + ')';
  img.style.cursor = _bulbaZoom > 1 ? 'zoom-out' : 'zoom-in';
}

function bulbaRenderContent(container, html) {
  if (!container) return;
  bulbaInjectCSS();
  container.innerHTML = html;
  container.scrollTop = 0;
  // Wire part nav links
  container.querySelectorAll('a[onclick]').forEach(function(a) {
    var m = (a.getAttribute('onclick')||'').match(/bulbaShowSection\((\d+)\)/);
    if (m) {
      var n = parseInt(m[1]);
      a.removeAttribute('onclick');
      a.addEventListener('click',function(e){e.preventDefault();bulbaShowSection(n);});
    }
  });
  // Image lightbox - get full-res URL and block parent <a>
  container.querySelectorAll('img').forEach(function(img){
    if(!img.src || img.width < 32) return; // skip tiny icons
    img.style.cursor='zoom-in';
    // Derive full-res URL: strip /thumb/ path and trailing size suffix
    function fullRes(src) {
      // e.g. .../thumb/a/ab/File.png/200px-File.png -> .../a/ab/File.png
      return src.replace(/\/thumb\/([a-f0-9]\/[a-f0-9]{2}\/[^/]+)\/[^/]+$/, '/$1');
    }
    img.addEventListener('click',function(e){
      e.stopPropagation();
      e.preventDefault();
      bulbaOpenLightbox(fullRes(img.src));
    });
    // Block parent <a> from navigating at all
    var par=img.closest('a');
    if(par){
      par.addEventListener('click',function(e){e.preventDefault();e.stopPropagation();});
    }
  });
}

