function bulbaSetActive(id) {
  document.querySelectorAll('.bulba-toc-item').forEach(function(el) { el.classList.remove('active'); });
  var prefix = BULBA_GAME === 'rs' ? 'btoc-rs-' : (BULBA_GAME === 'e' ? 'btoc-e-' : 'btoc-');
  var key = (id === 'index') ? (BULBA_GAME === 'rs' ? 'btoc-rs-index' : (BULBA_GAME === 'e' ? 'btoc-e-index' : 'btoc-index')) : (String(id).indexOf('extra-') === 0 ? id.replace(/^extra-/, 'btoc-extra-') : (prefix + id));
  var el = document.getElementById(key);
  if (el) { el.classList.add('active'); el.scrollIntoView({ block:'nearest' }); }
}

function bulbaGetGuideSections(ids) {
  var source = BULBA_GAME === 'frlg' ? GUIDE_SECTIONS : RSE_GUIDE_SECTIONS;
  return ids.map(function(id) {
    return source.find(function(sec) { return sec.id === id; });
  }).filter(Boolean);
}

function _bulbaNoteGuideKey() {
  return BULBA_GAME === 'rs' ? 'RS' : (BULBA_GAME === 'e' ? 'E' : 'FRLG');
}

function _bulbaNotePrimaryGame() {
  var game = (typeof GAME !== 'undefined') ? GAME : 'ALL';
  if (BULBA_GAME === 'frlg') return (game === 'FR' || game === 'LG') ? game : 'ALL';
  if (BULBA_GAME === 'rs') return (game === 'R' || game === 'S') ? game : 'ALL';
  if (BULBA_GAME === 'e') return game === 'E' ? 'E' : 'ALL';
  return 'ALL';
}

function _bulbaNoteActionHtml(mode, key, title) {
  var safeKey = String(key || '').replace(/\\/g, '\\\\').replace(/'/g, "\\'");
  var safeTitle = String(title || '').replace(/\\/g, '\\\\').replace(/'/g, "\\'");
  var gameCtx = _bulbaNotePrimaryGame();
  var hasLinked = typeof window.getLinkedRouteNotesForGame === 'function' && title && window.getLinkedRouteNotesForGame(title, gameCtx).length;
  var label = hasLinked ? 'Linked note' : '+ Note';
  return '<button onclick="event.stopPropagation();bulbaOpenGuideNote(\'' + mode + '\',\'' + safeKey + '\',\'' + safeTitle + '\')"'
    + ' style="font-size:9px;padding:5px 10px;border:1px solid var(--border);border-radius:4px;'
    + 'background:' + (hasLinked ? 'rgba(125,220,110,.9)' : 'color-mix(in srgb,var(--bulba-accent,var(--gold)) 8%,transparent)') + ';'
    + 'color:' + (hasLinked ? '#16310f' : 'var(--bulba-accent,var(--gold))') + ';'
    + 'cursor:pointer;white-space:nowrap;flex-shrink:0;">' + label + '</button>';
}

function bulbaUpdateSidebarNoteButton(mode, key, title) {
  var btn = document.getElementById('bulba-sidebar-note-btn');
  if (!btn) return;
  if (!mode) {
    btn.style.display = 'none';
    btn.onclick = null;
    btn.textContent = '+ Note';
    btn.title = '';
    return;
  }
  var gameCtx = _bulbaNotePrimaryGame();
  var hasLinked = typeof window.getLinkedRouteNotesForGame === 'function' && title && window.getLinkedRouteNotesForGame(title, gameCtx).length;
  btn.style.display = 'block';
  btn.textContent = hasLinked ? 'Linked note' : '+ Note';
  btn.style.background = hasLinked ? 'rgba(125,220,110,.9)' : 'color-mix(in srgb,var(--bulba-accent,var(--gold)) 8%,transparent)';
  btn.style.color = hasLinked ? '#16310f' : 'var(--bulba-accent,var(--gold))';
  btn.title = title ? ((hasLinked ? 'Open note for ' : 'Create a note for ') + title) : 'Create a note for this guide section';
  btn.onclick = function(event) {
    if (event) event.stopPropagation();
    bulbaOpenGuideNote(mode, key, title);
  };
}

window.updateBulbaLinkedNoteButtons = function() {
  if (!window._bulbaBuilt) return;
  if (BULBA_CURRENT === 'index') {
    if (typeof bulbaLoadIndex === 'function') bulbaLoadIndex();
    return;
  }
  if (typeof BULBA_CURRENT === 'string' && BULBA_CURRENT.indexOf('extra-') === 0) {
    var extraKey = BULBA_CURRENT.slice(6);
    var extra = (typeof bulbaGetExtraCards === 'function' ? bulbaGetExtraCards() : []).find(function(item){ return item.key === extraKey; });
    bulbaUpdateSidebarNoteButton('extra', extraKey, extra ? extra.title : extraKey);
    return;
  }
  var partNum = parseInt(BULBA_CURRENT, 10);
  if (!isNaN(partNum)) {
    var parts = BULBA_GAME==='rs' ? BULBA_PARTS_RS : BULBA_GAME==='e' ? BULBA_PARTS_E : BULBA_PARTS;
    var part = (parts || []).find(function(item){ return item && item.num === partNum; });
    bulbaUpdateSidebarNoteButton('part', partNum, part ? part.title : ('Part ' + partNum));
  }
};

window.bulbaOpenGuideNote = function(mode, key, title) {
  var guideKey = _bulbaNoteGuideKey();
  var game = _bulbaNotePrimaryGame();
  var keyLabel = mode === 'part'
    ? ('part:' + key + ':' + title)
    : mode === 'extra'
      ? ('extra:' + key)
      : ('section:' + key);
  var noteTitle = title || (mode === 'part' ? ('Part ' + key) : key);
  var guideLabel = guideKey === 'FRLG' ? 'FR/LG' : (guideKey === 'RS' ? 'R/S' : 'Emerald');
  var linkLabel = guideLabel + ' — ' + noteTitle;
  var content = '## Summary\n\n'
    + '## Checklist\n\n'
    + '[ ] \n\n'
    + '## Guide Link\n\n'
    + '[[bulba:' + guideKey + ':' + keyLabel + '|' + linkLabel + ']]\n';
  window.openRouteLinkedNote(noteTitle, content);
  setTimeout(function(){
    var gameEl = document.getElementById('ne-game');
    var labelsEl = document.getElementById('ne-labels');
    if (gameEl) gameEl.value = game;
    if (labelsEl && !labelsEl.value.trim()) labelsEl.value = 'Guide, Story';
    var _bulbaGameColorMap = {FR:'orange', LG:'green', R:'red', S:'blue', E:'green'};
    var _bulbaDefaultColor = _bulbaGameColorMap[game] || 'green';
    document.querySelectorAll('.ne-color-btn').forEach(function(b){ b.classList.toggle('active', b.dataset.color === _bulbaDefaultColor); });
    document.querySelectorAll('.ne-tag-btn').forEach(function(b){ b.classList.toggle('active', false); });
    var pin = document.getElementById('ne-pin');
    if (pin) {
      pin.classList.remove('active');
      pin.textContent = '📌 Pin';
    }
  }, 100);
};

function bulbaRenderGuideSections(ids) {
  var sections = bulbaGetGuideSections(ids);
  if (!sections.length) return '';
  var inner = sections.map(function(sec) {
    var richContent = (typeof renderGuideSection === 'function') ? renderGuideSection(sec.id) : null;
    return '<div class="guide-chapter-head' + (BULBA_GAME === 'frlg' ? '' : ' rse') + '">' + sec.chapter + '</div>' + (richContent || sec.content);
  }).join('');
  return '<div class="bulba-extra-shell">' + inner + '</div>';
}

function bulbaRenderCustomPart(num) {
  return '';
}

function bulbaGetExtraCards() {
  if (BULBA_GAME === 'frlg') {
    return [
      { key:'frlg-sevii',   title:'Sevii Islands Guide',  sub:'Moved from the Kanto guide and kept separate from Bulba progress' },
      { key:'frlg-legends', title:'Legendary Checklist',  sub:'FR/LG post-game legendary reference' },
      { key:'frlg-safari',  title:'Safari Zone Guide',    sub:'Full Kanto Safari Zone — areas, encounters, items & strategies' }
    ];
  }
  if (BULBA_GAME === 'rs') {
    return [
      { key:'rs-features', title:'RSE Features',         sub:'Mirage Island, Trick House, trades, and version differences' },
      { key:'rs-legends',  title:'Legendary Checklist',  sub:'Ruby & Sapphire post-game legendary reference' },
      { key:'rs-safari',   title:'Safari Zone Guide',    sub:'Full Hoenn Safari Zone — all zones, R/S exclusives, tips' }
    ];
  }
  if (BULBA_GAME === 'e') {
    return [
      { key:'e-features', title:'RSE Features',         sub:'Mirage Island, Trick House, trades, and version differences' },
      { key:'e-legends',  title:'Legendary Checklist',  sub:'Emerald post-game legendary reference' },
      { key:'e-safari',   title:'Safari Zone Guide',    sub:'Full Hoenn Safari Zone including Emerald expanded Johto areas' }
    ];
  }
  return [];
}

function bulbaRenderExtraCards(items) {
  return items.map(function(item) {
    return '<div class="bulba-index-card">'
      + '<div class="bulba-card-main" onclick="bulbaLoadExtra(\'' + item.key + '\',&apos;' + item.title.replace(/&/g,'&amp;').replace(/'/g,'&apos;') + '&apos;)">'
      + '<div class="bulba-index-card-num">Extra</div>'
      + '<div style="flex:1;min-width:0;"><div class="bulba-index-card-text">' + item.title + '</div>'
      + '<div class="bulba-index-card-sub">' + item.sub + '</div></div>'
      + '<div style="width:96px;display:flex;justify-content:flex-end;align-items:center;flex-shrink:0;">' + _bulbaNoteActionHtml('extra', item.key, item.title) + '</div>'
      + '<div style="width:18px;text-align:right;color:var(--muted);font-size:16px;flex-shrink:0;">›</div>'
      + '</div>'
      + '</div>';
  }).join('');
}

function bulbaHardenExtraStyles(container) {
  if (!container) return;
  var shell = container.querySelector('.bulba-extra-shell');
  if (!shell) return;

  function setImp(el, prop, value) {
    if (!el) return;
    el.style.setProperty(prop, value, 'important');
  }

  setImp(shell, 'color', 'var(--text)');
  setImp(shell, 'background-color', 'var(--darker)');
  setImp(shell, 'border-color', 'var(--border)');

  shell.querySelectorAll('p, li, ul, ol, td, th, span, strong, em, div').forEach(function(el) {
    if (!el.closest('.guide-tip strong') && !el.closest('.guide-warn strong')) {
      setImp(el, 'color', 'var(--text)');
    }
  });

  shell.querySelectorAll('.guide-h2, h2').forEach(function(el) {
    setImp(el, 'color', 'var(--gold)');
    setImp(el, 'border-bottom-color', 'var(--border)');
  });

  shell.querySelectorAll('.guide-h3, h3').forEach(function(el) {
    setImp(el, 'color', 'var(--gold)');
  });

  shell.querySelectorAll('.guide-poke-link, .poke-name, a').forEach(function(el) {
    setImp(el, 'color', 'var(--fire)');
  });

  shell.querySelectorAll('.guide-tip').forEach(function(el) {
    setImp(el, 'color', 'var(--text)');
    setImp(el, 'background', 'rgba(255,215,0,0.08)');
    setImp(el, 'border-left-color', 'var(--gold)');
  });
  shell.querySelectorAll('.guide-tip strong').forEach(function(el) {
    setImp(el, 'color', 'var(--gold)');
  });

  shell.querySelectorAll('.guide-warn').forEach(function(el) {
    setImp(el, 'color', 'var(--text)');
    setImp(el, 'background', 'rgba(255,107,53,0.09)');
    setImp(el, 'border-left-color', 'var(--fire)');
  });
  shell.querySelectorAll('.guide-warn strong').forEach(function(el) {
    setImp(el, 'color', 'var(--fire)');
  });

  shell.querySelectorAll('.enc-table').forEach(function(table) {
    setImp(table, 'background', 'rgba(10,12,20,0.42)');
    setImp(table, 'border-radius', '8px');
    setImp(table, 'overflow', 'hidden');
    // Wrap in horizontal scroll container if not already wrapped
    if (!table.parentElement.classList.contains('bulba-table-scroll')) {
      var wrap = document.createElement('div');
      wrap.className = 'bulba-table-scroll';
      table.parentNode.insertBefore(wrap, table);
      wrap.appendChild(table);
    }
  });
  shell.querySelectorAll('.enc-table th').forEach(function(el) {
    setImp(el, 'background', '#2b395f');
    setImp(el, 'color', '#d7deff');
    setImp(el, 'border-color', 'rgba(120,140,220,0.35)');
  });
  shell.querySelectorAll('.enc-table td').forEach(function(el) {
    setImp(el, 'color', '#f3f6ff');
    setImp(el, 'border-color', 'rgba(120,140,220,0.2)');
  });

  shell.querySelectorAll('.guide-chapter-head').forEach(function(el) {
    setImp(el, 'color', el.classList.contains('rse') ? '#44DD88' : 'var(--fire)');
  });
}

function bulbaLoadExtra(key, title) {
  BULBA_CURRENT = 'extra-' + key;
  setPageHash('bulba', { guide: BULBA_GAME, extra: key });
  bulbaSetActive('extra-' + key);
  bulbaUpdateSidebarNoteButton('extra', key, title || 'Guide Extra');
  var bc = document.getElementById('bulba-breadcrumb');
  if (bc) bc.textContent = '— ' + (title || 'Guide Extra');
  var container = document.getElementById('bulba-content');
  if (!container) return;
  container.style.background = '';
  container.style.color = '';
  container.classList.remove('bulba-mode-index');
  container.classList.add('bulba-mode-part');
  if (key === 'frlg-sevii') container.innerHTML = bulbaRenderGuideSections(['sevii']);
  else if (key === 'frlg-legends') container.innerHTML = bulbaRenderGuideSections(['frlg_legendaries']);
  else if (key === 'frlg-safari') container.innerHTML = bulbaRenderGuideSections(['safari_frlg']);
  else if (key === 'rs-features' || key === 'e-features') container.innerHTML = bulbaRenderGuideSections(['rse_mirage', 'rse_trick_house', 'rse_ingame_trades', 'rse_version_comparison']);
  else if (key === 'rs-legends' || key === 'e-legends') container.innerHTML = bulbaRenderGuideSections(['rse_legendaries']);
  else if (key === 'rs-safari' || key === 'e-safari') container.innerHTML = bulbaRenderGuideSections(['safari_rse']);
  else container.innerHTML = '<p style="padding:20px;color:var(--muted)">Guide extra not found.</p>';
  bulbaHardenExtraStyles(container);
  bulbaWrapTables(container);
  container.scrollTop = 0;
}

function buildBulbaGuide() {
  bulbaLoadIndex();
}

// Auto-init: if bulba tab is already active on load, trigger the guide
(function() {
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', function() {
      var page = document.getElementById('page-bulba');
      if (page && page.classList.contains('active') && !window._bulbaBuilt) {
        buildBulbaGuide();
        window._bulbaBuilt = true;
      }
    });
  } else {
    var page = document.getElementById('page-bulba');
    if (page && page.classList.contains('active') && !window._bulbaBuilt) {
      buildBulbaGuide();
      window._bulbaBuilt = true;
    }
  }
})();

function _bulbaProgressKey() {
  var g = (typeof GAME !== 'undefined') ? GAME : 'FR';
  // If no specific game selected, scope to guide
  if (g === 'all') return 'bulba-progress-guide-' + BULBA_GAME;
  // Ensure game belongs to current guide (prevent cross-guide bleed when
  // switching sidebar guide without changing game filter)
  var guideForGame = (g==='R'||g==='S') ? 'rs' : (g==='E') ? 'e' : 'frlg';
  if (guideForGame !== BULBA_GAME) return 'bulba-progress-guide-' + BULBA_GAME;
  return 'bulba-progress-' + g;
}
function _bulbaGetProgress() {
try { return JSON.parse(localStorage.getItem(_bulbaProgressKey()) || '{}'); } catch(e) { return {}; }
}
function _bulbaSetProgress(num, done) {
var p = _bulbaGetProgress();
if (done) p[num] = true; else delete p[num];
localStorage.setItem(_bulbaProgressKey(), JSON.stringify(p));
}
function bulbaToggleProgress(cb) {
var num = parseInt(cb.getAttribute('data-num'));
_bulbaSetProgress(num, cb.checked);
var gk = (typeof GAME !== 'undefined') ? GAME : 'FR';
var card = document.getElementById('bulba-card-' + gk + '-' + num);
if (card) {
  card.classList.toggle('bulba-card-done', cb.checked);
  var textEl = card.querySelector('.bulba-index-card-text');
  if (textEl) {
  var span = textEl.querySelector('span');
  var title = span ? span.textContent : textEl.textContent;
    textEl.innerHTML = cb.checked
      ? '<span style="text-decoration:line-through;opacity:0.55">' + title + '</span>'
      : title;
}
}
_bulbaUpdateProgressBar();
}
function _bulbaUpdateProgressBar() {
var gk = (typeof GAME !== 'undefined') ? GAME : 'FR';
if (gk === 'all') return; // no progress tracking on ALL
var ap = BULBA_GAME==='rs' ? BULBA_PARTS_RS : BULBA_GAME==='e' ? BULBA_PARTS_E : BULBA_PARTS;
var total = ap.filter(function(p){ return p; }).length;
var done  = Object.keys(_bulbaGetProgress()).length;
var bar = document.getElementById('bulba-progress-bar-current');
var lbl = document.getElementById('bulba-progress-label-current');
if (bar) bar.style.width = (total > 0 ? Math.round(done/total*100) : 0) + '%';
if (lbl) lbl.textContent = done + ' / ' + total + ' parts completed';
}
function makeCards(parts) {
var progress = _bulbaGetProgress();
var gk = (typeof GAME !== 'undefined') ? GAME : 'FR';
return parts.map(function(p) {
  var done = (gk !== 'all') && !!progress[p.num];
  var cbId = 'bulba-cb-' + gk + '-' + p.num;
  var titleHtml = done
    ? '<span style="text-decoration:line-through;opacity:0.55">' + p.title + '</span>'
    : p.title;
  return '<div class="bulba-index-card' + (done ? ' bulba-card-done' : '') + '" id="bulba-card-' + gk + '-' + p.num + '">'
    + '<input type="checkbox" class="bulba-part-cb" id="' + cbId + '"'
    + ' data-num="' + p.num + '"'
    + (done ? ' checked' : '') + (gk === 'all' ? ' style="display:none"' : '') + ' onclick="event.stopPropagation();bulbaToggleProgress(this)">'
    + '<div class="bulba-card-main" onclick="bulbaLoadPart(' + p.num + ',&apos;' + p.title.replace(/&/g,'&amp;').replace(/'/g,'&apos;') + '&apos;)">'
    + '<div class="bulba-index-card-num">Part ' + p.num + '</div>'
    + '<div style="flex:1;min-width:0;"><div class="bulba-index-card-text">' + titleHtml + '</div>'
    + '<div class="bulba-index-card-sub">' + p.sub + '</div></div>'
    + '<div style="width:96px;display:flex;justify-content:flex-end;align-items:center;flex-shrink:0;">' + _bulbaNoteActionHtml('part', p.num, p.title) + '</div>'
    + '<div style="width:18px;text-align:right;color:var(--muted);font-size:16px;flex-shrink:0;">›</div>'
    + '</div>'
    + '</div>';
}).join('');
}

function bulbaLoadIndex() {
  BULBA_CURRENT = 'index';
  setPageHash('bulba', BULBA_GAME ? { guide: BULBA_GAME } : null);
  bulbaSetActive('index');
  bulbaUpdateSidebarNoteButton(null);

  var extLink = document.getElementById('bulba-ext-link');
  if (extLink) extLink.href = BULBA_BASE;
  var bc = document.getElementById('bulba-breadcrumb');
  if (bc) bc.textContent = '— Table of Contents';

  var container = document.getElementById('bulba-content');
  if (!container) return;

  var allParts = BULBA_GAME==='rs' ? BULBA_PARTS_RS : BULBA_GAME==='e' ? BULBA_PARTS_E : BULBA_PARTS;
  var mainCutoff = BULBA_GAME==='rs' ? 16 : BULBA_GAME==='e' ? 18 : 18;
  var mainParts = allParts.slice(1, mainCutoff);
  var postParts = allParts.slice(mainCutoff);


  var gk2 = (typeof GAME !== 'undefined') ? GAME : 'FR';

  // When no specific game selected, show the game picker
  if (gk2 === 'all') {
    if (container) {
      container.style.background = '';
      container.style.color = '';
      container.classList.remove('bulba-mode-part');
      container.classList.add('bulba-mode-index');
      container.innerHTML =
        '<div class="bulba-game-picker">'
        + '<div style="font-family:\'Press Start 2P\',monospace;font-size:10px;color:var(--bulba-accent,var(--gold));letter-spacing:1px;margin-bottom:4px">SELECT A WALKTHROUGH</div>'
        + '<div style="font-size:11px;color:var(--muted);margin-bottom:12px">Choose a game to view its Bulbapedia guide</div>'
        + '<div class="bulba-game-grid">'
        + '<button onclick="bulbaPickGame(\'FR\')" class="guide-picker-btn" style="border-color:var(--fire);min-width:140px">'
        +   '<div style="font-family:\'Press Start 2P\',monospace;font-size:9px;color:var(--fire);margin-bottom:8px">\uD83D\uDD25 FIRERED</div>'
        +   '<div style="font-size:11px;color:var(--muted);line-height:1.7">Kanto region<br>Pallet Town \u2192 Elite Four<br>21 parts</div>'
        + '</button>'
        + '<button onclick="bulbaPickGame(\'LG\')" class="guide-picker-btn" style="border-color:var(--leaf);min-width:140px">'
        +   '<div style="font-family:\'Press Start 2P\',monospace;font-size:9px;color:var(--leaf);margin-bottom:8px">\uD83C\uDF3F LEAFGREEN</div>'
        +   '<div style="font-size:11px;color:var(--muted);line-height:1.7">Kanto region<br>Pallet Town \u2192 Elite Four<br>21 parts</div>'
        + '</button>'
        + '<button onclick="bulbaPickGame(\'R\')" class="guide-picker-btn" style="border-color:var(--ruby);min-width:140px">'
        +   '<div style="font-family:\'Press Start 2P\',monospace;font-size:9px;color:var(--ruby);margin-bottom:8px">🔴 RUBY</div>'
        +   '<div style="font-size:11px;color:var(--muted);line-height:1.7">Hoenn region<br>Littleroot \u2192 Champion<br>23 parts</div>'
        + '</button>'
        + '<button onclick="bulbaPickGame(\'S\')" class="guide-picker-btn" style="border-color:var(--sapphire);min-width:140px">'
        +   '<div style="font-family:\'Press Start 2P\',monospace;font-size:9px;color:var(--sapphire);margin-bottom:8px">\uD83D\uDD37 SAPPHIRE</div>'
        +   '<div style="font-size:11px;color:var(--muted);line-height:1.7">Hoenn region<br>Littleroot \u2192 Champion<br>23 parts</div>'
        + '</button>'
        + '<button onclick="bulbaPickGame(\'E\')" class="guide-picker-btn" style="border-color:var(--emerald);min-width:140px">'
        +   '<div style="font-family:\'Press Start 2P\',monospace;font-size:9px;color:var(--emerald);margin-bottom:8px">\uD83D\uDFE2 EMERALD</div>'
        +   '<div style="font-size:11px;color:var(--muted);line-height:1.7">Hoenn region<br>Littleroot \u2192 Champion<br>21 parts</div>'
        + '</button>'
        + '</div>'
        + '</div>';
    }
    return;
  }

  var _showProgress = (gk2 !== 'all');
  // Dark background for contents index page
  if (container) {
    container.style.background = '';
    container.style.color = '';
    container.classList.remove('bulba-mode-part');
    container.classList.add('bulba-mode-index');
  }
  var _allP  = allParts.filter(function(p){ return p; }).length;
  var _doneP = _showProgress ? Object.keys(_bulbaGetProgress()).length : 0;
  var _pct   = (_showProgress && _allP > 0) ? Math.round(_doneP/_allP*100) : 0;
  var _gnames = {FR:'FireRed',LG:'LeafGreen',R:'Ruby',S:'Sapphire',E:'Emerald'};
  var _gameLabel = _gnames[gk2] || gk2;

  container.innerHTML =
    '<div style="max-width:820px;margin:0 auto;padding:24px 20px;">'    + (_showProgress ?
    '<div style="margin-bottom:18px;padding:12px 16px;background:var(--dark)!important;border-radius:8px;border:1px solid var(--border);">'    + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">'    + '<span style="font-family:\'Press Start 2P\',monospace;font-size:7px;color:var(--bulba-accent,#5D9C00);">' + _gameLabel.toUpperCase() + ' PROGRESS</span>'    + '<span id="bulba-progress-label-current" style="font-size:11px;color:var(--muted);">' + _doneP + ' / ' + _allP + ' parts completed</span>'    + '</div>'    + '<div style="height:6px;background:var(--border);border-radius:3px;overflow:hidden;">'    + '<div id="bulba-progress-bar-current" style="height:100%;background:var(--bulba-accent,#5D9C00);border-radius:3px;transition:width 0.3s;width:' + _pct + '%;"></div>'    + '</div>'    + '</div>'    : '')    + '<div style="font-family:\'Press Start 2P\',monospace;font-size:7px;color:var(--muted);letter-spacing:1px;margin-bottom:10px;padding-left:4px;">MAIN STORYLINE</div>'
    + makeCards(mainParts)
    + '<div style="font-family:\'Press Start 2P\',monospace;font-size:7px;color:var(--muted);letter-spacing:1px;margin:20px 0 10px;padding-left:4px;">POST-GAME</div>'
    + makeCards(postParts)
    + (bulbaGetExtraCards().length ? '<div style="font-family:\'Press Start 2P\',monospace;font-size:7px;color:var(--muted);letter-spacing:1px;margin:20px 0 10px;padding-left:4px;">GUIDE EXTRAS</div>' + bulbaRenderExtraCards(bulbaGetExtraCards()) : '')
    + '</div>';
}

function bulbaWrapTables(container) {
  if (!container) return;
  container.querySelectorAll('table').forEach(function(tbl) {
    if (tbl.parentElement.classList.contains('bulba-table-scroll')) return;
    var wrap = document.createElement('div');
    wrap.className = 'bulba-table-scroll';
    tbl.parentNode.insertBefore(wrap, tbl);
    wrap.appendChild(tbl);
  });
}

function bulbaLoadPart(num, title) {
  BULBA_CURRENT = num;
  setPageHash('bulba', { guide: BULBA_GAME, part: num });
  bulbaSetActive(num);
  bulbaUpdateSidebarNoteButton('part', num, title || ('Part ' + num));
  var partUrl = BULBA_BASE + '/Part_' + num;
  var extLink = document.getElementById('bulba-ext-link');
  if (extLink) extLink.href = partUrl;
  var bc = document.getElementById('bulba-breadcrumb');
  if (bc) bc.textContent = '\u2014 Part ' + num + (title ? ': ' + title : '');
  var container = document.getElementById('bulba-content');
  if (!container) return;
  container.style.background = '';
  container.style.color = '';
  container.classList.remove('bulba-mode-index');
  container.classList.add('bulba-mode-part');
  container.scrollTop = 0;
  var key = String(num);
  var sd = BULBA_GAME==='rs' ? (typeof BULBA_STATIC_RS!=='undefined'?BULBA_STATIC_RS:null)
       : BULBA_GAME==='e'  ? (typeof BULBA_STATIC_E !=='undefined'?BULBA_STATIC_E :null)
       : (typeof BULBA_STATIC!=='undefined'?BULBA_STATIC:null);
  // Chapter splash header
  var gameLabel = {frlg:'FIRE RED & LEAF GREEN',rs:'RUBY & SAPPHIRE',e:'EMERALD'}[BULBA_GAME] || 'GEN 3';
  var splashSprite = ({frlg:6,rs:257,e:254}[BULBA_GAME]||25);
  var splashNum = num;
  var splash = '<div class="bulba-part-splash">'
    + '<div class="bps-eyebrow">'+gameLabel+' WALKTHROUGH</div>'
    + '<div class="bps-title">PART '+splashNum+(title?': '+title.toUpperCase():'')+' </div>'
    + '<img class="bps-sprite" src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/'+splashSprite+'.png" alt="" width="80" height="80" style="image-rendering:pixelated;">'
    + '</div>';
  if (sd && sd[key]) {
    container.innerHTML = splash;
    bulbaRenderContent(container, sd[key]);
  } else {
    container.innerHTML = splash + '<div style="padding:40px;text-align:center;">'
      + '<p style="color:#666;">Part ' + num + ' not embedded.</p>'
      + '<p><a href="' + partUrl + '" target="_blank" style="color:#5D9C00;">Open on Bulbapedia \u2197</a></p>'
      + '</div>';
  }
}

// Features overlay
window.toggleFeaturesOverlay = function() {
  var el = document.getElementById('featuresOverlay');
  el.classList.toggle('open');
};
window.closeFeaturesOverlay = function() {
  document.getElementById('featuresOverlay').classList.remove('open');
};
function _initSettingsSections() {
  document.querySelectorAll('#settingsOverlay .settings-section').forEach(function(section) {
    var title = section.querySelector('.settings-section-title');
    if (!title || title.dataset.collapsible) return;
    title.dataset.collapsible = '1';
    var body = document.createElement('div');
    body.className = 'settings-section-body';
    var children = Array.from(section.children);
    var idx = children.indexOf(title);
    children.slice(idx + 1).forEach(function(child) { body.appendChild(child); });
    section.appendChild(body);
    title.addEventListener('click', function() { section.classList.toggle('ss-open'); });
  });
}

window.openSettingsOverlay = function() {
  var el = document.getElementById('settingsOverlay');
  if (el) el.classList.add('open');
  if (!window._settingsSectionsInit) {
    _initSettingsSections();
    window._settingsSectionsInit = true;
  }
  settingsSyncAll();
};
window.closeSettingsOverlay = function() {
  var el = document.getElementById('settingsOverlay');
  if (el) el.classList.remove('open');
};
document.addEventListener('keydown', function(e) {
  if (e.key === 'Escape') {
    closeFeaturesOverlay();
    closeSettingsOverlay();
  }
  // Map zoom shortcuts — only when a map page is active and not typing in an input
  if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') return;
});

// ══════════════════════════════════════════════════════════════════
//  NAV DROPDOWN
// ══════════════════════════════════════════════════════════════════
(function() {
  // Map page id → which dropdown trigger group it belongs to
  var DROPDOWN_MAP = {
    // POKÉMON
    easydex:'navPokeGroup', excl:'navPokeGroup', tradeevo:'navPokeGroup', npctrades:'navPokeGroup',
    abilities:'navPokeGroup', learnsets:'navPokeGroup', encounters:'navPokeGroup',
    // MOVES & ITEMS
    moves:'navMovesItemsGroup', tmhm:'navMovesItemsGroup', tutors:'navMovesItemsGroup',
    items:'navMovesItemsGroup', held:'navMovesItemsGroup', itemlocs:'navMovesItemsGroup',
    // MAPS
    kantomapview:'navMapsGroup', emeraldmapview:'navMapsGroup', routebrowser:'navMapsGroup',
    // BATTLE
    team:'navBattleGroup', typechart:'navBattleGroup', calc:'navBattleGroup',
    speedtiers:'navBattleGroup', compare:'navBattleGroup', opt:'navBattleGroup',
    e4ref:'navBattleGroup', rematches:'navBattleGroup',
    // TRAINING
    ivev:'navTrainingGroup', natures:'navTrainingGroup', expcalc:'navTrainingGroup',
    breed:'navTrainingGroup', catchcalc:'navTrainingGroup', happiness:'navTrainingGroup',
    safarizone:'navTrainingGroup', statcalc:'navTrainingGroup',
    // PROGRESS
    dexdash:'navProgressGroup', ribbons:'navProgressGroup',
    missables:'navProgressGroup', distributions:'navProgressGroup',
    // GUIDES
    essentials:'navGuidesGroup', contests:'navGuidesGroup', frontier:'navGuidesGroup',
    berries:'navGuidesGroup', rng:'navGuidesGroup', pokeblock:'navGuidesGroup'
  };

  function _navMenu(id) {
    // Find the dropdown menu by container id — works whether menu is still inside
    // the container or has been moved to <body> (mobile iOS fix)
    return (window._navMenuMap && window._navMenuMap[id])
      || (function(){ var c=document.getElementById(id); return c && c.querySelector('.page-nav-dropdown-menu'); })();
  }

  window.toggleNavDropdown = function(e, id) {
    e.stopPropagation();
    var container = document.getElementById(id);
    var willOpen = !container.classList.contains('open');
    // Close all open dropdowns first
    document.querySelectorAll('.page-nav-dropdown.open').forEach(function(d) {
      d.classList.remove('open');
      var m = _navMenu(d.id); if (m) { m.classList.remove('open'); m.removeAttribute('style'); }
    });
    if (willOpen) {
      container.classList.add('open');
      var menu = _navMenu(id);
      if (menu) {
        // On desktop, position the body-appended menu below the trigger button
        if (window.innerWidth > 768) {
          var trigger = container.querySelector('.page-nav-dropdown-trigger');
          if (trigger) {
            var rect = trigger.getBoundingClientRect();
            menu.style.position = 'fixed';
            menu.style.top = rect.bottom + 'px';
            menu.style.left = rect.left + 'px';
            menu.style.right = '';
            menu.style.width = '';
          }
        }
        menu.classList.add('open');
      }
    }
  };

  window.closeNavDropdown = function(id) {
    var container = document.getElementById(id);
    if (container) container.classList.remove('open');
    var menu = _navMenu(id); if (menu) menu.classList.remove('open');
  };

  // Close on outside click
  document.addEventListener('click', function(e) {
    if (!e.target.closest('.page-nav-dropdown') && !e.target.closest('.page-nav-dropdown-menu')) {
      document.querySelectorAll('.page-nav-dropdown.open').forEach(function(d){ d.classList.remove('open'); });
      document.querySelectorAll('.page-nav-dropdown-menu.open').forEach(function(m){ m.classList.remove('open'); });
    }
  });

  // REGION: NAVIGATION
  // After showPage fires, highlight the correct dropdown trigger
  var _origShow = window.showPage;
  function ensurePageBuilt(id) {
    var alwaysBuild = {
      excl: function(){ buildExcl(); window._exclBuilt = true; },
      dexdash: function(){ buildDexDashPage(); },
      ribbons: function(){ buildRibbonPage(); window._ribbonsBuilt = true; },
      essentials: function(){ buildEssentialsPage(); window._essentialsBuilt = true; },
      contests: function(){ buildContestsPage(); window._contestsBuilt = true; },
      frontier: function(){ buildFrontierPage(); window._frontierBuilt = true; },
      missables: function(){ buildMissablesPage(); window._missablesBuilt = true; },
      berries: function(){ buildBerriesPage(); window._berriesBuilt = true; },
      rng: function(){ buildRngPage(); window._rngBuilt = true; }
    };
    if (alwaysBuild[id]) {
      alwaysBuild[id]();
      return;
    }
    if (window.ensurePageReady) window.ensurePageReady(id);
  }
  window.showPage = function(id, btn) {
    _origShow(id, btn);
    ensurePageBuilt(id);
    // Clear all dropdown trigger active states
    ['navPokeGroup','navMovesItemsGroup','navMapsGroup','navBattleGroup','navTrainingGroup','navProgressGroup','navGuidesGroup'].forEach(function(gid) {
      var el = document.getElementById(gid);
      if (el) el.classList.remove('active', 'calc-active');
    });
    var trigId = DROPDOWN_MAP[id];
    if (trigId) {
      var trig = document.getElementById(trigId);
      if (trig) trig.classList.add('calc-active');
      document.querySelectorAll('.page-nav-dropdown-item').forEach(function(b){ b.classList.remove('active'); });
      if (btn && btn.classList) btn.classList.add('active');
    }
    if (id === 'expcalc' && typeof expSyncSelectedPokemon === 'function') {
      expSyncSelectedPokemon();
    }
  };

  function scheduleHashRouteRecovery() {
    if (_hashSyncMuted) return;
    var route = getHashRoute();
    if (!route || !route.page || route.page === 'home') return;

    function enforceRoute() {
      if (_hashSyncMuted) return;
      var active = document.querySelector('.page.active');
      if (!active || active.id !== 'page-' + route.page) {
        applyHashRoute(route);
      }
    }

    enforceRoute();
    setTimeout(enforceRoute, 60);
    setTimeout(enforceRoute, 180);
    setTimeout(enforceRoute, 420);
    setTimeout(enforceRoute, 800);
  }

  window.addEventListener('hashchange', function() {
    if (_hashSyncMuted) return;
    applyHashRoute();
    scheduleHashRouteRecovery();
  });

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', scheduleHashRouteRecovery, { once:true });
  } else {
    scheduleHashRouteRecovery();
  }
})();

// ══ NATURE CHART ═══════════════════════════════════════════════
(function() {
  var STAT_NAMES = ['Atk','Def','SpA','SpD','Spe'];
  var FLAVOR_NAMES = ['Spicy','Sour','Dry','Bitter','Sweet'];
  var FLAVOR_CLASSES = ['nature-flavor-spicy','nature-flavor-sour','nature-flavor-dry','nature-flavor-bitter','nature-flavor-sweet'];
  var STAT_COLORS = ['#FF6B35','#9E9E9E','#64b4ff','#81C784','#FFD700'];

  // Natures in display order, grouped by boosted stat
  var NATURES = [
    // Neutral
    {name:'Hardy',b:-1,l:-1},{name:'Docile',b:-1,l:-1},{name:'Serious',b:-1,l:-1},
    {name:'Bashful',b:-1,l:-1},{name:'Quirky',b:-1,l:-1},
    // +Atk
    {name:'Lonely',b:0,l:1},{name:'Brave',b:0,l:4},{name:'Adamant',b:0,l:2},{name:'Naughty',b:0,l:3},
    // +Def
    {name:'Bold',b:1,l:0},{name:'Relaxed',b:1,l:4},{name:'Impish',b:1,l:2},{name:'Lax',b:1,l:3},
    // +SpA
    {name:'Modest',b:2,l:0},{name:'Mild',b:2,l:1},{name:'Quiet',b:2,l:4},{name:'Rash',b:2,l:3},
    // +SpD
    {name:'Calm',b:3,l:0},{name:'Gentle',b:3,l:1},{name:'Sassy',b:3,l:4},{name:'Careful',b:3,l:2},
    // +Spe
    {name:'Timid',b:4,l:0},{name:'Hasty',b:4,l:1},{name:'Jolly',b:4,l:2},{name:'Naive',b:4,l:3}
  ];

  var tbody = document.getElementById('nature-chart-tbody');
  if (!tbody) return;
  var rows = '';
  var lastGroup = null;
  for (var i = 0; i < NATURES.length; i++) {
    var n = NATURES[i];
    var isNeutral = n.b === -1;
    var group = isNeutral ? -1 : n.b;
    var sep = (lastGroup !== null && group !== lastGroup) ? 'border-top:1px solid var(--border);' : '';
    lastGroup = group;
    var boostCell = isNeutral
      ? '<span class="nature-neutral">— neutral —</span>'
      : '<span class="nature-boost" style="color:' + STAT_COLORS[n.b] + '">+' + STAT_NAMES[n.b] + '</span>';
    var cutCell = isNeutral
      ? '<span class="nature-neutral">— neutral —</span>'
      : '<span class="nature-cut">−' + STAT_NAMES[n.l] + '</span>';
    var likeCell = isNeutral
      ? '<span class="nature-neutral">—</span>'
      : '<span class="' + FLAVOR_CLASSES[n.b] + '">' + FLAVOR_NAMES[n.b] + '</span>';
    var dislikeCell = isNeutral
      ? '<span class="nature-neutral">—</span>'
      : '<span class="' + FLAVOR_CLASSES[n.l] + '">' + FLAVOR_NAMES[n.l] + '</span>';
    rows += '<tr style="' + sep + '"><td style="font-weight:600">' + n.name + '</td><td>' + boostCell + '</td><td>' + cutCell + '</td><td>' + likeCell + '</td><td>' + dislikeCell + '</td></tr>';
  }
  tbody.innerHTML = rows;
})();

// ══ TYPE CHART ═════════════════════════════════════════════════

// ══ TYPE CHART PAGE ════════════════════════════════════════════
var selectedDefendTypesPage = [];

function setTypeModeInPage(mode, btn) {
  var container = document.getElementById('typechart-page-body');
  if (!container) return;
  container.querySelectorAll('.tcp-mode-btn').forEach(function(b) {
    b.style.color = 'var(--muted)';
    b.style.borderBottomColor = 'transparent';
  });
  var _gc = gameColor();
  btn.style.setProperty('color', _gc);
  btn.style.setProperty('border-bottom-color', _gc);
  document.getElementById('tcp-full').style.display = mode === 'full' ? 'block' : 'none';
  document.getElementById('tcp-lookup').style.display = mode === 'lookup' ? 'block' : 'none';
}

function toggleDefTypePage(type, btn) {
  var idx = selectedDefendTypesPage.indexOf(type);
  if (idx >= 0) {
    selectedDefendTypesPage.splice(idx, 1);
    btn.classList.remove('active');
  } else {
    if (selectedDefendTypesPage.length >= 2) {
      var old = selectedDefendTypesPage.shift();
      var oldBtn = document.querySelector('#defTypeSelectorPage .type-sel-btn[data-type="' + old + '"]');
      if (oldBtn) oldBtn.classList.remove('active');
    }
    selectedDefendTypesPage.push(type);
    btn.classList.add('active');
  }
  renderLookupResultPage();
}

function renderLookupResultPage() {
  var el = document.getElementById('tcpLookupResult');
  if (!el) return;
  var types = selectedDefendTypesPage;
  if (types.length === 0) {
    el.innerHTML = '<div style="color:var(--muted);font-size:12px;font-style:italic">Select a type above to see its weaknesses and resistances.</div>';
    return;
  }

  var label = types.map(function(t) {
    return typeSprite(t);
  }).join(' + ');

  var results = {4:[],2:[],1:[],0.5:[],0.25:[],0:[]};
  TYPES.forEach(function(atk) {
    var mult = 1;
    types.forEach(function(def) { mult *= TYPE_CHART[atk][def]; });
    var key = mult === 4 ? 4 : mult === 2 ? 2 : mult === 1 ? 1 : mult === 0.5 ? 0.5 : mult === 0.25 ? 0.25 : 0;
    results[key].push(atk);
  });

  var TC = TYPE_COLORS;
  function typeBadges(arr) {
    return arr.map(function(t) {
      return typeSprite(t);
    }).join('');
  }

  var html = '<div class="tc-lookup"><div style="display:flex;align-items:center;gap:8px;margin-bottom:14px">'
    + '<span style="font-family:monospace;font-size:9px;font-weight:800;color:var(--muted)">DEFENDING:</span>'
    + '<span>' + label + '</span>'
    + '</div>';

  var groups = [
    {key:4,    label:'4× Weak',            color:'#c00'},
    {key:2,    label:'2× Weak',            color:'#e84040'},
    {key:0.5,  label:'½× Resists',         color:'#3a9e60'},
    {key:0.25, label:'¼× Strongly resists', color:'#2a7a50'},
    {key:0,    label:'0× Immune',           color:'#666'}
  ];

  groups.forEach(function(g) {
    if (results[g.key] && results[g.key].length > 0) {
      html += '<div class="tc-group"><div class="tc-group-label" style="color:' + g.color + '">' + g.label + '</div>'
        + '<div class="tc-badges">' + typeBadges(results[g.key]) + '</div></div>';
    }
  });

  if (results[1].length > 0) {
    html += '<div class="tc-group"><div class="tc-group-label">1× Normal</div>'
      + '<div class="tc-badges">' + typeBadges(results[1]) + '</div></div>';
  }

  html += '</div>';
  el.innerHTML = html;
}

function buildTypePage() {
  var body = document.getElementById('typechart-page-body');
  if (!body) return;

  // Build mode-tab bar
  var tabBar = '<div style="display:flex;gap:0;border-bottom:2px solid var(--border);margin-bottom:18px">'
    + '<button class="tcp-mode-btn" onclick="setTypeModeInPage(\'full\',this)" style="font-family:\'Press Start 2P\',monospace;font-size:9px;padding:8px 16px;background:none;border:none;cursor:pointer;color:var(--game-color,var(--gold));border-bottom:2px solid var(--game-color,var(--gold));margin-bottom:-2px">FULL CHART</button>'
    + '<button class="tcp-mode-btn" onclick="setTypeModeInPage(\'lookup\',this)" style="font-family:\'Press Start 2P\',monospace;font-size:9px;padding:8px 16px;background:none;border:none;cursor:pointer;color:var(--muted);border-bottom:2px solid transparent;margin-bottom:-2px">LOOKUP</button>'
    + '</div>';

  // Build full chart (reuse buildFullChart which returns pure HTML with no IDs)
  var fullHtml = '<div id="tcp-full" style="display:block">' + buildFullChart() + '</div>';

  // Build lookup view with page-unique IDs
  var lookupHtml = '<div id="tcp-lookup" style="display:none">'
    + '<p style="font-size:11px;color:var(--muted);margin-bottom:12px">Select one or two defending types to see full matchup breakdown:</p>'
    + '<div style="margin-bottom:6px;font-size:10px;font-weight:800;color:var(--muted)">DEFENDING TYPE(S):</div>'
    + '<div class="type-selector" id="defTypeSelectorPage">';

  TYPES.forEach(function(t) {
    lookupHtml += '<button class="type-sel-btn" data-type="' + t + '" onclick="toggleDefTypePage(\'' + t + '\',this)">' + typeSprite(t) + '</button>';
  });

  lookupHtml += '</div>'
    + '<div id="tcpLookupResult" style="margin-top:16px"><div style="color:var(--muted);font-size:12px;font-style:italic">Select a type above to see its weaknesses and resistances.</div></div>'
    + '</div>';

  body.innerHTML = tabBar + fullHtml + lookupHtml;

  // Reset page state
  selectedDefendTypesPage = [];
  window._typeChartBuilt = true;

  // Battle flash on type chart cell click
  var tcFull = document.getElementById('tcp-full');
  if (tcFull) {
    tcFull.addEventListener('click', function(e) {
      var td = e.target.closest('td');
      if (!td) return;
      var msg, sub, col;
      if      (td.classList.contains('tc-cell-2'))  { msg = 'SUPER EFFECTIVE!';      sub = '×2 DAMAGE';   col = '#2e8b34'; }
      else if (td.classList.contains('tc-cell-05')) { msg = 'NOT VERY EFFECTIVE...'; sub = '×½ DAMAGE';   col = '#8b2020'; }
      else if (td.classList.contains('tc-cell-0'))  { msg = 'IT HAD NO EFFECT!';     sub = '×0  IMMUNE';  col = '#222';    }
      else                                           { msg = 'NORMAL HIT';            sub = '×1 DAMAGE';   col = '#1a3a6e'; }
      _showTypeBattleFlash(msg, sub, col, td.title || '');
    });
  }
}

function _showTypeBattleFlash(msg, sub, col, matchup) {
  var el = document.getElementById('type-battle-flash');
  if (!el) return;
  // Parse matchup title into attacking/defending labels
  var parts = matchup ? matchup.split(/\s*[→:]\s*/) : [];
  var atkLabel = parts[0] || '';
  var defLabel = (parts[1] || '').split(':')[0].trim();
  var matchupHtml = (atkLabel && defLabel)
    ? '<div style="font-family:\'Press Start 2P\',monospace;font-size:7px;letter-spacing:1px;color:rgba(255,255,255,0.9);background:rgba(0,0,0,0.55);padding:5px 12px;border-radius:4px;animation:page-fade-in 0.15s ease both;">'
      + atkLabel.toUpperCase() + ' <span style="opacity:0.55">VS</span> ' + defLabel.toUpperCase()
      + '</div>'
    : '';
  el.innerHTML = '<div style="position:absolute;inset:0;background:rgba(0,0,0,0.72);"></div>'
    + '<div style="position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:10px;pointer-events:none;">'
    + matchupHtml
    + '<div class="tbf-text1" style="font-family:\'Press Start 2P\',monospace;font-size:clamp(13px,2.8vw,26px);'
      + 'color:#fff;background:'+col+';padding:10px 22px;border-radius:6px;'
      + 'box-shadow:0 0 30px '+col+',0 4px 12px rgba(0,0,0,0.6);'
      + 'text-shadow:0 1px 3px rgba(0,0,0,0.8);letter-spacing:1px;white-space:nowrap;">'+msg+'</div>'
    + '<div class="tbf-text1" style="font-family:\'Press Start 2P\',monospace;font-size:11px;'
      + 'color:#fff;background:rgba(0,0,0,0.6);padding:4px 14px;border-radius:4px;'
      + 'animation-delay:0.05s;letter-spacing:2px;">'+sub+'</div>'
    + '</div>';
  el.style.display = 'block';
  clearTimeout(el._hideTimer);
  el._hideTimer = setTimeout(function(){ el.style.display = 'none'; el.innerHTML = ''; }, 1000);
}

// ══ PROGRESS MODAL ════════════════════════════════════════════
function openProgressModal() {
  buildProgressDashboard();
  document.getElementById('progressModal').classList.add('open');
}
function closeProgressModal() {
  document.getElementById('progressModal').classList.remove('open');
}

function buildProgressDashboard() {
  var el = document.getElementById('progress-cards');
  if (!el) return;
  var games = [
    {id:'FR', label:'🔥 FireRed',  color:'var(--fire)',   total:386},
    {id:'LG', label:'🌿 LeafGreen',color:'var(--leaf)',   total:386},
    {id:'R',  label:'🔴 Ruby',     color:'#FF5555',       total:386},
    {id:'S',  label:'🔷 Sapphire', color:'#5599FF',       total:386},
    {id:'E',  label:'🟢 Emerald',  color:'var(--emerald)',total:386}
  ];
  var html = '';
  for (var i = 0; i < games.length; i++) {
    var g = games[i];
    var caught = trkLoad(g.id);
    var shinies = trkLoadShiny(g.id);
    var caughtCount = caught.length;
    var shinyCount = shinies.length;
    var caughtPct = Math.round(caughtCount / g.total * 100);
    var shinyPct = shinyCount > 0 ? Math.min(100, Math.round(shinyCount / g.total * 100)) : 0;

    // TM count
    var tmRaw = localStorage.getItem('trk_tm_' + g.id);
    var tmCount = 0;
    try { var tmArr = tmRaw ? JSON.parse(tmRaw) : []; tmCount = tmArr.length; } catch(e) {}

    html += '<div class="progress-game-card">';
    html += '<div class="progress-game-title" style="color:' + g.color + '">' + g.label + '</div>';
    // Caught bar
    html += '<div class="progress-bar-row">'
      + '<div class="progress-bar-label">Caught</div>'
      + '<div class="progress-bar-wrap"><div class="progress-bar-fill" style="width:' + caughtPct + '%;background:' + g.color + '"></div></div>'
      + '<div class="progress-bar-count">' + caughtCount + ' / ' + g.total + ' (' + caughtPct + '%)</div>'
      + '</div>';
    // Shiny bar
    html += '<div class="progress-bar-row">'
      + '<div class="progress-bar-label">✨ Shiny</div>'
      + '<div class="progress-bar-wrap"><div class="progress-bar-fill" style="width:' + shinyPct + '%;background:' + g.color + '"></div></div>'
      + '<div class="progress-bar-count" style="color:' + g.color + '">' + shinyCount + ' found</div>'
      + '</div>';
    // TM row
    html += '<div style="font-size:10px;color:var(--muted);margin-top:6px;">💿 TMs collected: <strong style="color:var(--text)">' + tmCount + '</strong></div>';
    html += '</div>';
  }
  if (!html) html = '<div style="color:var(--muted);font-size:12px;">No tracker data found. Start catching Pokémon in the Tracker page!</div>';
  el.innerHTML = html;
}

// ══ SPEED TIERS ═════════════════════════════════════════════════
function buildSpeedTiersPage() { stRender(); window._speedtiersBuilt = true; }

function stRender() {
  var mySpeed = parseInt(document.getElementById('st-myspeed').value || '0');
  var q = _norm((document.getElementById('st-search') || {}).value || '');
  var grouped = document.getElementById('st-group') ? document.getElementById('st-group').checked : true;

  // Build sorted list from BASE_STATS
  var entries = POKE.map(function(p) {
    var bs = BASE_STATS[String(p.num)] || [0,0,0,0,0,0];
    return { num:p.num, name:p.name, types:p.types, spd:bs[5] };
  }).filter(function(e) {
    return !q || _norm(e.name).includes(q);
  }).sort(function(a,b) { return b.spd - a.spd; });

  // Banner: what do I outspeed?
  var banner = document.getElementById('st-banner');
  if (mySpeed > 0) {
    var slower = entries.filter(function(e) { return e.spd < mySpeed; }).length;
    var tied = entries.filter(function(e) { return e.spd === mySpeed; }).length;
    var faster = entries.filter(function(e) { return e.spd > mySpeed; }).length;
    banner.style.display = '';
    banner.innerHTML = 'At <strong style="color:var(--game-color,var(--gold));">' + mySpeed + '</strong> Speed stat you outspeed <strong>' + slower + '</strong> Pokémon, tie with <strong>' + tied + '</strong>, and are outsped by <strong>' + faster + '</strong>.';
  } else {
    banner.style.display = 'none';
  }

  var typeColors = {normal:'#A8A878',fire:'#F08030',water:'#6890F0',grass:'#78C850',electric:'#F8D030',ice:'#98D8D8',fighting:'#C03028',poison:'#A040A0',ground:'#E0C068',flying:'#A890F0',psychic:'#F85888',bug:'#A8B820',rock:'#B8A038',ghost:'#705898',dragon:'#7038F8',dark:'#705848',steel:'#B8B8D0'};

  function chip(e) {
    var col = typeColors[e.types[0]] || '#888';
    var rel = mySpeed > 0 ? (e.spd < mySpeed ? 'rgba(68,221,136,0.08)' : e.spd === mySpeed ? 'rgba(255,215,0,0.08)' : 'rgba(255,85,85,0.08)') : 'var(--panel)';
    var border = mySpeed > 0 ? (e.spd < mySpeed ? '#44DD88' : e.spd === mySpeed ? 'var(--gold)' : '#FF5555') : 'var(--border)';
    return '<span onclick="guideDex(\''+e.name.replace(/'/g, "\\'")+'\')" title="'+e.name+' — Base Speed: '+e.spd+'" style="display:inline-flex;align-items:center;gap:3px;background:'+rel+';border:1px solid '+border+';border-radius:4px;padding:3px 7px;font-size:11px;cursor:pointer;margin:2px;" onmouseover="this.style.opacity=\'0.75\'" onmouseout="this.style.opacity=\'1\'">'
      +'<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/'+e.num+'.png" style="width:20px;height:20px;image-rendering:pixelated;">'
      +e.name+'</span>';
  }

  var html;
  if (grouped) {
    var seen = {};
    var tiers = [];
    entries.forEach(function(e) {
      if (!seen[e.spd]) { seen[e.spd] = []; tiers.push(e.spd); }
      seen[e.spd].push(e);
    });
    html = tiers.map(function(spd) {
      var label = mySpeed > 0 ? (spd < mySpeed ? ' <span style="color:#44DD88;font-size:9px;">✓ outsped</span>' : spd === mySpeed ? ' <span style="color:var(--game-color,var(--gold));font-size:9px;">= tie</span>' : ' <span style="color:#FF5555;font-size:9px;">↑ faster</span>') : '';
      return '<div style="display:flex;align-items:flex-start;gap:12px;padding:8px 0;border-bottom:1px solid rgba(255,255,255,0.04);">'
        +'<div style="min-width:48px;text-align:right;font-family:\'Press Start 2P\',monospace;font-size:9px;color:var(--game-color,var(--gold));padding-top:6px;">'+spd+label+'</div>'
        +'<div style="display:flex;flex-wrap:wrap;">'+seen[spd].map(chip).join('')+'</div>'
        +'</div>';
    }).join('');
  } else {
    html = '<table style="width:100%;border-collapse:collapse;">'
      +'<thead><tr style="border-bottom:2px solid var(--border);">'
      +'<th style="padding:6px 10px;font-family:\'Press Start 2P\',monospace;font-size:6px;color:var(--muted);text-align:right;">SPD</th>'
      +'<th style="padding:6px 10px;font-family:\'Press Start 2P\',monospace;font-size:6px;color:var(--muted);text-align:left;">POKÉMON</th>'
      +'<th style="padding:6px 10px;font-family:\'Press Start 2P\',monospace;font-size:6px;color:var(--muted);">TYPE</th>'
      +'</tr></thead><tbody>'
      + entries.map(function(e) {
          var rel = mySpeed > 0 ? (e.spd < mySpeed ? '#44DD88' : e.spd === mySpeed ? 'var(--gold)' : '#FF5555') : 'var(--text)';
          var type1 = e.types[0];
          return '<tr style="border-bottom:1px solid rgba(255,255,255,0.04);">'
            +'<td style="padding:5px 10px;font-family:\'Press Start 2P\',monospace;font-size:8px;color:'+rel+';text-align:right;">'+e.spd+'</td>'
            +'<td style="padding:5px 10px;display:flex;align-items:center;gap:6px;">'
            +'<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/'+e.num+'.png" style="width:24px;height:24px;image-rendering:pixelated;">'
            +'<span style="font-size:12px;cursor:pointer;" onclick="guideDex(\''+e.name.replace(/'/g, "\\'")+'\')">'+e.name+'</span></td>'
            +'<td style="padding:5px 8px;">'+typeSprite(type1)+'</td>'
            +'</tr>';
        }).join('')
      +'</tbody></table>';
  }
  document.getElementById('st-list').innerHTML = html;
}

// ══ CONTESTS PAGE ════════════════════════════════════════════════
function buildContestsPage() {
  var c = document.getElementById('contests-content');
  if (!c) return;

  function card(title, body) {
    return '<div style="background:var(--card);border:1px solid var(--border);border-radius:8px;padding:16px 18px;margin-bottom:16px;">'
      +'<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));margin-bottom:10px;">'+title+'</div>'
      +body+'</div>';
  }
  function info(text) { return '<p style="font-size:12px;color:var(--text);line-height:1.7;margin:0 0 8px;">'+text+'</p>'; }
  function table(headers, rows, hideCols) {
    hideCols = hideCols || [];
    return '<table class="contests-tbl" style="width:100%;border-collapse:collapse;font-size:12px;">'
      +'<thead><tr style="border-bottom:2px solid var(--border);">'
      +headers.map(function(h,i){return '<th class="'+(hideCols.indexOf(i)>=0?'contests-tbl-hide':'')+'" style="padding:6px 10px;font-family:\'Press Start 2P\',monospace;font-size:6px;color:var(--muted);text-align:left;">'+h+'</th>';}).join('')
      +'</tr></thead><tbody>'
      +rows.map(function(r){return '<tr style="border-bottom:1px solid rgba(255,255,255,0.04);">'
        +r.map(function(cell,i){return '<td class="'+(hideCols.indexOf(i)>=0?'contests-tbl-hide':'')+'" style="padding:6px 10px;color:var(--text);">'+cell+'</td>';}).join('')
        +'</tr>';}).join('')
      +'</tbody></table>';
  }

  var condColors = {Coolness:'#4A9FFF',Beauty:'#FF6AB4',Cuteness:'#FF9040',Cleverness:'#AA66FF',Toughness:'#44BB44'};
  var condBadge = function(name) {
    return '<span style="display:inline-block;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:700;background:'+condColors[name]+'22;border:1px solid '+condColors[name]+';color:'+condColors[name]+';">'+name+'</span>';
  };

  var html = '';

  // Overview
  html += card('OVERVIEW',
    info('Pokémon Contests are side events available in every Pokémon Center in Hoenn. There are <strong>5 contest categories</strong> and <strong>4 ranks</strong> — earning a ribbon in every rank of every category gives your Pokémon 20 ribbons.')
    +'<div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:8px;">'
    +Object.keys(condColors).map(condBadge).join('')
    +'</div>'
  );

  // Conditions & Pokéblocks
  html += card('CONDITIONS &amp; POKÉBLOCKS',
    info('Each contest category is powered by a <strong>condition stat</strong> raised by feeding Pokéblocks. Higher condition = higher starting appeal score.')
    +table(['Condition','Raised by','Berry colour','Pokéblock type'],
      [['Coolness','Red, Blue berries','Red / Blue','Cool'],
       ['Beauty','Blue, Green berries','Blue / Indigo','Beauty'],
       ['Cuteness','Pink, Yellow berries','Pink / Yellow','Cute'],
       ['Cleverness','Green, Yellow berries','Green / Yellow','Smart'],
       ['Toughness','Yellow, Red berries','Yellow / Red','Tough']],[2])
    +'<div style="margin-top:10px;padding:10px;background:var(--panel);border-radius:6px;font-size:11px;color:var(--muted);line-height:1.7;">'
    +'<strong style="color:var(--text);">Pokéblock limit:</strong> Each Pokémon can only eat a limited number of Pokéblocks (based on its <strong>nature</strong>). Natures that "like" a flavor give +2 to that condition; natures that "dislike" give only +1. Jolly/Timid/etc. Pokémon cannot raise some conditions at all.<br>'
    +'<strong style="color:var(--text);">Sheen:</strong> Each Pokéblock raises Sheen. When Sheen maxes out (255), the Pokémon can eat no more Pokéblocks — plan your Pokéblock diet carefully.'
    +'</div>'
  );

  // Contest flow
  html += card('HOW CONTESTS WORK',
    info('Each contest round: all contestants pick a move. <strong>Appeal</strong> is generated from the move\'s base appeal value plus crowd bonuses. The Pokémon with the most appeal at the end of 5 rounds wins.')
    +'<div style="display:flex;flex-direction:column;gap:8px;margin-top:6px;">'
    +[['Appeal','The main score. Generated by moves. Doubled when the crowd is excited (filled heart meter). Some moves generate more appeal when used after specific other moves.'],
      ['Jamming','Some moves reduce the appeal of other contestants on that turn. Blocking jamming gives +2 appeal.'],
      ['Crowd hearts','The audience has 5 hearts. Using moves of the matching contest category fills hearts. Filled = excited crowd → ×2 appeal multiplier. Hearts drain if you ignore the crowd.'],
      ['Move order','Determined by your condition stat matching the category (e.g. Coolness contests use the Coolness stat). Higher condition = earlier turn = ability to jam before others appeal.'],
      ['Combos','Some moves set up combos: using move A then move B on the next turn gives +8 bonus appeal. The move description hints at this ("appeal increases greatly if used after X").']]
      .map(function(row){return '<div style="display:flex;gap:10px;padding:8px;background:var(--panel);border-radius:6px;">'
        +'<div><strong style="font-size:11px;color:var(--text);">'+row[0]+'</strong><div style="font-size:11px;color:var(--muted);line-height:1.6;margin-top:2px;">'+row[1]+'</div></div>'
        +'</div>';})
      .join('')
    +'</div>'
  );

  // Ranks
  html += card('RANKS &amp; RIBBONS',
    info('Each category has 4 ranks. Win them all for 20 ribbons (100 total with effort ribbons etc.).')
    +table(['Rank','Location','Requirement'],
      [['Normal','Verdanturf / Fallarbor / Slateport / Lilycove','Any Pokémon'],
       ['Super','Lilycove Contest Hall (2F)','Won Normal in that category'],
       ['Hyper','Lilycove Contest Hall (3F)','Won Super in that category'],
       ['Master','Lilycove Contest Hall (4F)','Won Hyper in that category']])
    +'<div style="margin-top:10px;padding:8px 12px;background:rgba(255,215,0,0.06);border:1px solid var(--gold);border-radius:6px;font-size:11px;color:var(--muted);">Win the Master rank of all 5 categories to get the <strong style="color:var(--gold);">Artist</strong> to paint your Pokémon\'s portrait, displayed in the Lilycove Museum.</div>'
  );

  // Ribbon checklist
  html += card('RIBBON CHECKLIST',
    '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:8px;">'
    + Object.keys(condColors).map(function(cat) {
        return ['Normal','Super','Hyper','Master'].map(function(rank, i) {
          var key = 'contest_'+cat+'_'+rank;
          var checked = localStorage.getItem('g3_ribbon_'+key) === '1';
          return '<label style="display:flex;align-items:center;gap:6px;padding:6px 8px;background:var(--panel);border-radius:5px;cursor:pointer;font-size:11px;">'
            +'<input type="checkbox" '+(checked?'checked':'')
            +' onchange="localStorage.setItem(\'g3_ribbon_'+key+'\',this.checked?\'1\':\'\');this.parentElement.style.opacity=this.checked?\'0.5\':\'\'" '
            +'style="accent-color:'+condColors[cat]+';">'
            +'<span style="color:'+condColors[cat]+';font-weight:700;">'+cat.slice(0,4)+'</span>'
            +'<span style="color:var(--muted);">'+rank+'</span>'
            +'</label>';
        }).join('');
      }).join('')
    +'</div>'
  );

  c.innerHTML = html;
  window._contestsBuilt = true;
}

// ══ BATTLE FRONTIER PAGE ════════════════════════════════════════
function buildFrontierPage() {
  var c = document.getElementById('frontier-content');
  if (!c) return;

  var _frPokeNames = POKE.map(function(p){ return p.name; }).sort(function(a,b){ return b.length-a.length; });
  var _frItemNames = ALL_ITEMS.map(function(it){ return it[1]; }).sort(function(a,b){ return b.length-a.length; });
  var _frMoveNames = ALL_MOVES_DATA.map(function(m){ return m[1]; }).sort(function(a,b){ return b.length-a.length; });
  function _frReplaceInTextNodes(html, names, cssClass, onclickFn) {
    if (!names.length) return html;
    var pattern = names.map(function(n){ return '\\b' + n.replace(/[.*+?^${}()|[\]\\]/g,'\\$&') + '\\b'; }).join('|');
    var nameRe = new RegExp('(' + pattern + ')', 'g');
    return html.replace(/(<[^>]+>)|([^<]+)/g, function(match, tag, txt) {
      if (tag) return tag;
      return txt.replace(nameRe, function(matched) {
        return '<span class="' + cssClass + '" onclick="' + onclickFn(matched) + '">' + matched + '</span>';
      });
    });
  }
  function _frLink(text) {
    text = _frReplaceInTextNodes(text, _frPokeNames, 'guide-poke-link', function(n){ return 'guideDex(\'' + n.replace(/'/g,"\\'") + '\')'; });
    text = _frReplaceInTextNodes(text, _frItemNames, 'guide-item-link', function(n){ return 'openItemByName(\'' + n.replace(/'/g,"\\'") + '\')'; });
    text = _frReplaceInTextNodes(text, _frMoveNames, 'guide-move-link', function(n){ return '_openMoveDex(\'' + n.replace(/'/g,"\\'") + '\')'; });
    return text;
  }

  function card(title, color, body) {
    return '<div style="background:var(--card);border:1px solid '+(color||'var(--border)')+';border-radius:8px;padding:16px 18px;margin-bottom:16px;">'
      +'<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:'+(color||'var(--gold)')+';margin-bottom:10px;">'+title+'</div>'
      +body+'</div>';
  }
  function p(t) { return '<p style="font-size:12px;color:var(--text);line-height:1.7;margin:0 0 8px;">'+_frLink(t)+'</p>'; }
  function muted(t) { return '<p style="font-size:11px;color:var(--muted);line-height:1.7;margin:0 0 6px;">'+_frLink(t)+'</p>'; }
  function badge(label, color) { return '<span style="display:inline-block;padding:2px 8px;border-radius:4px;font-size:10px;font-weight:700;background:'+color+'22;border:1px solid '+color+';color:'+color+';margin:2px;">'+label+'</span>'; }

  var facilities = [
    { name:'BATTLE TOWER', color:'#5599FF', brain:'Anabel', streak:50, mode:'Own Pokémon (Level 50 or Open Level). Singles or Doubles.',
      tip:'The most straightforward facility. Level 50 format lets weaker Pokémon compete. Bring Pokémon with high individual stat totals — Salamence, Metagross, Snorlax, Blissey, and Latios are top-tier.',
      prize:'BP prizes include Salac/Petaya/Liechi berries at 1 BP, and Choice Band / Scope Lens at 48 BP.' },
    { name:'BATTLE DOME', color:'#FF9040', brain:'Tucker', streak:50, mode:'Tournament bracket (16 Pokémon, 4 rounds per set). Own Pokémon.',
      tip:'You see opponent\'s Pokémon before each battle — pick your 3 from your 6 strategically. Info screens reveal opponent\'s tendencies. Tucker uses Swampert and Salamence.',
      prize:'Same BP pool as Tower.' },
    { name:'BATTLE FACTORY', color:'#44BB44', brain:'Noland', streak:21, mode:'Rental Pokémon only — choose 3 from 6 random rentals. After every win, you can swap one rental.',
      tip:'IVs and EVs on rentals are random. Focus on raw base stats and coverage. After 21 wins, Noland challenges you with the legendary Articuno. Accept the swap offer strategically — don\'t just take the shiny new option.',
      prize:'BP rewarded based on win streak length.' },
    { name:'BATTLE PIKE', color:'#AA66FF', brain:'Lucy', streak:70, mode:'Choose from 3 rooms per floor (14 floors). Rooms may contain nothing, trainers, or hazards.',
      tip:'No healing between floors except from specific rooms. Room hints: two people = safe, one person = trainer or healing, nobody = wild Pokémon or status. Lucy uses Seviper and Milotic at room 140.',
      prize:'BP per streak segment.' },
    { name:'BATTLE PYRAMID', color:'#FF5555', brain:'Brandon', streak:70, mode:'Navigate dark floors, find items, reach the top. Own Pokémon — no PP/HP recovery between floors.',
      tip:'Items found in the pyramid replenish PP and HP — collect everything. Bring Pokémon with Rest, or wide move coverage. Brandon uses legendary Regis (Regirock, Regice, Registeel).',
      prize:'BP per cleared pyramid.' },
    { name:'BATTLE ARENA', color:'#FFD700', brain:'Greta', streak:50, mode:'3 turns per battle — if neither Pokémon faints, a judge awards points for HP remaining, Defense shown, and "Mind" (attacking vs. status moves).',
      tip:'KO your opponent in 3 turns or have more judge points. Avoid stall strategies — pure defense scores poorly on Mind. High-power physical attackers (Heracross, Slaking) excel.',
      prize:'BP as normal.' },
    { name:'BATTLE PALACE', color:'#FF6AB4', brain:'Spenser', streak:50, mode:'Your Pokémon choose their own moves based on nature. You only control switches.',
      tip:'Natures determine attack bias (Hardy = balanced, Modest = mostly special, Adamant = mostly physical). Bring Pokémon with all good moves regardless of category, so the AI picks well. Bold/Careful natures often stall.',
      prize:'BP as normal.' },
  ];

  var html = p('Emerald\'s Battle Frontier contains <strong>7 facilities</strong>, each with unique rules. Earn Battle Points (BP) by winning streaks and spend them on rare items. Each facility has a <strong>Frontier Brain</strong> who challenges you after reaching a win milestone.')
    +'<div style="padding:10px 14px;background:color-mix(in srgb,var(--game-color,var(--gold)) 6%,transparent);border:1px solid var(--game-color,var(--gold));border-radius:6px;font-size:11px;color:var(--muted);margin-bottom:20px;line-height:1.7;">'
    +'<strong style="color:var(--text);">Key BP prizes:</strong> ' + _frLink('Salac/Petaya/Liechi/Ganlon/Apicot/Lansat/Starf berries (1 BP) · TM26 Earthquake (32 BP) · Choice Band (48 BP) · Scope Lens (48 BP) · Bright Powder (48 BP) · White Herb (48 BP)')
    +'</div>';

  html += facilities.map(function(f) {
    return '<div style="background:var(--card);border:1px solid '+f.color+';border-radius:8px;padding:16px 18px;margin-bottom:14px;">'
      +'<div style="margin-bottom:10px;">'
      +'<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));margin-bottom:4px;">'+f.name+'</div>'
      +'<div style="font-size:10px;color:var(--muted);">Brain: <strong style="color:var(--text);">'+f.brain+'</strong> · Challenge at win '+f.streak+'</div>'
      +'</div>'
      +'<div style="font-size:12px;color:var(--muted);margin-bottom:8px;padding:6px 10px;background:var(--panel);border-radius:5px;line-height:1.6;"><strong style="color:var(--text);">Format:</strong> '+_frLink(f.mode)+'</div>'
      +'<div style="font-size:12px;color:var(--text);line-height:1.7;margin-bottom:8px;">'+_frLink(f.tip)+'</div>'
      +'<div style="font-size:11px;color:var(--muted);">'+_frLink(f.prize)+'</div>'
      +'</div>';
  }).join('');

  c.innerHTML = html;
  window._frontierBuilt = true;
}

