function buildMissablesPage() {
  var games = ['FR','LG','R','S','E'];
  var colors = { FR:'var(--fire)', LG:'var(--leaf)', R:'#FF5555', S:'#5599FF', E:'var(--emerald)' };
  var btns = document.getElementById('miss-game-btns');
  btns.innerHTML = games.map(function(g) {
    var active = g === _missGame;
    var col = colors[g];
    return '<button onclick="missSetGame(\''+g+'\')" data-game="'+g+'" style="font-family:\'Press Start 2P\',monospace;font-size:7px;padding:6px 12px;border-radius:4px;border:2px solid '+(active?col:'var(--border)')+';background:transparent;cursor:pointer;color:'+(active?col:'var(--muted)')+';">'
      +{FR:'🔥 FR',LG:'🌿 LG',R:'🔴 R',S:'🔷 S',E:'🟢 E'}[g]+'</button>';
  }).join('');
  missRender();
  window._missablesBuilt = true;
}

function missSetGame(g) {
  _missGame = g;
  var colors = { FR:'var(--fire)', LG:'var(--leaf)', R:'#FF5555', S:'#5599FF', E:'var(--emerald)' };
  document.querySelectorAll('#miss-game-btns button').forEach(function(b) {
    var bg = b.getAttribute('data-game');
    b.style.borderColor = bg === g ? colors[g] : 'var(--border)';
    b.style.color = bg === g ? colors[g] : 'var(--muted)';
  });
  missRender();
}

function buildEssentialsPage() {
  var c = document.getElementById('essentials-content');
  if (!c) return;

  var _esPokeNames = POKE.map(function(p){ return p.name; }).sort(function(a,b){ return b.length-a.length; });
  var _esItemNames = ALL_ITEMS.map(function(it){ return it[1]; }).sort(function(a,b){ return b.length-a.length; });
  var _esMoveNames = ALL_MOVES_DATA.map(function(m){ return m[1]; }).sort(function(a,b){ return b.length-a.length; });
  function _esReplaceInTextNodes(html, names, cssClass, onclickFn) {
    if (!names.length) return html;
    var pattern = names.map(function(n){ return '\\b' + n.replace(/[.*+?^${}()|[\]\\]/g,'\\$&') + '\\b'; }).join('|');
    var nameRe = new RegExp('(' + pattern + ')', 'g');
    return html.replace(/(<[^>]+>)|([^<]+)/g, function(match, tag, txt) {
      if (tag) return tag;
      return txt.replace(nameRe, function(matched) {
        return '<span class="' + cssClass + '" onclick="' + onclickFn(matched) + '">' + matched + '</span>';
      });
    });
  }
  function _esLink(text) {
    text = _esReplaceInTextNodes(text, _esPokeNames, 'guide-poke-link', function(n){ return 'guideDex(\'' + n.replace(/'/g,"\\'") + '\')'; });
    text = _esReplaceInTextNodes(text, _esItemNames, 'guide-item-link', function(n){ return 'openItemByName(\'' + n.replace(/'/g,"\\'") + '\')'; });
    text = _esReplaceInTextNodes(text, _esMoveNames, 'guide-move-link', function(n){ return '_openMoveDex(\'' + n.replace(/'/g,"\\'") + '\')'; });
    return text;
  }

  function card(title, body) {
    return '<div style="background:var(--card);border:1px solid var(--border);border-radius:8px;padding:16px 18px;margin-bottom:16px;">'
      + '<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));margin-bottom:10px;">' + title + '</div>'
      + body + '</div>';
  }
  function p(text) {
    return '<p style="font-size:12px;color:var(--text);line-height:1.7;margin:0 0 8px;">' + _esLink(text) + '</p>';
  }
  function tip(label, text) {
    return '<div style="padding:8px 10px;background:var(--panel);border-radius:6px;font-size:11px;color:var(--muted);line-height:1.7;margin:8px 0 0;">'
      + '<strong style="color:var(--text);">' + label + ':</strong> ' + _esLink(text) + '</div>';
  }
  function bullets(items) {
    return '<div style="display:flex;flex-direction:column;gap:8px;">'
      + items.map(function(item) {
        var content = (item && typeof item === 'object' && item.raw) ? item.raw : _esLink(item);
        return '<div style="display:flex;gap:10px;align-items:flex-start;">'
          + '<span style="color:var(--game-color,var(--gold));font-size:12px;line-height:1.6;">•</span>'
          + '<div style="font-size:12px;color:var(--text);line-height:1.7;">' + content + '</div>'
          + '</div>';
      }).join('')
      + '</div>';
  }

  var html = '';
  html += card('START HERE',
    p('If you are new to Gen 3, the basic loop is simple: <strong>fight trainers, heal often, catch useful Pokemon, beat the next Gym, and use new HMs to open more of the map</strong>.')
    + bullets([
      'Pokemon Centers are your reset point. Heal there constantly. There is no penalty.',
      'Talk to NPCs in every town. Key items, rods, trade offers, and progression hints often come from side houses rather than the main path.',
      'Trainer battles are your safest source of money and EXP. Wild battles are mostly for catching, training, and filling gaps.',
      'If a route suddenly feels too hard, go back, clear optional trainers, and evolve your team before pushing forward.'
    ])
  );

  html += card('TALL GRASS & WILD ENCOUNTERS',
    p('Tall grass, caves, water, fishing spots, Rock Smash rocks, and Safari areas all use different encounter tables. A Pokemon being "on a route" does not mean every encounter method can find it.')
    + bullets([
      'Grass encounters are the default and usually the easiest way to catch a route\'s common Pokemon.',
      'Caves often have lower visibility and more filler encounters, so bring Repels if you already know what you want.',
      'Higher encounter rates do not always mean best value. Sometimes a rare catch is still worth targeting because it saves you a late-game replacement.',
      'Use the site\'s `Encounters` and `Easy Dex` pages when you want the exact method instead of guessing.'
    ])
    + tip('Repel rule', 'Repel only blocks wild Pokemon below the level of the first conscious Pokemon in your party. This is useful for filtering junk encounters.')
  );

  html += card('CATCHING POKEMON',
    p('The easiest catch routine is: <strong>lower HP, inflict status, then throw the right ball</strong>.')
    + bullets([
      'Sleep and Freeze are the strongest statuses for catching. Paralysis is the easiest reliable backup.',
      'Do not overdamage targets you only get one shot at. Switch to weaker moves or status support before going for a catch.',
      'Great Balls become your normal midgame option. Ultra Balls are for harder late catches. Specialty balls matter when available.',
      'If you are unsure, use the site\'s `Catch Rate Calc` before committing rare balls.'
    ])
    + tip('Early utility', 'A Pokemon with Sleep Powder, Thunder Wave, Hypnosis, or Stun Spore can carry a run much harder than raw damage does.')
  );

  html += card('FISHING & SURFING',
    p('Water routes are not just "more encounters." Surfing and fishing each unlock different pools, and rods matter.')
    + bullets([
      'Old Rod usually gives the weakest pool and is mostly for very early Water-type access.',
      'Good Rod opens the first actually useful fishing range in many games.',
      'Super Rod is where many late evolutions and stronger Water catches show up.',
      'Surf encounters are separate from fishing encounters, so always check both if you are hunting something specific.'
    ])
    + tip('Progression use', 'HM03 Surf is one of the biggest map-expansion moments in Gen 3. Once you get it, revisit earlier routes and towns because lots of side items and optional catches unlock at once.')
  );

  html += card('HMS, FIELD MOVES & MAP FLOW',
    p('HMs are progression tools first and battle moves second. Think of them as keys that open the world.')
    + bullets([
      'Cut usually opens small shortcuts and early side items.',
      'Surf opens major routes, islands, and whole optional areas.',
      'Strength unlocks caves and puzzle routes.',
      'Flash is quality-of-life for dark caves, not always mandatory.',
      'Waterfall and Dive matter mostly in late Hoenn progression.'
    ])
    + tip('Team planning', 'Avoid teaching every HM to your main battlers unless the move is genuinely useful. Keeping one utility slot or HM slave is usually cleaner.')
  );

  html += card('STATUS, HEALING & ITEM BASICS',
    p('Status conditions matter more than they seem early because they quietly drain money, turns, and momentum.')
    + bullets([
      'Poison and Burn punish route exploration if you try to push one more fight.',
      'Paralysis and Sleep are battle-losers more often than raw damage is.',
      'Antidotes, Paralyze Heals, Awakenings, and Burn Heals are worth carrying in small stacks.',
      'Potions are for route stabilization. Pokemon Centers are for full reset.'
    ])
    + tip('Money saver', 'Do not overspend on healing items when the next town is close. Buy enough to survive routes, not enough to replace Centers.')
  );

  html += card('TEAM BUILDING WITHOUT OVERTHINKING',
    p('A good story team does not need perfect stats. It needs <strong>coverage, consistency, and a few safe switch-ins</strong>.')
    + bullets([
      {raw: 'Try to cover Water, Flying, Psychic, Electric, and Ground threats somewhere on the team.'},
      'Do not stack four Pokemon weak to the same Gym just because they are favorites.',
      'Fast Pokemon help you avoid getting snowballed. Bulky Pokemon help you recover from mistakes.',
      'An HM user, a status support mon, and one reliable sweeper already gives you a strong structure.'
    ])
    + tip('Simple rule', 'If a Pokemon keeps winning fights cleanly, keep investing in it. If it is always dead weight, replace it instead of forcing the idea.')
  );

  html += card('MONEY, SHOPPING & TMS',
    p('Your money should mostly go toward <strong>Balls, healing, Repels, and a few key TMs</strong>.')
    + bullets([
      'Poke Balls and Great Balls are almost always a better early buy than piles of extra Potions.',
      'Repels save time in caves and while backtracking.',
      'Do not spam one-time TMs the second you get them unless you are sure of the target.',
      'Department stores and Game Corners often hold major power spikes, especially stones and premium TMs.'
    ])
    + tip('Trainer rematches', 'If the game offers rematches or repeatable battles, use them before selling useful held items or burning all your cash.')
  );

  html += card('WHAT TO DO WHEN YOU FEEL LOST',
    p('Gen 3 sometimes expects you to remember an NPC line from a town ago. If you lose the thread, use this order:')
    + bullets([
      'Check the next available Gym town.',
      'Revisit the last place where a story event happened.',
      'See whether a new HM or key item opened an older route.',
      'Talk to houses near the Pokemon Center, Gym, harbor, cave entrance, or major landmark.',
      'Use the site\'s `Bulba Guide` if you want exact next-step routing.'
    ])
  );

  html += card('BEST COMPANION PAGES',
    bullets([
      'Use `Bulba Guide` when you want the next destination.',
      'Use `Encounters` or `Easy Dex` when you want to know where a Pokemon actually appears.',
      'Use `TM/HM` and `Move Tutors` when building coverage.',
      'Use `Catch Rate Calc` before rare or annoying catches.',
      'Use `Missables` if you are worried about one-time gifts, legendaries, or choices.'
    ])
  );

  c.innerHTML = html;
  window._essentialsBuilt = true;
}

function missStorageKey(g, id) { return 'g3miss_'+g+'_'+id; }

function missIsDone(g, it) {
  if (it.choices) return !!localStorage.getItem(missStorageKey(g, it.id));
  return localStorage.getItem(missStorageKey(g, it.id)) === '1';
}

function missUpdateProgress(g) {
  var data = MISSABLES_DATA[g] || {};
  var allItems = [];
  Object.values(data).forEach(function(items) { items.forEach(function(it) { allItems.push(it); }); });
  var done = allItems.filter(function(it) { return missIsDone(g, it); }).length;
  var total = allItems.length;
  document.getElementById('miss-progress-label').textContent = done + ' / ' + total + ' checked';
  document.getElementById('miss-progress-fill').style.width = total ? (done/total*100)+'%' : '0%';
}

function missRender() {
  var g = _missGame;
  var data = MISSABLES_DATA[g] || {};

  var _missPokeNames = POKE.map(function(p){ return p.name; }).sort(function(a,b){ return b.length-a.length; });
  var _missItemNames = ALL_ITEMS.map(function(it){ return it[1]; }).sort(function(a,b){ return b.length-a.length; });
  function _missLink(text) {
    _missPokeNames.forEach(function(name) {
      var re = new RegExp('\\b' + name.replace(/[.*+?^${}()|[\]\\]/g,'\\$&') + '\\b', 'g');
      text = text.replace(re, '<span class="guide-poke-link" onclick="guideDex(\'' + name.replace(/'/g,"\\'") + '\')">' + name + '</span>');
    });
    _missItemNames.forEach(function(name) {
      var re = new RegExp('\\b' + name.replace(/[.*+?^${}()|[\]\\]/g,'\\$&') + '\\b', 'g');
      text = text.replace(re, '<span class="guide-item-link" onclick="openItemByName(\'' + name.replace(/'/g,"\\'") + '\')">' + name + '</span>');
    });
    return text;
  }

  var allItems = [];
  Object.values(data).forEach(function(items) { items.forEach(function(it) { allItems.push(it); }); });

  var pb = document.getElementById('miss-progress-bar');
  pb.style.display = allItems.length ? '' : 'none';
  missUpdateProgress(g);

  var html = Object.keys(data).map(function(section) {
    var items = data[section];
    var rows = items.map(function(it) {
      var done = missIsDone(g, it);
      var rowStyle = 'display:flex;align-items:flex-start;gap:10px;padding:10px 12px;border-bottom:1px solid rgba(255,255,255,0.04);'+(done?'opacity:0.55;':'');

      if (it.choices) {
        var chosen = localStorage.getItem(missStorageKey(g, it.id)) || '';
        var btns = it.choices.map(function(ch) {
          var active = chosen === ch.value;
          return '<button onclick="missPickChoice(\''+g+'\',\''+it.id+'\',\''+ch.value+'\')" '
            +'style="font-size:10px;padding:5px 10px;border-radius:5px;cursor:pointer;border:2px solid '+(active?'var(--game-color,var(--gold))':'var(--border)')+';background:'+(active?'color-mix(in srgb,var(--game-color,var(--gold)) 12%,transparent)':'transparent')+';color:'+(active?'var(--game-color,var(--gold))':'var(--muted)')+';white-space:nowrap;" '
            +'id="miss-choice-'+g+'-'+it.id+'-'+ch.value+'">'
            +'<span style="font-weight:700;">'+ch.label+'</span>'
            +(ch.sub ? '<span style="font-size:9px;opacity:0.75;margin-left:4px;">'+ch.sub+'</span>' : '')
            +'</button>';
        }).join('');
        return '<div style="'+rowStyle+'" id="miss-row-'+g+'-'+it.id+'">'
          +'<div style="flex:1;">'
          +'<div style="font-size:12px;font-weight:600;color:var(--text);">'+_missLink(it.label)+'</div>'
          +'<div style="font-size:11px;color:var(--muted);margin-top:2px;line-height:1.6;">'+_missLink(it.desc)+'</div>'
          +'<div style="display:flex;flex-wrap:wrap;gap:6px;margin-top:8px;">'+btns+'</div>'
          +'</div></div>';
      }

      return '<label style="'+rowStyle+'cursor:pointer;" id="miss-row-'+g+'-'+it.id+'">'
        +'<input type="checkbox" '+(done?'checked':'')
        +' onchange="missToggle(\''+g+'\',\''+it.id+'\',this)" '
        +'style="margin-top:2px;flex-shrink:0;width:15px;height:15px;cursor:pointer;">'
        +'<div>'
        +'<div style="font-size:12px;font-weight:600;color:var(--text);">'+_missLink(it.label)+'</div>'
        +'<div style="font-size:11px;color:var(--muted);margin-top:2px;line-height:1.6;">'+_missLink(it.desc)+'</div>'
        +'</div></label>';
    }).join('');
    return '<div style="background:var(--card);border:1px solid var(--border);border-radius:8px;margin-bottom:12px;overflow:hidden;">'
      +'<div style="font-family:\'Press Start 2P\',monospace;font-size:7px;color:var(--game-color,var(--gold));padding:9px 14px;border-bottom:1px solid var(--border);background:var(--panel);">'+section+'</div>'
      +rows+'</div>';
  }).join('');

  document.getElementById('miss-content').innerHTML = html || '<div style="text-align:center;padding:40px;color:var(--muted);font-size:12px;">No data for this game yet.</div>';
}

function missPickChoice(g, id, value) {
  var current = localStorage.getItem(missStorageKey(g, id)) || '';
  // clicking the active choice deselects it
  var next = current === value ? '' : value;
  if (next) localStorage.setItem(missStorageKey(g, id), next);
  else localStorage.removeItem(missStorageKey(g, id));

  // Update button styles in-place
  var data = MISSABLES_DATA[g] || {};
  var it = null;
  Object.values(data).forEach(function(items) { items.forEach(function(i) { if (i.id === id) it = i; }); });
  if (it && it.choices) {
    it.choices.forEach(function(ch) {
      var btn = document.getElementById('miss-choice-'+g+'-'+id+'-'+ch.value);
      if (!btn) return;
      var active = next === ch.value;
      var gc = getComputedStyle(document.documentElement).getPropertyValue('--game-color').trim() || 'var(--gold)';
      btn.style.borderColor = active ? gc : 'var(--border)';
      btn.style.background = active ? 'color-mix(in srgb,' + gc + ' 12%,transparent)' : 'transparent';
      btn.style.color = active ? gc : 'var(--muted)';
    });
  }
  var row = document.getElementById('miss-row-'+g+'-'+id);
  if (row) row.style.opacity = next ? '0.55' : '';
  missUpdateProgress(g);
}

function missToggle(g, id, cb) {
  if (cb.checked) localStorage.setItem(missStorageKey(g, id), '1');
  else localStorage.removeItem(missStorageKey(g, id));
  var row = document.getElementById('miss-row-'+g+'-'+id);
  if (row) row.style.opacity = cb.checked ? '0.55' : '';
  missUpdateProgress(g);
}

function missReset() {
  var g = _missGame;
  var data = MISSABLES_DATA[g] || {};
  Object.values(data).forEach(function(items) { items.forEach(function(it) { localStorage.removeItem(missStorageKey(g,it.id)); }); });
  missRender();
}

// ══ BERRY FARMING PAGE ══════════════════════════════════════════
function buildBerriesPage() {
  var c = document.getElementById('berries-content');
  if (!c) return;

  var _brPokeNames = POKE.map(function(p){ return p.name; }).sort(function(a,b){ return b.length-a.length; });
  var _brItemNames = ALL_ITEMS.map(function(it){ return it[1]; }).sort(function(a,b){ return b.length-a.length; });
  var _brMoveNames = ALL_MOVES_DATA.map(function(m){ return m[1]; }).sort(function(a,b){ return b.length-a.length; });
  function _brReplaceInTextNodes(html, names, cssClass, onclickFn) {
    if (!names.length) return html;
    var pattern = names.map(function(n){ return '\\b' + n.replace(/[.*+?^${}()|[\]\\]/g,'\\$&') + '\\b'; }).join('|');
    var nameRe = new RegExp('(' + pattern + ')', 'g');
    return html.replace(/(<[^>]+>)|([^<]+)/g, function(match, tag, txt) {
      if (tag) return tag;
      return txt.replace(nameRe, function(matched) {
        return '<span class="' + cssClass + '" onclick="' + onclickFn(matched) + '">' + matched + '</span>';
      });
    });
  }
  function _brLink(text) {
    text = _brReplaceInTextNodes(text, _brPokeNames, 'guide-poke-link', function(n){ return 'guideDex(\'' + n.replace(/'/g,"\\'") + '\')'; });
    text = _brReplaceInTextNodes(text, _brItemNames, 'guide-item-link', function(n){ return 'openItemByName(\'' + n.replace(/'/g,"\\'") + '\')'; });
    text = _brReplaceInTextNodes(text, _brMoveNames, 'guide-move-link', function(n){ return '_openMoveDex(\'' + n.replace(/'/g,"\\'") + '\')'; });
    return text;
  }

  function card(title, body) {
    return '<div style="background:var(--card);border:1px solid var(--border);border-radius:8px;padding:16px 18px;margin-bottom:16px;">'
      +'<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));margin-bottom:10px;">'+title+'</div>'
      +body+'</div>';
  }
  function p(t) { return '<p style="font-size:12px;color:var(--text);line-height:1.7;margin:0 0 8px;">'+_brLink(t)+'</p>'; }
  function table(headers, rows) {
    return '<div style="overflow-x:auto;"><table style="width:100%;border-collapse:collapse;font-size:12px;">'
      +'<thead><tr style="border-bottom:2px solid var(--border);">'
      +headers.map(function(h){return '<th style="padding:6px 10px;font-family:\'Press Start 2P\',monospace;font-size:6px;color:var(--game-color,var(--gold));text-align:left;">'+h+'</th>';}).join('')
      +'</tr></thead><tbody>'
      +rows.map(function(r){return '<tr style="border-bottom:1px solid rgba(255,255,255,0.04);">'
        +r.map(function(cell,i){
          var content = (cell && typeof cell === 'object' && cell.raw) ? cell.raw : _brLink(String(cell));
          return '<td style="padding:6px 10px;color:'+(i===0?'var(--text)':'var(--muted)')+';">'+content+'</td>';
        }).join('')
        +'</tr>';}).join('')
      +'</tbody></table></div>';
  }

  var html = '';

  html += card('HOW BERRY FARMING WORKS (RSE)',
    p('Berry trees grow in <strong>4 stages</strong>: Planted → Sprout → Taller → Bloom → Berry. Each stage takes a set number of hours. Watering a tree keeps it healthy and <strong>increases berry yield</strong> (up to 5 extra berries per watering, for a max yield).')
    +'<div style="padding:10px 12px;background:var(--panel);border-radius:6px;font-size:11px;color:var(--muted);line-height:1.7;margin-top:6px;">'
    +'<strong style="color:var(--text);">Watering tip:</strong> ' + _brLink('Water once per growth stage for maximum yield. A tree watered at every stage (4×) gives the maximum harvest. In Emerald, <strong>Mulch</strong> items (Amaze Mulch, Damp Mulch, etc.) can speed growth or improve yield — obtained in Emerald only from the Berry Master on Route 123.')
    +'</div>'
  );

  var isMobile = window.innerWidth <= 600;
  var berryRows = [
    ['Oran Berry','2h','8h','20','Common healing berry'],
    ['Sitrus Berry','8h','32h','20','Better healing, held-item tier'],
    ['Lum Berry','16h','64h','20','Cures any status — highly valuable'],
    ['Salac Berry','24h','96h','6','Speed +1 <¼HP — get via Berry Master phrase in RSE'],
    ['Petaya Berry','24h','96h','6','Sp.Atk +1 <¼HP — Berry Master phrase'],
    ['Liechi Berry','24h','96h','6','Attack +1 <¼HP — Shoal Cave gift (4 shells + 4 salts)'],
    ['Ganlon Berry','24h','96h','6','Defense +1 <¼HP — Berry Master phrase'],
    ['Apicot Berry','24h','96h','6','Sp.Def +1 <¼HP — Berry Master phrase'],
    ['Starf Berry','24h','96h','6','Random stat +2 <¼HP — extremely rare phrase'],
    ['Lansat Berry','24h','96h','6','Crit rate +1 <¼HP — Berry Master phrase'],
    ['Figy Berry / Wiki Berry / Mago Berry / Aguav Berry / Iapapa Berry','8h','32h','10','Flavor berries for Pokéblocks'],
    ['Pomeg Berry / Kelpsy Berry / Qualot Berry / Hondew Berry / Grepa Berry / Tamato Berry','10h','40h','8','EV-reducing berries'],
  ];
  var berryTableHtml;
  if (!isMobile) {
    berryTableHtml = table(['Berry','Hours/stage','Total to harvest','Max yield','Notes'], berryRows);
  } else {
    berryTableHtml = '<table style="width:100%;border-collapse:collapse;font-size:12px;">'
      +'<thead><tr style="border-bottom:2px solid var(--border);">'
      +'<th style="padding:6px 10px;font-family:\'Press Start 2P\',monospace;font-size:6px;color:var(--game-color,var(--gold));text-align:left;">Berry</th>'
      +'<th style="padding:6px 10px;font-family:\'Press Start 2P\',monospace;font-size:6px;color:var(--game-color,var(--gold));text-align:left;">Hrs/stage</th>'
      +'<th style="padding:6px 10px;font-family:\'Press Start 2P\',monospace;font-size:6px;color:var(--game-color,var(--gold));text-align:left;">Total</th>'
      +'<th style="padding:6px 10px;font-family:\'Press Start 2P\',monospace;font-size:6px;color:var(--game-color,var(--gold));text-align:left;">Max</th>'
      +'</tr></thead><tbody>'
      + berryRows.map(function(r, idx) {
          var detId = 'berry-det-' + idx;
          return '<tr onclick="berryRowToggle(\'' + detId + '\')" style="border-bottom:1px solid rgba(255,255,255,0.04);cursor:pointer;">'
            +'<td style="padding:6px 8px;color:var(--text);font-size:11px;">'+_brLink(r[0])+'</td>'
            +'<td style="padding:6px 8px;color:var(--muted);">'+r[1]+'</td>'
            +'<td style="padding:6px 8px;color:var(--muted);">'+r[2]+'</td>'
            +'<td style="padding:6px 8px;color:var(--muted);">'+r[3]+'</td>'
            +'</tr>'
            +'<tr id="'+detId+'" style="display:none;background:var(--darker);"><td colspan="4" style="padding:8px 14px;font-size:11px;color:var(--muted);line-height:1.6;border-bottom:2px solid var(--gold);"><span style="font-size:9px;font-weight:800;text-transform:uppercase;letter-spacing:0.5px;color:var(--leaf);display:block;margin-bottom:4px;">Notes</span>'+_brLink(r[4])+'</td></tr>';
        }).join('')
      +'</tbody></table>';
  }
  html += card('BERRY GROWTH TIMERS', berryTableHtml);

  html += card('BERRY MASTER PHRASES (EMERALD)',
    p('Talk to the Berry Master\'s wife on Route 123 and enter these phrases to get rare berries. <strong>Each phrase works only once per save file.</strong>')
    +table(['Phrase','Berry received'],
      [[{raw:'COOL LATIOS'},'Salac Berry (Speed +1 <¼HP)'],
       [{raw:'CHALLENGE CONTEST'},'Petaya Berry (Sp.Atk +1 <¼HP)'],
       [{raw:'OVERWHELMING LATIAS'},'Ganlon Berry (Defense +1 <¼HP)'],
       [{raw:'SUPER HUSTLE'},'Apicot Berry (Sp.Def +1 <¼HP)'],
       [{raw:'COOL LATIAS'},'Starf Berry (Random stat +2 <¼HP)'],
       [{raw:'OVERWHELMING LATIOS'},'Lansat Berry (Crit rate +1 <¼HP)']])
    +'<div style="margin-top:10px;padding:8px 12px;background:rgba(255,85,85,0.08);border:1px solid rgba(255,85,85,0.3);border-radius:6px;font-size:11px;color:var(--muted);">⚠ These phrases are Emerald-only. In Ruby/Sapphire the Berry Master\'s wife only gives one berry per phrase, and the rare stat-boosting berries must be obtained from Shoal Cave (Liechi), the Berry Masters themselves, or by trading.</div>'
  );

  html += card('BERRY BLENDER (CONTEST POKÉBLOCKS)',
    p('Insert berries into the blender at any Contest Hall. The Pokéblock\'s <strong>level and smoothness</strong> depend on the berries used and how many people are blending. Higher-level Pokéblocks raise conditions more.')
    +'<div style="display:flex;flex-direction:column;gap:6px;">'
    +[['Solo blending','Lowest level Pokéblocks, least efficient'],
      ['2 players','Mid-level Pokéblocks — good balance'],
      ['3–4 players','Highest level Pokéblocks — best condition gain per block'],
      ['Berry flavors','Sweet → Cuteness · Spicy → Coolness · Dry → Beauty · Bitter → Cleverness · Sour → Toughness'],
      ['Nature limits','Some natures dislike certain flavors — check Pokémon\'s nature before feeding blocks']]
    .map(function(row) {
      return '<div style="display:flex;gap:8px;padding:7px 10px;background:var(--panel);border-radius:5px;font-size:11px;">'
        +'<strong style="color:var(--text);min-width:110px;">'+row[0]+'</strong>'
        +'<span style="color:var(--muted);">'+_brLink(row[1])+'</span></div>';
    }).join('')+'</div>'
  );

  c.innerHTML = html;
  window._berriesBuilt = true;
}

