function ribStorageKey(g, id) { return 'g3rib_'+g+'_'+id; }

function buildRibbonPage() {
  var games = ['FR','LG','R','S','E'];
  var colors = { FR:'var(--fire)', LG:'var(--leaf)', R:'#FF5555', S:'#5599FF', E:'var(--emerald)' };
  var labels = { FR:'🔥 FR', LG:'🌿 LG', R:'🔴 R', S:'🔷 S', E:'🟢 E' };
  var btns = document.getElementById('ribbon-game-btns');
  btns.innerHTML = games.map(function(g) {
    var active = g === _ribbonGame;
    var col = colors[g];
    return '<button onclick="ribbonSetGame(\''+g+'\')" data-game="'+g+'" '
      +'style="font-family:\'Press Start 2P\',monospace;font-size:7px;padding:6px 12px;border-radius:4px;border:2px solid '+(active?col:'var(--border)')+';background:transparent;cursor:pointer;color:'+(active?col:'var(--muted)')+';">'
      +labels[g]+'</button>';
  }).join('');
  ribbonRender();
  window._ribbonsBuilt = true;
}

function ribbonSetGame(g) {
  _ribbonGame = g;
  var colors = { FR:'var(--fire)', LG:'var(--leaf)', R:'#FF5555', S:'#5599FF', E:'var(--emerald)' };
  document.querySelectorAll('#ribbon-game-btns button').forEach(function(b) {
    var bg = b.getAttribute('data-game');
    b.style.borderColor = bg === g ? colors[g] : 'var(--border)';
    b.style.color = bg === g ? colors[g] : 'var(--muted)';
  });
  ribbonRender();
}

function ribbonRender() {
  var g = _ribbonGame;
  var sections = [
    { key:'contest', label:'🎀 Contest Ribbons', note:'Pokémon Contests — Ruby, Sapphire & Emerald only' },
    { key:'battle',  label:'⚔ Battle & Achievement Ribbons', note:'Earned in battle facilities or from NPCs' },
    { key:'special', label:'✨ Special & Event Ribbons', note:'One-time awards, NPC gifts, and event distributions' },
  ];

  var allItems = [], doneCount = 0;
  Object.values(RIBBON_DATA).forEach(function(arr) {
    arr.forEach(function(r) { allItems.push(r); });
  });
  allItems.forEach(function(r) {
    if (localStorage.getItem(ribStorageKey(g, r.id)) === '1') doneCount++;
  });

  // Count only ribbons obtainable in this game
  var obtainable = allItems.filter(function(r) { return r.games.length === 0 || r.games.indexOf(g) !== -1; });
  var obtainableDone = obtainable.filter(function(r) { return localStorage.getItem(ribStorageKey(g, r.id)) === '1'; });
  document.getElementById('ribbon-progress-label').textContent = obtainableDone.length + ' / ' + obtainable.length + ' ribbons';
  document.getElementById('ribbon-progress-fill').style.width = obtainable.length ? (obtainableDone.length/obtainable.length*100)+'%' : '0%';

  var html = sections.map(function(sec) {
    var items = RIBBON_DATA[sec.key].filter(function(r) { return r.games.indexOf(g) !== -1; });
    if (!items.length) return '';
    var rows = items.map(function(r) {
      var checked = localStorage.getItem(ribStorageKey(g, r.id)) === '1';
      var rowId = 'rib-row-'+g+'-'+r.id;
      return '<label style="display:flex;align-items:flex-start;gap:10px;padding:10px 12px;border-bottom:1px solid rgba(255,255,255,0.04);cursor:pointer;'+(checked?'opacity:0.5;':'')+'" id="'+rowId+'">'
        +'<input type="checkbox" '+(checked?'checked':'')
        +' onchange="ribToggle(\''+g+'\',\''+r.id+'\',this)" '
        +'style="margin-top:2px;flex-shrink:0;width:15px;height:15px;cursor:pointer;">'
        +'<div>'
        +'<div style="font-size:12px;font-weight:600;color:var(--text);">'+r.label+'</div>'
        +'<div style="font-size:11px;color:var(--muted);margin-top:2px;line-height:1.5;">'+r.desc+(r.note?'<br><em style="font-size:10px;">'+r.note+'</em>':'')+'</div>'
        +'</div></label>';
    }).join('');

    return '<div style="background:var(--card);border:1px solid var(--border);border-radius:8px;margin-bottom:14px;overflow:hidden;">'
      +'<div style="font-family:\'Press Start 2P\',monospace;font-size:7px;color:var(--game-color,var(--gold));padding:9px 14px;border-bottom:1px solid var(--border);background:var(--panel);">'
      +sec.label+'<span style="font-size:9px;font-family:sans-serif;font-weight:400;margin-left:10px;color:var(--muted);opacity:0.7;">'+sec.note+'</span>'
      +'</div>'+rows+'</div>';
  }).join('');

  document.getElementById('ribbon-content').innerHTML = html;
}

function ribToggle(g, id, cb) {
  if (cb.checked) localStorage.setItem(ribStorageKey(g, id), '1');
  else localStorage.removeItem(ribStorageKey(g, id));
  var row = document.getElementById('rib-row-'+g+'-'+id);
  if (row) row.style.opacity = cb.checked ? '0.5' : '';
  // update progress
  var obtainable = [];
  Object.values(RIBBON_DATA).forEach(function(arr) { arr.forEach(function(r) { if (!r.games.length || r.games.indexOf(g)!==-1) obtainable.push(r); }); });
  var done = obtainable.filter(function(r) { return localStorage.getItem(ribStorageKey(g,r.id))==='1'; }).length;
  document.getElementById('ribbon-progress-label').textContent = done+' / '+obtainable.length+' ribbons';
  document.getElementById('ribbon-progress-fill').style.width = obtainable.length ? (done/obtainable.length*100)+'%' : '0%';
}

function ribbonReset() {
  var g = _ribbonGame;
  Object.values(RIBBON_DATA).forEach(function(arr) { arr.forEach(function(r) { localStorage.removeItem(ribStorageKey(g,r.id)); }); });
  ribbonRender();
}

// ══ EXPERIENCE CALCULATOR PAGE ══════════════════════════════════

var EXP_GROUPS = {
  'Erratic':    { name:'Erratic',     fn:function(n) {
    if (n<=50)  return Math.floor(Math.pow(n,3)*(100-n)/50);
    if (n<=68)  return Math.floor(Math.pow(n,3)*(150-n)/100);
    if (n<=98)  return Math.floor(Math.pow(n,3)*Math.floor((1911-10*n)/3)/500);
    return Math.floor(Math.pow(n,3)*(160-n)/100);
  }},
  'Fast':       { name:'Fast',        fn:function(n) { return Math.floor(4*Math.pow(n,3)/5); } },
  'Medium Fast':{ name:'Medium Fast', fn:function(n) { return Math.floor(Math.pow(n,3)); } },
  'Medium Slow':{ name:'Medium Slow', fn:function(n) { return Math.floor(6/5*Math.pow(n,3)-15*Math.pow(n,2)+100*n-140); } },
  'Slow':       { name:'Slow',        fn:function(n) { return Math.floor(5*Math.pow(n,3)/4); } },
  'Fluctuating':{ name:'Fluctuating', fn:function(n) {
    if (n<=15)  return Math.floor(Math.pow(n,3)*(Math.floor((n+1)/3)+24)/50);
    if (n<=35)  return Math.floor(Math.pow(n,3)*(n+14)/50);
    return Math.floor(Math.pow(n,3)*(Math.floor(n/2)+32)/50);
  }},
};

// growth group per Pokédex number (index = num-1)
var EXP_GROUP_MAP = (function() {
  // Each entry: group abbreviation E=Erratic, F=Fast, MF=MedFast, MS=MedSlow, S=Slow, FL=Fluctuating
  var raw = 'MS,S,S,MS,MS,MS,S,MS,MS,MS,S,S,MS,S,S,MS,S,S,MS,MS,MF,MF,MF,MF,MF,MF,MF,MF,MF,S,S,S,MF,MF,MS,MS,MF,MF,MF,MS,MF,MF,MS,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MS,MS,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,S,S,S,S,S,S,S,S,S,S,S,S,S,S,S,S,S,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,E,E,E,E,E,E,E,E,E,E,E,E,E,E,E,E,E,E,E,E,E,E,E,E,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,F,F,F,F,F,F,F,F,F,F,F,F,F,F,F,F,F,F,F,F,F,F,F,F,F,F,F,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF,MF';
  var arr = raw.split(',');
  var map = { 'E':'Erratic','F':'Fast','MF':'Medium Fast','MS':'Medium Slow','S':'Slow','FL':'Fluctuating' };
  return arr.map(function(code) { return map[code] || 'Medium Fast'; });
})();

function buildExpCalcPage() {
  var c = document.getElementById('expcalc-content');
  if (!c) return;

  c.innerHTML = '<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:20px;">'

    // ── Input panel ──
    +'<div style="background:var(--card);border:1px solid var(--border);border-radius:8px;padding:16px;">'
    +'<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));margin-bottom:12px;">LOOK UP POKÉMON</div>'
    +'<div style="position:relative;display:flex;align-items:center;margin-bottom:8px;">'
    +'<input id="exp-poke-search" type="text" placeholder="Search Pokémon name or #..." '
    +'oninput="expPokeSearch(this.value);updateClearBtn(this,\'exp-poke-clear\')" autocomplete="off" '
    +'style="flex:1;box-sizing:border-box;background:var(--panel);border:1px solid var(--border);color:var(--text);border-radius:5px;padding:8px 32px 8px 10px;font-size:12px;">'
    +'<button class="search-bar-clear" id="exp-poke-clear" onclick="expClearPoke()" title="Remove Pokémon">✕</button>'
    +'</div>'
    +'<div class="calc-poke-selected" id="exp-selected" style="display:none;margin-bottom:8px;"></div>'
    +'<div id="exp-poke-results" style="max-height:160px;overflow-y:auto;"></div>'
    +'</div>'

    // ── Level panel ──
    +'<div style="background:var(--card);border:1px solid var(--border);border-radius:8px;padding:16px;">'
    +'<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));margin-bottom:12px;">LEVEL SETTINGS</div>'
    +'<div style="font-size:11px;color:var(--muted);margin-bottom:6px;">Current Level</div>'
    +'<input id="exp-cur-level" type="number" min="1" max="100" value="1" oninput="expCalcUpdate()" '
    +'style="width:100%;box-sizing:border-box;background:var(--panel);border:1px solid var(--border);color:var(--text);border-radius:5px;padding:8px 10px;font-size:14px;font-weight:700;margin-bottom:10px;">'
    +'<div style="font-size:11px;color:var(--muted);margin-bottom:6px;">Current EXP (optional)</div>'
    +'<input id="exp-cur-exp" type="number" min="0" value="0" oninput="expCalcUpdate()" '
    +'style="width:100%;box-sizing:border-box;background:var(--panel);border:1px solid var(--border);color:var(--text);border-radius:5px;padding:8px 10px;font-size:14px;margin-bottom:10px;">'
    +'<div style="font-size:11px;color:var(--muted);margin-bottom:6px;">Target Level</div>'
    +'<input id="exp-tgt-level" type="number" min="2" max="100" value="100" oninput="expCalcUpdate()" '
    +'style="width:100%;box-sizing:border-box;background:var(--panel);border:1px solid var(--border);color:var(--text);border-radius:5px;padding:8px 10px;font-size:14px;font-weight:700;">'
    +'</div>'
    +'</div>'

    // ── Results ──
    +'<div id="exp-results" style="background:var(--card);border:1px solid var(--border);border-radius:8px;padding:16px;margin-bottom:20px;">'
    +'<div style="text-align:center;color:var(--muted);font-size:12px;padding:20px;">Select a Pokémon above to begin.</div>'
    +'</div>'

    // ── EXP Group reference table ──
    +'<div style="background:var(--card);border:1px solid var(--border);border-radius:8px;padding:16px;">'
    +'<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));margin-bottom:12px;">EXP GROUP REFERENCE — TOTAL EXP TO LEVEL 100</div>'
    +'<table style="width:100%;border-collapse:collapse;font-size:12px;">'
    +'<thead><tr style="border-bottom:1px solid var(--border);">'
    +'<th style="padding:6px 10px;text-align:left;color:var(--game-color,var(--gold));font-size:10px;">Group</th>'
    +'<th style="padding:6px 10px;text-align:right;color:var(--game-color,var(--gold));font-size:10px;">To Lv 50</th>'
    +'<th style="padding:6px 10px;text-align:right;color:var(--game-color,var(--gold));font-size:10px;">To Lv 100</th>'
    +(window.innerWidth > 600 ? '<th style="padding:6px 10px;text-align:left;color:var(--game-color,var(--gold));font-size:10px;">Notable Pokémon</th>' : '')
    +'</tr></thead><tbody>'
    +[
      ['Erratic',     'Chansey, Clefairy, Jigglypuff, Snorunt, Spheal'],
      ['Fast',        'Gastly, Gengar, Nidoran, Pidgey, Caterpie line'],
      ['Medium Fast', 'Most Pokémon — Bulbasaur, Charmander, Squirtle starters'],
      ['Medium Slow', 'Larvitar, Bagon, Dratini, Ralts, Beldum lines'],
      ['Slow',        'Mewtwo, Legendaries (Groudon, Kyogre, Rayquaza)'],
      ['Fluctuating', 'Slowpoke, Shellder, Krabby, Voltorb, Diglett lines'],
    ].map(function(row, idx) {
      var grp = EXP_GROUPS[row[0]];
      var to50 = grp ? grp.fn(50).toLocaleString() : '—';
      var to100 = grp ? grp.fn(100).toLocaleString() : '—';
      var isMobile = window.innerWidth <= 600;
      var detId = 'exp-grp-det-' + idx;
      return '<tr style="border-bottom:1px solid rgba(255,255,255,0.04);' + (isMobile ? 'cursor:pointer;' : '') + '"'
        + (isMobile ? ' onclick="expGrpToggle(\'' + detId + '\')"' : '') + '>'
        +'<td style="padding:8px 10px;font-weight:700;color:var(--text);">'+row[0]+'</td>'
        +'<td style="padding:8px 10px;text-align:right;color:var(--muted);">'+to50+'</td>'
        +'<td style="padding:8px 10px;text-align:right;color:var(--gold);">'+to100+'</td>'
        +(!isMobile ? '<td style="padding:8px 10px;font-size:11px;color:var(--muted);">'+row[1]+'</td>' : '')
        +'</tr>'
        +(isMobile ? '<tr id="'+detId+'" style="display:none;background:var(--darker);"><td colspan="3" style="padding:8px 14px;font-size:11px;color:var(--muted);line-height:1.6;border-bottom:2px solid var(--gold);"><span style="font-size:9px;font-weight:800;text-transform:uppercase;letter-spacing:0.5px;color:var(--leaf);display:block;margin-bottom:4px;">Notable Pokémon</span>'+row[1]+'</td></tr>' : '');
    }).join('')
    +'</tbody></table></div>';

  window._expCalcBuilt = true;
  expSyncSelectedPokemon();
}

function ensureExpCalcPage() {
  var c = document.getElementById('expcalc-content');
  if (!c) return;
  if (!window._expCalcBuilt || !c.innerHTML.trim()) {
    buildExpCalcPage();
  }
}

function berryRowToggle(detId) {
  var det = document.getElementById(detId);
  if (!det) return;
  det.style.display = det.style.display === 'none' ? 'table-row' : 'none';
}

function expGrpToggle(detId) {
  var det = document.getElementById(detId);
  if (!det) return;
  det.style.display = det.style.display === 'none' ? 'table-row' : 'none';
}

var _expCalcPoke = null;

function expGetCurrentSelectedPokemonNum() {
  if (_expCalcPoke) return _expCalcPoke;
  if (typeof openEvoNum === 'number' && openEvoNum > 0) return openEvoNum;

  var candidates = [];
  if (typeof SEARCH === 'string' && SEARCH.trim()) candidates.push(SEARCH.trim());
  var dexSearch = document.getElementById('searchInput');
  if (dexSearch && dexSearch.value.trim()) candidates.push(dexSearch.value.trim());
  var expSearch = document.getElementById('exp-poke-search');
  if (expSearch && expSearch.value.trim()) candidates.push(expSearch.value.trim());

  for (var i = 0; i < candidates.length; i++) {
    var raw = candidates[i];
    var dexMatch = raw.match(/^#?(\d{1,3})\b/);
    if (dexMatch) {
      var num = parseInt(dexMatch[1], 10);
      if (POKE.some(function(p) { return p.num === num; })) return num;
    }

    var byName = POKE.find(function(p) { return p.name.toLowerCase() === raw.toLowerCase(); });
    if (byName) return byName.num;
  }

  return null;
}

function expSyncSelectedPokemon() {
  var num = expGetCurrentSelectedPokemonNum();
  if (!num) return;
  expSelectPoke(num);
}

function expRenderSelected(p) {
  var el = document.getElementById('exp-selected');
  if (!el) return;
  if (!p) {
    el.style.display = 'none';
    el.innerHTML = '';
    return;
  }

  var typeHtml = (p.types || []).map(function(t) {
    return typeSprite(t.toLowerCase());
  }).join('');
  var grpName = EXP_GROUP_MAP[p.num - 1] || 'Medium Fast';

  el.style.display = 'flex';
  el.innerHTML = '<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + p.num + '.png" width="56" height="56" style="image-rendering:pixelated;flex-shrink:0">'
    + '<div class="calc-poke-selected-body">'
    + '<div class="calc-poke-selected-meta"><div class="calc-poke-selected-name">' + p.name + '</div><div class="calc-poke-selected-num">#' + String(p.num).padStart(3,'0') + '</div></div>'
    + '<div class="calc-poke-selected-summary">EXP Group: ' + grpName + '</div>'
    + '<div class="calc-poke-selected-types">' + typeHtml + '</div>'
    + '</div>'
    + '<button class="calc-poke-clear" onmousedown="expClearPoke()">✕</button>';
}

function expPokeSearch(q) {
  var res = document.getElementById('exp-poke-results');
  q = q.trim();
  if (!q) { res.innerHTML = ''; return; }
  var norm = q.toLowerCase();
  var matches = POKE.filter(function(p) {
    return p.name.toLowerCase().includes(norm) || String(p.num) === q;
  }).slice(0, 8);
  if (!matches.length) { res.innerHTML = '<div style="padding:8px;color:var(--muted);font-size:11px;">No results</div>'; return; }
  res.innerHTML = matches.map(function(p) {
    var grpName = EXP_GROUP_MAP[p.num - 1] || 'Medium Fast';
    return '<div onclick="expSelectPoke('+p.num+')" style="display:flex;align-items:center;gap:8px;padding:6px 8px;cursor:pointer;border-radius:5px;font-size:12px;" '
      +'onmouseover="this.style.background=\'var(--panel)\'" onmouseout="this.style.background=\'transparent\'">'
      +'<img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/'+p.num+'.png" style="width:28px;height:28px;image-rendering:pixelated;">'
      +'<span style="color:var(--text);">#'+String(p.num).padStart(3,'0')+' '+p.name+'</span>'
      +'<span style="margin-left:auto;font-size:10px;color:var(--muted);">'+grpName+'</span>'
      +'</div>';
  }).join('');
}

function expSelectPoke(num) {
  _expCalcPoke = num;
  var p = POKE.find(function(p) { return p.num === num; });
  var inp = document.getElementById('exp-poke-search');
  var results = document.getElementById('exp-poke-results');
  if (!inp || !results) return;
  inp.value = p ? '#'+String(p.num).padStart(3,'0')+' '+p.name : '';
  results.innerHTML = '';
  var clr = document.getElementById('exp-poke-clear');
  if (clr) clr.classList.add('visible');
  expRenderSelected(p);
  expCalcUpdate();
}

function expClearPoke() {
  _expCalcPoke = null;
  var inp = document.getElementById('exp-poke-search');
  if (inp) inp.value = '';
  var results = document.getElementById('exp-poke-results');
  if (results) results.innerHTML = '';
  var clr = document.getElementById('exp-poke-clear');
  if (clr) clr.classList.remove('visible');
  expRenderSelected(null);
  var res = document.getElementById('exp-results');
  if (res) res.innerHTML = '<div style="text-align:center;color:var(--muted);font-size:12px;padding:20px;">Select a Pokémon above to begin.</div>';
}

function expCalcUpdate() {
  var res = document.getElementById('exp-results');
  if (!res || !_expCalcPoke) return;
  var grpName = EXP_GROUP_MAP[_expCalcPoke - 1] || 'Medium Fast';
  var grp = EXP_GROUPS[grpName];
  if (!grp) return;
  var curLvEl = document.getElementById('exp-cur-level');
  var tgtLvEl = document.getElementById('exp-tgt-level');
  var curExpEl = document.getElementById('exp-cur-exp');
  if (!curLvEl || !tgtLvEl || !curExpEl) return;
  var curLv = Math.max(1, Math.min(100, parseInt(curLvEl.value) || 1));
  var tgtLv = Math.max(curLv+1, Math.min(100, parseInt(tgtLvEl.value) || 100));
  var curExpInput = Math.max(0, parseInt(curExpEl.value) || 0);
  var p = POKE.find(function(x) { return x.num === _expCalcPoke; });

  var expAtCur = grp.fn(curLv);
  var expAtNext = grp.fn(curLv + 1);
  var expAtTgt = grp.fn(tgtLv);
  var expIntoLevel = curExpInput > 0 ? curExpInput - expAtCur : 0;
  var expThisLevel = expAtNext - expAtCur;
  var expToNext = expThisLevel - Math.max(0, expIntoLevel);
  var expToTarget = expAtTgt - (curExpInput > 0 ? curExpInput : expAtCur);
  var candies = Math.ceil(expToTarget / ((expAtCur > 0 ? expAtCur : expAtNext) - expAtCur || 1000));
  // Rare Candy gives exactly 1 level — simpler to just say levels needed
  var levelsNeeded = tgtLv - curLv;

  function fmt(n) { return n.toLocaleString(); }
  function row(label, val, gold) {
    return '<div style="display:flex;justify-content:space-between;align-items:center;padding:9px 14px;border-bottom:1px solid rgba(255,255,255,0.05);">'
      +'<span style="font-size:12px;color:var(--muted);">'+label+'</span>'
      +'<span style="font-size:14px;font-weight:700;color:'+(gold?'var(--gold)':'var(--text)')+';">'+val+'</span>'
      +'</div>';
  }

  res.innerHTML = '<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));margin-bottom:10px;">'
    +(p ? '#'+String(p.num).padStart(3,'0')+' '+p.name.toUpperCase() : 'RESULTS')
    +' · '+grpName.toUpperCase()+'</div>'
    +'<div style="background:var(--panel);border-radius:6px;overflow:hidden;">'
    +row('EXP group', grpName)
    +row('EXP at Lv '+curLv, fmt(expAtCur))
    +row('EXP at Lv '+(curLv+1), fmt(expAtNext))
    +row('EXP needed for next level', fmt(expToNext > 0 ? expToNext : expThisLevel), true)
    +row('EXP at Lv '+tgtLv+' (target)', fmt(expAtTgt))
    +row('Total EXP needed (Lv '+curLv+'→'+tgtLv+')', fmt(Math.max(0, expToTarget)), true)
    +row('Rare Candies needed', levelsNeeded + ' candies (1 candy = 1 level)')
    +'</div>'
    // Level table: current to target, show EXP per level
    +(tgtLv - curLv <= 20 ? (function() {
      var rows = '<div style="font-family:\'Press Start 2P\',monospace;font-size:7px;color:var(--muted);margin:14px 0 6px;">EXP PER LEVEL</div>'
        +'<table style="width:100%;border-collapse:collapse;font-size:11px;">'
        +'<thead><tr style="border-bottom:1px solid var(--border);">'
        +'<th style="padding:5px 10px;text-align:left;color:var(--muted);">Level</th>'
        +'<th style="padding:5px 10px;text-align:right;color:var(--muted);">Total EXP</th>'
        +'<th style="padding:5px 10px;text-align:right;color:var(--muted);">EXP this level</th>'
        +'</tr></thead><tbody>';
      for (var lv = curLv; lv <= tgtLv; lv++) {
        var tot = grp.fn(lv);
        var diff = lv > 1 ? tot - grp.fn(lv-1) : 0;
        var isCur = lv === curLv;
        rows += '<tr style="border-bottom:1px solid rgba(255,255,255,0.03);'+(isCur?'background:rgba(255,215,0,0.05);':'')+'">'
          +'<td style="padding:5px 10px;font-weight:'+(isCur?'700':'400')+';color:'+(isCur?'var(--gold)':'var(--text)')+';">'+lv+'</td>'
          +'<td style="padding:5px 10px;text-align:right;color:var(--muted);">'+fmt(tot)+'</td>'
          +'<td style="padding:5px 10px;text-align:right;color:var(--text);">'+(diff>0?fmt(diff):'—')+'</td>'
          +'</tr>';
      }
      return rows + '</tbody></table>';
    })() : '<div style="font-size:11px;color:var(--muted);margin-top:10px;font-style:italic;">Level-by-level table shown for gaps of 20 levels or fewer.</div>');
}

// ══ RNG MANIPULATION GUIDE PAGE ══════════════════════════════════

function buildRngPage() {
  var c = document.getElementById('rng-content');
  if (!c) return;

  function card(title, body) {
    return '<div style="background:var(--card);border:1px solid var(--border);border-radius:8px;padding:18px 20px;margin-bottom:16px;">'
      +'<div style="font-family:\'Press Start 2P\',monospace;font-size:8px;color:var(--game-color,var(--gold));margin-bottom:12px;">'+title+'</div>'
      +body+'</div>';
  }
  function p(text) { return '<p style="font-size:12px;color:var(--muted);line-height:1.8;margin:0 0 10px;">'+text+'</p>'; }
  function h(text) { return '<div style="font-size:12px;font-weight:700;color:var(--text);margin:12px 0 6px;">'+text+'</div>'; }
  function table(headers, rows) {
    return '<div style="overflow-x:auto;"><table style="width:100%;border-collapse:collapse;font-size:11px;margin-bottom:8px;">'
      +'<thead><tr style="border-bottom:1px solid var(--border);">'
      +headers.map(function(hh) { return '<th style="padding:6px 10px;text-align:left;color:var(--muted);">'+hh+'</th>'; }).join('')
      +'</tr></thead><tbody>'
      +rows.map(function(row) {
        return '<tr style="border-bottom:1px solid rgba(255,255,255,0.04);">'
          +row.map(function(cell,i) { return '<td style="padding:7px 10px;color:'+(i===0?'var(--text)':'var(--muted)')+';">'+cell+'</td>'; }).join('')
          +'</tr>';
      }).join('')
      +'</tbody></table></div>';
  }
  function warn(text) {
    return '<div style="background:rgba(255,180,0,0.08);border:1px solid rgba(255,180,0,0.25);border-radius:6px;padding:10px 14px;font-size:11px;color:var(--gold);line-height:1.7;margin-bottom:10px;">⚠ '+text+'</div>';
  }
  function info(text) {
    return '<div style="background:rgba(100,180,255,0.07);border:1px solid rgba(100,180,255,0.2);border-radius:6px;padding:10px 14px;font-size:11px;color:#7bbfff;line-height:1.7;margin-bottom:10px;">ℹ '+text+'</div>';
  }

  c.innerHTML = [

    card('OVERVIEW — HOW GEN 3 RNG WORKS',
      p('Gen 3 uses a 32-bit Linear Congruential Generator (LCG) for all randomness. The formula is:')
      +'<div style="background:var(--panel);border-radius:5px;padding:10px 14px;font-family:monospace;font-size:13px;color:var(--gold);margin-bottom:10px;">seed = (0x41C64E6D × seed + 0x6073) mod 2³²</div>'
      +p('Every "random" event (wild encounter, PID/IV generation, frames advancing during gameplay) steps this seed forward. The seed is initialized at boot from an internal timer — making it theoretically predictable.')
      +warn('Emerald is famous for having a <strong>fixed initial seed of 0x0000</strong> on every boot, making RNG manipulation significantly easier than in R/S/FR/LG.')
      +info('Tools: RNG Reporter (PC), PokéFinder (modern cross-platform), EonTimer for frame timing.')
    ),

    card('TID/SID MANIPULATION',
      p('Your <strong>Trainer ID (TID)</strong> and <strong>Secret ID (SID)</strong> together determine which PIDs create shinies. Together they form a 32-bit value used in the shiny XOR check.')
      +h('Shiny condition: (TID XOR SID XOR PID_upper XOR PID_lower) < 8')
      +h('Emerald — easiest method')
      +p('Because Emerald\'s seed is always 0x0000 on boot, your TID/SID pair is fully predictable based on how many frames have advanced before you press New Game. Tools like PokéFinder can calculate your exact TID/SID target frame.')
      +table(['Step','Action'],
        [['1','Boot Emerald with a target TID/SID in mind (use PokéFinder to find target frame)'],
         ['2','Wait for the title screen — use a timer to advance to the correct frame before pressing A'],
         ['3','Name your character and confirm — TID/SID are now set'],
         ['4','Verify in-game with a cheat device or save and check with a ROM editor']])
      +h('Ruby/Sapphire — harder')
      +p('R/S uses a live timer-based initial seed derived from the internal battery. The seed changes every ~17ms. Hitting a specific seed requires precise timing or many resets. Most players use the Mirage Island RNG (which advances based on daily seed) as a reference.')
      +h('FireRed/LeafGreen')
      +p('FR/LG uses the GBA clock for seeding. Slightly more predictable than R/S but still requires EonTimer or similar for frame-accurate play.')
    ),

    card('PID GENERATION — METHODS 1, 2, 4',
      p('The Method used for wild encounters and bred Pokémon determines which RNG calls generate the PID vs IVs. This affects shiny hunting because the IVs and shininess are linked to specific call patterns.')
      +(window.innerWidth <= 600
        ? [['Method 1','Stationary legendaries, gifts, in-game trades, bred Pokémon','Calls 1–2','Calls 3–4','Most common for target hunting'],
           ['Method 2','Wild Pokémon (Gen 3 standard — Ruby/Sapphire/Emerald)','Calls 1–2','Calls 4–5','Call 3 is skipped — important for IV spread calculation'],
           ['Method 4','Wild Pokémon (FireRed/LeafGreen only)','Calls 1–2','Calls 3+5','Call 4 skipped — unique to FR/LG wild encounters']]
          .map(function(r) {
            return '<div style="background:var(--panel);border-radius:6px;padding:10px 12px;margin-bottom:8px;font-size:11px;">'
              +'<div style="font-weight:800;color:var(--gold);margin-bottom:6px;">'+r[0]+'</div>'
              +'<div style="color:var(--text);margin-bottom:4px;">'+r[1]+'</div>'
              +'<div style="display:flex;gap:12px;color:var(--muted);font-size:10px;margin-bottom:4px;">'
              +'<span>PID: '+r[2]+'</span><span>IV: '+r[3]+'</span></div>'
              +'<div style="color:var(--muted);font-size:10px;font-style:italic;">'+r[4]+'</div>'
              +'</div>';
          }).join('')
        : table(['Method','Used for','PID calls','IV calls','Notes'],
            [['Method 1','Stationary legendaries, gifts, in-game trades, bred Pokémon','Calls 1–2','Calls 3–4','Most common for target hunting'],
             ['Method 2','Wild Pokémon (Gen 3 standard — Ruby/Sapphire/Emerald)','Calls 1–2','Calls 4–5','Call 3 is skipped — important for IV spread calculation'],
             ['Method 4','Wild Pokémon (FireRed/LeafGreen only)','Calls 1–2','Calls 3+5','Call 4 skipped — unique to FR/LG wild encounters']]))
      +warn('Method 2 skips an RNG call between PID and IVs. This means the IVs cannot be calculated from the PID directly — you need to search both independently in RNG Reporter.')
      +info('Method 1 is the most RNG-friendly for shiny + IV spreads because the calls are contiguous. Always use Method 1 when targeting stationaries.')
    ),

    card('SHINY HUNTING BY METHOD',
      h('Stationary Legendaries (Method 1) — Recommended')
      +p('Groudon, Kyogre, Rayquaza, Regirock, Regice, Registeel, the Lati@s, Deoxys, Lugia, Ho-Oh (event). Save in front. Use RNG Reporter to find a shiny Method 1 frame with desired IVs. Advance to that frame via menuing/step counting, then initiate battle.')
      +table(['Game','Strategy','Seed type'],
        [['Emerald','Fixed seed 0x0000 — most consistent. Use PokéFinder or RNG Reporter "Emerald" mode','Fixed (easy)'],
         ['Ruby/Sapphire','Seed varies — abuse initial seed via Mirage Island check or battery manipulation','Variable (harder)'],
         ['FR/LG','Clock-based seed — use EonTimer. Method 1 for stationaries','Variable']])
      +h('Wild Pokémon Shiny Hunting (Method 2/4)')
      +p('For wild shinies, you need the PID to pass the shiny check AND IVs to come from the correct offset. Use RNG Reporter\'s "Wild" tab. Filter by shiny, then identify the target frame. Walk in grass on that frame.')
      +warn('Wild shinies are harder to hit than stationaries because you also need to trigger the encounter on exactly the right frame — grass encounters advance the RNG unpredictably per step.')
      +h('Egg/Breeding (Emerald)')
      +p('In Emerald, bred Pokémon PIDs use a separate "egg PID" RNG track. The Masuda Method does not exist in Gen 3 — shiny eggs require hitting a shiny PID frame on the hatching RNG. PokéFinder has a dedicated egg section for this.')
    ),

    card('IV MANIPULATION',
      h('Finding 31 IV spreads')
      +p('Each Method has a fixed offset between PID and IV RNG calls. RNG Reporter lets you search for a spread by entering the desired IVs and filtering by method. It shows you the exact advance number (frame) to target.')
      +table(['Stat','IV source (Method 1)'],
        [['HP / Attack','RNG call 3 (high 5 bits + low 5 bits)'],
         ['Defense / Speed','RNG call 4 (same split)'],
         ['Sp. Atk / Sp. Def','RNG call 5 (same split)']])
      +h('Advancing the RNG frame')
      +p('Each of the following advances the RNG by 1 frame in most Gen 3 games:')
      +'<ul style="font-size:12px;color:var(--muted);line-height:2;padding-left:20px;margin:0 0 10px;">'
      +'<li>Opening and closing a menu</li>'
      +'<li>Each step taken in a dungeon (also triggers encounter rolls)</li>'
      +'<li>Talking to an NPC</li>'
      +'<li>The Pokémon summary screen cycling</li>'
      +'<li>Battle animations playing (in-battle)</li>'
      +'</ul>'
      +warn('In Emerald, the RNG also advances passively while the battle idle animation plays — time your menu actions carefully.')
      +h('Chatot / Noise advance (not available in Gen 3)')
      +p('The Chatot Chatter trick for rapid RNG advancement does not exist in Gen 3. Frame advancement requires manual menuing or step-counting.')
    ),

    card('QUICK REFERENCE CHEAT SHEET',
      table(['Goal','Game','Method','Key tool'],
        [['Shiny legendary',   'Emerald',   'Method 1',  'PokéFinder — fixed seed, set target frame'],
         ['Shiny legendary',   'Ruby/Sapphire','Method 1','RNG Reporter + EonTimer — seed via Mirage Island'],
         ['Shiny legendary',   'FR/LG',     'Method 1',  'RNG Reporter + EonTimer — clock-based seed'],
         ['Perfect IVs (wild)','Ruby/Sapphire/E','Method 2','RNG Reporter Wild tab — filter IVs + Method 2'],
         ['Perfect IVs (wild)','FR/LG',     'Method 4',  'RNG Reporter Wild tab — filter IVs + Method 4'],
         ['Shiny egg',         'Emerald',   'Egg RNG',   'PokéFinder egg section — advance egg PID frame'],
         ['TID/SID target',    'Emerald',   '—',         'PokéFinder — frame 0 boot, time New Game press'],
         ['TID/SID target',    'R/S/FR/LG', '—',         'RNG Reporter + EonTimer — variable initial seed']])
    ),

  ].join('');

  window._rngBuilt = true;
}

// ══ NATURE CHART PAGE ══════════════════════════════════════════
function buildNaturesPage() {
  var el = document.getElementById('natures-content');
  if (!el) return;

  var STAT_NAMES  = ['Atk','Def','SpA','SpD','Spe'];
  var STAT_COLORS = ['#FF6B35','#9E9E9E','#64b4ff','#81C784','#FFD700'];
  var FLAVOR_NAMES   = ['Spicy','Sour','Dry','Bitter','Sweet'];
  var FLAVOR_CLASSES = ['nature-flavor-spicy','nature-flavor-sour','nature-flavor-dry','nature-flavor-bitter','nature-flavor-sweet'];

  var NATURES = [
    {name:'Hardy',b:-1,l:-1},{name:'Docile',b:-1,l:-1},{name:'Serious',b:-1,l:-1},
    {name:'Bashful',b:-1,l:-1},{name:'Quirky',b:-1,l:-1},
    {name:'Lonely',b:0,l:1},{name:'Brave',b:0,l:4},{name:'Adamant',b:0,l:2},{name:'Naughty',b:0,l:3},
    {name:'Bold',b:1,l:0},{name:'Relaxed',b:1,l:4},{name:'Impish',b:1,l:2},{name:'Lax',b:1,l:3},
    {name:'Modest',b:2,l:0},{name:'Mild',b:2,l:1},{name:'Quiet',b:2,l:4},{name:'Rash',b:2,l:3},
    {name:'Calm',b:3,l:0},{name:'Gentle',b:3,l:1},{name:'Sassy',b:3,l:4},{name:'Careful',b:3,l:2},
    {name:'Timid',b:4,l:0},{name:'Hasty',b:4,l:1},{name:'Jolly',b:4,l:2},{name:'Naive',b:4,l:3}
  ];

  var rows = '';
  var lastGroup = null;
  for (var i = 0; i < NATURES.length; i++) {
    var n = NATURES[i];
    var isNeutral = n.b === -1;
    var group = isNeutral ? -1 : n.b;
    var sep = (lastGroup !== null && group !== lastGroup) ? 'border-top:2px solid var(--border);' : '';
    lastGroup = group;
    var boostCell = isNeutral
      ? '<span class="nature-neutral">— neutral —</span>'
      : '<span class="nature-boost" style="color:' + STAT_COLORS[n.b] + '">+' + STAT_NAMES[n.b] + '</span>';
    var cutCell = isNeutral
      ? '<span class="nature-neutral">— neutral —</span>'
      : '<span class="nature-cut">−' + STAT_NAMES[n.l] + '</span>';
    var likeCell = isNeutral
      ? '<span class="nature-neutral">—</span>'
      : '<span class="' + FLAVOR_CLASSES[n.b] + '">' + FLAVOR_NAMES[n.b] + '</span>';
    var dislikeCell = isNeutral
      ? '<span class="nature-neutral">—</span>'
      : '<span class="' + FLAVOR_CLASSES[n.l] + '">' + FLAVOR_NAMES[n.l] + '</span>';
    rows += '<tr style="' + sep + '"><td style="font-weight:600">' + n.name + '</td><td>' + boostCell + '</td><td>' + cutCell + '</td><td>' + likeCell + '</td><td>' + dislikeCell + '</td></tr>';
  }

  el.innerHTML = '<div class="nature-chart-wrap"><table class="nature-chart-table">'
    + '<thead><tr>'
    + '<th>Nature</th><th>+10% Stat</th><th>−10% Stat</th><th>Likes</th><th>Dislikes</th>'
    + '</tr></thead><tbody>' + rows + '</tbody></table></div>'
    + '<div style="font-size:11px;color:var(--muted);margin-top:14px;line-height:1.8;">'
    + '<strong style="color:var(--text)">How natures work:</strong> A Pokémon\'s nature boosts one non-HP stat by 10% and lowers another by 10%. '
    + 'The five neutral natures (Hardy, Docile, Serious, Bashful, Quirky) have no effect. '
    + 'In Gen 3, a Pokémon that likes a flavor will eagerly eat Pokéblocks of that type, affecting Contest stat growth. '
    + 'Nature is determined at encounter and cannot be changed in Gen 3.'
    + '</div>';

  window._naturesBuilt = true;
}

// ══ CATCH RATE CALCULATOR ══════════════════════════════════════
function buildCatchCalcPage() {
  var el = document.getElementById('catchcalc-content');
  if (!el) return;

  var SPRITE_BASE = 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/items/';

  // Ball definitions: name, sprite slug, bonus fn, master flag, note
  var BALLS = [
    { name:'Poké Ball',    slug:'poke-ball',    master:false, bonus: function(cr,turn,wildLvl){ return 1; } },
    { name:'Great Ball',   slug:'great-ball',   master:false, bonus: function(cr,turn,wildLvl){ return 1.5; } },
    { name:'Ultra Ball',   slug:'ultra-ball',   master:false, bonus: function(cr,turn,wildLvl){ return 2; } },
    { name:'Master Ball',  slug:'master-ball',  master:true,  bonus: function(cr,turn,wildLvl){ return 255; } },
    { name:'Safari Ball',  slug:'safari-ball',  master:false, bonus: function(cr,turn,wildLvl){ return 1.5; }, note:'Safari Zone only' },
    { name:'Net Ball',     slug:'net-ball',     master:false, bonus: function(cr,turn,wildLvl){ return 3; },   note:'Water/Bug types ×3, else ×1' },
    { name:'Dive Ball',    slug:'dive-ball',    master:false, bonus: function(cr,turn,wildLvl){ return 3.5; }, note:'While Surfing/Diving' },
    { name:'Nest Ball',    slug:'nest-ball',    master:false, bonus: function(cr,turn,wildLvl){ return Math.max(1, Math.floor((41 - Math.min(30, wildLvl)) * 100 / 10) / 100); }, note:'Better at low levels' },
    { name:'Repeat Ball',  slug:'repeat-ball',  master:false, bonus: function(cr,turn,wildLvl){ return 3; },   note:'If already caught species' },
    { name:'Timer Ball',   slug:'timer-ball',   master:false, bonus: function(cr,turn,wildLvl){ return Math.min(4, 1 + Math.floor(turn * 1229 / 4096)); }, note:'Better with more turns' },
    { name:'Premier Ball', slug:'premier-ball', master:false, bonus: function(cr,turn,wildLvl){ return 1; },   note:'Same as Poké Ball' },
    { name:'Luxury Ball',  slug:'luxury-ball',  master:false, bonus: function(cr,turn,wildLvl){ return 1; },   note:'Raises friendship faster' },
  ];

  var STATUSES = [
    { name:'None',      mult:1,   color:'var(--muted)',  emoji:'' },
    { name:'Sleep',     mult:2,   color:'#9966CC',       emoji:'💤' },
    { name:'Freeze',    mult:2,   color:'#64b4ff',       emoji:'🧊' },
    { name:'Paralysis', mult:1.5, color:'#FFD700',       emoji:'⚡' },
    { name:'Burn',      mult:1.5, color:'#FF6B35',       emoji:'🔥' },
    { name:'Poison',    mult:1.5, color:'#AA44AA',       emoji:'☠️' },
  ];

  // Build Pokémon search list
  var pokeList = POKE.map(function(p) {
    var meta = POKE_META[p.num] || {};
    return { num: p.num, name: p.name, cr: meta.cr || 0, types: p.types || [] };
  });

  function spriteImg(slug) {
    return '<img src="' + SPRITE_BASE + slug + '.png" alt="" width="24" height="24"'
      + ' style="image-rendering:pixelated;vertical-align:middle;margin-right:6px;"'
      + ' onerror="this.style.display=\'none\'">';
  }

  el.innerHTML = [
    // ── Inputs row ──
    '<div class="cc-inputs-grid">',

    // Left: Pokémon + sliders
    '<div class="panel" style="padding:16px;">',
    '<div style="font-family:\'Press Start 2P\',monospace;font-size:7px;color:var(--game-color,var(--gold));letter-spacing:1px;margin-bottom:12px;">INPUTS</div>',

    '<label style="font-size:11px;color:var(--muted);display:block;margin-bottom:4px;">Pokémon (or enter catch rate manually)</label>',
    '<div style="display:flex;gap:8px;align-items:center;margin-bottom:4px;">',
    '<input id="cc-poke-search" type="text" placeholder="e.g. Mewtwo, Latias…" autocomplete="off"',
    ' style="flex:1;background:var(--input-bg,var(--bg));border:1px solid var(--border);border-radius:4px;padding:7px 10px;color:var(--text);font-size:12px;"',
    ' oninput="ccPokeSearch(this.value)">',
    '<input id="cc-catch-rate" type="number" min="1" max="255" placeholder="CR" title="Catch rate (1-255)"',
    ' style="width:60px;background:var(--input-bg,var(--bg));border:1px solid var(--border);border-radius:4px;padding:7px 8px;color:var(--text);font-size:12px;text-align:center;"',
    ' oninput="ccRecalc()">',
    '</div>',
    '<div id="cc-poke-results" style="position:relative;z-index:10;margin-bottom:10px;"></div>',

    '<label style="font-size:11px;color:var(--muted);display:block;margin-bottom:3px;">HP Remaining: <span id="cc-hp-label" style="color:var(--text);">50%</span></label>',
    '<input id="cc-hp" type="range" min="1" max="100" value="50" style="width:100%;margin-bottom:10px;" oninput="document.getElementById(\'cc-hp-label\').textContent=this.value+\'%\';ccRecalc()">',

    '<label style="font-size:11px;color:var(--muted);display:block;margin-bottom:3px;">Wild Pokémon Level: <span id="cc-lvl-label" style="color:var(--text);">20</span></label>',
    '<input id="cc-lvl" type="range" min="1" max="100" value="20" style="width:100%;margin-bottom:10px;" oninput="document.getElementById(\'cc-lvl-label\').textContent=this.value;ccRecalc()">',

    '<label style="font-size:11px;color:var(--muted);display:block;margin-bottom:3px;">Turn Number: <span id="cc-turn-label" style="color:var(--text);">1</span></label>',
    '<input id="cc-turn" type="range" min="1" max="40" value="1" style="width:100%;margin-bottom:10px;" oninput="document.getElementById(\'cc-turn-label\').textContent=this.value;ccRecalc()">',

    '<label style="font-size:11px;color:var(--muted);display:block;margin-bottom:6px;">Status Condition</label>',
    '<div style="display:flex;flex-wrap:wrap;gap:5px;" id="cc-status-btns">',
    STATUSES.map(function(s, i) {
      var active = i === 0;
      return '<button onclick="ccSetStatus(this,\'' + s.name + '\')"'
        + ' style="font-size:10px;padding:5px 9px;background:' + (active ? 'var(--game-color,var(--gold))' : 'var(--panel)') + ';color:' + (active ? '#000' : 'var(--text)') + ';border:1px solid var(--border);border-radius:4px;cursor:pointer;">'
        + (s.emoji ? s.emoji + ' ' : '') + s.name + '</button>';
    }).join(''),
    '</div>',
    '</div>',

    // Right: results
    '<div class="panel" style="padding:16px;display:flex;flex-direction:column;">',
    '<div style="font-family:\'Press Start 2P\',monospace;font-size:7px;color:var(--game-color,var(--gold));letter-spacing:1px;margin-bottom:12px;">CATCH PROBABILITIES</div>',
    '<div id="cc-results" style="font-size:12px;color:var(--muted);flex:1;">Enter a Pokémon or catch rate above.</div>',
    '</div>',

    '</div>',

    // Best combo section
    '<div class="panel" style="padding:16px;margin-bottom:16px;">',
    '<div style="font-family:\'Press Start 2P\',monospace;font-size:7px;color:var(--game-color,var(--gold));letter-spacing:1px;margin-bottom:12px;">⭐ BEST COMBINATIONS (excluding Master Ball)</div>',
    '<div id="cc-best" style="font-size:12px;color:var(--muted);">Enter a Pokémon or catch rate above.</div>',
    '</div>',

    // Formula note
    '<div style="font-size:10px;color:var(--muted);line-height:1.8;background:var(--panel);border:1px solid var(--border);border-radius:6px;padding:12px 14px;">',
    '<strong style="color:var(--text)">Gen 3 Catch Formula:</strong> ',
    'a = ((3×MaxHP − 2×CurrentHP) × CatchRate × BallBonus × StatusBonus) ÷ (3×MaxHP). ',
    'Shake threshold b = floor(65536 ÷ (255÷a)^0.1875). P(catch) = (b÷65536)^4.<br>',
    'Status: Sleep/Freeze = ×2 &nbsp;|&nbsp; Paralysis/Burn/Poison = ×1.5 &nbsp;|&nbsp; None = ×1. '
    + 'Nest Ball bonus = max(1, floor((41 − min(wildLvl, 30)) ÷ 10)).',
    '</div>'
  ].join('');

  window._ccStatus = 'None';
  window._ccCatchRate = 0;

  function calcProb(cr, hpFactor, statusMult, bonus) {
    var a = Math.floor(hpFactor * cr * bonus * statusMult);
    a = Math.max(1, Math.min(255, a));
    var b = Math.floor(65536 / Math.pow(255 / a, 0.1875));
    return Math.pow(b / 65536, 4) * 100;
  }

  function pctColor(pct) {
    return pct >= 80 ? '#4CAF50' : pct >= 40 ? '#FFC107' : pct >= 10 ? '#FF9800' : '#F44336';
  }

  function pctStr(pct) {
    return pct >= 99.9 ? '100%' : pct.toFixed(1) + '%';
  }

  function ballRow(ball, pct) {
    pct = Math.min(100, pct);
    var color = pctColor(pct);
    var isMaster = ball.master;
    return '<div style="display:flex;align-items:center;gap:8px;padding:4px 0;">'
      + spriteImg(ball.slug)
      + '<span style="width:88px;font-size:11px;white-space:nowrap;' + (isMaster ? 'color:var(--gold);font-weight:700;' : '') + '">' + ball.name + '</span>'
      + (ball.note ? '<span style="font-size:9px;color:var(--muted);flex:1;font-style:italic;">' + ball.note + '</span>' : '<span style="flex:1;"></span>')
      + '<div style="width:120px;height:10px;background:rgba(255,255,255,.08);border-radius:5px;overflow:hidden;flex-shrink:0;">'
      + '<div style="width:' + Math.round(pct) + '%;height:100%;background:' + color + ';border-radius:5px;transition:width .2s;"></div>'
      + '</div>'
      + '<span style="width:44px;text-align:right;font-size:11px;font-weight:700;color:' + color + ';flex-shrink:0;">' + pctStr(pct) + '</span>'
      + '</div>';
  }

  window.ccPokeSearch = function(q) {
    var box = document.getElementById('cc-poke-results');
    q = q.trim().toLowerCase();
    if (!q) { box.innerHTML = ''; return; }
    var matches = pokeList.filter(function(p){ return p.name.toLowerCase().indexOf(q) === 0; }).slice(0, 8);
    if (!matches.length) matches = pokeList.filter(function(p){ return p.name.toLowerCase().indexOf(q) !== -1; }).slice(0, 8);
    if (!matches.length) { box.innerHTML = ''; return; }
    box.innerHTML = '<div style="position:absolute;top:0;left:0;right:0;background:var(--panel);border:1px solid var(--border);border-radius:4px;box-shadow:0 4px 16px rgba(0,0,0,.4);z-index:20;">'
      + matches.map(function(p){
          return '<div onclick="ccSelectPoke(\'' + p.name.replace(/'/g,"\\'") + '\',' + p.cr + ')"'
            + ' style="padding:7px 12px;cursor:pointer;font-size:12px;display:flex;justify-content:space-between;align-items:center;"'
            + ' onmouseover="this.style.background=\'rgba(255,255,255,.06)\'" onmouseout="this.style.background=\'\'">'
            + '<span>' + p.name + '</span>'
            + '<span style="font-size:10px;color:var(--muted);">CR: ' + p.cr + '</span>'
            + '</div>';
        }).join('')
      + '</div>';
  };

  window.ccSelectPoke = function(name, cr) {
    document.getElementById('cc-poke-search').value = name;
    document.getElementById('cc-catch-rate').value = cr;
    document.getElementById('cc-poke-results').innerHTML = '';
    window._ccCatchRate = cr;
    ccRecalc();
  };

  window.ccSetStatus = function(btn, status) {
    document.querySelectorAll('#cc-status-btns button').forEach(function(b){
      b.style.background = 'var(--panel)'; b.style.color = 'var(--text)';
    });
    btn.style.background = 'var(--game-color,var(--gold))'; btn.style.color = '#000';
    window._ccStatus = status;
    ccRecalc();
  };

  window.ccRecalc = function() {
    var crInput = parseInt(document.getElementById('cc-catch-rate').value, 10);
    var cr = crInput > 0 ? crInput : window._ccCatchRate;
    var resultsEl = document.getElementById('cc-results');
    var bestEl    = document.getElementById('cc-best');
    if (!cr || cr <= 0) {
      resultsEl.innerHTML = '<span style="color:var(--muted)">Enter a Pokémon or catch rate above.</span>';
      bestEl.innerHTML    = '<span style="color:var(--muted)">Enter a Pokémon or catch rate above.</span>';
      return;
    }

    var hpPct    = parseInt(document.getElementById('cc-hp').value, 10) / 100;
    var wildLvl  = parseInt(document.getElementById('cc-lvl').value, 10);
    var turn     = parseInt(document.getElementById('cc-turn').value, 10);
    var status   = window._ccStatus || 'None';
    var statusObj = STATUSES.filter(function(s){ return s.name === status; })[0] || STATUSES[0];
    var hpFactor = (3 - 2 * hpPct) / 3;

    // ── Main results: sorted by probability (master ball always last) ──
    var ballResults = BALLS.map(function(ball) {
      var bonus = ball.bonus(cr, turn, wildLvl);
      var pct = ball.master ? 100 : calcProb(cr, hpFactor, statusObj.mult, bonus);
      return { ball: ball, pct: pct, bonus: bonus };
    });
    // Sort non-master by pct desc, master ball at end
    var nonMaster = ballResults.filter(function(r){ return !r.ball.master; });
    var masterR   = ballResults.filter(function(r){ return r.ball.master; });
    nonMaster.sort(function(a,b){ return b.pct - a.pct; });
    var sorted = nonMaster.concat(masterR);

    resultsEl.innerHTML = '<div style="display:flex;flex-direction:column;gap:2px;">'
      + sorted.map(function(r){ return ballRow(r.ball, r.pct); }).join('')
      + '</div>';

    // ── Best combos: all balls (excl. master) × all statuses ──
    var combos = [];
    BALLS.forEach(function(ball) {
      if (ball.master) return;
      STATUSES.forEach(function(st) {
        var bonus = ball.bonus(cr, turn, wildLvl);
        var pct = calcProb(cr, hpFactor, st.mult, bonus);
        combos.push({ ball: ball, status: st, pct: pct, bonus: bonus });
      });
    });
    combos.sort(function(a, b){ return b.pct - a.pct; });

    // Show top 5, deduped by (ball+status) already unique; show medal for top 3
    var medals = ['🥇', '🥈', '🥉'];
    var bestRows = combos.slice(0, 5).map(function(c, i) {
      var color = pctColor(c.pct);
      var medal = medals[i] || '';
      return '<div style="display:flex;align-items:center;gap:10px;padding:5px 0;border-bottom:1px solid rgba(255,255,255,.04);">'
        + '<span style="width:20px;text-align:center;font-size:14px;">' + medal + '</span>'
        + spriteImg(c.ball.slug)
        + '<span style="width:80px;font-size:11px;">' + c.ball.name + '</span>'
        + '<span style="font-size:11px;color:' + c.status.color + ';width:72px;">'
        + (c.status.emoji ? c.status.emoji + ' ' : '') + c.status.name + '</span>'
        + '<div style="flex:1;height:10px;background:rgba(255,255,255,.08);border-radius:5px;overflow:hidden;">'
        + '<div style="width:' + Math.round(c.pct) + '%;height:100%;background:' + color + ';border-radius:5px;"></div>'
        + '</div>'
        + '<span style="width:44px;text-align:right;font-size:11px;font-weight:700;color:' + color + ';">' + pctStr(c.pct) + '</span>'
        + '</div>';
    });

    bestEl.innerHTML = '<div style="font-size:10px;color:var(--muted);margin-bottom:8px;">Best ball + status combinations at current HP/turn settings:</div>'
      + '<div>' + bestRows.join('') + '</div>';
  };

  window._catchCalcBuilt = true;
}

