// ══ MAP PANEL ═══════════════════════════════════════════════════
var _mapRegionUrls = {
  kanto3: 'https://simplyblgdev.github.io/pokemon/kanto3',
  hoenn:  'https://simplyblgdev.github.io/pokemon/hoenn'
};

window.mapSelectRegion = function(region) {
  var iframe = document.getElementById('map-iframe');
  iframe.src = _mapRegionUrls[region] || _mapRegionUrls.hoenn;
};

/* iOS Safari scroll-lock for panels.
   overflow:hidden on html/body is not enough — Safari decides to show/hide
   its toolbar before any DOM scroll event fires. The only reliable fix is a
   non-passive touchmove listener that calls preventDefault(), cancelling the
   gesture entirely, while still allowing scroll inside any overflow container. */
function _iosPanelTouchGuard(e) {
  var el = e.target;
  while (el && el !== document.documentElement) {
    var ov = window.getComputedStyle(el).overflowY;
    if ((ov === 'auto' || ov === 'scroll') && el.scrollHeight > el.clientHeight) {
      return; // touch is inside a real scroll container — let it scroll
    }
    el = el.parentElement;
  }
  e.preventDefault(); // nothing scrollable in the chain — block the gesture
}

function _panelScrollLock() {
  if (window.innerWidth <= 767) {
    document.documentElement.classList.add('panel-open');
    document.addEventListener('touchmove', _iosPanelTouchGuard, { passive: false });
  }
}
function _panelScrollUnlock() {
  // Only unlock if no panel is still open
  var anyOpen = (document.getElementById('notes-panel') && document.getElementById('notes-panel').classList.contains('open'))
             || (document.getElementById('map-panel') && document.getElementById('map-panel').classList.contains('open'));
  if (!anyOpen) {
    document.documentElement.classList.remove('panel-open');
    document.removeEventListener('touchmove', _iosPanelTouchGuard, { passive: false });
  }
}

window.toggleMapPanel = function() {
  var panel = document.getElementById('map-panel');
  if (panel.classList.contains('open')) { closeMapPanel(); return; }
  // Close notes if open
  var notesPanel = document.getElementById('notes-panel');
  if (notesPanel && notesPanel.classList.contains('open')) { closeNotesPanel(); }
  // Auto-select region based on current game
  var region = (['FR','LG'].indexOf(GAME) !== -1) ? 'kanto3' : 'hoenn';
  var sel = document.getElementById('map-select');
  if (sel) sel.value = region;
  var iframe = document.getElementById('map-iframe');
  var url = _mapRegionUrls[region];
  if (iframe.src !== url) iframe.src = url;
  panel.classList.add('open');
  _panelScrollLock();
  if (typeof iosSetActiveByOptId === 'function') iosSetActiveByOptId('map');
};
window.closeMapPanel = function() {
  document.getElementById('map-panel').classList.remove('open');
  _panelScrollUnlock();
  if (typeof iosRestorePageActive === 'function') iosRestorePageActive();
};

window.toggleNotesPanel=function(){
  var p=document.getElementById('notes-panel'),o=document.getElementById('notes-overlay');
  if (p.classList.contains('fullpage')) { closeNotesPanel(); return; }
  if(p.classList.contains('open')){
    p.classList.remove('open');o.classList.remove('open');
    _panelScrollUnlock();
    if(typeof iosRestorePageActive==='function') iosRestorePageActive();
  } else{
    if(typeof window.notesSyncToGlobalGame==='function') window.notesSyncToGlobalGame();
    p.classList.add('open');o.classList.add('open');renderNotesList();renderLabelBar();
    _panelScrollLock();
    if(typeof iosSetActiveByOptId==='function') iosSetActiveByOptId('notes');
  }
};
window.enterNotesFullPage=function(){
  var panel=document.getElementById('notes-panel');
  var overlay=document.getElementById('notes-overlay');
  var host=document.getElementById('notes-page-host');
  if(!panel||!host)return;
  var currentPage=getPageHashId() || 'home';
  if(currentPage && currentPage !== 'notes') NOTES_PREV_PAGE=currentPage;
  if(panel.parentElement !== host) host.appendChild(panel);
  panel.classList.add('fullpage','open');
  if(overlay) overlay.classList.remove('open');
  if(typeof window.notesSyncToGlobalGame==='function') window.notesSyncToGlobalGame();
  renderNotesList();
  renderLabelBar();
};
window.exitNotesFullPage=function(restorePage){
  var panel=document.getElementById('notes-panel');
  var sideHost=document.getElementById('notes-side-host');
  if(!panel||!sideHost||!panel.classList.contains('fullpage')) return;
  sideHost.appendChild(panel);
  panel.classList.remove('fullpage','open');
  _panelScrollUnlock();
  if(restorePage){
    var target=NOTES_PREV_PAGE || 'home';
    if(target === 'home') resetHome();
    else showPage(target, document.getElementById('nav' + target.charAt(0).toUpperCase() + target.slice(1)));
  }
};
window.closeNotesPanel=function(){
  var panel=document.getElementById('notes-panel');
  var overlay=document.getElementById('notes-overlay');
  if(panel && panel.classList.contains('fullpage')){window.exitNotesFullPage(true);destroySlashDropdown();return;}
  if(panel) panel.classList.remove('open');
  if(overlay) overlay.classList.remove('open');
  _panelScrollUnlock();
  destroySlashDropdown();
};

/* ── HTML escape ── */
function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}

/* ── Auto-link name maps (built lazily) ── */
var _pokeMap=null,_itemMap=null,_moveMap=null,_pokeNumMap=null;

// Convert an item name to its PokeAPI sprite slug (e.g. "Poké Ball" → "poke-ball")
function _itemSlug(name){
  return name.toLowerCase()
    .replace(/[éèê]/g,'e').replace(/[àâ]/g,'a').replace(/[ïî]/g,'i')
    .replace(/[ùûü]/g,'u').replace(/[ôö]/g,'o').replace(/[ñ]/g,'n')
    .replace(/['']/g,'')
    .replace(/[^a-z0-9\s-]/g,'')
    .replace(/\s+/g,'-')
    .replace(/-+/g,'-');
}
// Normalise a name for fuzzy matching: strip accents, spaces, punctuation, lowercase
// Lets "pokeball" match "Poké Ball", "flamethrower" match "Flamethrower", etc.
function normName(s){
  return s.toLowerCase()
    .replace(/[éèê]/g,'e').replace(/[àâ]/g,'a').replace(/[ïî]/g,'i')
    .replace(/[ùûü]/g,'u').replace(/[ôö]/g,'o').replace(/[ñ]/g,'n')
    .replace(/[\s\-''.,:()/]/g,'');
}

function getPokeMap(){
  if(_pokeMap)return _pokeMap; _pokeMap=new Map();
  try{(typeof POKE!=='undefined'?POKE:[]).forEach(function(p){
    var lo=p.name.toLowerCase(),nk=normName(p.name);
    _pokeMap.set(lo,p.name);
    if(nk!==lo)_pokeMap.set(nk,p.name);
  });}catch(e){}
  return _pokeMap;
}
function getPokeNumMap(){
  if(_pokeNumMap)return _pokeNumMap; _pokeNumMap=new Map();
  try{(typeof POKE!=='undefined'?POKE:[]).forEach(function(p){
    _pokeNumMap.set(p.name,p.num);
    _pokeNumMap.set(p.name.toLowerCase(),p.num);
  });}catch(e){}
  return _pokeNumMap;
}
function getItemMap(){
  if(_itemMap)return _itemMap; _itemMap=new Map();
  try{(typeof ALL_ITEMS!=='undefined'?ALL_ITEMS:[]).forEach(function(it){
    var lo=it[1].toLowerCase(),nk=normName(it[1]);
    _itemMap.set(lo,it[1]);
    if(nk!==lo)_itemMap.set(nk,it[1]);
  });}catch(e){}
  return _itemMap;
}
function getMoveMap(){
  if(_moveMap)return _moveMap; _moveMap=new Map();
  try{(typeof ALL_MOVES_DATA!=='undefined'?ALL_MOVES_DATA:[]).forEach(function(m){
    var lo=m[1].toLowerCase(),nk=normName(m[1]);
    _moveMap.set(lo,m[1]);
    if(nk!==lo)_moveMap.set(nk,m[1]);
  });}catch(e){}
  return _moveMap;
}

var _POKE_SPRITE='https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/';
var _ITEM_SPRITE='https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/items/';
var _SPR_STYLE='image-rendering:pixelated;vertical-align:middle;margin-right:2px;';

function autoLink(text){
  var pm=getPokeMap(),im=getItemMap(),mm=getMoveMap(),nm=getPokeNumMap();
  var onerr='onerror="this.style.display=\'none\'"';
  // Match both capitalised and lowercase words (single or two-word)
  return text.replace(/\b([A-Za-zÉé][a-zA-Zé'.:\-]+(?:\s[A-Za-zÉé][a-zA-Zé'.:\-]+)?)\b/g,function(match){
    var lo=match.toLowerCase(), nk=normName(match);
    var cn;
    if((cn=pm.get(lo)||pm.get(nk))){
      var num=nm.get(cn);
      var spr=num?'<img src="'+_POKE_SPRITE+num+'.png" alt="" width="20" height="20" style="'+_SPR_STYLE+'" '+onerr+'>':'';
      return '<a class="note-autolink" data-type="poke" data-val="'+esc(cn)+'">'+spr+esc(match)+'</a>';
    }
    if((cn=im.get(lo)||im.get(nk))){
      var spr2='<img src="'+_ITEM_SPRITE+_itemSlug(cn)+'.png" alt="" width="20" height="20" style="'+_SPR_STYLE+'" '+onerr+'>';
      return '<a class="note-autolink" data-type="item" data-val="'+esc(cn)+'">'+spr2+esc(match)+'</a>';
    }
    if((cn=mm.get(lo)||mm.get(nk)))return '<a class="note-autolink" data-type="move" data-val="'+esc(cn)+'">'+esc(match)+'</a>';
    return esc(match);
  });
}

/* ── Markdown-lite parser ── */
var _cbSeq=0;
function renderMd(raw,noteId){
  var lines=raw.split('\n'),html='',inUl=false;
  lines.forEach(function(line){
    var cbm=line.match(/^(\s*)\[([ xX])\] (.*)$/);
    if(cbm){
      if(inUl){html+='</ul>';inUl=false;}
      var cbId=noteId+'_c'+(++_cbSeq);
      // Use saved checkbox state if available; fall back to [x]/[ ] in raw text
      var rawChecked=cbm[2].toLowerCase()==='x';
      var noteObj=notes.find(function(n){return n.id===noteId;});
      var checked=(noteObj&&noteObj.checkboxStates&&noteObj.checkboxStates[cbId]!==undefined)
                  ?noteObj.checkboxStates[cbId]:rawChecked;
      var rest=inlineFmt(cbm[3],noteId);
      html+='<div class="note-cb-row"><input type="checkbox" class="note-cb" id="cb_'+cbId+'"'+(checked?' checked':'')+' onchange="noteToggleCb(\''+noteId+'\',\''+cbId+'\',this.checked)">'
        +'<label for="cb_'+cbId+'" style="cursor:pointer;'+(checked?'text-decoration:line-through;color:var(--muted);':'')+'">'+rest+'</label></div>';
      return;
    }
    if(line.startsWith('## ')){if(inUl){html+='</ul>';inUl=false;}html+='<div class="note-h2">'+esc(line.slice(3))+'</div>';return;}
    if(line.startsWith('# ')){if(inUl){html+='</ul>';inUl=false;}html+='<div class="note-h1">'+esc(line.slice(2))+'</div>';return;}
    if(/^[-*] /.test(line)){if(!inUl){html+='<ul class="note-ul">';inUl=true;}html+='<li>'+inlineFmt(line.slice(2),noteId)+'</li>';return;}
    if(inUl){html+='</ul>';inUl=false;}
    if(!line.trim()){html+='<div class="note-spacer"></div>';return;}
    html+='<div class="note-line">'+inlineFmt(line,noteId)+'</div>';
  });
  if(inUl)html+='</ul>';
  return html;
}
function renderRouteChip(route){
  if(!route) return '';
  return '<button class="note-meta-chip route" onclick="event.stopPropagation();noteOpenRoute(\''+esc(route).replace(/'/g,"\\'")+'\')">Route: '+esc(route)+'</button>';
}
function renderPokemonChip(pokemon){
  if(!pokemon) return '';
  return '<button class="note-meta-chip pokemon" onclick="event.stopPropagation();noteLinkPoke(\''+esc(pokemon).replace(/'/g,"\\'")+'\')">Pokemon: '+esc(pokemon)+'</button>';
}
function isGuideLinkedNote(note){
  return !!(note && /\[\[bulba:/i.test(String(note.content||'')));
}

function inlineFmt(text,noteId){
  // Page links
  text=text.replace(/\[\[page:([^\]|]+)(?:\|([^\]]+))?\]\]/g,function(_,pid,lbl){
    var d=lbl||pid;
    return '<a class="note-link-page" onclick="noteNavPage(\''+pid+'\')">'+esc(d)+' ↗</a>';
  });
  // Bulba links
  text=text.replace(/\[\[bulba:([^:]+):([^\]|]+)(?:\|([^\]]+))?\]\]/g,function(_,game,key,lbl){
    var d=lbl||(game+': '+key);
    return '<a class="note-link-bulba" onclick="noteNavBulba(\''+game+'\',\''+esc(key)+'\')">'+esc(d)+' ↗</a>';
  });
  // Type badges — [[type:Fire]] → same pixel-art sprite as the Pokédex
  text=text.replace(/\[\[type:([A-Za-z]+)\]\]/g,function(_,t){
    return typeSprite(t.toLowerCase());
  });
  // Bold / italic
  text=text.replace(/\*\*([^*]+)\*\*/g,'<strong>$1</strong>');
  text=text.replace(/\*([^*]+)\*/g,'<em>$1</em>');
  // Auto-link: only process text nodes (skip tag contents)
  var out=text.split(/(<[^>]+>)/);
  return out.map(function(part,i){return i%2===0?autoLink(part):part;}).join('');
}

/* ── Note navigation from links ── */
var NOTE_BTN_MAP={
  dex:'navDex',bulba:'navBulba',moves:'navMoves',items:'navItems',
  excl:'navExcl',tracker:'navTracker',tmhm:'navTmhm',held:'navHeld',opt:'navOpt',
  easydex:'navEasydex',tradeevo:'navTradeEvo',team:'navTeam',calc:'navCalc',
  ivev:'navIvev',compare:'navCompare',breed:'navBreed',
  abilities:'navAbilities',learnsets:'navLearnsets',encounters:'navEncounters',itemlocs:'navItemLocs',
  speedtiers:'navSpeedTiers',contests:'navContests',frontier:'navFrontier',missables:'navMissables',berries:'navBerries',
  kantomapview:'navKantoMapView',emeraldmapview:'navEmeraldMapView',tutors:'navTutors',
  ribbons:'navRibbons',rng:'navRng',expcalc:'navExpCalc',
  natures:'navNatures',catchcalc:'navCatchCalc',dexdash:'navDexDash',
  npctrades:'navNpcTrades',happiness:'navHappiness',typechart:'navTypeChart',
  safarizone:'navSafariZone',statcalc:'navStatCalc',
  distributions:'navDistributions',distributionchecklist:'navDistributions',pokeblock:'navPokeblock',e4ref:'navE4Ref',rematches:'navRematches',routebrowser:'navRouteBrowser',
};

window.openTopLevelPage = function(pid) {
  if(pid==='distributionchecklist') pid='distributions';
  if(pid==='bulba'){showPage('bulba',document.getElementById('navBulba'));if(!window._bulbaBuilt){buildBulbaGuide();window._bulbaBuilt=true;}if(typeof bulbaAutoSelectGame==='function')bulbaAutoSelectGame();return;}
  if(pid==='tracker'){showPage('tracker',document.getElementById('navTracker'));buildTracker();window._trackerBuilt=true;return;}
  var directBuilders = {
    excl: function(){ buildExcl(); window._exclBuilt = true; },
    dexdash: function(){ buildDexDashPage(); },
    ribbons: function(){ if(!window._ribbonsBuilt){ buildRibbonPage(); window._ribbonsBuilt=true; } },
    essentials: function(){ if(!window._essentialsBuilt){ buildEssentialsPage(); window._essentialsBuilt=true; } },
    contests: function(){ if(!window._contestsBuilt){ buildContestsPage(); window._contestsBuilt=true; } },
    frontier: function(){ if(!window._frontierBuilt){ buildFrontierPage(); window._frontierBuilt=true; } },
    missables: function(){ if(!window._missablesBuilt){ buildMissablesPage(); window._missablesBuilt=true; } },
    berries: function(){ if(!window._berriesBuilt){ buildBerriesPage(); window._berriesBuilt=true; } },
    rng: function(){ if(!window._rngBuilt){ buildRngPage(); window._rngBuilt=true; } }
  };
  var navId=NOTE_BTN_MAP[pid];
  var btn=navId?document.getElementById(navId):null;
  if (window.PAGE_REGISTRY && window.PAGE_REGISTRY[pid]) {
    showPage(pid, btn);
    if (window.ensurePageReady) window.ensurePageReady(pid);
    return;
  }
  if (directBuilders[pid]) {
    showPage(pid, btn);
    directBuilders[pid]();
    return;
  }
  if(btn){btn.click();}else{showPage(pid,null);}
};

window.noteNavPage=function(pid){
  closeNotesPanel();
  if (typeof window.openTopLevelPage === 'function') {
    window.openTopLevelPage(pid);
  }
};

window.noteNavBulba=function(game,key){
  closeNotesPanel();
  showPage('bulba',document.getElementById('navBulba'));
  if(!window._bulbaBuilt){buildBulbaGuide();window._bulbaBuilt=true;}
  var gMap={FRLG:'frlg',RS:'rs',E:'e'};
  var gkey=gMap[game]||'frlg';
  if(typeof bulbaSwitchGame==='function')bulbaSwitchGame(gkey,null);
  setTimeout(function(){
    if(key==='index'){if(typeof bulbaLoadIndex==='function')bulbaLoadIndex();}
    else{
      var pm=key.match(/^part:(\d+):(.+)$/);
      var em=key.match(/^extra:(.+)$/);
      var sm=key.match(/^section:(.+)$/);
      if(pm&&typeof bulbaLoadPart==='function')bulbaLoadPart(parseInt(pm[1]),pm[2]);
      else if(em&&typeof bulbaLoadExtra==='function'){
        var secs=BULBA_SECTIONS[game]||[];
        var found=null;for(var i=0;i<secs.length;i++){if(secs[i].key===em[1]){found=secs[i];break;}}
        bulbaLoadExtra(em[1],found?found.label:em[1]);
      }
      else if(sm&&typeof _openGuideSection==='function'){ _openGuideSection(sm[1]); }
    }
  },120);
};

/* ── Checkbox toggle ── */
window.noteToggleCb=function(noteId,cbId,checked){
  var n=notes.find(function(x){return x.id===noteId;});
  if(!n)return;
  if(!n.checkboxStates)n.checkboxStates={};
  n.checkboxStates[cbId]=checked;
  var lbl=document.querySelector('label[for="cb_'+cbId+'"]');
  if(lbl){lbl.style.textDecoration=checked?'line-through':'';lbl.style.color=checked?'var(--muted)':'';}
  saveNotes();
};

/* ── Auto-link navigation ── */
function noteLinkPoke(name){
  closeNotesPanel();
  showPage('dex',document.getElementById('navDex'));
  setTimeout(function(){
    // Filter the dex to show just this Pokémon
    if(typeof jumpToDex==='function') jumpToDex(name);
    else{var s=document.getElementById('searchInput');if(s){s.value=name;s.dispatchEvent(new Event('input'));}}
    // Open its detail panel — buildTable() is synchronous so the row exists now
    if(typeof POKE!=='undefined'&&typeof toggleEvoRow==='function'){
      var pk=POKE.find(function(p){return p.name.toLowerCase()===name.toLowerCase();});
      if(pk){
        toggleEvoRow(pk.num);
        flashDexRow(pk.num);
        var row=document.getElementById('poke-row-'+pk.num);
        if(row)setTimeout(function(){row.scrollIntoView({behavior:'smooth',block:'start'});},60);
      }
    }
  },100);
}
function noteLinkItem(name){
  closeNotesPanel();
  showPage('items',document.getElementById('navItems'));
  if(!window._itemsBuilt){buildItemDex();window._itemsBuilt=true;}
  setTimeout(function(){
    var inp=document.getElementById('itSearch');
    if(inp){inp.value=name;updateItClear(inp);if(typeof filterItemDex==='function')filterItemDex();}
    // Find the item's numeric ID and open its detail panel
    var item=typeof ALL_ITEMS!=='undefined'
      ? ALL_ITEMS.find(function(it){return it[1].toLowerCase()===name.toLowerCase();})
      : null;
    if(item&&typeof toggleItDet==='function'){
      setTimeout(function(){toggleItDet(item[0]);},80);
    }
  },150);
}
function noteLinkMove(name){
  closeNotesPanel();
  // goToMoveInDex handles page navigation, search and auto-opens the row
  if(typeof goToMoveInDex==='function'){goToMoveInDex(name);}
  else{
    showPage('moves',document.getElementById('navMoves'));
    if(!window._movesBuilt){buildMoveDex();window._movesBuilt=true;}
    setTimeout(function(){var s=document.getElementById('mdex-search');if(s){s.value=name;s.dispatchEvent(new Event('input'));}},150);
  }
}
window.noteOpenRoute=function(route){
  closeNotesPanel();
  var pid=routePageIdForName(route) || 'routebrowser';
  showPage(pid,document.getElementById('navRouteBrowser'));
  if(pid==='routebrowser' && typeof buildRouteBrowser==='function' && !window._routeBrowserBuilt){buildRouteBrowser();window._routeBrowserBuilt=true;}
  setTimeout(function(){
    var inp=document.getElementById('route-search')||document.getElementById('routeSearch')||document.getElementById('rb-search');
    if(inp){
      inp.value=route;
      inp.dispatchEvent(new Event('input'));
    }
  },120);
};

/* ── Render list ── */
function timeAgo(ts){var d=Date.now()-ts;if(d<60000)return 'just now';if(d<3600000)return Math.floor(d/60000)+'m ago';if(d<86400000)return Math.floor(d/3600000)+'h ago';return Math.floor(d/86400000)+'d ago';}

function getVisible(){
  var q=searchQuery.toLowerCase();
  return notes.filter(function(n){
    if((notesView==='archived' && n.status!=='archived') || (notesView!=='archived' && n.status==='archived')) return false;
    if(currentGame!=='ALL'){
      var ok=n.primaryGame===currentGame||n.primaryGame==='ALL'||(n.taggedGames&&n.taggedGames.indexOf(currentGame)>=0);
      if(!ok)return false;
    }
    if(currentLabel&&(!n.labels||n.labels.indexOf(currentLabel)<0))return false;
    if(notesChecklistOnly && !noteHasChecklist(n)) return false;
    if(q){
      var hay=((n.title||'')+' '+(n.content||'')+' '+(n.routeRef||'')+' '+(n.pokemonRef||'')).toLowerCase();
      if(hay.indexOf(q)<0)return false;
    }
    return true;
  }).sort(function(a,b){
    if(a.pinned&&!b.pinned)return -1;if(!a.pinned&&b.pinned)return 1;
    if(notesSort==='created') return (b.created||0)-(a.created||0);
    if(notesSort==='title') return String(a.title||a.routeRef||'').localeCompare(String(b.title||b.routeRef||''));
    return (b.modified||0)-(a.modified||0);
  });
}
function renderPinnedBar(){
  var bar=document.getElementById('notes-pinned-bar'); if(!bar) return;
  var pins=getVisible().filter(function(n){return n.pinned && n.status!=='archived';}).slice(0,3);
  if(!pins.length){bar.style.display='none';bar.innerHTML='';return;}
  bar.style.display='block';
  bar.innerHTML='<div style="font-family:\'Press Start 2P\',monospace;font-size:6px;color:var(--gold);margin-bottom:8px;letter-spacing:1px;">PINNED OBJECTIVES</div>'
    + pins.map(function(n){
      var prog=noteSavedProgress(n)||noteChecklistProgress(n), progText=(prog&&prog.total)?(' · '+prog.done+'/'+prog.total):'';
      return '<button class="note-pinned-chip" onclick="openNoteEditor(\''+n.id+'\')">'+esc(n.title||n.routeRef||'Pinned note')+progText+'</button>';
    }).join('');
}
function refreshNotesToolbar(){
  var a=document.getElementById('notes-view-active'), ar=document.getElementById('notes-view-archived');
  if(a) a.classList.toggle('active',notesView==='active');
  if(ar) ar.classList.toggle('active',notesView==='archived');
  ['modified','created','title'].forEach(function(k){
    var el=document.getElementById('notes-sort-'+k);
    if(el) el.classList.toggle('active',notesSort===k);
  });
  var chk=document.getElementById('notes-filter-checklist');
  if(chk) chk.classList.toggle('active',notesChecklistOnly);
}
window.notesSyncToGlobalGame=function(){
  var globalGame=(typeof GAME!=='undefined' && GAME)?GAME:'all';
  currentGame=(globalGame==='all')?'ALL':globalGame;
  document.querySelectorAll('.notes-game-tab').forEach(function(b){
    b.classList.toggle('active',b.dataset.game===currentGame);
  });
};

function renderNotesList(){
  var el=document.getElementById('notes-list-inner');if(!el)return;
  var vis=getVisible();
  renderPinnedBar();
  refreshNotesToolbar();
  if(!vis.length){
    el.innerHTML='<div style="text-align:center;padding:40px 16px;color:var(--muted);font-size:12px;line-height:2;">'
      +(notes.length===0?'📝<br><br>No notes yet.<br>Press <strong>+ New</strong> to get started.':'No notes match your filters.')+'</div>';
    return;
  }
  _cbSeq=0;
  el.innerHTML=vis.map(function(note){
    var accent=COLOR_ACCENT[note.color||'none'];
    var glbl=note.primaryGame==='ALL'?'🌐 All':GAME_LABELS[note.primaryGame]||note.primaryGame;
    var gcol=GAME_COLORS[note.primaryGame]||'var(--gold)';
    var tagHtml=(note.taggedGames||[]).map(function(g){return '<span class="note-tag-chip" style="color:'+(GAME_COLORS[g]||'var(--muted)')+';border-color:'+(GAME_COLORS[g]||'var(--border)')+';">+'+g+'</span>';}).join('');
    var lblHtml=(note.labels||[]).map(function(l){return '<span class="note-tag-chip">'+esc(l)+'</span>';}).join('');
    var progress=noteSavedProgress(note)||noteChecklistProgress(note);
    var progressHtml=(progress&&progress.total)?'<span class="note-progress-chip">'+progress.done+'/'+progress.total+' done</span>':'';
    var statusChip=note.status&&note.status!=='active'?'<span class="note-progress-chip '+note.status+'">'+esc(note.status)+'</span>':'';
    var linkedHtml=(isGuideLinkedNote(note)?renderRouteChip(note.routeRef):'')+renderPokemonChip(note.pokemonRef);
    var body=String(note.content||'');
    var longBody=body.length>520 || body.split('\n').length>14;
    return '<div class="note-card'+(note.pinned?' pinned':'')+(note.status==='completed'?' completed':'')+'" style="border-left:3px solid '+accent+';">'
      +'<div class="note-card-header">'
      +(note.color&&note.color!=='none'?'<div class="note-color-dot" style="background:'+accent+';"></div>':'')
      +(note.pinned?'<span title="Pinned">📌</span>':'')
      +'<span style="font-size:10px;font-weight:700;color:'+gcol+';">'+glbl+'</span>'
      +statusChip+progressHtml+tagHtml+lblHtml
      +'<span style="margin-left:auto;font-size:9px;color:var(--muted);">'+timeAgo(note.modified)+'</span>'
      +'<button onclick="event.stopPropagation();duplicateNote(\''+note.id+'\')" style="background:none;border:none;color:var(--muted);cursor:pointer;font-size:13px;padding:0 3px;" title="Duplicate">⎘</button>'
      +'<button onclick="event.stopPropagation();noteCycleStatus(\''+note.id+'\')" style="background:none;border:none;color:var(--muted);cursor:pointer;font-size:13px;padding:0 3px;" title="Change status">◎</button>'
      +'<button onclick="event.stopPropagation();openNoteEditor(\''+note.id+'\')" style="background:none;border:none;color:var(--muted);cursor:pointer;font-size:14px;padding:0 3px;" title="Edit">✏️</button>'
      +'<button onclick="event.stopPropagation();confirmDeleteNote(\''+note.id+'\')" style="background:none;border:none;color:var(--muted);cursor:pointer;font-size:14px;padding:0 3px;" title="Delete">🗑</button>'
      +'</div>'
      +(note.title?'<div style="padding:8px 12px 0;font-size:12px;font-weight:700;color:var(--gold);">'+esc(note.title)+'</div>':'')
      +(linkedHtml?'<div class="note-linked-row">'+linkedHtml+'</div>':'')
      +'<div class="note-card-body'+(longBody?' collapsed':'')+'" id="note-body-'+note.id+'">'+renderMd(note.content||'',note.id)+'</div>'
      +(longBody?'<div class="note-card-footer"><button class="note-label-pill" onclick="toggleNoteCollapse(\''+note.id+'\')">Expand</button></div>':'')
      +'</div>';
  }).join('');
  // Wire auto-link clicks
  el.querySelectorAll('.note-autolink').forEach(function(a){
    a.addEventListener('click',function(){
      var t=this.dataset.type,v=this.dataset.val;
      if(t==='poke')noteLinkPoke(v);else if(t==='item')noteLinkItem(v);else if(t==='move')noteLinkMove(v);
    });
  });
}

/* ── Label bar ── */
function getAllLabels(){var s={};notes.forEach(function(n){(n.labels||[]).forEach(function(l){s[l]=1;});});return Object.keys(s);}
function renderLabelBar(){
  var bar=document.getElementById('notes-label-bar');if(!bar)return;
  var labels=getAllLabels();
  if(!labels.length){bar.innerHTML='';bar.style.display='none';return;}
  bar.style.display='flex';
  bar.innerHTML='<button class="note-label-pill'+(currentLabel===null?' active':'')+'" onclick="noteLabelFilter(null)">All</button>'
    +labels.map(function(l){return '<button class="note-label-pill'+(currentLabel===l?' active':'')+'" onclick="noteLabelFilter(\''+l.replace(/'/g,"\\'")+'\')">'+ esc(l)+'</button>';}).join('');
}
window.noteLabelFilter=function(l){currentLabel=l;renderLabelBar();renderNotesList();};
window.notesSetView=function(v){notesView=v;renderNotesList();};
window.notesSetSort=function(v){notesSort=v;renderNotesList();};
window.notesToggleChecklistOnly=function(){notesChecklistOnly=!notesChecklistOnly;renderNotesList();};
window.toggleNoteCollapse=function(id){
  var el=document.getElementById('note-body-'+id);
  if(!el) return;
  var collapsed=el.classList.toggle('collapsed');
  var btn=el.parentElement.querySelector('.note-card-footer .note-label-pill');
  if(btn) btn.textContent=collapsed?'Expand':'Collapse';
};

/* ── Game tab ── */
window.notesSetGame=function(g){
  currentGame=g;
  document.querySelectorAll('.notes-game-tab').forEach(function(b){b.classList.toggle('active',b.dataset.game===g);});
  renderNotesList();
};

/* ── Search ── */
window.notesSearch=function(q){searchQuery=q;renderNotesList();};

/* ── Delete ── */
window.confirmDeleteNote=function(id){
  if(!confirm('Delete this note?'))return;
  notes=notes.filter(function(n){return n.id!==id;});
  saveNotes();renderNotesList();renderLabelBar();
};
window.duplicateNote=function(id){
  var n=notes.find(function(x){return x.id===id;}); if(!n) return;
  var copy=JSON.parse(JSON.stringify(n));
  copy.id=genId();
  copy.title=(n.title||'Untitled')+' Copy';
  copy.status='active';
  copy.pinned=false;
  copy.created=Date.now();
  copy.modified=Date.now();
  notes.unshift(copy);
  saveNotes(); renderNotesList(); renderLabelBar();
};
window.noteCycleStatus=function(id){
  var n=notes.find(function(x){return x.id===id;}); if(!n) return;
  n.status = n.status==='active' ? 'completed' : n.status==='completed' ? 'archived' : 'active';
  n.modified=Date.now();
  saveNotes(); renderNotesList(); renderLabelBar();
};

/* ── Editor ── */
window.openNoteEditor=function(id){
  var lv=document.getElementById('notes-list-view'),ev=document.getElementById('notes-editor-view');
  if(!lv||!ev)return;
  noteEditorSeedToken++;
  initNoteAutocomplete();
  var note=id?notes.find(function(n){return n.id===id;}):null;
  editingId=id||'new';
  document.getElementById('ne-title').value=note?(note.title||''):'';
  document.getElementById('ne-content').value=note?(note.content||''):'';
  document.getElementById('ne-game').value=note?(note.primaryGame||currentGame):currentGame;
  document.getElementById('ne-route').value=note?(note.routeRef||''):'';
  document.getElementById('ne-pokemon').value=note?(note.pokemonRef||''):'';
  var routeWrap=document.getElementById('ne-route-wrap');
  var pokemonWrap=document.getElementById('ne-pokemon-wrap');
  if(routeWrap) routeWrap.style.display=(note && isGuideLinkedNote(note))?'block':'none';
  if(pokemonWrap) pokemonWrap.style.display=(note && note.pokemonRef)?'block':'none';
  var tagged=note?(note.taggedGames||[]):[];
  document.querySelectorAll('.ne-tag-btn').forEach(function(b){b.classList.toggle('active',tagged.indexOf(b.dataset.game)>=0);});
  var col=note?(note.color||'none'):'none';
  document.querySelectorAll('.ne-color-btn').forEach(function(b){b.classList.toggle('active',b.dataset.color===col);});
  document.getElementById('ne-labels').value=note?(note.labels||[]).join(', '):'';
  var pin=document.getElementById('ne-pin');
  pin.classList.toggle('active',!!(note&&note.pinned));
  pin.textContent=(note&&note.pinned)?'📌 Pinned':'📌 Pin';
  noteEditorStatus=note?(note.status||'active'):'active';
  if(typeof window.neRefreshStatusButtons==='function') window.neRefreshStatusButtons();
  // Label presets
  var presetsEl=document.getElementById('ne-label-presets');
  if(presetsEl){
    presetsEl.innerHTML=LABEL_PRESETS.map(function(l){
      return '<button class="note-label-pill" onclick="neAddLabel(\''+l+'\')" style="font-size:8px;padding:2px 7px;">'+l+'</button>';
    }).join('');
  }
  // Template menu
  var tmenu=document.getElementById('ne-template-menu');
  if(tmenu){
    tmenu.innerHTML=TEMPLATES.map(function(t,i){
      return '<div class="slash-item" onclick="applyTemplate('+i+')"><span class="slash-item-icon">'+t.name.split(' ')[0]+'</span><div style="font-size:12px;">'+esc(t.name.replace(/^[\S]+ /,''))+'</div></div>';
    }).join('');
  }
  lv.style.display='none';ev.style.display='flex';
  setTimeout(function(){document.getElementById('ne-content').focus();},50);
  initSlashCommands(document.getElementById('ne-content'));
};
window.openNoteEditorNew=function(){openNoteEditor(null);};
window.openQuickObjectiveNote=function(){
  openNoteEditor(null);
  document.getElementById('ne-title').value='Current Objective';
  document.getElementById('ne-content').value='[ ] ';
  var routeWrap=document.getElementById('ne-route-wrap');
  var pokemonWrap=document.getElementById('ne-pokemon-wrap');
  if(routeWrap) routeWrap.style.display='none';
  if(pokemonWrap) pokemonWrap.style.display='none';
  document.getElementById('ne-pin').classList.add('active');
  document.getElementById('ne-pin').textContent='📌 Pinned';
  noteEditorStatus='active';
  if(typeof window.neRefreshStatusButtons==='function') window.neRefreshStatusButtons();
  document.getElementById('ne-content').focus();
};

window.cancelNoteEditor=function(){
  editingId=null;
  document.getElementById('notes-list-view').style.display='flex';
  document.getElementById('notes-editor-view').style.display='none';
  destroySlashDropdown();
};

window.saveNoteEditor=function(){
  var title=document.getElementById('ne-title').value.trim();
  var content=document.getElementById('ne-content').value;
  var game=document.getElementById('ne-game').value;
  var routeRef=document.getElementById('ne-route').value.trim();
  var pokemonRef=document.getElementById('ne-pokemon').value.trim();
  if(!title) title=pokemonRef||routeRef||'';
  if(routeRef && isGuideLinkedNote({content:content})) title=routeRef;
  else if(pokemonRef) title=pokemonRef;
  var labels=document.getElementById('ne-labels').value.split(',').map(function(l){return l.trim();}).filter(Boolean);
  var tagged=[];document.querySelectorAll('.ne-tag-btn.active').forEach(function(b){tagged.push(b.dataset.game);});
  var color='none';document.querySelectorAll('.ne-color-btn.active').forEach(function(b){color=b.dataset.color;});
  var pinned=document.getElementById('ne-pin').classList.contains('active');
  if(editingId&&editingId!=='new'){
    var n=notes.find(function(x){return x.id===editingId;});
    if(n){n.title=title;n.content=content;n.primaryGame=game;n.taggedGames=tagged;n.labels=labels;n.color=color;n.pinned=pinned;n.routeRef=routeRef;n.pokemonRef=pokemonRef;n.status=noteEditorStatus;n.modified=Date.now();n.checkboxStates={};}
  }else{
    notes.unshift({id:genId(),title:title,content:content,primaryGame:game,taggedGames:tagged,labels:labels,color:color,pinned:pinned,routeRef:routeRef,pokemonRef:pokemonRef,status:noteEditorStatus,checkboxStates:{},created:Date.now(),modified:Date.now()});
  }
  saveNotes();cancelNoteEditor();renderNotesList();renderLabelBar();
};

window.neTogglePin=function(){var b=document.getElementById('ne-pin');b.classList.toggle('active');b.textContent=b.classList.contains('active')?'📌 Pinned':'📌 Pin';};
window.neSelectColor=function(btn){document.querySelectorAll('.ne-color-btn').forEach(function(b){b.classList.remove('active');});btn.classList.add('active');};
window.neAddLabel=function(l){var inp=document.getElementById('ne-labels');var cur=inp.value.split(',').map(function(x){return x.trim();}).filter(Boolean);if(cur.indexOf(l)<0)cur.push(l);inp.value=cur.join(', ');};
window.neInsertChip=function(l){
  if(typeof window.neAddLabel==='function') window.neAddLabel(l);
  var ta=document.getElementById('ne-content'); if(!ta) return;
  var s=ta.selectionStart,v=ta.value,bef=v.slice(0,s),aft=v.slice(s);
  var txt='['+l+'] ';
  ta.value=bef+txt+aft;
  ta.selectionStart=ta.selectionEnd=bef.length+txt.length;
  ta.focus();
};
window.neSetStatus=function(status){noteEditorStatus=status; if(typeof window.neRefreshStatusButtons==='function') window.neRefreshStatusButtons();};
window.neRefreshStatusButtons=function(){
  ['active','completed','archived'].forEach(function(k){
    var el=document.getElementById('ne-status-'+k);
    if(el) el.classList.toggle('active',noteEditorStatus===k);
  });
};
window.neInsertTimestamp=function(){
  var d=new Date(), mo=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  var hh=String(d.getHours()).padStart(2,'0'), mm=String(d.getMinutes()).padStart(2,'0');
  var stamp='['+d.getDate()+' '+mo[d.getMonth()]+' '+d.getFullYear()+' '+hh+':'+mm+'] ';
  var ta=document.getElementById('ne-content'); if(!ta) return;
  var s=ta.selectionStart,v=ta.value,bef=v.slice(0,s),aft=v.slice(s);
  ta.value=bef+stamp+aft;
  ta.selectionStart=ta.selectionEnd=bef.length+stamp.length;
  ta.focus();
};
window.neDuplicateEditing=function(){
  if(!editingId || editingId==='new') return;
  duplicateNote(editingId);
};
window.neTemplateMenuToggle=function(){var m=document.getElementById('ne-template-menu');m.style.display=m.style.display==='none'?'block':'none';};
window.applyTemplate=function(i){var t=TEMPLATES[i];if(!t)return;document.getElementById('ne-content').value=t.content;if(t.label){var inp=document.getElementById('ne-labels');neAddLabel(t.label);}document.querySelectorAll('.ne-color-btn').forEach(function(b){b.classList.toggle('active',b.dataset.color===t.color);});document.getElementById('ne-template-menu').style.display='none';};
window.neCommand=function(type){
  var ta=document.getElementById('ne-content');
  if(!ta)return;
  var s=ta.selectionStart,e=ta.selectionEnd,v=ta.value,bef=v.slice(0,s),aft=v.slice(e);
  function place(text, offset){
    ta.value=bef+text+aft;
    var pos=typeof offset==='number'?bef.length+offset:bef.length+text.length;
    ta.selectionStart=ta.selectionEnd=pos;
    ta.focus();
  }
  function trigger(cmd){
    place(cmd);
    if(typeof _sin==='function')_sin();
  }
  if(type==='page') return trigger('/p');
  if(type==='guide') return trigger('/b');
  if(type==='game') return trigger('/g');
  if(type==='type') return trigger('/type');
  if(type==='badge') return trigger('/badge');
  if(type==='template'){
    if(typeof window.neTemplateMenuToggle==='function')window.neTemplateMenuToggle();
    ta.focus();
    return;
  }
  if(type==='date'){
    var d=new Date(),mo=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    return place(d.getDate()+' '+mo[d.getMonth()]+' '+d.getFullYear());
  }
  if(type==='divider') return place('\n\n---\n\n');
  if(type==='note') return place('📝 **Note:** ');
  if(type==='warn') return place('⚠️ **Warning:** ');
};
window.neFmt=function(type){
  var ta=document.getElementById('ne-content');
  var s=ta.selectionStart,e=ta.selectionEnd,v=ta.value,sel=v.slice(s,e),bef=v.slice(0,s),aft=v.slice(e);
  var ins,ns,ne2;
  if(type==='bold'){ins='**'+(sel||'text')+'**';ns=s+2;ne2=ns+(sel||'text').length;}
  else if(type==='italic'){ins='*'+(sel||'text')+'*';ns=s+1;ne2=ns+(sel||'text').length;}
  else if(type==='h2'){var ls=bef.lastIndexOf('\n')+1,lc=v.slice(ls,e);if(lc.startsWith('## ')){ta.value=v.slice(0,ls)+lc.slice(3)+aft;}else{ta.value=v.slice(0,ls)+'## '+lc+aft;}ta.selectionStart=ta.selectionEnd=ta.value.length-aft.length;ta.focus();return;}
  else if(type==='bullet'){var pre=(bef.endsWith('\n')||bef===''?'':'\n');ins=pre+'- '+(sel||'item')+'\n';ns=s+(pre?1:0)+2;ne2=ns+(sel||'item').length;}
  else if(type==='check'){var pre2=(bef.endsWith('\n')||bef===''?'':'\n');ins=pre2+'[ ] '+(sel||'task')+'\n';ns=s+(pre2?1:0)+4;ne2=ns+(sel||'task').length;}
  else return;
  ta.value=bef+ins+aft;ta.selectionStart=ns;ta.selectionEnd=ne2;ta.focus();
};

/* ── Slash commands ── */
var _sd=null,_ss=-1,_sm=null,_sbg=null,_sfi=0,_si=[];
var _sdTouching=false; // true while a finger is down on the dropdown (iOS scroll guard)

// Full reset — call when cancelling the slash command entirely
function destroySlashDropdown(){
  _sdTouching=false;
  if(_sd){
    if(_sd._vpListener&&window.visualViewport)window.visualViewport.removeEventListener('resize',_sd._vpListener);
    _sd.remove();_sd=null;
  }
  _ss=-1;_sm=null;_sbg=null;_sfi=0;_si=[];
}
// DOM-only removal — preserves state when transitioning between dropdown steps
function _clearSlashDom(){
  if(_sd){
    if(_sd._vpListener&&window.visualViewport)window.visualViewport.removeEventListener('resize',_sd._vpListener);
    _sd.remove();_sd=null;
  }
}

function initSlashCommands(ta){
  ta.removeEventListener('keydown',_skd);
  ta.removeEventListener('input',_sin);
  ta.addEventListener('keydown',_skd);
  ta.addEventListener('input',_sin);
  ta.addEventListener('blur',function(){
    // If a finger is currently on the dropdown (_sdTouching) we must NOT destroy
    // yet — the touchend handler will clean up once the gesture is finished.
    setTimeout(function(){if(_sd&&!_sdTouching)destroySlashDropdown();},300);
  });
}

var _CMD_LIST=[
  {icon:'📄',label:'Page link',      sub:'/p — link to any site page',          cmd:'p'},
  {icon:'🌿',label:'Guide link',     sub:'/b — link to a Bulba Guide section',  cmd:'b'},
  {icon:'📅',label:'Timestamp',      sub:'/d — insert date &amp; time',          cmd:'d'},
  {icon:'🎮',label:'Game name',      sub:'/g — insert a game name',             cmd:'g'},
  {icon:'─', label:'Divider',        sub:'/hr — horizontal separator line',     cmd:'hr'},
  {icon:'🏅',label:'Badge',          sub:'/badge — Kanto & Hoenn badge names',  cmd:'badge'},
  {icon:'🔮',label:'Type',           sub:'/type — Pokémon type name',           cmd:'type'},
  {icon:'📋',label:'Template',       sub:'/t — apply a note template',          cmd:'t'},
  {icon:'📝',label:'Note callout',   sub:'/n — 📝 Note: callout prefix',       cmd:'n'},
  {icon:'⚠️',label:'Warning callout',sub:'/warn — ⚠️ Warning: callout prefix',cmd:'warn'},
];
