// Dynamic page height — keeps calc(100vh - var(--page-top)) correct when header wraps on mobile
function updatePageTop() {
  var h = (document.querySelector('header') || {}).offsetHeight || 0;
  var n = (document.querySelector('.page-nav-scroll-wrap') || {}).offsetHeight || 0;
  document.documentElement.style.setProperty('--page-top', (h + n) + 'px');
}
window.addEventListener('resize', function() { requestAnimationFrame(updatePageTop); });
requestAnimationFrame(updatePageTop);

// iOS fix: position:fixed is clipped by overflow:auto ancestors on iOS Safari.
// Move dropdown menus to <body> so they escape the nav scroll container.
window._navMenuMap = {};
requestAnimationFrame(function() {
  document.querySelectorAll('.page-nav-dropdown').forEach(function(container) {
    var menu = container.querySelector('.page-nav-dropdown-menu');
    if (menu && container.id) {
      window._navMenuMap[container.id] = menu;
      document.body.appendChild(menu);
    }
  });
});

