// ── KANTO MAP ENGINE ───────────────────────────────────────────
var KM_SCALE = 0.08;
var KM_TX = 0;
var KM_TY = 0;
var KM_DRAGGING = false;
var KM_DRAG_START = null;
var KM_MARKED = new Set();
var KM_MAP_W = 7700;
var KM_MAP_H = 6400;
var KM_IMG_BASE = 'https://raw.githubusercontent.com/kelseyyoung/FRLGIronmonMap/main/src/assets/FullKanto.png';
var KM_IMG_PATHS = 'https://raw.githubusercontent.com/kelseyyoung/FRLGIronmonMap/main/src/assets/FullKantoPaths.png';
var KM_MAP_URL = './FRLGIronmonMap/index.html';
var EM_MAP_URL = './EmeraldIronmonMap/index.html';
var KM_MAP_STORAGE_KEY = 'FRLG_StorageKey';
var EM_MAP_STORAGE_KEY = 'Emerald_StorageKey';

function kmApplyTransform() {
  var canvas = document.getElementById('km-canvas');
  if (canvas) canvas.style.transform = 'translate(' + KM_TX + 'px,' + KM_TY + 'px) scale(' + KM_SCALE + ')';
}

function kmResetView() {
  var wrap = document.getElementById('km-wrap');
  if (!wrap) return;
  var vw = wrap.clientWidth, vh = wrap.clientHeight;
  // Start centered on Pallet Town area (approx map centre-south)
  KM_SCALE = Math.min(vw / KM_MAP_W, vh / KM_MAP_H) * 1.0;
  KM_TX = (vw - KM_MAP_W * KM_SCALE) / 2;
  KM_TY = (vh - KM_MAP_H * KM_SCALE) / 2;
  kmApplyTransform();
}

function kmZoom(factor) {
  var wrap = document.getElementById('km-wrap');
  if (!wrap) return;
  var cx = wrap.clientWidth / 2, cy = wrap.clientHeight / 2;
  var newScale = Math.max(0.04, Math.min(4, KM_SCALE * factor));
  KM_TX = cx - (cx - KM_TX) * (newScale / KM_SCALE);
  KM_TY = cy - (cy - KM_TY) * (newScale / KM_SCALE);
  KM_SCALE = newScale;
  kmApplyTransform();
}

function kmUpdateVisibility() {
  var showT = document.getElementById('km-show-trainers') && document.getElementById('km-show-trainers').checked;
  var showI = document.getElementById('km-show-items') && document.getElementById('km-show-items').checked;
  var showP = document.getElementById('km-show-portals') && document.getElementById('km-show-portals').checked;
  var showR = document.getElementById('km-show-routes') && document.getElementById('km-show-routes').checked;
  var showN = document.getElementById('km-show-normal') && document.getElementById('km-show-normal').checked;
  var showH = document.getElementById('km-show-hidden') && document.getElementById('km-show-hidden').checked;
  var showM = document.getElementById('km-show-tm') && document.getElementById('km-show-tm').checked;
  var paths = document.getElementById('km-paths');
  if (paths) paths.style.display = showR ? 'block' : 'none';
  var svg = document.getElementById('km-svg');
  if (!svg) return;
  svg.querySelectorAll('.km-trainer').forEach(function(el) { el.style.display = showT ? '' : 'none'; });
  svg.querySelectorAll('.km-item-normal').forEach(function(el) { el.style.display = (showI && showN) ? '' : 'none'; });
  svg.querySelectorAll('.km-item-hidden').forEach(function(el) { el.style.display = (showI && showH) ? '' : 'none'; });
  svg.querySelectorAll('.km-item-tm').forEach(function(el) { el.style.display = (showI && showM) ? '' : 'none'; });
  svg.querySelectorAll('.km-portal').forEach(function(el) { el.style.display = showP ? '' : 'none'; });
  svg.querySelectorAll('.km-portal-line').forEach(function(el) { el.style.display = showP ? '' : 'none'; });
}

function kmJumpTo(x, y) {
  var wrap = document.getElementById('km-wrap');
  if (!wrap) return;
  var cx = wrap.clientWidth / 2, cy = wrap.clientHeight / 2;
  KM_TX = cx - x * KM_SCALE;
  KM_TY = cy - y * KM_SCALE;
  kmApplyTransform();
}

function buildKantoMap() {
  var wrap = document.getElementById('km-wrap');
  if (!wrap) return;
  var base = document.getElementById('km-base');
  var paths = document.getElementById('km-paths');
  var canvas = document.getElementById('km-canvas');
  var loading = document.getElementById('km-loading');

  base.src = KM_IMG_BASE;
  paths.src = KM_IMG_PATHS;

  base.onload = function() {
    if (loading) loading.style.display = 'none';
    if (canvas) canvas.style.display = '';
    kmResetView();
    kmRenderSVG();
    kmBindControls();
    kmBindPanZoom();
  };
  base.onerror = function() {
    if (loading) loading.innerHTML = '<div style="color:var(--fire);font-size:9px;font-family:monospace;text-align:center">⚠ MAP FAILED TO LOAD<br><br><span style="font-size:10px;color:var(--muted)">Internet connection required</span></div>';
  };

  window._kantomapBuilt = true;
}

function buildKantoMapView() {
  var iframe = document.getElementById('kmc-iframe');
  var status = document.getElementById('kmc-status');
  if (!iframe) return;
  if (status) {
    status.classList.remove('hidden');
    status.innerHTML = 'Loading Kanto Map...';
  }
  iframe.onload = function() {
    if (status) status.classList.add('hidden');
    // Sync current game color into the freshly loaded iframe
    setTimeout(function() {
      var _rc = getComputedStyle(document.documentElement).getPropertyValue('--game-color').trim() || '#f5c518';
      try { iframe.contentWindow.postMessage({ type: 'mapGameColor', color: _rc }, '*'); } catch(e) {}
    }, 80);
  };
  iframe.onerror = function() {
    if (status) {
      status.classList.remove('hidden');
      status.innerHTML = 'Kanto Map failed to load.<br><br>Check that <code>FRLGIronmonMap/index.html</code> exists beside this file.';
    }
  };
  iframe.src = KM_MAP_URL + '?v=1';
  window._kantomapviewBuilt = true;
}

function buildEmeraldMapView() {
  var iframe = document.getElementById('emc-iframe');
  var status = document.getElementById('emc-status');
  if (!iframe) return;
  if (status) {
    status.classList.remove('hidden');
    status.innerHTML = 'Loading Emerald Map...';
  }
  iframe.onload = function() {
    if (status) status.classList.add('hidden');
    // Sync current game color into the freshly loaded iframe
    setTimeout(function() {
      var _rc = getComputedStyle(document.documentElement).getPropertyValue('--game-color').trim() || '#f5c518';
      try { iframe.contentWindow.postMessage({ type: 'mapGameColor', color: _rc }, '*'); } catch(e) {}
    }, 80);
  };
  iframe.onerror = function() {
    if (status) {
      status.classList.remove('hidden');
      status.innerHTML = 'Emerald Map failed to load.<br><br>Check that <code>EmeraldIronmonMap/index.html</code> exists beside this file.';
    }
  };
  iframe.src = EM_MAP_URL + '?v=1';
  window._emeraldmapviewBuilt = true;
}

function kmRenderSVG() {
  var svg = document.getElementById('km-svg');
  if (!svg) return;
  var html = '';

  // Portals — draw lines between pairs first (so they appear under icons)
  KM_PORTALS.forEach(function(group) {
    group.portals.forEach(function(pair, pi) {
      var p1 = pair.portal1, p2 = pair.portal2;
      var color = group.color || '#888';
      html += '<line class="km-portal-line" x1="' + (p1.x + KM_PORTAL_SIZE/2) + '" y1="' + (p1.y + KM_PORTAL_SIZE/2) + '" x2="' + (p2.x + KM_PORTAL_SIZE/2) + '" y2="' + (p2.y + KM_PORTAL_SIZE/2) + '" stroke="' + color + '"/>';
    });
  });

  // Portal icons
  KM_PORTALS.forEach(function(group) {
    group.portals.forEach(function(pair, pi) {
      var p1 = pair.portal1, p2 = pair.portal2;
      var color = group.color || '#888';
      var area = (group.area || '').replace(/"/g, '&quot;');
      // Portal 1
      html += '<rect class="km-portal" x="' + p1.x + '" y="' + p1.y + '" width="' + KM_PORTAL_SIZE + '" height="' + KM_PORTAL_SIZE + '" fill="' + color + '" stroke="#fff" stroke-width="1.5" rx="3" opacity="0.8" data-tx="' + p2.x + '" data-ty="' + p2.y + '" data-area="' + area + '" onclick="kmJumpTo(this.dataset.tx*1+' + KM_PORTAL_SIZE/2 + ',this.dataset.ty*1+' + KM_PORTAL_SIZE/2 + ')"><title>' + area + ' portal → jump to other side</title></rect>';
      // Portal 2
      html += '<rect class="km-portal" x="' + p2.x + '" y="' + p2.y + '" width="' + KM_PORTAL_SIZE + '" height="' + KM_PORTAL_SIZE + '" fill="' + color + '" stroke="#fff" stroke-width="1.5" rx="3" opacity="0.8" data-tx="' + p1.x + '" data-ty="' + p1.y + '" data-area="' + area + '" onclick="kmJumpTo(this.dataset.tx*1+' + KM_PORTAL_SIZE/2 + ',this.dataset.ty*1+' + KM_PORTAL_SIZE/2 + ')"><title>' + area + ' portal → jump to other side</title></rect>';
    });
  });

  // Items
  KM_ITEMS.forEach(function(item, idx) {
    var cls = 'km-item-' + (item.type || 'normal');
    var label = item.type === 'hidden' ? 'Hidden item' + (item.spawnChance ? ' (' + item.spawnChance + ')' : '') : item.type === 'tm' ? 'TM/HM' : 'Item';
    html += '<circle class="' + cls + '" cx="' + (item.x + KM_ITEM_W/2) + '" cy="' + (item.y + KM_ITEM_H/2) + '" r="5"><title>' + label + '</title></circle>';
  });

  // Trainers
  KM_TRAINERS.forEach(function(trainer, idx) {
    var levels = (trainer.pokemonLevels || []).join(', ');
    var name = (trainer.name || '').replace(/"/g, '&quot;');
    var marked = KM_MARKED.has(idx);
    var markCls = marked ? ' km-marked' : '';
    html += '<g class="km-trainer' + markCls + '" data-idx="' + idx + '" onclick="kmToggleMark(' + idx + ',this)" onmouseenter="kmShowTooltip(event,' + idx + ')" onmouseleave="kmHideTooltip()">'
      + '<rect x="' + (trainer.x - KM_TRAINER_W/2) + '" y="' + (trainer.y - KM_TRAINER_H/2) + '" width="' + KM_TRAINER_W + '" height="' + KM_TRAINER_H + '" rx="3"/>'
      + '<text x="' + trainer.x + '" y="' + (trainer.y + 4) + '" text-anchor="middle" font-size="10" fill="#fff" pointer-events="none">T</text>'
      + '</g>';
  });

  svg.innerHTML = html;
}

function kmToggleMark(idx, el) {
  if (KM_MARKED.has(idx)) { KM_MARKED.delete(idx); el.classList.remove('km-marked'); }
  else { KM_MARKED.add(idx); el.classList.add('km-marked'); }
}

function kmShowTooltip(event, idx) {
  var trainer = KM_TRAINERS[idx];
  if (!trainer) return;
  var tt = document.getElementById('km-tooltip');
  var nameEl = document.getElementById('km-tt-name');
  var lvlEl = document.getElementById('km-tt-lvl');
  if (!tt || !nameEl || !lvlEl) return;
  nameEl.textContent = trainer.name;
  var lvls = (trainer.pokemonLevels || []);
  lvlEl.textContent = trainer.numPokemon + ' Pokémon · Lv ' + lvls.join(', ');
  tt.style.display = 'block';
  kmPositionTooltip(event, trainer);
}

function kmPositionTooltip(event, trainer) {
  var tt = document.getElementById('km-tooltip');
  if (!tt) return;
  var x = event.clientX + 14, y = event.clientY - 10;
  if (x + 230 > window.innerWidth) x = event.clientX - 240;
  if (y + 80 > window.innerHeight) y = event.clientY - 80;
  tt.style.left = x + 'px';
  tt.style.top = y + 'px';
}

function kmHideTooltip() {
  var tt = document.getElementById('km-tooltip');
  if (tt) tt.style.display = 'none';
}

function kmBindControls() {
  ['km-show-trainers','km-show-items','km-show-portals','km-show-routes','km-show-normal','km-show-hidden','km-show-tm'].forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.addEventListener('change', kmUpdateVisibility);
  });
}

function kmBindPanZoom() {
  var wrap = document.getElementById('km-wrap');
  if (!wrap) return;

  wrap.addEventListener('mousedown', function(e) {
    if (e.target.closest('.km-trainer') || e.target.closest('.km-portal') || e.target.closest('#km-controls')) return;
    KM_DRAGGING = true;
    KM_DRAG_START = { x: e.clientX - KM_TX, y: e.clientY - KM_TY };
    wrap.classList.add('grabbing');
    e.preventDefault();
  });

  window.addEventListener('mousemove', function(e) {
    if (!KM_DRAGGING) return;
    KM_TX = e.clientX - KM_DRAG_START.x;
    KM_TY = e.clientY - KM_DRAG_START.y;
    kmApplyTransform();
    kmHideTooltip();
  });

  window.addEventListener('mouseup', function() {
    KM_DRAGGING = false;
    var wrap = document.getElementById('km-wrap');
    if (wrap) wrap.classList.remove('grabbing');
  });

  wrap.addEventListener('wheel', function(e) {
    e.preventDefault();
    var rect = wrap.getBoundingClientRect();
    var cx = e.clientX - rect.left;
    var cy = e.clientY - rect.top;
    var factor = e.deltaY < 0 ? 1.12 : 1/1.12;
    var newScale = Math.max(0.04, Math.min(4, KM_SCALE * factor));
    KM_TX = cx - (cx - KM_TX) * (newScale / KM_SCALE);
    KM_TY = cy - (cy - KM_TY) * (newScale / KM_SCALE);
    KM_SCALE = newScale;
    kmApplyTransform();
  }, { passive: false });

  // Touch support
  var lastTouchDist = null;
  wrap.addEventListener('touchstart', function(e) {
    if (e.target.closest('#km-controls')) return;
    if (e.touches.length === 1) {
      KM_DRAGGING = true;
      KM_DRAG_START = { x: e.touches[0].clientX - KM_TX, y: e.touches[0].clientY - KM_TY };
    } else if (e.touches.length === 2) {
      KM_DRAGGING = false;
      lastTouchDist = Math.hypot(e.touches[0].clientX - e.touches[1].clientX, e.touches[0].clientY - e.touches[1].clientY);
    }
    e.preventDefault();
  }, { passive: false });

  wrap.addEventListener('touchmove', function(e) {
    if (e.touches.length === 1 && KM_DRAGGING) {
      KM_TX = e.touches[0].clientX - KM_DRAG_START.x;
      KM_TY = e.touches[0].clientY - KM_DRAG_START.y;
      kmApplyTransform();
    } else if (e.touches.length === 2 && lastTouchDist) {
      var dist = Math.hypot(e.touches[0].clientX - e.touches[1].clientX, e.touches[0].clientY - e.touches[1].clientY);
      var factor = dist / lastTouchDist;
      lastTouchDist = dist;
      var cx = (e.touches[0].clientX + e.touches[1].clientX) / 2;
      var cy = (e.touches[0].clientY + e.touches[1].clientY) / 2;
      var rect = wrap.getBoundingClientRect();
      cx -= rect.left; cy -= rect.top;
      var newScale = Math.max(0.04, Math.min(4, KM_SCALE * factor));
      KM_TX = cx - (cx - KM_TX) * (newScale / KM_SCALE);
      KM_TY = cy - (cy - KM_TY) * (newScale / KM_SCALE);
      KM_SCALE = newScale;
      kmApplyTransform();
    }
    e.preventDefault();
  }, { passive: false });

  wrap.addEventListener('touchend', function() { KM_DRAGGING = false; lastTouchDist = null; });
}


