// ── EMERALD MAP ENGINE ────────────────────────────────────────
var EM_SCALE = 0.08;
var EM_TX = 0;
var EM_TY = 0;
var EM_DRAGGING = false;
var EM_DRAG_START = null;
var EM_MARKED = new Set();
var EM_MAP_W = 12800;
var EM_MAP_H = 6408;
var EM_BASE_URL = 'https://raw.githubusercontent.com/kelseyyoung/EmeraldIronmonMap/main/src/assets/';

var EM_ROUTES = [
  { id:'em-granite',   file:'GraniteCaveRoute.webp' },
  { id:'em-newmau',    file:'NewMauvilleRoute.webp' },
  { id:'em-meteor',    file:'MeteorFallsRoute.webp' },
  { id:'em-magma',     file:'MagmaHideoutRoute.webp' },
  { id:'em-aqua',      file:'AquaHideoutRoute.webp' },
  { id:'em-seafloor',  file:'SeafloorCavernRoute.webp' },
  { id:'em-victory',   file:'VictoryRoadRoute.webp' },
  { id:'em-currents',  file:'CurrentsRoute.webp' }
];

function emApplyTransform() {
  var c = document.getElementById('em-canvas');
  if (c) c.style.transform = 'translate('+EM_TX+'px,'+EM_TY+'px) scale('+EM_SCALE+')';
}
function emResetView() {
  var wrap = document.getElementById('em-wrap');
  if (!wrap) return;
  var vw = wrap.clientWidth, vh = wrap.clientHeight;
  EM_SCALE = Math.min(vw/EM_MAP_W, vh/EM_MAP_H);
  EM_TX = (vw - EM_MAP_W*EM_SCALE)/2;
  EM_TY = (vh - EM_MAP_H*EM_SCALE)/2;
  emApplyTransform();
}
function emZoom(factor) {
  var wrap = document.getElementById('em-wrap');
  if (!wrap) return;
  var cx = wrap.clientWidth/2, cy = wrap.clientHeight/2;
  var ns = Math.max(0.04, Math.min(4, EM_SCALE*factor));
  EM_TX = cx-(cx-EM_TX)*(ns/EM_SCALE);
  EM_TY = cy-(cy-EM_TY)*(ns/EM_SCALE);
  EM_SCALE = ns;
  emApplyTransform();
}
function emJumpTo(x, y) {
  var wrap = document.getElementById('em-wrap');
  if (!wrap) return;
  EM_TX = wrap.clientWidth/2 - x*EM_SCALE;
  EM_TY = wrap.clientHeight/2 - y*EM_SCALE;
  emApplyTransform();
}
function emUpdateVisibility() {
  function chk(id){ var el=document.getElementById(id); return el&&el.checked; }
  var showT=chk('em-show-trainers'), showI=chk('em-show-items'), showP=chk('em-show-portals');
  var showR=chk('em-show-routes'), showN=chk('em-show-normal'), showH=chk('em-show-hidden'), showM=chk('em-show-tm');
  EM_ROUTES.forEach(function(r){ var el=document.getElementById(r.id); if(el) el.style.display=showR?'':'none'; });
  var svg=document.getElementById('em-svg');
  if (!svg) return;
  svg.querySelectorAll('.km-trainer').forEach(function(el){ el.style.display=showT?'':'none'; });
  svg.querySelectorAll('.km-item-normal').forEach(function(el){ el.style.display=(showI&&showN)?'':'none'; });
  svg.querySelectorAll('.km-item-hidden').forEach(function(el){ el.style.display=(showI&&showH)?'':'none'; });
  svg.querySelectorAll('.km-item-tm').forEach(function(el){ el.style.display=(showI&&showM)?'':'none'; });
  svg.querySelectorAll('.km-portal').forEach(function(el){ el.style.display=showP?'':'none'; });
  svg.querySelectorAll('.km-portal-line').forEach(function(el){ el.style.display=showP?'':'none'; });
}
function buildEmeraldMap() {
  var wrap=document.getElementById('em-wrap');
  if (!wrap) return;
  var base=document.getElementById('em-base');
  var canvas=document.getElementById('em-canvas');
  var loading=document.getElementById('em-loading');
  base.src = EM_BASE_URL+'FullHoenn.webp';
  base.onload = function() {
    if (loading) loading.style.display='none';
    if (canvas) canvas.style.display='';
    emResetView();
    emRenderSVG();
    emBindControls();
    emBindPanZoom();
    EM_ROUTES.forEach(function(r){ var el=document.getElementById(r.id); if(el) el.src=EM_BASE_URL+r.file; });
  };
  base.onerror = function() {
    if (loading) loading.innerHTML='<div style="color:var(--fire);font-size:9px;font-family:monospace;text-align:center">MAP FAILED TO LOAD<br><br><span style="font-size:10px;color:var(--muted)">Internet connection required</span></div>';
  };
  window._emeraldmapBuilt = true;
}
function emRenderSVG() {
  var svg=document.getElementById('em-svg');
  if (!svg) return;
  var html='';
  EM_PORTALS.forEach(function(group) {
    group.portals.forEach(function(pair) {
      var p1=pair.portal1, p2=pair.portal2, color=group.color||'#888';
      html+='<line class="km-portal-line" x1="'+(p1.x+EM_PORTAL_SIZE/2)+'" y1="'+(p1.y+EM_PORTAL_SIZE/2)+'" x2="'+(p2.x+EM_PORTAL_SIZE/2)+'" y2="'+(p2.y+EM_PORTAL_SIZE/2)+'" stroke="'+color+'"/>';
    });
  });
  EM_PORTALS.forEach(function(group) {
    group.portals.forEach(function(pair) {
      var p1=pair.portal1, p2=pair.portal2, color=group.color||'#888', area=(group.area||'').replace(/"/g,'&quot;');
      html+='<rect class="km-portal" x="'+p1.x+'" y="'+p1.y+'" width="'+EM_PORTAL_SIZE+'" height="'+EM_PORTAL_SIZE+'" fill="'+color+'" stroke="#fff" stroke-width="1.5" rx="3" opacity="0.8" onclick="emJumpTo('+(p2.x+EM_PORTAL_SIZE/2)+','+(p2.y+EM_PORTAL_SIZE/2)+')"><title>'+area+' portal</title></rect>';
      html+='<rect class="km-portal" x="'+p2.x+'" y="'+p2.y+'" width="'+EM_PORTAL_SIZE+'" height="'+EM_PORTAL_SIZE+'" fill="'+color+'" stroke="#fff" stroke-width="1.5" rx="3" opacity="0.8" onclick="emJumpTo('+(p1.x+EM_PORTAL_SIZE/2)+','+(p1.y+EM_PORTAL_SIZE/2)+')"><title>'+area+' portal</title></rect>';
    });
  });
  EM_ITEMS.forEach(function(item) {
    var cls='km-item-'+(item.type||'normal');
    var lbl=item.type==='hidden'?'Hidden item'+(item.spawnChance?' ('+item.spawnChance+')':''):item.type==='tm'?'TM/HM':'Item';
    html+='<circle class="'+cls+'" cx="'+(item.x+EM_ITEM_W/2)+'" cy="'+(item.y+EM_ITEM_H/2)+'" r="5"><title>'+lbl+'</title></circle>';
  });
  EM_TRAINERS.forEach(function(trainer, idx) {
    var cls='km-trainer'+(EM_MARKED.has(idx)?' km-marked':'');
    html+='<g class="'+cls+'" data-idx="'+idx+'" onclick="emToggleMark('+idx+',this)" onmouseenter="emShowTooltip(event,'+idx+')" onmouseleave="emHideTooltip()">'
      +'<rect x="'+(trainer.x-EM_TRAINER_W/2)+'" y="'+(trainer.y-EM_TRAINER_H/2)+'" width="'+EM_TRAINER_W+'" height="'+EM_TRAINER_H+'" rx="3"/>'
      +'<text x="'+trainer.x+'" y="'+(trainer.y+4)+'" text-anchor="middle" font-size="10" fill="#fff" pointer-events="none">T</text>'
      +'</g>';
  });
  svg.innerHTML=html;
}
function emToggleMark(idx,el) {
  if (EM_MARKED.has(idx)){EM_MARKED.delete(idx);el.classList.remove('km-marked');}
  else{EM_MARKED.add(idx);el.classList.add('km-marked');}
}
function emShowTooltip(event,idx) {
  var t=EM_TRAINERS[idx]; if(!t) return;
  var tt=document.getElementById('em-tooltip');
  document.getElementById('em-tt-name').textContent=t.name;
  document.getElementById('em-tt-lvl').textContent=t.numPokemon+' Pokemon - Lv '+(t.pokemonLevels||[]).join(', ');
  tt.style.display='block';
  var x=event.clientX+14, y=event.clientY-10;
  if(x+230>window.innerWidth) x=event.clientX-240;
  if(y+80>window.innerHeight) y=event.clientY-80;
  tt.style.left=x+'px'; tt.style.top=y+'px';
}
function emHideTooltip(){var tt=document.getElementById('em-tooltip');if(tt)tt.style.display='none';}
function emBindControls() {
  ['em-show-trainers','em-show-items','em-show-portals','em-show-routes','em-show-normal','em-show-hidden','em-show-tm'].forEach(function(id){
    var el=document.getElementById(id); if(el) el.addEventListener('change',emUpdateVisibility);
  });
}
function emBindPanZoom() {
  var wrap=document.getElementById('em-wrap');
  if(!wrap) return;
  wrap.addEventListener('mousedown',function(e){
    if(e.target.closest('.km-trainer')||e.target.closest('.km-portal')||e.target.closest('#em-controls')) return;
    EM_DRAGGING=true; EM_DRAG_START={x:e.clientX-EM_TX,y:e.clientY-EM_TY};
    wrap.style.cursor='grabbing'; e.preventDefault();
  });
  window.addEventListener('mousemove',function(e){
    if(!EM_DRAGGING) return;
    EM_TX=e.clientX-EM_DRAG_START.x; EM_TY=e.clientY-EM_DRAG_START.y;
    emApplyTransform(); emHideTooltip();
  });
  window.addEventListener('mouseup',function(){ EM_DRAGGING=false; var w=document.getElementById('em-wrap'); if(w) w.style.cursor='grab'; });
  wrap.addEventListener('wheel',function(e){
    e.preventDefault();
    var rect=wrap.getBoundingClientRect();
    var cx=e.clientX-rect.left, cy=e.clientY-rect.top;
    var factor=e.deltaY<0?1.12:1/1.12;
    var ns=Math.max(0.04,Math.min(4,EM_SCALE*factor));
    EM_TX=cx-(cx-EM_TX)*(ns/EM_SCALE); EM_TY=cy-(cy-EM_TY)*(ns/EM_SCALE); EM_SCALE=ns;
    emApplyTransform();
  },{passive:false});
  var ltd=null;
  wrap.addEventListener('touchstart',function(e){
    if(e.target.closest('#em-controls')) return;
    if(e.touches.length===1){EM_DRAGGING=true;EM_DRAG_START={x:e.touches[0].clientX-EM_TX,y:e.touches[0].clientY-EM_TY};}
    else if(e.touches.length===2){EM_DRAGGING=false;ltd=Math.hypot(e.touches[0].clientX-e.touches[1].clientX,e.touches[0].clientY-e.touches[1].clientY);}
    e.preventDefault();
  },{passive:false});
  wrap.addEventListener('touchmove',function(e){
    if(e.touches.length===1&&EM_DRAGGING){EM_TX=e.touches[0].clientX-EM_DRAG_START.x;EM_TY=e.touches[0].clientY-EM_DRAG_START.y;emApplyTransform();}
    else if(e.touches.length===2&&ltd){var d=Math.hypot(e.touches[0].clientX-e.touches[1].clientX,e.touches[0].clientY-e.touches[1].clientY);var f=d/ltd;ltd=d;var cx=(e.touches[0].clientX+e.touches[1].clientX)/2-wrap.getBoundingClientRect().left;var cy=(e.touches[0].clientY+e.touches[1].clientY)/2-wrap.getBoundingClientRect().top;var ns=Math.max(0.04,Math.min(4,EM_SCALE*f));EM_TX=cx-(cx-EM_TX)*(ns/EM_SCALE);EM_TY=cy-(cy-EM_TY)*(ns/EM_SCALE);EM_SCALE=ns;emApplyTransform();}
    e.preventDefault();
  },{passive:false});
  wrap.addEventListener('touchend',function(){EM_DRAGGING=false;ltd=null;});
}

// ══════════════════════════════════════════════════════════════════
//  #10  MASCOT TIP BUBBLES
// ══════════════════════════════════════════════════════════════════
(function() {
  var TIPS = [
    'Synchronize in your lead slot copies wild encounter natures — great for hunting legendaries.',
    'Pickup (Meowth/Linoone) farms Rare Candies and Nuggets passively during battles.',
    'False Swipe can\'t knock out the target — the safest way to catch a legendary.',
    'Repel only blocks Pokémon lower-level than your lead. Keep it topped up in long caves.',
    'Blaze / Torrent / Overgrow activate at ≤⅓ HP — risky but powerful.',
    'Macho Brace halves your Speed but doubles EVs gained from every battle.',
    'Inner Focus prevents flinching — useful against Fake Out leads.',
    'Pokéblocks made from Lv.2+ berries raise conditions higher — quality matters for contests.',
    'EXP Share sends full EVs to the holder even without dealing damage.',
    'Skill Swap lets you steal Arena Trap or Magnet Pull from annoying opponents.',
    'Emerald\'s Battle Frontier has 7 facilities — Gold Symbols are the real endgame.',
    'Soft-reset in front of any legendary by saving before the battle — hunt for better IVs.',
    'Intimidate drops the opponent\'s Attack one stage on switch-in — great opener.',
    'Secret Power has different effects depending on the terrain you use it on.',
    'Wonder Guard (Shedinja) only works if you keep it healthy — bring a Safety Goggles team.',
  ];
  var MASCOTS = { all:25, FR:6, LG:3, R:257, S:260, E:254 };
  var tipIdx = Math.floor(Math.random() * TIPS.length);

  window.hideMascotTip = function() {
    var el = document.getElementById('mascot-tip');
    if (el) el.classList.remove('visible');
  };

  function showMascotTip() {
    var el = document.getElementById('mascot-tip');
    var txt = document.getElementById('mascot-tip-text');
    var img = document.getElementById('mascot-sprite');
    if (!el || !txt || !img) return;
    try { if (localStorage.getItem('gen3-mascot-off') === '1') return; } catch(e) {}
    txt.textContent = TIPS[tipIdx % TIPS.length];
    tipIdx++;
    var game = (function(){ try{ return localStorage.getItem('gen3-game')||'all'; }catch(e){ return 'all'; }})();
    img.src = 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + (MASCOTS[game] || 25) + '.png';
    el.classList.add('visible');
    clearTimeout(el._hideTimer);
    el._hideTimer = setTimeout(window.hideMascotTip, 8000);
  }

  // First tip after 25s, then every 55s
  document.addEventListener('DOMContentLoaded', function() {
    setTimeout(function() {
      showMascotTip();
      setInterval(showMascotTip, 55000);
    }, 25000);
  });
})();

// ── BADGE CLICK DELEGATION ────────────────────────────────────────────────────
// .hm-badge → open Move Dex (strip "TM##" / "HM##" prefix to get move name)
// .item-badge → open Item Dex (skip gym badges that won't be in the item list)
(function() {
  var GYM_BADGES = new Set([
    'Boulder Badge','Cascade Badge','Thunder Badge','Rainbow Badge',
    'Soul Badge','Marsh Badge','Volcano Badge','Earth Badge',
    'Stone Badge','Knuckle Badge','Dynamo Badge','Heat Badge',
    'Balance Badge','Feather Badge','Mind Badge','Rain Badge',
    'Coal Badge','Forest Badge','Cobble Badge','Fen Badge',
    'Relic Badge','Mine Badge','Icicle Badge','Beacon Badge',
  ]);

  document.addEventListener('click', function(e) {
    var el = e.target;
    if (el.classList.contains('hm-badge')) {
      var text = el.textContent.trim();
      // Strip leading "TM##" or "HM##" code, e.g. "TM39 Rock Tomb" → "Rock Tomb"
      var moveName = text.replace(/^(?:TM|HM)\d+\s+/i, '');
      if (moveName && typeof goToMoveInDex === 'function') goToMoveInDex(moveName);
    } else if (el.classList.contains('item-badge')) {
      var text = el.textContent.trim();
      if (!GYM_BADGES.has(text) && typeof openItemByName === 'function') openItemByName(text);
    }
  });
})();
